window.HADITH_CACHE = window.HADITH_CACHE || {};
window.HADITH_CACHE["nasai_7"] = {"3501":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ يَزِيدَ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ عَنْ سَعْدٍأَنَّهُ قَالَ مَاتَتْ أُمِّي وَعَلَيْهَا نَذْرٌ فَسَأَلْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَنِي أَنْ أَقْضِيَهُ عَنْهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin Yazid] ia berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari ['Ubaidullah bin Abdullah] dari [Ibnu Abbas] dari [Sa'd] bahwa ia berkata, \"Ibuku meninggal dan ia mempunyai kewajiban nadzar, kemudian aku menanyakan hal itu kepada Nabi shallallahu 'alaihi wasallam. Beliau lalu memerintahkan agar aku melakukan untuknya.\""},"3502":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ قَالَاسْتَفْتَى سَعْدُ بْنُ عُبَادَةَ الْأَنْصَارِيُّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي نَذْرٍ كَانَ عَلَى أُمِّهِ فَتُوُفِّيَتْ قَبْلَ أَنْ تَقْضِيَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْضِهِ عَنْهَا","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] berkata; telah menceritakan kepada kami [Al Laits] dari [Az Zuhri] dari ['Ubaidullah bin Abdullah] dari [Ibnu Abbas] berkata, \"Sa'd bin 'Ubadah Al Anshari meminta fatwa kepada Rasulullah shallallahu 'alaihi wasallam mengenai nadzar yang menjadi kewajiban atas ibunya, dan ibunya meninggal sebelum ia menunaikannya. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tunaikanlah untuknya.\""},"3503":{"ar":"أَخْبَرَنَا هَارُونُ بْنُ إِسْحَقَ الْهَمْدَانِيُّ عَنْ عَبْدَةَ عَنْ هِشَامٍ هُوَ ابْنُ عُرْوَةَ عَنْ بَكْرِ بْنِ وَائِلٍ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ قَالَجَاءَ سَعْدُ بْنُ عُبَادَةَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ أُمِّي مَاتَتْ وَعَلَيْهَا نَذْرٌ وَلَمْ تَقْضِهِ قَالَ اقْضِهِ عَنْهَا","id":"Telah mengabarkan kepada kami [Harun bin Ishaq Al Hamdani] dari ['Abdah] dari [Hisyam] -yaitu Ibnu 'Urwah- dari [Bakr bin Wail] dari [Az Zuhri] dari ['Ubaidullah bin Abdullah] dari [Ibnu Abbas] berkata, \"Sa'd bin 'Ubadah datang kepada Nabi shallallahu 'alaihi wasallam lalu berkata, \"Sesungguhnya ibuku meninggal dan ia memiliki kewajiban nadzar dan belum menunaikannya? ' Beliau bersabda: \"Tunaikanlah untuknya.\""},"3504":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ قَالَ حَدَّثَنَا وَكِيعٌ عَنْ هِشَامٍ عَنْ قَتَادَةَ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ سَعْدِ بْنِ عُبَادَةَ قَالَ قُلْتُيَا رَسُولَ اللَّهِ إِنَّ أُمِّي مَاتَتْ أَفَأَتَصَدَّقُ عَنْهَا قَالَ نَعَمْ قُلْتُ فَأَيُّ الصَّدَقَةِ أَفْضَلُ قَالَ سَقْيُ الْمَاءِ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin Al Mubarak] berkata; telah menceritakan kepada kami [Waki'] dari [Hisyam] dari [Qatadah] dari [Sa'id bin Al Musayyab] dari [Sa'd bin 'Ubadah] berkata, \"Aku berkata, \"Wahai Rasulullah, sesungguhnya ibuku meninggal, bolehkah aku bersedekah untuknya?\" Beliau menjawab: \"Ya.\" Aku lalu bertanya, \"Sedekah apakah yang paling utama?\" Beliau menjawab: \"Memberi minum air.\""},"3505":{"ar":"أَخْبَرَنَا أَبُو عَمَّارٍ الْحُسَيْنُ بْنُ حُرَيْثٍ عَنْ وَكِيعٍ عَنْ هِشَامٍ عَنْ قَتَادَةَ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ سَعْدِ بْنِ عُبَادَةَ قَالَ قُلْتُيَا رَسُولَ اللَّهِ أَيُّ الصَّدَقَةِ أَفْضَلُ قَالَ سَقْيُ الْمَاءِ","id":"Telah mengabarkan kepada kami [Abu 'Ammar Al Husaini bin Huraits] dari [Waki'] dari [Hisyam] dari [Qatadah] dari [Sa'id bin Al Musayyab] dari [Sa'd bin 'Ubadah] ia berkata, \"Aku bertanya, \"Wahai Rasulullah, sedekah apakah yang paling utama?\" Beliau menjawab: \"Memberi minum air.\""},"3506":{"ar":"أَخْبَرَنِي إِبْرَاهِيمُ بْنُ الْحَسَنِ عَنْ حَجَّاجٍ قَالَ سَمِعْتُ شُعْبَةَ يُحَدِّثُ عَنْ قَتَادَةَ قَالَ سَمِعْتُ الْحَسَنَ يُحَدِّثُ عَنْ سَعْدِ بْنِ عُبَادَةَأَنَّ أُمَّهُ مَاتَتْ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّ أُمِّي مَاتَتْ أَفَأَتَصَدَّقُ عَنْهَا قَالَ نَعَمْ قَالَ فَأَيُّ الصَّدَقَةِ أَفْضَلُ قَالَ سَقْيُ الْمَاءِ فَتِلْكَ سِقَايَةُ سَعْدٍ بِالْمَدِينَةِ","id":"Telah mengabarkan kepadaku [Ibrahim bin Al Hasan] dari [Hajjaj] ia berkata; aku mendengar [Syu'bah] menceritakan dari [Qatadah] berkata; aku mendengar [Al Hasan] menceritakan dari [Sa'd bin 'Ubadah], bahwa ibunya meninggal kemudian berkata, \"Wahai Rasulullah, sedekah apakah yang paling utama?\" Beliau menjawab: \"Memberi minum air.\" Itulah pemberian minum Sa'd di Madinah."},"3507":{"ar":"أَخْبَرَنَا الْعَبَّاسُ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ عَنْ سَعِيدِ بْنِ أَبِي أَيُّوبَ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي جَعْفَرٍ عَنْ سَالِمِ بْنِ أَبِي سَالِمٍ الْجَيْشَانِيِّ عَنْ أَبِيهِ عَنْ أَبِي ذَرٍّ قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أَبَا ذَرٍّ إِنِّي أَرَاكَ ضَعِيفًا وَإِنِّي أُحِبُّ لَكَ مَا أُحِبُّ لِنَفْسِي لَا تَأَمَّرَنَّ عَلَى اثْنَيْنِ وَلَا تَوَلَّيَنَّ عَلَى مَالِ يَتِيمٍ","id":"Telah mengabarkan kepada kami [Al Abbas bin Muhammad] berkata; telah menceritakan kepada kami [Abdullah bin Yazid] dari [Sa'id bin Abu Ayyub] dari ['Ubaidullah bin Abi Ja'far] dari [Salim bin Abu Salim Al Jaisyani] dari [ayahnya] dari [Abu Dzar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku: \"Wahai Abu Dzar, aku melihatmu orang yang lemah, namun aku mencintaimu sebagaimana aku mencintai diriku, janganlah engkau mengangkat dirimu sebagai pemimpin atas dua orang, dan janganlah engkau menjadi wali anak yatim.\""},"3508":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدٌ عَنْ حُسَيْنٍ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَجُلًا أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنِّي فَقِيرٌ لَيْسَ لِي شَيْءٌ وَلِي يَتِيمٌ قَالَ كُلْ مِنْ مَالِ يَتِيمِكَ غَيْرَ مُسْرِفٍ وَلَا مُبَاذِرٍ وَلَا مُتَأَثِّلٍ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] berkata; telah menceritakan kepada kami [Khalid] dari [Husain] dari ['Amru bin Syu'aib] dari [ayahnya] dari [kakeknya], bahwa seseorang datang kepada Nabi shallallahu 'alaihi wasallam kemudian berkata, \"Sesungguhnya aku orang yang fakir, aku tidak memiliki apa-apa namun aku mempunyai anak yatim?\" Beliau bersabda: \"Makanlah dari harta anak yatimmu tanpa berlebih-lebihan, tidak boros dan tidak menjadikannya sebagai pokok harta.\""},"3509":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عُثْمَانَ بْنِ حَكِيمٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ الصَّلْتِ قَالَ حَدَّثَنَا أَبُو كُدَيْنَةَ عَنْ عَطَاءٍ وَهُوَ ابْنُ السَّائِبِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَلَمَّا نَزَلَتْ هَذِهِ الْآيَةُ{ وَلَا تَقْرَبُوا مَالَ الْيَتِيمِ إِلَّا بِالَّتِي هِيَ أَحْسَنُ }وَ{ إِنَّ الَّذِينَ يَأْكُلُونَ أَمْوَالَ الْيَتَامَى ظُلْمًا }قَالَ اجْتَنَبَ النَّاسُ مَالَ الْيَتِيمِ وَطَعَامَهُ فَشَقَّ ذَلِكَ عَلَى الْمُسْلِمِينَ فَشَكَوْا ذَلِكَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَنْزَلَ اللَّهُ{ وَيَسْأَلُونَكَ عَنْ الْيَتَامَى قُلْ إِصْلَاحٌ لَهُمْ خَيْرٌ إِلَى قَوْلِهِ لَأَعْنَتَكُمْ }","id":"Telah mengabarkan kepada kami [Ahmad bin Utsman bin Hakim] berkata; telah menceritakan kepada kami [Muhammad bin Ash Shalt] berkata; telah menceritakan kepada kami [Abu Kudainah] dari ['Atha] -yaitu Ibnu As Saib- dari [Sa'id bin Jubair] dari [Ibnu Abbas] berkata, \"Tatkala turun ayat: '(Dan janganlah kamu dekati harta anak yatim, kecuali dengan cara yang lebih bermanfaat) ' (Qs. Al Israa': 34), serta '(sesungguhnya orang-orang yang memakan harta orang yatim secara zhalim) ' (Qs. An Nisaa: 10). Ibnu Abbas berkata, \"Maka orang-orang menjauhi harta anak yatim dan makanannya, sehingga hal tersebut terasa berat atas orang-orang muslim. Maka mereka mengadukan hal tersebut kepada Nabi shallallahu 'alaihi wasallam, kemudian Allah menurunkan ayat: '(Dan mereka bertanya kepadamu tentang anak yatim, katakalah: \"Mengurus urusan mereka secara patut adalah baik, dan jika kamu bergaul dengan mereka, maka mereka adalah saudaramu; dan Allah mengetahui siapa yang membuat kerusakan dari yang mengadakan perbaikan. Dan jikalau Allah menghendaki, niscaya Dia dapat mendatangkan kesulitan kepadamu) ' (Qs. Al Baqarah: 220)."},"3510":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا عِمْرَانُ بْنُ عُيَيْنَةَ قَالَ حَدَّثَنَا عَطَاءُ بْنُ السَّائِبِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍفِي قَوْلِهِ{ إِنَّ الَّذِينَ يَأْكُلُونَ أَمْوَالَ الْيَتَامَى ظُلْمًا }قَالَ كَانَ يَكُونُ فِي حَجْرِ الرَّجُلِ الْيَتِيمُ فَيَعْزِلُ لَهُ طَعَامَهُ وَشَرَابَهُ وَآنِيَتَهُ فَشَقَّ ذَلِكَ عَلَى الْمُسْلِمِينَ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ وَإِنْ تُخَالِطُوهُمْ فَإِخْوَانُكُمْ }فِي الدِّينِ فَأَحَلَّ لَهُمْ خُلْطَتَهُمْ","id":"Telah mengabarkan kepada kami ['Amru bin Ali] berkata; telah menceritakan kepada kami [Imran bin 'Uyainah] berkata; telah menceritakan kepada kami ['Atha bin As Saib] dari [Sa'id bin Jubair] dari [Ibnu Abbas] mengenaii firman Allah: '(sesungguhnya orang-orang yang memakan harta orang yatim secara zhalim) ' (Qs. An Nisaa: 10). Ia berkata, \"Dahulu terdapat seorang anak yatim dalam pemeliharaan seorang laki-laki, kemudian laki-laki tersebut menjauhi makanan serta minuman dan bejananya, sehingga hal tersebut terasa berat bagi orang-orang muslim. Kemudian Allah 'azza wajalla menurunkan ayat: '(dan jika kamu bergaul dengan mereka, maka mereka adalah saudaramu) ' (Qs. Al Baqarah: 220), yaitu seagama, maka Allah pun menghalalkan bagi mereka untuk bergaul dengan mereka.\""},"3511":{"ar":"أَخْبَرَنَا الرَّبِيعُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ سُلَيْمَانَ بْنِ بِلَالٍ عَنْ ثَوْرِ بْنِ زَيْدٍ عَنْ أَبِي الْغَيْثِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اجْتَنِبُوا السَّبْعَ الْمُوبِقَاتِ قِيلَ يَا رَسُولَ اللَّهِ مَا هِيَ قَالَ الشِّرْكُ بِاللَّهِ وَالشُّحُّ وَقَتْلُ النَّفْسِ الَّتِي حَرَّمَ اللَّهُ إِلَّا بِالْحَقِّ وَأَكْلُ الرِّبَا وَأَكْلُ مَالِ الْيَتِيمِ وَالتَّوَلِّي يَوْمَ الزَّحْفِ وَقَذْفُ الْمُحْصَنَاتِ الْغَافِلَاتِ الْمُؤْمِنَاتِ","id":"Telah mengabarkan kepada kami [Ar Rabi' bin Sulaiman] berkata; telah menceritakan kepada kami [Ibnu Wahb] dari [Sulaiman bin Bilal] dari [Tsaur bin Zaid] dari [Abu Al Ghaits] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jauhilah tujuh perkara yang membinasakan, \" dikatakan, \"Wahai Rasulullah, apakah perkara yang membinasakan itu?\" Beliau menjawab: \"Berbuat syirik kepada Allah, kikir, membunuh jiwa yang Allah haramkan kecuali dengan hak, makan riba, makan harta anak yatim, lari dari peperangan dan menuduh seorang wanita mukmin yang suci dan baik berbuat zina.\""},"3512":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ ابْنِ الْقَاسِمِ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ وَمُحَمَّدِ بْنِ النُّعْمَانِ يُحَدِّثَانِهِ عَنْ النُّعْمَانِ بْنِ بَشِيرِأَنَّ أَبَاهُ أَتَى بِهِ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنِّي نَحَلْتُ ابْنِي غُلَامًا كَانَ لِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَكُلَّ وَلَدِكَ نَحَلْتَهُ قَالَ لَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَارْجِعْهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dan [Al Harits bin Miskin] dia membacakannya dan aku mendengar, dari [Ibnu Al Qasim] dari [Malik] dari [Ibnu Syihab] dari [Humaid bin 'Abdurrahman] dan [Muhammad bin An Nu'man] mereka menceritakan kepadanya, dari [An Nu'man bin Basyir], bahwa ayahnya datang membawanya kepada Rasulullah shallallahu 'alaihi wasallam dan berkata, \"Sesungguhnya aku telah memberikan seorang budak kepada anakku ini.\" Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apakah engkau memberi seluruh anakmu?\" Ia menjawab, \"Tidak.\" Maka Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Ambillah dia kembali.\""},"3513":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ هَاشِمٍ قَالَ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ قَالَ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ الزُّهْرِيِّ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ وَعَنْ مُحَمَّدِ بْنِ النُّعْمَانِ عَنْ النُّعْمَانِ بْنِ بَشِيرٍأَنَّ أَبَاهُ بَشِيرَ بْنَ سَعْدٍ جَاءَ بِابْنِهِ النُّعْمَانِ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي نَحَلْتُ ابْنِي هَذَا غُلَامًا كَانَ لِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَكُلَّ بَنِيكَ نَحَلْتَ قَالَ لَا قَالَ فَارْجِعْهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Hisyam] berkata; telah menceritakan kepada kami [Al Walid bin Muslim] berkata; telah menceritakan kepada kami [Al Auza'i] dari [Az Zuhri] dari [Humaid bin 'Abdurrahman] dan [Muhammad bin An Nu'man] dari [An Nu'man bin Basyir], bahwa ayahnya, Basyir bin Sa'd, datang membawa anaknya, An Nu'man, dan berkata, \"Wahai Rasulullah, sesungguhnya aku telah memberikan seorang budak kepada anakku ini.\" Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apakah engkau memberi seluruh anakmu?\" Ia menjawab, \"Tidak.\" Maka Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Ambillah dia kembali.\""},"3514":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ النُّعْمَانِ بْنِ بَشِيرٍأَنَّ أَبَاهُ نَحَلَهُ نُحْلًا فَقَالَتْ لَهُ أُمُّهُ أَشْهِدْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى مَا نَحَلْتَ ابْنِي فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ ذَلِكَ لَهُ فَكَرِهَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَشْهَدَ لَهُ","id":"Telah mengabarkan kepada kami [Ahmad bin Harb] berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Hisyam] dari [ayahnya] dari [An Nu'man bin Basyir], bahwa ayahnya telah memberikan pemberian kepadanya, kemudian isterinya (ibunya) berkata, \"Persaksikanlah kepada Nabi shallallahu 'alaihi wasallam atas apa yang telah engkau berikan kepada anakmu.\" Kemudian ia pergi kepada Nabi shallallahu 'alaihi wasallam dan menceritakan hal tersebut. Maka Nabi shallallahu 'alaihi wasallam pun enggan untuk memberikan saksi kepadanya.\""},"3515":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَعْمَرٍ قَالَ حَدَّثَنَا أَبُو عَامِرٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ سَعْدٍ يَعْنِي ابْنَ إِبْرَاهِيمَ عَنْ عُرْوَةَ عَنْ بَشِيرٍأَنَّهُ نَحَلَ ابْنَهُ غُلَامًا فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَرَادَ أَنْ يُشْهِدَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَكُلَّ وَلَدِكَ نَحَلْتَهُ مِثْلَ ذَا قَالَ لَا قَالَ فَارْدُدْهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Ma'mar] berkata; telah menceritakan kepada kami [Abu 'Amir] berkata; telah menceritakan kepada kami [Syu'bah] dari [Sa'd] -yaitu Ibnu Ibrahim- dari ['Urwah] dari [Basyir], bahwa ia telah memberikan budak kepada anaknya, kemudian ia datang kepada Nabi shallallahu 'alaihi wasallam untuk minta persaksian kepada Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Apakah engkau memberi kepada seluruh anakmu seperti ini?\" ia menjawab, \"Tidak.\" Beliau lalu bersabda: \"Kembalikanlah dia.\""},"3516":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ حَاتِمٍ قَالَ حَدَّثَنَا حِبَّانُ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ أَنَّ بَشِيرًاأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا نَبِيَّ اللَّهِ نَحَلْتُ النُّعْمَانَ نِحْلَةً قَالَ أَعْطَيْتَ لِإِخْوَتِهِ قَالَ لَا قَالَ فَارْدُدْهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Hatim] berkata; telah menceritakan kepada kami [Hibban] berkata; telah menceritakan kepada kami [Abdullah] dari [Hisyam bin 'Urwah] dari [ayahnya], bahwa Basyir datang kepada Nabi shallallahu 'alaihi wasallam dan berkata, \"Wahai Nabi Allah, aku telah memberikan pemberian kepada An Nu'man?\" Maka beliau bertanya: \"Apakah engkau memberi saudara-saudaranya juga?\" Basyir menjawab, \"Tidak.\" Beliau lalu bersabda: \"Kembalikanlah dia.\""},"3517":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى عَنْ عَبْدِ الْوَهَّابِ قَالَ حَدَّثَنَا دَاوُدُ عَنْ عَامِرٍ عَنْ النُّعْمَانِأَنَّ أَبَاهُ أَتَى بِهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُشْهِدُ عَلَى نُحْلٍ نَحَلَهُ إِيَّاهُ فَقَالَ أَكُلَّ وَلَدِكَ نَحَلْتَ مِثْلَ مَا نَحَلْتَهُ قَالَ لَا قَالَ فَلَا أَشْهَدُ عَلَى شَيْءٍ أَلَيْسَ يَسُرُّكَ أَنْ يَكُونُوا إِلَيْكَ فِي الْبِرِّ سَوَاءً قَالَ بَلَى قَالَ فَلَا إِذًا","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dari [Abdull Wahhab] berkata; telah menceritakan kepada kami [Daud] dari ['Amir] dari [An Nu'man], bahwa ayahnya datang bersamanya kepada Nabi shallallahu 'alaihi wasallam meminta persaksian terhadap pemberian yang telah ia berikan kepadanya. Kemudian beliau bersabda: \"Apakah engkau memberikan kepada seluruh anakmu seperti yang engkau berikan kepadanya?\" Ia menjawab, \"Tidak.\" Maka beliau bersabda: \"Aku tidak akan bersaksi terhadap sesuatupun, bukankah engkau senang jika mereka dalam berbuat baik kepadamu juga sama?\" Ia menjawab, \"Ya.\" Beliau lalu bersabda: \"Kalau demikian maka tidak boleh.\""},"3518":{"ar":"أَخْبَرَنَا مُوسَى بْنُ عَبْدِ الرَّحْمَنِ قَالَ حَدَّثَنَا أَبُو أُسَامَةَ قَالَ حَدَّثَنَا أَبُو حَيَّانَ عَنْ الشَّعْبِيِّ قَالَ حَدَّثَنِي النُّعْمَانُ ��ْنُ بَشِيرٍ الْأَنْصَارِيُّأَنَّ أُمَّهُ ابْنَةَ رَوَاحَةَ سَأَلَتْ أَبَاهُ بَعْضَ الْمَوْهِبَةِ مِنْ مَالِهِ لِابْنِهَا فَالْتَوَى بِهَا سَنَةً ثُمَّ بَدَا لَهُ فَوَهَبَهَا لَهُ فَقَالَتْ لَا أَرْضَى حَتَّى تُشْهِدَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّ أُمَّ هَذَا ابْنَةَ رَوَاحَةَ قَاتَلَتْنِي عَلَى الَّذِي وَهَبْتُ لَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا بَشِيرُ أَلَكَ وَلَدٌ سِوَى هَذَا قَالَ نَعَمْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَفَكُلُّهُمْ وَهَبْتَ لَهُمْ مِثْلَ الَّذِي وَهَبْتَ لِابْنِكَ هَذَا قَالَ لَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَا تُشْهِدْنِي إِذًا فَإِنِّي لَا أَشْهَدُ عَلَى جَوْرٍ","id":"Telah mengabarkan kepada kami [Musa bin 'Abdurrahman] berkata; telah menceritakan kepada kami [Abu Usamah] berkata; telah menceritakan kepada kami [Abu Hibban] dari [Asy Sya'bi] berkata; telah menceritakan kepadaku [An Nu'man bin Basyir Al Anshari], bahwa ibunya, binti Rawahah, meminta kepada ayahnya sebagian pemberian dari hartanya untuk anaknya. Lalu ia menundanya selama satu tahun sebelum ia berikan kepada anaknya tersebut. Lalu ibunya berkata, \"Aku tidak ridla hingga engkau mempersaksikannya kepada Rasulullah shallallahu 'alaihi wasallam. Kemudian ia (bapaknya) berkata, \"Wahai Rasulullah, sesungguhnya ibu anak ini, binti Rawahah, menentangku atas sesuatu yang aku berikan kepada anak ini.\" Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai Basyir, apakah engkau memiliki anak selain ini?\" Ia menjawab, \"Ya.\" Rasulullah shallallahu 'alaihi wasallam lalu bertanya lagi: \"Apakah seluruh mereka engkau beri seperti yang engkau berikan kepada anakmu ini?\" Ia menjawab, \"Tidak.\" Rasulullah shallallahu 'alaihi wasallam kemudian bersabda: \"Kalau demikian maka jangan meminta persaksian kepadaku. Sesungguhnya aku tidak bersaksi terhadap ketidak adilan.\""},"3519":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ قَالَ حَدَّثَنَا إِسْمَعِيلُ عَنْ عَامِرٍ قَالَأُخْبِرْتُ أَنَّ بَشِيرَ بْنَ سَعْدٍ أَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّ امْرَأَتِي عَمْرَةَ بِنْتَ رَوَاحَةَ أَمَرَتْنِي أَنْ أَتَصَدَّقَ عَلَى ابْنِهَا نُعْمَانَ بِصَدَقَةٍ وَأَمَرَتْنِي أَنْ أُشْهِدَكَ عَلَى ذَلِكَ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلْ لَكَ بَنُونَ سِوَاهُ قَالَ نَعَمْ قَالَ فَأَعْطَيْتَهُمْ مِثْلَ مَا أَعْطَيْتَ لِهَذَا قَالَ لَا قَالَ فَلَا تُشْهِدْنِي عَلَى جَوْرٍ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] berkata; telah menceritakan kepada kami [Muhammad bin 'Ubaid] berkata; telah menceritakan kepada kami [Isma'il] dari ['Amir] berkata, \"Aku telah diberitahu bahwa Basyir bin Sa'd datang kepada Rasulullah shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, sesungguhnya isteriku, 'Amrah binti Rawahah, menyuruhku untuk bersedekah kepada anaknya, yaitu Nu'man, dengan suatu sedekah. Dan ia memerintahkan aku agar meminta persaksian kepadamu terhadap hal tersebut!\" Maka Nabi shallallahu 'alaihi wasallam pun bertanya kepadanya: \"Apakah engkau memiliki anak-anak selainnya?\" Ia menjawab, \"Ya.\" Beliau bertanya lagi: \"Engkau memberi mereka seperti apa yang engkau berikan kepada anak ini?\" Ia menjawab, \"Tidak.\" Maka beliau pun bersabda: \"Janganlah engkau meminta persaksian kepadaku terhadap ketidak adilan.\""},"3520":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا أَبُو نُعَيْمٍ قَالَ حَدَّثَنَا زَكَرِيَّا عَنْ عَامِرٍ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ عُتْبَةَ بْنِ مَسْعُودٍ ح وَأَنْبَأَنَا مُحَمَّدُ بْنُ حَاتِمٍ قَالَ أَنْبَأَنَا حِبَّانُ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ زَكَرِيَّا عَنْ الشَّعْبِيِّ عَنْ عَبْدِ اللَّهِ بْنِ عُتْبَةَ بْنِ مَسْعُودٍأَنَّ رَجُلًا جَاءَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ مُحَمَّدٌ أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنِّي تَصَدَّقْتُ عَلَى ابْنِي بِصَدَقَةٍ فَاشْهَدْ فَقَالَ هَلْ لَكَ وَلَدٌ غَيْرُهُ قَالَ نَعَمْ قَالَ أَعْطَيْتَهُمْ كَمَا أَعْطَيْتَهُ قَالَ لَا قَالَ أَشْهَدُ عَلَى جَوْرٍ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] berkata; telah menceritakan kepada kami [Abu Nu'aim] berkata; telah menceritakan kepada kami [Zakaria] dari ['Amir] berkata; telah menceritakan kepadaku [Abdullah bin 'Utbah bin Mas'ud]. (dalam jalur lain disebutkan) Telah memberitakan kepada kami [Muhammad bin Hatim] berkata; telah memberitakan kepada kami [Hibban] berkata; telah memberitakan kepada kami [Abdullah] dari [Zakaria] dari [Asy Sya'bi] dari [Abdullah bin 'Utbah bin Mas'ud], bahwa seseorang mendatangi Nabi shallallahu 'alaihi wasallam… dan Muhammad menyebutkan, \"Ia mendatangi Nabi shallallahu 'alaihi wasallam dan berkata, \"Aku bersedekah kepada anakku dengan suatu sedekah, maka saksikanlah!\" Beliau lalu bertanya: \"Apakah engkau memiliki anak selainnya, \" ia menjawab, \"Ya.\" Beliau bertanya lagi: \"Apakah engkau memberi mereka seperti engkau memberinya.\" Ia menjawab, \"Tidak.\" Maka beliau pun bersabda: \"Apakah aku akan bersaksi atas ketidak adilan?\""},"3521":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ عَنْ يَحْيَى عَنْ فِطْرٍ قَالَ حَدَّثَنِي مُسْلِمُ بْنُ صُبَيْحٍ قَالَ سَمِعْتُ النُّعْمَانَ بْنَ بَشِيرٍ يَقُولُذَهَبَ بِي أَبِي إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُشْهِدُهُ عَلَى شَيْءٍ أَعْطَانِيهِ فَقَالَ أَلَكَ وَلَدٌ غَيْرُهُ قَالَ نَعَمْ وَصَفَّ بِيَدِهِ بِكَفِّهِ أَجْمَعَ كَذَا أَلَا سَوَّيْتَ بَيْنَهُمْ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'id] dari [Yahya] dari [Fithr] berkata; telah menceritakan kepada kami [Muslim bin Shubaih] berkata; aku mendengar [An Nu'man bin Basyir] berkata, \"Ayahku pergi membawa aku menemui Nabi shallallahu 'alaihi wasallam, ia meminta Rasulullah untuk bersaksi terhadap sesuatu yang ia berikan kepadaku. Kemudian beliau bertanya: \"Apakah engkau memiliki anak selainnya?\" Ia menjawab, \"Ya.\" Lalu -seraya membariskan seluruh telapaknya demikian- beliau bersabda: \"Tidakkah engkau samakan antara mereka (seperti ini)?\""},"3522":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ يَزِيدَ قَالَ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَكُنَّا عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذْ أَتَتْهُ وَفْدُ هَوَازِنَ فَقَالُوا يَا مُحَمَّدُ إِنَّا أَصْلٌ وَعَشِيرَةٌ وَقَدْ نَزَلَ بِنَا مِنْ الْبَلَاءِ مَا لَا يَخْفَى عَلَيْكَ فَامْنُنْ عَلَيْنَا مَنَّ اللَّهُ عَلَيْكَ فَقَالَ اخْتَارُوا مِنْ أَمْوَالِكُمْ أَوْ مِنْ نِسَائِكُمْ وَأَبْنَائِكُمْ فَقَالُوا قَدْ خَيَّرْتَنَا بَيْنَ أَحْسَابِنَا وَأَمْوَالِنَا بَلْ نَخْتَارُ نِسَاءَنَا وَأَبْنَاءَنَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَّا مَا كَانَ لِي وَلِبَنِي عَبْدِ الْمُطَّلِبِ فَهُوَ لَكُمْ فَإِذَا صَلَّيْتُ الظُّهْرَ فَقُومُوا فَقُولُوا إِنَّا نَسْتَعِينُ بِرَسُولِ اللَّهِ عَلَى الْمُؤْمِنِينَ أَوْ الْمُسْلِمِينَ فِي نِسَائِنَا وَأَبْنَائِنَا فَلَمَّا صَلَّوْا الظُّهْرَ قَامُوا فَقَالُوا ذَلِكَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَا كَانَ لِي وَلِبَنِي عَبْدِ الْمُطَّلِبِ فَهُوَ لَكُمْ فَقَالَ الْمُهَاجِرُونَ وَمَا كَانَ لَنَا فَهُوَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَتْ الْأَنْصَارُ مَا كَانَ لَنَا فَهُوَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ الْأَقْرَعُ بْنُ حَابِسٍ أَمَّا أَنَا وَبَنُو تَمِيمٍ فَلَا وَقَالَ عُيَيْنَةُ بْنُ حِصْنٍ أَمَّا أَنَا وَبَنُو فَزَارَةَ فَلَا وَقَالَ الْعَبَّاسُ بْنُ مِرْدَاسٍ أَمَّا أَنَا وَبَنُو سُلَيْمٍ فَلَا فَقَامَتْ بَنُو سُلَيْمٍ فَقَالُوا كَذَبْتَ مَا كَانَ لَنَا فَهُوَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أَيُّهَا النَّاسُ رُدُّوا عَلَيْهِمْ نِسَاءَهُمْ وَأَبْنَاءَهُمْ فَمَنْ تَمَسَّكَ مِنْ هَذَا الْفَيْءِ بِشَيْءٍ فَلَهُ سِتُّ فَرَائِضَ مِنْ أَوَّلِ شَيْءٍ يُفِيئُهُ اللَّهُ عَزَّ وَجَلَّ عَلَيْنَا وَرَكِبَ رَاحِلَتَهُ وَرَكِبَ النَّاسُ اقْسِمْ عَلَيْنَا فَيْئَنَا فَأَلْجَئُوهُ إِلَى شَجَرَةٍ فَخَطِفَتْ رِدَاءَهُ فَقَالَ يَا أَيُّهَا النَّاسُ رُدُّوا عَلَيَّ رِدَائِي فَوَاللَّهِ لَوْ أَنَّ لَكُمْ شَجَرَ تِهَامَةَ نَعَمًا قَسَمْتُهُ عَلَيْكُمْ ثُمَّ لَمْ تَلْقَوْنِي بَخِيلًا وَلَا جَبَانًا وَلَا كَذُوبًا ثُمَّ أَتَى بَعِيرًا فَأَخَذَ مِنْ سَنَامِهِ وَبَرَةً بَيْنَ أُصْبُعَيْهِ ثُمَّ يَقُولُ هَا إِنَّهُ لَيْسَ لِي مِنْ الْفَيْءِ شَيْءٌ وَلَا هَذِهِ إِلَّا خُمُسٌ وَالْخُمُسُ مَرْدُودٌ فِيكُمْ فَقَامَ إِلَيْهِ رَجُلٌ بِكُبَّةٍ مِنْ شَعْرٍ فَقَالَ يَا رَسُولَ اللَّهِ أَخَذْتُ هَذِهِ لِأُصْلِحَ بِهَا بَرْدَعَةَ بَعِيرٍ لِي فَقَالَ أَمَّا مَا كَانَ لِي وَلِبَنِي عَبْدِ الْمُطَّلِبِ فَهُوَ لَكَ فَقَالَ أَوَبَلَغَتْ هَذِهِ فَلَا أَرَبَ لِي فِيهَا فَنَبَذَهَا وَقَالَ يَا أَيُّهَا النَّاسُ أَدُّوا الْخِيَاطَ وَالْمَخِيطَ فَإِنَّ الْغُلُولَ يَكُونُ عَلَى أَهْلِهِ عَارًا وَشَنَارًا يَوْمَ الْقِيَامَةِ","id":"Telah mengabarkan kepada kami ['Amru bin Yazid] berkata; telah menceritakan kepada kami [Ibnu Abu 'Adi] berkata; telah menceritakan kepada kami [Hammad bin Salamah] dari [Muhammad bin Ishaq] dari ['Amru bin Syu'aib] dari [ayahnya] dari [kakeknya] ia berkata, \"Kami pernah bersama Rasulullah shallallahu 'alaihi wasallam, tiba-tiba datanglah kepada beliau utusan dari Hawazin. Mereka lalu berkata, \"Wahai Muhammad, sesungguhnya kami adalah berkeluarga, kami mendapatkan musibah yang tidak tersembunyi bagimu, maka berilah kami sesuatu semoga Allah memberimu.\" Kemudian beliau bersabda: \"Pilihlah antara harta, atau wanita dan anak-anak kalian.\" Mereka lalu berkata, \"Engkau memberi kami pilihan antara keturunan dan harta, akan tetapi kami memilih isteri dan anak-anak kami.\" Lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Adapun yang dulu milikku dan milik Bani Abdul Muthalib adalah menjadi milik kalian, jika aku shalat zhuhur maka berdiri dan katakanlah 'sesungguhnya kami meminta tolong kepada Rasulullah atas kaum Mukminin dan Muslimin akan para wanita dan anak-anak kami'.\" Ketika mereka shalat zhuhur, mereka berdiri dan mengucapkan hal itu, lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Adapun yang dulu milikku dan milik bani Abdul Muthalib adalah milik kalian.\" Kemudian orang-orang Muhajirin berkata, \"Adapun yang dulu milik kami maka itu adalah milik Rasulullah shallallahu 'alaihi wasallam.\" Dan orang-orang Anshar berkata, \"Dan yang dulu milik kami maka itu adalah milik Rasulullah shallallahu 'alaihi wasallam.\" Lalu Al Aqra` bin Habis berkata, \"Adapun aku dan bani Tamim tidak seperti itu.\" Uyainah bin Hishn berkata, \"Adapun aku dan bani Fazarah tidak seperti itu.\" Al Abbas bin Mirdas berkata, \"Sedangkan aku dan Bani Sulaim tidak seperti itu.\" Lalu berdirilah Bani Sulaim dan berkata, \"Engkau dusta! Apa yang dulu milik kami maka itu adalah milik Rasulullah shallallahu 'alaihi wasallam.\" Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai manusia, kembalikan kepada mereka wanita-wanita dan anak-anak mereka, maka barangsiapa memegang harta fai` ini maka ia mendapatkan enam ekor unta, dari sejak pertama Allah Azza wa jalla memberikan harta fai` ini kepadanya.\" Lalu beliau naik kendaraan beliau dan orang-orang menaiki kendaraan mereka, mereka berkata 'Beri kami harta fai`'. Mereka lalu membawa beliau ke sebuah pohon dan selendang beliau terjatuh, beliau bersabda: \"Wahai manusia kembalikan selendangku, demi Allah seandainya kalian mendapatkan nikmat seluas Makkah, maka aku akan membaginya untuk kalian, lalu kalian tidak akan mendapatiku sebagai orang yang bakhil atau pengecut atau berdusta.\" Kemudian beliau mendatangi seekor unta dan mengambil sebuah rambut dari punuknya di antara dua jarinya seraya bersabda: \"Sesungguhnya tidak ada sedikitpun harta fai` untukku atau rambut ini, kecuali seperlima, dan seperlima akan kembali kepada kalian.\" Lalu seorang laki-laki berdiri dengan membawa segenggam rambut dan berkata, \"Wahai Rasulullah, aku mengambil ini agar aku bisa memperbaiki barda'ah (lampu penerang di atas unta) unta milikku.\" Beliau bersabda: \"Adapun yang dulu milikku dan milik bani Abdul Muththalib adalah untukmu.\" Ia berkata, 'Apakah hal ini telah disampaikan, aku tidak butuh lagi padanya', lalu ia pun membuangnya. Beliau bersabda: \"Wahai manusia kembalikanlah meskipun itu sebuah jarum dan seutas benang. Sesungguhnya ghulul (harta ghanimah yang dicuri sebelum dibagi), akan menjadi keburukan dan aib bagi pelakunya pada hari kiamat.\""},"3523":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ حَفْصٍ قَالَ حَدَّثَنِي أَبِي قَالَ حَدَّثَنِي إِبْرَاهِيمُ عَنْ سَعِيدِ بْنِ أَبِي عَرُوبَةَ عَنْ عَامِرٍ الْأَحْوَلِ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَرْجِعُ أَحَدٌ فِي هِبَتِهِ إِلَّا وَالِدٌ مِنْ وَلَ��ِهِ وَالْعَائِدُ فِي هِبَتِهِ كَالْعَائِدِ فِي قَيْئِهِ","id":"Telah mengabarkan kepada kami [Ahmad bin Hafsh] berkata; telah menceritakan kepadaku [ayahku] berkata; telah menceritakan kepadaku [Ibrahim] dari [Sa'd bin Abu 'Arubah] dari ['Amir Al Ahwal] dari ['Amru bin Syu'aib] dari [ayahnya] dari [kakeknya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak boleh seseorang mengambil kembali pemberiannya kecuali orang tua dari anaknya. Orang yang mengambil kembali pemberiannya seperti orang yang mengambil kembali muntahannya.\""},"3524":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ حُسَيْنٍ عَنْ عَمْرِو بْنِ شُعَيْبٍ قَالَ حَدَّثَنِي طَاوُسٌ عَنْ ابْنِ عُمَرَ وَابْنِ عَبَّاسٍيَرْفَعَانِ الْحَدِيثَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَحِلُّ لِرَجُلٍ يُعْطِي عَطِيَّةً ثُمَّ يَرْجِعُ فِيهَا إِلَّا الْوَالِدَ فِيمَا يُعْطِي وَلَدَهُ وَمَثَلُ الَّذِي يُعْطِي عَطِيَّةً ثُمَّ يَرْجِعُ فِيهَا كَمَثَلِ الْكَلْبِ أَكَلَ حَتَّى إِذَا شَبِعَ قَاءَ ثُمَّ عَادَ فِي قَيْئِهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] berkata; telah menceritakan kepada kami [Ibnu Abu 'Adi] dari [Husain] dari ['Amru bin Syu'aib] berkata; telah menceritakan kepadaku [Thawus] dari [Ibnu Umar] dan [Ibnu Abbas] mereka berdua memarfu'kan hadits tersebut kepada Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak halal bagi seseorang yang memberi suatu pemberian kemudian mengambilnya kembali, kecuali orang tua atas apa yang ia berikan kepada anaknya. Dan permisalan orang yang memberi suatu pemberian kemudian mengambilnya kembali seperti anjing yang makan hingga kenyang dan muntah kemudian ia memakan muntahannya kembali.\""},"3525":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الْخَلَنْجِيُّ الْمَقْدِسِيُّ قَالَ حَدَّثَنَا أَبُو سَعِيدٍ وَهُوَ مَوْلَى بَنِي هَاشِمٍ عَنْ وُهَيْبٍ قَالَ حَدَّثَنَا ابْنُ طَاوُسٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعَائِدُ فِي هِبَتِهِ كَالْكَلْبِ يَقِيءُ ثُمَّ يَعُودُ فِي قَيْئِهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah Al Khalanji Al Maqdisi] berkata; telah menceritakan kepada kami [Abu Sa'id] -yaitu mantan budak Bani Hasyim- dari [Wuhaib] berkata; telah menceritakan kepada kami [Ibnu Thawus] dari [ayahnya] dari [Ibnu Abbas] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang yang mengambil kembali pemberiannya seperti anjing yang muntah kemudian ia makan kembali muntahannya.\""},"3526":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ حَاتِمٍ قَالَ حَدَّثَنَا حِبَّانُ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ إِبْرَاهِيمَ بْنِ نَافِعٍ عَنْ الْحَسَنِ بْنِ مُسْلِمٍ عَنْ طَاوُسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَحِلُّ لِأَحَدٍ أَنْ يَهَبَ هِبَةً ثُمَّ يَرْجِعَ فِيهَا إِلَّا مِنْ وَلَدِهِ قَالَ طَاوُسٌ كُنْتُ أَسْمَعُ وَأَنَا صَغِيرٌ عَائِدٌ فِي قَيْئِهِ فَلَمْ نَدْرِ أَنَّهُ ضَرَبَ لَهُ مَثَلًا قَالَ فَمَنْ فَعَلَ ذَلِكَ فَمَثَلُهُ كَمَثَلِ الْكَلْبِ يَأْكُلُ ثُمَّ يَقِيءُ ثُمَّ يَعُودُ فِي قَيْئِهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Hatim] berkata; telah menceritakan kepada kami [Hibban] berkata; telah memberitakan kepada kami [Abdullah] dari [Ibrahim bin Nafi'] dari [Al Hasan bin Muslim] dari [Thawus] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak halal bagi seseorang yang memberikan pemberian kemudian mengambilnya kembali kecuali dari orang anaknya sendiri.\" Thawus berkata, \"Aku mendengar di saat masih kecil perkataan; 'orang yang kembali memakan muntahannya', aku tidak mengetahui bahwa beliau memberikan suatu permisalan.\" Beliau mengatakan: \"Barangsiapa melakukan hal tersebut (mengambil kembali sesuatu yang telah diberikannya) maka permisalannya seperti anjing yang makan kemudian muntah, lalu ia makan kembali muntahannya.\""},"3527":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ خَالِدٍ قَالَ حَدَّثَنَا عُمَرُ عَنْ الْأَوْزَاعِيِّ قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ عَلِيِّ بْنِ حُسَيْنٍ قَالَ حَدَّثَنِي سَعِيدُ بْنُ الْمُسَيَّبِ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَثَلُ الَّذِي يَرْجِعُ فِي صَدَقَتِهِ كَمَثَلِ الْكَلْبِ يَرْجِعُ فِي قَيْئِهِ فَيَأْكُلُهُ","id":"Telah mengabarkan kepada kami [Mahmud bin Khalid] ia berkata; telah menceritakan kepada kami [Umar] dari [Al Auza'i] berkata; telah menceritakan kepadaku [Muhammad bin Ali bin Husain] berkata; telah menceritakan kepadaku [Sa'id bin Al Musayyab] berkata; telah menceritakan kepadaku [Abdullah bin Abbas] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Permisalan orang yang mengambil kembali sedekahnya seperti anjing yang mengambil kembali muntahannya kemudian memakannya.\""},"3528":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا عَبْدُ الصَّمَدِ قَالَ حَدَّثَنَا حَرْبٌ وَهُوَ ابْنُ شَدَّادٍ قَالَ حَدَّثَنِي يَحْيَى هُوَ ابْنُ أَبِي كَثِيرٍ قَالَ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ عَمْرٍو هُوَ الْأَوْزَاعِيُّ أَنَّ مُحَمَّدَ بْنَ عَلِيِّ بْنِ حُسَيْنِ بْنِ فَاطِمَةَ بِنْتِ رَسِولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدَّثَهُ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَثَلُ الَّذِي يَتَصَدَّقُ بِالصَّدَقَةِ ثُمَّ يَرْجِعُ فِيهَا كَمَثَلِ الْكَلْبِ قَاءَ ثُمَّ عَادَ فِي قَيْئِهِ فَأَكَلَهُ","id":"Telah mengabarkan kepada kami [Ishaq bin Manshur] berkata; telah menceritakan kepada kami [Abdush Shamad] berkata; telah menceritakan kepada kami [Harb] -yaitu Ibnu Syaddad- berkata; telah menceritakan kepadaku [Yahya] -yaitu Ibnu Abu Katsir- ia berkata; telah menceritakan kepadaku ['Abdurrahman bin 'Amru] -yaitu Al Auza'i- bahwa [Muhammad bin Ali bin Husain bin Fatimah binti Rasulullah] shallallahu 'alaihi wasallam telah menceritakan kepadanya, dari [Sa'id bin Al Musayyab] dari [Ibnu Abbas], bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Permisalan orang yang bersedekah dengan suatu sedekah kemudian mengambilnya kembali seperti anjing yang muntah kemudian memakan kembali muntahannya.\""},"3529":{"ar":"أَخْبَرَنَا الْهَيْثَمُ بْنُ مَرْوَانَ بْنِ الْهَيْثَمِ بْنِ عِمْرَانَ قَالَ حَدَّثَنَا مُحَمَّدٌ وَهُوَ ابْنُ بَكَّارِ بْنِ بِلَالٍ قَالَ حَدَّثَنَا يَحْيَى عَنْ الْأَوْزَاعِيِّ أَنَّ مُحَمَّدَ بْنَ عَلِيِّ بْنِ الْحُسَيْنِ حَدَّثَهُ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَثَلُ الَّذِي يَرْجِعُ فِي صَدَقَتِهِ كَمَثَلِ الْكَلْبِ يَقِيءُ ثُمَّ يَعُودُ فِي قَيْئِهِقَالَ الْأَوْزَاعِيُّ سَمِعْتُهُ يُحَدِّثُ عَطَاءَ بْنَ أَبِي رَبَاحٍ بِهَذَا الْحَدِيثِ","id":"Telah mengabarkan kepada kami [Al Hutsaim bin Marwan bin Al Haitsam bin Umar] berkata; telah menceritakan kepada kami [Muhammad] -yaitu Ibnu Bakkar bin Bilal- berkata; telah menceritakan kepada kami [Yahya] dari [Al Auza'i] bahwa [Muhammad bin Ali bin Al Husain] telah menceritakan kepadanya dari [Sa'id bin Al Musayyab] dari [Ibnu Abbas], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Permisalan orang yang mengambil kembali sedekahnya seperti anjing yang muntah kemudian memakan kembali muntahannya.\""},"3530":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْعَائِدُ فِي هِبَتِهِ كَالْعَائِدِ فِي قَيْئِهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] berkata; telah menceritakan kepada kami ['Abdurrahman] berkata; telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Sa'id bin Al Musayyab] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Orang yang mengambil kembali pemberiannya seperti orang yang memakan kembali muntahannya.\""},"3531":{"ar":"أَخْبَرَنَا أَبُو الْأَشْعَثِ قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعَائِدُ فِي هِبَتِهِ كَالْعَائِدِ فِي قَيْئِهِ","id":"Telah mengabarkan kepada kami [Abu Al Asy'ats] berkata; telah menceritakan kepada kami [Khalid] berkata; telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Sa'id bin Al Musayyab] dari [Ibnu Abbas] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang yang kembali mengambil pemberiannya seperti orang yang memakan kembali muntahannya.\""},"3532":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْعَلَاءِ قَالَ حَدَّثَنَا أَبُو خَالِدٍ وَهُوَ سُلَيْمَانُ بْنُ حَيَّانَ عَنْ سَعِيدِ بْنِ أَبِي عَرُوبَةَ عَنْ أَيُّوبَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ لَنَا مَثَلُ السَّوْءِ الْعَائِدُ فِي هِبَتِهِ كَالْعَائِدِ فِي قَيْئِهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Al 'Ala] berkata; telah menceritakan kepada kami [Abu Khalid] -yaitu Sulaiman bin Hayyan- dari [Sa'id bin Abu 'Arubah] dari [Ayyub] dari [Ikrimah] dari [Ibnu Abbas] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kita tidak memiliki permisalan yang buruk, sesungguhnya orang yang mengambil kembali pemberiannya seperti orang yang memakan kembali muntahannya.\""},"3533":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ زُرَارَةَ قَالَ حَدَّثَنَا إِسْمَعِيلُ عَنْ أَيُّوبَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ لَنَا مَثَلُ السَّوْءِ الْعَائِدُ فِي هِبَتِهِ كَالْكَلْبِ يَعُودُ فِي قَيْئِهِ","id":"Telah mengabarkan kepada kami ['Amru bin Zurarah] berkata; telah menceritakan kepada kami [Isma'il] dari [Ayyub] dari ['Ikrimah] dari [Ibnu Abbas] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kita tidak memiliki permisalan yang buruk, sesungguhnya orang yang mengambil kembali pemberiannya seperti anjing yang memakan kembali muntahannya.\""},"3534":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ حَاتِمِ بْنِ نُعَيْمٍ قَالَ حَدَّثَنَا حِبَّانُ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ خَالِدٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ لَنَا مَثَلُ السَّوْءِ الرَّاجِعُ فِي هِبَتِهِ كَالْكَلْبِ فِي قَيْئِهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Hatim bin Nu'aim] berkata; telah menceritakan kepada kami [Hibban] berkata; telah memberitakan kepada kami [Abdullah] dari [Khalid] dari ['Ikrimah] dari [Ibnu Abbas] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kita tidak memiliki permisalan yang buruk, sesungguhnya orang yang mengambil kembali pemberiannya seperti anjing dalam muntahannya.\""},"3535":{"ar":"أَخْبَرَنِي زَكَرِيَّا بْنُ يَحْيَى قَالَ حَدَّثَنَا إِسْحَقُ قَالَ حَدَّثَنَا الْمَخْزُومِيُّ قَالَ حَدَّثَنَا وُهَيْبٌ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ طَاوُسٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْعَائِدُ فِي هِبَتِهِ كَالْكَلْبِ يَقِيءُ ثُمَّ يَعُودُ فِي قَيْئِهِ","id":"Telah mengabarkan kepada kami [Zakaria bin Yahya] berkata; telah menceritakan kepada kami [Ishaq] berkata; telah menceritakan kepada kami [Al Makhzumi] berkata; telah menceritakan kepada kami [Wuhaib] berkata; telah menceritakan kepada kami [Abdullah bin Thawus] dari [ayahnya] dari [Ibnu Abbas], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang yang mengambil kembali pemberiannya seperti anjing yang muntah kemudian memakan kembali muntahannya.\""},"3536":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ حَجَّاجٍ عَنْ أَبِي الزُّبَيْرِ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعَائِدُ فِي هِبَتِهِ كَالْعَائِدِ فِي قَيْئِهِ","id":"Telah mengabarkan kepada kami [Ahmad bin Harb] berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Hajjaj] dari [Abu Az Zubair] dari [Thawus] dari [Ibnu Abbas] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang yang mengambil kembali pemberiannya seperti orang yang memakan kembali muntahannya.\""},"3537":{"ar":"أَخْبَرَنَا عَبْدُ الرَّحْمَنِ بْنُ مُحَمَّدِ بْنِ سَلَّامٍ قَالَ حَدَّثَنَا إِسْحَقُ الْأَزْرَقُ قَالَ حَدَّثَنَا بِهِ حُسَيْنٌ الْمُعَلِّمُ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ طَاوُسٍ عَنْ ابْنِ عُمَرَ وَابْنِ عَبَّاسٍ قَالَاقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَحِلُّ لِأَحَدٍ أَنْ يُعْطِيَ الْعَطِيَّةَ فَيَرْجِعَ فِيهَا إِلَّا الْوَالِدَ فِيمَا يُعْطِي وَلَدَهُ وَمَثَلُ الَّذِي يُعْطِي الْعَطِيَّةَ فَيَرْجِعُ فِيهَا كَالْكَلْبِ يَأْكُلُ حَتَّى إِذَا شَبِعَ قَاءَ ثُمَّ عَادَ فَرَجَعَ فِي قَيْئِهِ","id":"Telah mengabarkan kepada kami ['Abdurrahman bin Muhammad bin Sallam] berkata; telah menceritakan kepada kami [Ishaq Al Azraq] berkata; telah menceritakan kepada kami [Husain Al Mu'allim] dari ['Amru bin Syu'aib] dari [Thawus] dari [Ibnu Umar] dan [Ibnu Abbas] mereka berdua berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda; \"Tidak halal bagi seseorang yang memberi suatu pemberian kemudian mengambilnya kembali, kecuali orang tua mengambil kembali apa yang diberikan kepada anaknya. Dan permisalan orang yang memberi kemudian mengambilnya kembali seperti anjing yang makan hingga setelah Kenyang ia muntah dan memakannya kembali.\""},"3538":{"ar":"أَخْبَرَنَا عَبْدُ الْحَمِيدِ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا مَخْلَدٌ قَالَ حَدَّثَنَا ابْنُ جُرَيْجٍ عَنْ الْحَسَنِ بْنِ مُسْلِمٍ عَنْ طَاوُسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَحِلُّ لِأَحَدٍ يَهَبُ هِبَةً ثُمَّ يَعُودُ فِيهَا إِلَّا الْوَالِدَ قَالَ طَاوُسٌ كُنْتُ أَسْمَعُ الصِّبْيَانَ يَقُولُونَ يَا عَائِدًا فِي قَيْئِهِ وَلَمْ أَشْعُرْ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ضَرَبَ ذَلِكَ مَثَلًا حَتَّى بَلَغَنَا أَنَّهُ كَانَ يَقُولُ مَثَلُ الَّذِي يَهَبُ الْهِبَةَ ثُمَّ يَعُودُ فِيهَا وَذَكَرَ كَلِمَةً مَعْنَاهَا كَمَثَلِ الْكَلْبِ يَأْكُلُ قَيْئَهُ","id":"Telah mengabarkan kepada kami [Abdul Hamid bin Muhammad] berkata; telah menceritakan kepada kami [Makhlad] berkata; telah menceritakan kepada kami [Ibnu Juraij] dari [Al Hasan bin Muslim] dari [Thawus], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak halal bagi seseorang yang memberikan suatu pemberian kemudian mengambilnya, kembali kecuali orang tua (dari anaknya).\" Thawus berkata, \"Aku mendengar beberapa anak kecil berkata, 'Wahai orang yang memakan muntahannya.' Dan aku tidak merasa bahwa Rasulullah shallallahu 'alaihi wasallam memberikan hal tersebut sebagai permisalan, hingga sampai kepada kami bahwa beliau bersabda: \"Permisalan orang yang memberi suatu pemberian kemudian mengambilnya kembali…dan beliau menyebutkan suatu kata yang maknanya adalah 'seperti anjing yang memakan muntahannya'.\""},"3539":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ حَاتِمِ بْنِ نُعَيْمٍ قَالَ حَدَّثَنَا حِبَّانُ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ حَنْظَلَةَ أَنَّهُ سَمِعَ طَاوُسًا يَقُولُ أَخْبَرَنَا بَعْضُ مَنْ أَدْرَكَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّهُ قَالَ مَثَلُ الَّذِي يَهَبُ فَيَرْجِعُ فِي هِبَتِهِ كَمَثَلِ الْكَلْبِ يَأْكُلُ فَيَقِيءُ ثُمَّ يَأْكُلُ قَيْئَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Hatim bin Nu'aim] berkata; telah menceritakan kepada kami [Hibban] telah memberitakan kepada kami [Abdullah] dari [Hanzhalah] bahwa ia telah mendengar [Thawus] berkata; telah memberitakan kepada kami [sebagian orang] yang menjumpai Nabi shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Permisalan orang yang memberi kemudian mengambilnya kembali seperti anjing yang makan, setelah muntah kemudian ia makan kembali muntahannya tersebut.\""},"3540":{"ar":"أَخْبَرَنَا هِلَالُ بْنُ الْعَلَاءِ قَالَ حَدَّثَنَا أَبِي قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ وَهُوَ ابْنُ عَمْرٍو عَنْ سُفْيَانَ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ طَاوُسٍ عَنْ زَيْدِ بْنِ ثَابِتٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الرُّقْبَى جَائِزَةٌ","id":"Telah mengabarkan kepada kami [Hilal bin Al 'Ala] berkata; telah menceritakan kepada kami [ayahku] berkata; telah menceritakan kepada kami ['Ubaidullah] -yaitu Ibnu 'Amru- dari [Sufyan] dari [Ibnu Abu Najih] dari [Thawus] darii [Zaid bin Tsabit] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Ruqba itu dibolehkan.\" "},"3541":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ عَلِيِّ بْنِ مَيْمُونٍ قَالَ حَدَّثَنَا مُحَمَّدٌ وَهُوَ ابْنُ يُوسُفَ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ طَاوُسٍ عَنْ رَجُلٍ عَنْ زَيْدِ بْنِ ثَابِتٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَعَلَ الرُّقْبَى لِلَّذِي أُرْقِبَهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Ali bin Maimun] berkata; telah menceritakan kepada kami [Muhammad] -yaitu Ibnu Yusuf- berkata; telah menceritakan kepada kami [Sufyan] dari [Ibnu Abu Najih] dari [Thawus] dari [seorang laki-laki] dari [Zaid bin Tsabit], bahwa Nabi shallallahu 'alaihi wasallam menjadikan ruqba untuk orang yang diberinya.\" "},"3542":{"ar":"أَخْبَرَنَا زَكَرِيَّا بْنُ يَحْيَى قَالَ حَدَّثَنَا عَبْدُ الْجَبَّارِ بْنُ الْعَلَاءِ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ طَاوُسٍ لَعَلَّهُ عَنْ ابْنِ عَبَّاسٍ قَالَلَا رُقْبَى فَمَنْ أُرْقِبَ شَيْئًا فَهُوَ سَبِيلُ الْمِيرَاثِ","id":"Telah mengabarkan kepada kami [Zakaria bin Yahya] berkata; telah menceritakan kepada kami [Abdul Jabbar bin Al 'Ala] berkata; telah menceritakan kepada kami [Sufyan] dari [Ibnu Abu Najih] dari [Thawus] kemungkinan dari [Ibnu Abbas] ia berkata, \"Tidak ada ruqba. Barangsiapa diberi sesuatu dengan system ruqba maka hal itu adalah jalan warisan.\" "},"3543":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ وَهْبٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ قَالَ حَدَّثَنِي أَبُو عَبْدِ الرَّحِيمِ قَالَ حَدَّثَنِي زَيْدٌ عَنْ أَبِي الزُّبَيْرِ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تُرْقِبُوا أَمْوَالَكُمْ فَمَنْ أَرْقَبَ شَيْئًا فَهُوَ لِمَنْ أُرْقِبَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Wahb] berkata; telah menceritakan kepada kami [Muhammad bin Salamah] berkata; telah menceritakan kepadaku [Abu Abdurrahim] berkata; telah menceritakan kepadaku [Zaid] dari [Abu Az Zubair] dari [Thawus] dari [Ibnu Abbas] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Janganlah memberikan harta kalian dengan system ruqba, barangsiapa memberikan sesuatu dengan system ruqba maka sesuatu tersebut untuk orang yang diberi.\" "},"3544":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ حَجَّاجٍ عَنْ أَبِي الزُّبَيْرِ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعُمْرَى جَائِزَةٌ لِمَنْ أُعْمِرَهَا وَالرُّقْبَى جَائِزَةٌ لِمَنْ أُرْقِبَهَا وَالْعَائِدُ فِي هِبَتِهِ كَالْعَائِدِ فِي قَيْئِهِ","id":"Telah mengabarkan kepada kami [Ahmad bin Harb] berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Hajjaj] dari [Abu Az Zubair] dari [Thawus] dari [Ibnu Abbas] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Umra adalah diperbolehkan bagi orang yang diberinya dan ruqba diperbolehkan bagi orang yang diberinya, dan orang yang mengambil kembali pemberiannya seperti orang yang memakan kembali muntahannya.\" "},"3545":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي الزُّبَيْرِ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ قَالَالْعُمْرَى وَالرُّقْبَى سَوَاءٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] berkata; telah menceritakan kepada kami [Yahya] berkata; telah menceritakan kepada kami [Sufyan] dari [Abu Az Zubair] dari [Thawus] dari [Ibnu Abbas] berkata, \"'Umra dan Ruqba adalah sama.\" "},"3546":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا يَعْلَى قَالَ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي الزُّبَيْرِ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ قَالَلَا تَحِلُّ الرُّقْبَى وَلَا الْعُمْرَى فَمَنْ أُعْمِرَ شَيْئًا فَهُوَ لَهُ وَمَنْ أُرْقِبَ شَيْئًا فَهُوَ لَهُ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] berkata; telah menceritakan kepada kami [Ya'la] berkata; telah menceritakan kepada kami [Sufyan] dari [Abu Az Zubair] dari [Thawus] dari [Ibnu Abbas] berkata, \"Tidak halal Ruqba dan 'Umra, barangsiapa yang diberi sesuatu dengan system 'Umra maka sesuatu tersebut menjadi miliknya. Dan barangsiapa diberi sesuatu dengan system Ruqba maka sesuatu tersebut adalah miliknya.\" "},"3547":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ قَالَ حَدَّثَنَا حَجَّاجٌ عَنْ أَبِي الزُّبَيْرِ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ قَالَلَا تَصْلُحُ الْعُمْرَى وَلَا الرُّقْبَى فَمَنْ أَعْمَرَ شَيْئًا أَوْ أَرْقَبَهُ فَإِنَّهُ لِمَنْ أُعْمِرَهُ وَأُرْقِبَهُ حَيَاتَهُ وَمَوْتَهُأَرْسَلَهُ حَنْظَلَةُ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] berkata; telah menceritakan kepada kami [Muhammad bin Bisyr] berkata; telah menceritakan kepada kami [Hajjaj] dari [Abu Az Zubair] dari [Thawus] dari Ibnu Abbas berkata, \"Tidak layak 'Umra dan Ruqba, barangsiapa yang diberi sesuatu dengan system Umra atau Ruqba maka sesuatu tersebut milik orang yang diberi, disaat ia hidup dan matinya.\" Hadits tersebut dimursalkan oleh Hanzhalah. "},"3548":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ حَاتِمٍ قَالَ أَنْبَأَنَا حِبَّانُ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ عَنْ حَنْظَلَةَ أَنَّهُ سَمِعَ طَاوُسًا يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَحِلُّ الرُّقْبَى فَمَنْ أُرْقِبَ رُقْبَى فَهُوَ سَبِيلُ الْمِيرَاثِ","id":"Telah mengabarkan kepada kami [Muhammad bin Hatim] berkata; telah memberitakan kepada kami [Hibban] berkata; telah menceritakan kepada kami [Abdullah] dari [Hanzhalah] bahwa ia telah mendengar [Thawus] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak halal Ruqba, maka barangsiapa yang diberi dengan system ruqba maka itu adalah jalan warisan.\" "},"3549":{"ar":"أَخْبَرَنِي عَبْدَةُ بْنُ عَبْدِ الرَّحِيمِ عَنْ وَكِيعٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ طَاوُسٍ عَنْ زَيْدِ بْنِ ثَابِتٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعُمْرَى مِيرَاثٌ","id":"Telah mengabarkan kepada kami ['Abdah bin Abdurrahim] dari [Waki'] berkata; telah menceritakan kepada kami [Sufyan] dari [Ibnu Abu Najih] dari [Thawus] dari [Zaid bin Tsabit] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"'Umra adalah warisan.\" "},"3550":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ يَزِيدَ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ طَاوُسٍ عَنْ أَبِيهِ عَنْ حُجْرٍ الْمَدَرِيِّ عَنْ زَيْدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعُمْرَى لِلْوَارِثِ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin Yazid] berkata; telah menceritakan kepada kami [Sufyan] dari [Ibnu Thawus] dari [ayahnya] dari [Hujr Al Madari] dari [Zaid] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"'Umra adalah untuk pewaris.\" "},"3551":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عُبَيْدٍ عَنْ ابْنِ الْمُبَارَكِ عَنْ مَعْمَرٍ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ طَاوُسٍ عَنْ زَيْدِ بْنِ ثَابِتٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْعُمْرَى لِلْوَارِثِ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Ubaid] dari [Ibnu Al Mubarak] dari [Ma'mar] dari ['Amru bin Dinar] dari [Thawus] dari [Zaid bin Tsabit] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"'Umra adalah untuk pewaris.\" "},"3552":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ حَاتِمٍ قَالَ أَنْبَأَنَا حِبَّانُ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ مَعْمَرٍ قَالَ سَمِعْتُ عَمْرَو بْنَ دِينَارٍ يُحَدِّثُ عَنْ طَاوُسٍ عَنْ حُجْرٍ الْمَدَرِيِّ عَنْ زَيْدِ بْنِ ثَابِتٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْعُمْرَى لِلْوَارِثِ وَاللَّهُ أَعْلَمُ","id":"Telah mengabarkan kepada kami [Muhammad bin Hatim] berkata; telah memberitakan kepada kami [Hibban] berkata; telah memberitakan kepada kami [Abdullah] dari [Ma'mar] berkata; aku mendengar ['Amru bin Dinar] menceritakan dari [Thawus] dari [Hujr Al Madari] dari [Zaid bin Tsabit], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"'Umra adalah untuk pewaris.\" Wallahu a'lam. "},"3553":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ دِينَارٍ قَالَ سَمِعْتُ طَاوُسًا يُحَدِّثُ عَنْ زَيْدِ بْنِ ثَابِتٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْعُمْرَى هِيَ لِلْوَارِثِ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la] berkata; telah menceritakan kepada kami [Khalid] berkata; telah menceritakan kepada kami [Syu'bah] dari ['Amru bin Dinar] berkata; aku mendengar [Thawus] menceritakan dari [Zaid bin Tsabit] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"'Umra adalah untuk pewaris.\" "},"3554":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي عَمْرُو بْنُ دِينَارٍ قَالَ سَمِعْتُ طَاوُسًا يُحَدِّثُ عَنْ حُجْرٍ الْمَدَرِيِّ عَنْ زَيْدِ بْنِ ثَابِتٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْعُمْرَى لِلْوَارِثِ","id":"Telah mengabarkan kepada kami ['Amru bin Ali] berkata; telah menceritakan kepada kami [Abu Daud] berkata; telah menceritakan kepada kami [Syu'bah] berkata; telah mengabarkan kepadaku ['Amru bin Dinar] berkata; aku mendengar [Thawus] menceritakan dari [Hujr Al Madari] dari [Zaid bin Tsabit], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"'Umra adalah untuk pewaris.\" "},"3555":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ يَزِيدَ عَنْ سُفْيَانَ عَنْ عَمْرٍو عَنْ طَاوُسٍ عَنْ حُجْرٍ الْمَدَرِيِّ عَنْ زَيْدِ بْنِ ثَابِتٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى بِالْعُمْرَى لِلْوَارِثِ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin Yazid] dari [Sufyan] dari ['Amru] dari [Thawus] dari [Hujr Al Madariji] dari [Zaid bin Tsabit], bahwa Nabi shallallahu 'alaihi wasallam memutuskan bahwa 'Umra adalah untuk pewaris.\" "},"3556":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عُبَيْدِ اللَّهِ بْنِ يَزِيدَ بْنِ إِبْرَاهِيمَ قَالَ أَخْبَرَنِي أَبِي أَنَّهُ عَرَضَ عَلَيَّ مَعْقَلٌ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ حُجْرٍ الْمَدَرِيِّ عَنْ زَيْدِ بْنِ ثَابِتٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَعْمَرَ شَيْئًا فَهُوَ لِمُعْمَرِهِ مَحْيَاهُ وَمَمَاتَهُ وَلَا تُرْقِبُوا فَمَنْ أَرْقَبَ شَيْئًا فَهُوَ لِسَبِيلِهِ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Ubaidullah bin Yazid bin Ibrahim] berkata; telah mengabarkan kepadaku [ayahku] bahwasanya [Ma'qil] telah menyampaikan kepadaku dari ['Amru bin Dinar] dari [Hujr Al Madari] dari [Zaid bin Tsabit] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa memberikan sesuatu dengan system Umra maka sesuatu tersebut milik orang yang diberi, disaat hidup dan matinya. Dan janganlah kalian memberi dengan system Ruqba, barangsiapa memberi sesuatu dengan system Ruqba maka sesuatu tersebut menjadi miliknya.\" "},"3557":{"ar":"أَخْبَرَنِي زَكَرِيَّا بْنُ يَحْيَى قَالَ حَدَّثَنَا زَيْدُ بْنُ أَخْزَمَ قَالَ أَنْبَأَنَا مُعَاذُ بْنُ هِشَامٍ قَالَ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ قَالَ حَدَّثَنَا عَمْرُو بْنُ دِينَارٍ عَنْ طَاوُسٍ عَنْ الْحَجُورِيِّ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْعُمْرَى جَائِزَةٌ","id":"Telah mengabarkan kepada kami [Zakaria bin Yahya] berkata; telah menceritakan kepada kami [Zaid bin Akhzam] berkata; telah memberitakan kepada kami [Mu'adz bin Hisyam] berkata; telah menceritakan kepada kami [ayahku] dari [Qatadah] berkata; telah menceritakan kepada kami ['Amru bin Dinar] dari [Thawus] dari [Al Hajuri] dari [Abdullah bin Abbas] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Umra adalah boleh.\" "},"3558":{"ar":"أَخْبَرَنَا هَارُونُ بْنُ مُحَمَّدِ بْنِ بَكَّارِ بْنِ بِلَالٍ قَالَ حَدَّثَنَا أَبِي قَالَ حَدَّثَنَا سَعِيدٌ هُوَ ابْنُ بَشِيرٍ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الْعُمْرَى جَائِزَةٌ","id":"Telah mengabarkan kepada kami [Harun bin Muhammad bin Bakkar bin Bilal] berkata; telah menceritakan kepada kami [ayahku] ia berkata; telah menceritakan kepada kami [Sa'id] -yaitu Ibnu Basyir- dari ['Amru bin Dinar] dari [Thawus] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya Umra adalah boleh.\" "},"3559":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ حَاتِمٍ قَالَ حَدَّثَنَا حِبَّانُ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ قَالَ حَدَّثَنَا مَكْحُولٌ عَنْ طَاوُسٍبَتَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعُمْرَى وَالرُّقْبَى","id":"Telah mengabarkan kepada kami [Muhammad bin Hatim] berkata; telah menceritakan kepada kami [Hibban] berkata; telah memberitakan kepada kami [Abdullah] dari [Muhammad bin Ishaq] ia berkata; telah menceritakan kepada kami [Makhul] dari [Thawus] bahwa Rasulullah shallallahu 'alaihi wasallam membedakan antara Umra dan Ruqba.\" "},"3560":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا بِسْطَامُ بْنُ مُسْلِمٍ قَالَ حَدَّثَنَا مَالِكُ بْنُ دِينَارٍ عَنْ عَطَاءٍ عَنْ جَابِرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَطَبَهُمْ فَقَالَ الْعُمْرَى جَائِزَةٌ","id":"Telah mengabarkan kepada kami ['Amru bin Ali] berkata; telah menceritakan kepada kami [Abu Daud] berkata; telah menceritakan kepada kami [Bistham bin Muslim] berkata; telah menceritakan kepada kami [Malik bin Dinar] dari ['Atha] dari [Jabir], bahwa Rasulullah shallallahu 'alaihi wasallam berkhutbah kepada mereka, beliau bersabda: \"Umra itu boleh.\" "},"3561":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ أَنْبَأَنَا عُبَيْدُ اللَّهِ عَنْ إِسْرَائِيلَ عَنْ عَبْدِ الْكَرِيمِ عَنْ عَطَاءٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْعُمْرَى وَالرُّقْبَىقُلْتُ وَمَا الرُّقْبَى قَالَ يَقُولُ الرَّجُلُ لِلرَّجُلِ هِيَ لَكَ حَيَاتَكَ فَإِنْ فَعَلْتُمْ فَهُوَ جَائِزَةٌ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] berkata; telah memberitakan kepada kami ['Ubaidullah] dari [Israil] dari [Abdul Karim] dari ['Atha] berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang dari Umra dan Ruqba. Aku lalu bertanya, \"Apakah Ruqba itu? Ia menjawab, \"Seseorang berkata kepada orang lain, 'Ini untukmu sepanjang hidupmu.' Maka jika kalian melakukannya maka hal tersebut adalah boleh.\""},"3562":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا مُحَمَّدٌ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ قَتَادَةَ يُحَدِّثُ عَنْ عَطَاءٍ عَنْ جَابِرٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْعُمْرَى جَائِزَةٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] berkata; telah menceritakan kepada kami [Muhammad] berkata; telah menceritakan kepada kami [Syu'bah] berkata; aku mendengar [Qatadah] menceritakan dari ['Atha] dari [Jabir] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"'Umra adalah boleh.\" "},"3563":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ حَاتِمٍ قَالَ أَنْبَأَنَا حِبَّانُ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ عَبْدِ الْمَلِكِ بْنِ أَبِي سُلَيْمَانَ عَنْ عَطَاءٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أُعْطِيَ شَيْئًا حَيَاتَهُ فَهُوَ لَهُ حَيَاتَهُ وَمَوْتَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Hatim] berkata; telah memberitakan kepada kami [Hibban] berkata; telah memberitakan kepada kami [Abdullah] dari [Abdul Malik bin Abu Sulaiman] dari ['Atha] Ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa diberi sesuatu selama hidupnya, maka sesuatu tersebut miliknya sepanjang hidup dan matinya.\""},"3564":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عَبْدُ الرَّزَّاقِ قَالَ أَنْبَأَنَا ابْنُ جُرَيْجٍ عَنْ عَطَاءٍ أَنْبَأَنَا حَبِيبُ بْنُ أَبِي ثَابِتٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا عُمْرَى وَلَا رُقْبَى فَمَنْ أُعْمِرَ شَيْئًا أَوْ أُرْقِبَهُ فَهُوَ لَهُ حَيَاتَهُ وَمَمَاتَهُ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] berkata; telah memberitakan kepada kami [Abdurrazaq] berkata; telah memberitakan kepada kami [Ibnu Juraij] dari ['Atha] telah memberitakan kepada kami [Habib bin Abu Tsabit] dari [Ibnu Umar], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada Umra atau ruqba, barangsiapa akan melakukan umra atau ruqba, maka ia adalah untuknya selama hidup atau matinya.\" "},"3565":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ بَكْرٍ قَالَ أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي عَطَاءٌ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ ابْنِ عُمَرَ وَلَمْ يَسْمَعْهُ مِنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا عُمْرَى وَلَا رُقْبَى فَمَنْ أُعْمِرَ شَيْئًا أَوْ أُرْقِبَهُ فَهُوَ لَهُ حَيَاتَهُ وَمَمَاتَهُقَالَ عَطَاءٌ هُوَ لِلْآخَرِ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'id] berkata; telah menceritakan kepada kami [Muhammad bin Bakr] berkata; telah mengabarkan kepada kami [Ibnu Juraij] berkata; telah mengabarkan kepadaku ['Atha] dari [Habib bin Abu Tsabit] dari [Ibnu Umar] dan ia belum mendengarnya darinya, ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada 'Umra dan Ruqba, barangsiapa yang diberi sesuatu dengan system umra atau ruqba maka sesuatu tersebut adalah miliknya, selama hidup dan matinya.\" ['Atha] berkata, \"Sesuatu tersebut untuk orang lain.\" "},"3566":{"ar":"أَخْبَرَنِي عَبْدَةُ بْنُ عَبْدِ الرَّحِيمِ قَالَ أَنْبَأَنَا وَكِيعٌ عَنْ يَزِيدَ بْنِ زِيَادِ بْنِ أَبِي الْجَعْدِ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ قَالَ سَمِعْتُ ابْنَ عُمَرَ يَقُولُنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الرُّقْبَى وَقَالَ مَنْ أُرْقِبَ رُقْبَى فَهُوَ لَهُ","id":"Telah mengabarkan kepada kami ['Abdah bin Abdurrahim] berkata; telah memberitakan kepada kami [Waki'] dari [Yazid bin Abu Al Ja'd] dari [Habib bin Abu Tsabit] berkata; aku mendengar [Ibnu Umar] berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang dari ruqba. Beliau bersabda: \"Barangsiapa diberi dengan system ruqba maka sesuatu sesuatu tersebut menjadi miliknya.\" "},"3567":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ إِبْرَاهِيمَ بْنِ صُدْرَانَ عَنْ بِشْرِ بْنِ الْمُفَضَّلِ قَالَ حَدَّثَنَا الْحَجَّاجُ الصَّوَّافُ عَنْ أَبِي الزُّبَيْرِ قَالَ حَدَّثَنَا جَابِرٌ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا مَعْشَرَ الْأَنْصَارِ أَمْسِكُوا عَلَيْكُمْ يَعْنِي أَمْوَالَكُمْ لَا تُعْمِرُوهَا فَإِنَّهُ مَنْ أَعْمَرَ شَيْئًا فَإِنَّهُ لِمَنْ أُعْمِرَهُ حَيَاتَهُ وَمَمَاتَهُ","id":"Telah mengabarkan kepadaku [Muhammad bin Ibrahim bin Shudran] dari [Bisyr bin Al Mufadhdhal] berkata; telah menceritakan kepada kami [Al Hajjaj Ash Shawwaf] dari [Abu Az Zubair] berkata; telah menceritakan kepada kami [Jabir] berkata; Rasulullah shallallahu 'alaihi wasallam: \"Wahai orang-orang Anshar, tahanlah harta-harta kalian janganlah kalian memberikannya dengan system umra, sesungguhnya orang yang memberikan sesuatu dengan system umra maka sesuatu tersebut adalah milik orang yang diberi selama hidup dan matinya.\" "},"3568":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ عَنْ هِشَامٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَمْسِكُوا عَلَيْكُمْ أَمْوَالَكُمْ وَلَا تُعْمِرُوهَا فَمَنْ أُعْمِرَ شَيْئًا حَيَاتَهُ فَهُوَ لَهُ حَيَاتَهُ وَبَعْدَ مَوْتِهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la] berkata; telah menceritakan kepada kami [Khalid] dari [Hisyam] dari [Abu Az Zubair] dari [Jabir], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tahanlah harta kalian dan janganlah memberikannya dengan system umra, barangsiapa diberi sesuatu dengan system umra maka sesuatu tersebut adalah miliknya selama hidup dan matinya.\" "},"3569":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ حَدَّثَنَا هُشَيْمٌ عَنْ دَاوُدَ عَنْ أَبِي ��لزُّبَيْرِ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعُمْرَى جَائِزَةٌ لِأَهْلِهَا وَالرُّقْبَى جَائِزَةٌ لِأَهْلِهَا","id":"Telah mengabarkan kepada kami [Ali bin Hujr] berkata; telah menceritakan kepada kami [Husyaim] dari [Daud] dari [Abu Az Zubair] dari [Jabir] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"'Umra diperbolehkan bagi pemiliknya dan ruqba diperbolehkan bagi pemiliknya.\" "},"3570":{"ar":"أَخْبَرَنِي مَحْمُودُ بْنُ خَالِدٍ قَالَ حَدَّثَنَا عُمَرُ عَنْ الْأَوْزَاعِيِّ حَدَّثَنَا ابْنُ شِهَابٍ قَالَ و أَخْبَرَنِي عَمْرُو بْنُ عُثْمَانَ أَنْبَأَنَا بَقِيَّةُ بْنُ الْوَلِيدِ عَنْ الْأَوْزَاعِيِّ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أُعْمِرَ عُمْرَى فَهِيَ لَهُ وَلِعَقِبِهِ يَرِثُهَا مَنْ يَرِثُهُ مِنْ عَقِبِهِ","id":"Telah mengabarkan kepada kami [Mahmud bin Khalid] berkata; telah menceritakan kepada kami [Umar] dari [Al Auza'i] telah menceritakan kepada kami [Ibnu Syihab] berkata; dan telah mengabarkan kepadaku ['Amru bin Utsman] telah memberitakan kepadaku [Baqiyyah bin Al Walid] dari [Al Auza'i] dari [Az Zuhri] dari ['Urwah] dari [Jabir] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa diberi Umra maka umra tersebut untuknya dan orang setelahnya, dan akan diwarisi oleh orang setelahnya.\" "},"3571":{"ar":"أَخْبَرَنَا عِيسَى بْنُ مُسَاوِرٍ قَالَ حَدَّثَنَا الْوَلِيدُ قَالَ حَدَّثَنَا أَبُو عَمْرٍو عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعُمْرَى لِمَنْ أُعْمِرَهَا هِيَ لَهُ وَلِعَقِبِهِ يَرِثُهَا مَنْ يَرِثُهُ مِنْ عَقِبِهِ","id":"Telah mengabarkan kepada kami [Isa bin Musawir] berkata; telah menceritakan kepada kami [Al Walid] berkata; telah menceritakan kepada kami [Abu 'Amru] dari [Ibnu Syihab] dari [Abu Salamah] dari [Jabir] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"'Umra itu untuk orang yang diberi dan orang yang setelahnya, dan akan diwarisi oleh orang setelahnya lagi.\" "},"3572":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ هَاشِمٍ الْبَعْلَبَكِّيُّ قَالَ حَدَّثَنَا الْوَلِيدُ قَالَ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ وَأَبِي سَلَمَةَ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعُمْرَى لِمَنْ أُعْمِرَهَا هِيَ لَهُ وَلِعَقِبِهِ يَرِثُهَا مَنْ يَرِثُهُ مِنْ عَقِبِهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Hasyim Al Ba'labaki] berkata; telah menceritakan kepada kami [Al Walid] berkata; telah menceritakan kepada kami [Al Auza'i] dari [Az Zuhri] dari ['Urwah] dan [Abu Salamah] dari [Jabir] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Umra itu untuk orang yang diberi dengan system umra, dia miliknya dan milik orang setelahnya, dan akan diwarisi oleh orang yang mewarisinya setelahnya.\" "},"3573":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحِيمِ قَالَ حَدَّثَنَا عَمْرُو بْنُ أَبِي سَلَمَةَ الدِّمَشْقِيُّ عَنْ أَبِي عُمَرَ الصَّنْعَانِيِّ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَيُّمَا رَجُلٍ أَعْمَرَ رَجُلًا عُمْرَى لَهُ وَلِعَقِبِهِ فَهِيَ لَهُ وَلِمَنْ يَرِثُهُ مِنْ عَقِبِهِ مَوْرُوثَةٌ","id":"Telah mengabarkan kepadaku [Muhammad bin Abdullah bin Abdurrahim] berkata; telah menceritakan kepada kami ['Amru bin Abu Salamah Ad Dimasyqi] dari [Abu Umar Ash Shan'ani] dari [Hisyam bin 'Urwah] dari [ayahnya] dari [Abdullah bin Az Zubair], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapapun lelaki yang memberikan umra kepada orang lain untuknya dan orang setelahnya, maka ia adalah miliknya dan milik orang yang mewarisi setelahnya sebagai warisan.\" "},"3574":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ جَابِرٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ أَعْمَرَ رَجُلًا عُمْرَى لَهُ وَلِعَقِبِهِ فَقَدْ قَطَعَ قَوْلُهُ حَقَّهُ وَهِيَ لِمَنْ أُعْمِرَ وَلِعَقِبِهِ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] berkata; telah menceritakan kepada kami [Al Laits] dari [Ibnu Syihab] dari [Abu Salamah bin 'Abdurrahman] dari [Jabir] berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa memberikan umra kepada orang lain untuknya dan orang setelahnya, maka perkataannya telah memutuskan haknya, dan umra tersebut milik orang yang diberi dan orang setelahnya.\" "},"3575":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ ابْنِ الْقَاسِمِ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ عَنْ جَابِرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَيُّمَا رَجُلٍ أُعْمِرَ عُمْرَى لَهُ وَلِعَقِبِهِ فَإِنَّهَا لِلَّذِي يُعْطَاهَا لَا تَرْجِعُ إِلَى الَّذِي أَعْطَاهَا لِأَنَّهُ أَعْطَى عَطَاءً وَقَعَتْ فِيهِ الْمَوَارِيثُ","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dan [Al Harits bin Miskin] dia membacakan dan aku yang mendengar, dari [Ibnu Al Qasim] dari [Malik] dari [Ibnu Syihab] dari [Abu Salamah] dari [Jabir] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapapun laki-laki yang diberi umra untuknya dan orang setelahnya, maka ia adalah milik orang yang diberi, tidak akan kembali kepada orang yang memberinya. Karena ia telah memberikan suatu pemberian, dan berlaku padanya pewarisan.\" "},"3576":{"ar":"أَخْبَرَنَا عِمْرَانُ بْنُ بَكَّارٍ قَالَ حَدَّثَنَا أَبُو الْيَمَانِ قَالَ حَدَّثَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ حَدَّثَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ أَنَّ جَابِرًا أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى أَنَّهُ مَنْ أَعْمَرَ رَجُلًا عُمْرَى لَهُ وَلِعَقِبِهِ فَإِنَّهَا لِلَّذِي أُعْمِرَهَا يَرِثُهَا مِنْ صَاحِبِهَا الَّذِي أَعْطَاهَا مَا وَقَعَ مِنْ مَوَارِيثِ اللَّهِ وَحَقِّهِ","id":"Telah mengabarkan kepada kami [Imran bin Bakkar] berkata; telah menceritakan kepada kami [Abu Al Yaman] berkata; telah menceritakan kepada kami [Syu'aib] dari [Az Zuhri] berkata; telah menceritakan kepadaku [Abu Salamah bin 'Abdurrahman] bahwa [Jabir] telah mengabarkan kepadanya, bahwa Rasulullah shallallahu 'alaihi wasallam memberi putusan bahwa barangsiapa memberikan umra kepada orang lain, maka umra tersebut menjadi miliknya dan milik orang setelahnya. Sesungguhnya ia untuk orang yang diberi, ia mewarisi dari pemilik yang telah memberikan kepadanya, sesuatu yang berlaku dari warisan dan hak Allah.\" "},"3577":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ عَبْدِ الْحَكَمِ عَنْ ابْنِ أَبِي فُدَيْكٍ قَالَ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ عَنْ جَابِرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى فِيمَنْ أُعْمِرَ عُمْرَى لَهُ وَلِعَقِبِهِ فَهِيَ لَهُ بَتْلَةٌ لَا يَجُوزُ لِلْمُعْطِي مِنْهَا شَرْطٌ وَلَا ثُنْيَاقَالَ أَبُو سَلَمَةَ لِأَنَّهُ أَعْطَى عَطَاءً وَقَعَتْ فِيهِ الْمَوَارِيثُ فَقَطَعَتْ الْمَوَارِيثُ شَرْطَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin Abdul Hakam] dari [Ibnu Abu Fudaik] berkata; telah menceritakan kepada kami [Ibnu Abu Dzi`b] dari [Ibnu Syihab] dari [Abu Salamah] dari [Jabir], bahwa Rasulullah shallallahu 'alaihi wasallam memberi putusan tentang orang yang menerima umra, bahwa umra tersebut adalah (menjadi) miliknya dan milik orang setelahnya, ia tidak bisa kembali kepada orang yang memberinya dan si pemberi pun tidak boleh memberikan dengan bersyarat.\" Abu Salamah berkata, \"Karena ia memberi suatu pemberian yang berlaku padanya pewarisan, sehingga pewarisan telah memutus syaratnya.\" "},"3578":{"ar":"أَخْبَرَنَا أَبُو دَاوُدَ سُلَيْمَانُ بْنُ سَيْفٍ قَالَ حَدَّثَنَا يَعْقُوبُ قَالَ حَدَّثَنَا أَبِي عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ أَنَّ أَبَا سَلَمَةَ أَخْبَرَهُ عَنْ جَابِرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَيُّمَا رَجُلٍ أَعْمَرَ رَجُلًا عُمْرَى لَهُ وَلِعَقِبِهِ قَالَ قَدْ أَعْطَيْتُكَهَا وَعَقِبَكَ مَا بَقِيَ مِنْكُمْ أَحَدٌ فَإِنَّهَا لِمَنْ أُعْطِيَهَا وَإِنَّهَا لَا تَرْجِعُ إِلَى صَاحِبِهَا مِنْ أَجْلِ أَنَّهُ أَعْطَاهَا عَطَاءً وَقَعَتْ فِيهِ الْمَوَارِيثُ","id":"Telah mengabarkan kepada kami [Abu Daud Sulaiman bin Saif] berkata; telah menceritakan kepada kami [Ya'qub] berkata; telah menceritakan kepada kami [ayahku] dari [Shalih] dari [Ibnu Syihab] bahwa [Abu Salamah] telah mengabarkan kepadanya dari [Jabir], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapapun laki-laki yang memberikan umra, maka umra tersebut menjadi miliknya dan milik orang yang setelahnya. Ia berkata, 'Aku telah memberikannya kepadamu dan orang setelahmu', maka ia milik orang yang diberinya dan tidak kembali kepada pemiliknya karena ia telah memberikannya sebagai suatu pemberian, dan berlaku padanya (hukum) pewarisan.\" "},"3579":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ يَزِيدَ قَالَ حَدَّثَنَا أَبِي قَالَ حَدَّثَنَا سَعِيدٌ قَالَ حَدَّثَنِي يَزِيدُ بْنُ أَبِي حَبِيبٍ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ عَنْ جَابِرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى بِالْعُمْرَى أَنْ يَهَبَ الرَّجُلُ لِلرَّجُلِ وَلِعَقِبِهِ الْهِبَةَ وَيَسْتَثْنِيَ إِنْ حَدَثَ بِكَ حَدَثٌ وَبِعَقِبِكَ فَهُوَ إِلَيَّ وَإِلَى عَقِبِي إِنَّهَا لِمَنْ أُعْطِيَهَا وَلِعَقِبِهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin Yazid] berkata; telah menceritakan kepada kami [ayahku] ia berkata; telah menceritakan kepada kami [Sa'id] ia berkata; telah menceritakan kepadaku [Yazid bin Abu Habib] dari [Ibnu Syihab] dari [Abu Salamah] dari [Jabir], bahwa Rasulullah shallallahu 'alaihi wasallam memutuskan mengenai umra, yaitu seorang laki-laki memberikan suatu pemberian kepada orang lain dan orang yang setelahnya, dan ia memberikan syarat. Yaitu 'Apabila terjadi sesuatu padamu dan orang yang setelahmu maka kembali kepadaku dan orang yang setelahku'. Beliau kemudian memutuskan, bahwa pemberian tersebut adalah milik orang yang diberinya dan orang yang setelahnya.\""},"3580":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ قَالَ حَدَّثَنَا هِشَامٌ قَالَ حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ قَالَ حَدَّثَنِي أَبُو سَلَمَةَ قَالَ سَمِعْتُ جَابِرًا يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعُمْرَى لِمَنْ وُهِبَتْ لَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la] berkata; telah menceritakan kepada kami [Khalid bin Al Harits] berkata; telah menceritakan kepada kami [Hisyam] ia berkata; telah menceritakan kepada kami [Yahya bin Abu Katsir] berkata; telah menceritakan kepadaku [Abu Salamah] ia berkata; aku mendengar [Jabir] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Umra adalah milik orang yang diberinya.\" "},"3581":{"ar":"أَخْبَرَنَا يَحْيَى بْنُ دُرُسْتَ قَالَ حَدَّثَنَا أَبُو إِسْمَعِيلَ قَالَ حَدَّثَنَا يَحْيَى أَنَّ أَبَا سَلَمَةَ حَدَّثَهُ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِعَنْ نَبِيِّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْعُمْرَى لِمَنْ وُهِبَتْ لَهُ","id":"Telah mengabarkan kepada kami [Yahya bin Durust] ia berkata; telah menceritakan kepada kami [Abu Isma'il] ia berkata; telah menceritakan kepada kami [Yahya] bahwa [Abu Salamah] telah menceritakan kepadanya dari [Jabir bin Abdullah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Umra adalah milik orang yang diberi.\" "},"3582":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ أَنْبَأَنَا إِسْمَعِيلُ عَنْ مُحَمَّدٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا عُمْرَى فَمَنْ أُعْمِرَ شَيْئًا فَهُوَ لَهُ","id":"Telah mengabarkan kepada kami [Ali bin Hujr] ia berkata; telah memberitakan kepada kami [Isma'il] dari [Muhammad] dari [Abu Salamah] dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada umra, barangsiapa diberi sesuatu dengan system umra maka ia adalah miliknya.\" "},"3583":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا عِيسَى وَعَبْدَةُ بْنُ سُلَيْمَانَ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرٍو قَالَ حَدَّثَنَا أَبُو سَلَمَةَ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أُعْمِرَ شَيْئًا فَهُوَ لَهُ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] ia berkata; telah menceritakan kepada kami [Isa] dan ['Abdah bin Sulaiman] mereka berdua berkata; telah menceritakan kepada kami [Muhammad bin 'Amru] ia berkata; telah menceritakan kepada kami [Abu Salamah] dari [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa diberi sesuatu maka ia adalah miliknya.\""},"3584":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا مُحَمَّدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ النَّضْرِ بْنِ أَنَسٍ عَنْ بَشِيرِ بْنِ نَهِيكٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْعُمْرَى جَائِزَةٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] berkata; telah menceritakan kepada kami [Muhammad] ia berkata; telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [An Nadhr bin Anas] dari [Basyir bin Nahik] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Umra itu dibolehkan.\" "},"3585":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ قَالَ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ قَالَ سَأَلَنِي سُلَيْمَانُ بْنُ هِشَامٍ عَنْ الْعُمْرَى فَقُلْتُ حَدَّثَ مُحَمَّدُ بْنُ سِيرِينَ عَنْ شُرَيْحٍ قَالَقَضَى نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ الْعُمْرَى جَائِزَةٌقَالَ قَتَادَةُ قُلْتُ حَدَّثَنِي النَّضْرُ بْنُ أَنَسٍ عَنْ بَشِيرِ بْنِ نَهِيكٍ عَنْ أَبِي هُرَيْرَةَ أَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْعُمْرَى جَائِزَةٌ قَالَ قَتَادَةُ وَقُلْتُ كَانَ الْحَسَنُ يَقُولُ الْعُمْرَى جَائِزَةٌ قَالَ قَتَادَةُ فَقَالَ الزُّهْرِيُّ إِنَّمَا الْعُمْرَى إِذَا أُعْمِرَ وَعَقِبُهُ مِنْ بَعْدِهِ فَإِذَا لَمْ يَجْعَلْ عَقِبَهُ مِنْ بَعْدِهِ كَانَ لِلَّذِي يَجْعَلُ شَرْطَهُ قَالَ قَتَادَةُ فَسُئِلَ عَطَاءُ بْنُ أَبِي رَبَاحٍ فَقَالَ حَدَّثَنِي جَابِرُ بْنُ عَبْدِ اللَّهِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْعُمْرَى جَائِزَةٌ قَالَ قَتَادَةُ فَقَالَ الزُّهْرِيُّ كَانَ الْخُلَفَاءُ لَا يَقْضُونَ بِهَذَا قَالَ عَطَاءٌ قَضَى بِهَا عَبْدُ الْمَلِكِ بْنُ مَرْوَانَ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] berkata; telah menceritakan kepada kami [Mu'adz bin Hisyam] berkata; telah menceritakan kepadaku [Bapakku] dari [Qatadah] ia berkata, \"Sulaiman bin Hisyam bertanya kepadaku mengenai Umra. Kemudian aku katakan, \" [Muhammad bin Sirin] telah menceritakan dari [Syuraih], ia berkata, \"Nabi shallallahu 'alaihi wasallam memutuskan bahwa umra itu dibolehkan.\" [Qatadah] berkata, \"Aku berkata; telah menceritakan kepadaku [An Nadlr bin Anas] dari [Basyir bin Nahik] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Umrah itu dibolehkan.\" Qatadah berkata, \"Aku berkata, \"Al Hasan berkata, \"Umra itu dibolehkan.\" Qatadah berkata, \"Az Zuhri berkata, \"Sesungguhnya umra itu adalah apabila seseorang dan orang yang setelahnya diberi pemberian, kemudian apabila orang yang memberi tidak menjadikan umra untuk orang setelahnya maka pemberian tersebut milik orang yang memberikan syarat.\" [Qatadah] berkata, \" ['Atha bin Abu Rabah] ditanya mengenai hal tersebut, kemudian ia berkata, \" [Jabir bin Abdullah] menceritakan kepadaku, bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Umra itu dibolehkan.\" Qatadah berkata, \"Az Zuhri berkata, \"Dahulu para khalifah tidak memutuskan dengan hal ini.\" 'Atha berkata, \"Abdul Malik bin Marwan memberi putusan dengannya.\" "},"3586":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَعْمَرٍ قَالَ حَدَّثَنَا حَبَّانُ قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ ح و أَخْبَرَنِي إِبْرَاهِيمُ بْنُ يُونُسَ بْنِ مُحَمَّدٍ قَالَ حَدَّثَنَا أَبِي قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ دَاوُدَ وَهُوَ ابْنُ أَبِي هِنْدٍ وَحَبِيبٌ الْمُعَلِّمُ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَجُوزُ لِامْرَأَةٍ هِبَةٌ فِي مَالِهَا إِذَا مَلَكَ زَوْجُهَا عِصْمَتَهَااللَّفْظُ لِمُحَمَّدٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Ma'mar] berkata; telah menceritakan kepada kami [Habban] berkata; telah menceritakan kepada kami [Hammad bin Salamah]. (dalam jalur lain disebutkan) Telah mengabarkan kepadaku [Ibrahim bin Yunus bin Muhammad] berkata; telah menceritakan kepada kami [ayahku] berkata; telah menceritakan kepada kami [Hammad bin Salamah] dari [Daud] -yaitu Ibnu Abu Hind- dan [Habib Al Mu'allim] dari ['Amru bin Syu'aib] dari [ayahnya] dari [kakeknya], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak boleh bagi seorang wanita memberikan hartanya apabila suaminya memilki ikatan pernikahannya.\" Dan ini adalah lafadz Muhammad."},"3587":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا حُسَيْنٌ الْمُعَلِّمُ عَنْ عَمْرِو بْنِ شُعَيْبٍ أَنَّ أَبَاهُ حَدَّثَهُ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو ح و أَخْبَرَنَا حُمَيْدُ بْنُ مَسْعَدَةَ قَالَ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ قَالَ حَدَّثَنَا حُسَيْنٌ الْمُعَلِّمُ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَلَمَّا فَتَحَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَكَّةَ قَامَ خَطِيبًا فَقَالَ فِي خُطْبَتِهِ لَا يَجُوزُ لِامْرَأَةٍ عَطِيَّةٌ إِلَّا بِإِذْنِ زَوْجِهَا","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] ia berkata; telah menceritakan kepada kami [Khalid] berkata; telah menceritakan kepada kami [Husain Al Mu'allim] dari ['Amru bin Syu'aib] bahwa [ayahnya] menceritakan kepadanya dari [Abdullah bin 'Amru]. (dalam jalur lain disebutkan) Dan telah mengabarkan kepada kami [Humaid bin Mas'adah] berkata; telah menceritakan kepada kami [Yazid bin Zurai'] berkata; telah menceritakan kepada kami [Husain Al Mu'allim] dari ['Amru bin Syu'aib] dari [ayahnya] dari [kakeknya] berkata, \"Tatkala Rasulullah shallallahu 'alaihi wasallam menaklukkan Makkah, beliau berdiri untuk berkhutbah, beliau katakan: \"Tidak boleh bagi seorang wanita memberikan pemberian kecuali dengan seizin suaminya.\""},"3588":{"ar":"أَخْبَرَنَا هَنَّادُ بْنُ السَّرِيِّ قَالَ حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ عَنْ يَحْيَى بْنِ هَانِئٍ عَنْ أَبِي حُذَيْفَةَ عَنْ عَبْدِ الْمَلِكِ بْنِ مُحَمَّدِ بْنِ بَشِيرٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَلْقَمَةَ الثَّقَفِّيِّ قَالَقَدِمَ وَفْدُ ثَقِيفٍ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَعَهُمْ هَدِيَّةٌ فَقَالَ أَهَدِيَّةٌ أَمْ صَدَقَةٌ فَإِنْ كَانَتْ هَدِيَّةٌ فَإِنَّمَا يُبْتَغَى بِهَا وَجْهُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَضَاءُ الْحَاجَةِ وَإِنْ كَانَتْ صَدَقَةٌ فَإِنَّمَا يُبْتَغَى بِهَا وَجْهُ اللَّهِ عَزَّ وَجَلَّ قَالُوا لَا بَلْ هَدِيَّةٌ فَقَبِلَهَا مِنْهُمْ وَقَعَدَ مَعَهُمْ يُسَائِلُهُمْ وَيُسَائِلُونَهُ حَتَّى صَلَّى الظُّهْرَ مَعَ الْعَصْرِ","id":"Telah mengabarkan kepada kami [Hannad bin As Sari] berkata; telah menceritakan kepada kami [Abu Bakr bin 'Ayyasy] dari [Yahya bin Hani`] dari [Abu Hudzifah] dari [Abdul Malik bin Muhammad bin Basyir] dari ['Abdurrahman bin 'Alqamah Ats Tsaqafi] ia berkata, \"Utusan Tsaqif datang kepada Rasulullah shallallahu 'alaihi wasallam dengan membawa hadiah, beliau lalu bertanya: \"Ini hadiah atau sedekah. Jika hadiah maka itu adalah karena mengharapkan ridla Rasulullah shallallahu 'alaihi wasallam dan memenuhi kebutuhan, namun jika sedekah maka itu adalah karena mengharap ridla Allah Azza wa Jalla.\" Mereka menjawab, \"Tidak, ini adalah hadiah.\" Maka beliau pun menerimanya dan duduk bersama mereka, beliau bertanya kepada mereka dan mereka bertanya kepada beliau hingga beliau melakukan shalat zhuhur dan ashar.\""},"3589":{"ar":"أَخْبَرَنَا أَبُو عَاصِمٍ خُشَيْشُ بْنُ أَصْرَمَ قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَنْبَأَنَا مَعْمَرٌ عَنْ ابْنِ عَجْلَانَ عَنْ سَعِيدٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَقَدْ هَمَمْتُ أَنْ لَا أَقْبَلَ هَدِيَّةً إِلَّا مِنْ قُرَشِيٍّ أَوْ أَنْصَارِيٍّ أَوْ ثَقَفِيٍّ أَوْ دَوْسِيٍّ","id":"Telah mengabarkan kepada kami [Abu 'Ashim Khusyaisy bin Ashram] ia berkata; telah menceritakan kepada kami [Abdurrazaq] berkata; telah memberitakan kepada kami [Ma'mar] dari [Ibnu 'Ajlan] dari [Sa'id] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh aku ingin tidak menerima hadiah kecuali dari orang Quraisy, atau Anshar, atau Tsaqif, atau Daus.\""},"3590":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَنَسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُتِيَ بِلَحْمٍ فَقَالَ مَا هَذَا فَقِيلَ تُصُدِّقَ بِهِ عَلَى بَرِيرَةَ فَقَالَ هُوَ لَهَا صَدَقَةٌ وَلَنَا هَدِيَّةٌ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] berkata; telah menceritakan kepada kami [Waki'] berkata; telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Anas], bahwa ketika Rasulullah shallallahu 'alaihi wasallam diberi daging maka beliau pun bertanya: \"Apakah ini?\" Lalu dijawab, \"Daging yang disedekahkan kepada Barirah.\" Kemudian beliau bersabda: \"Itu sedekah baginya dan hadiah untuk kita.\""},"3591":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ الرُّهَاوِيُّ وَمُوسَى بْنُ عَبْدِ الرَّحْمَنِ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ ابْنِ عُمَرَ قَالَكَانَتْ يَمِينٌ يَحْلِفُ عَلَيْهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا وَمُقَلِّبِ الْقُلُوبِ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman Ar Ruhawi] dan [Musa bin 'Abdurrahman] mereka berkata; telah menceritakan kepada kami [Muhammad bin Bisyr] berkata; telah menceritakan kepada kami [Sufyan] dari [Musa bin 'Uqbah] dari [Salim bin Abdullah bin Umar] dari [Ibnu Umar] berkata, \"Sumpah yang biasa diucapkan Rasulullah shallallahu 'alaihi wasallam adalah 'Tidak, demi Dzat yang membolak-balikkan hati'.\""},"3592":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ يَحْيَى بْنِ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ الصَّلْتِ أَبُو يَعْلَى قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ رَجَاءٍ عَنْ عَبَّادِ بْنِ إِسْحَقَ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِ قَالَكَانَتْ يَمِينُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الَّتِي يَحْلِفُ بِهَا لَا وَمُصَرِّفِ الْقُلُوبِ","id":"Telah mengabarkan kepadaku [Muhammad bin Yahya bin Abdullah] berkata; telah menceritakan kepada kami [Muhammad bin Ash Shalt Abu Ya'la] berkata; telah menceritakan kepada kami [Abdullah bin Raja`] dari ['Abbad bin Ishaq] dari [Az Zuhri] dari [Salim] dari [ayahnya] berkata, \"Sumpah yang biasa Rasulullah shallallahu 'alaihi wasallam diucapkan adalah 'Tidak, demi Dzat yang memalingkan hati'.\""},"3593":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا الْفَضْلُ بْنُ مُوسَى قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ عَمْرٍو قَالَ حَدَّثَنَا أَبُو سَلَمَةَ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَمَّا خَلَقَ اللَّهُ الْجَنَّةَ وَالنَّارَ أَرْسَلَ جِبْرِيلَ عَلَيْهِ السَّلَام إِلَى الْجَنَّةِ فَقَالَ انْظُرْ إِلَيْهَا وَإِلَى مَا أَعْدَدْتُ لِأَهْلِهَا فِيهَا فَنَظَرَ إِلَيْهَا فَرَجَعَ فَقَالَ وَعِزَّتِكَ لَا يَسْمَعُ بِهَا أَحَدٌ إِلَّا دَخَلَهَا فَأَمَرَ بِهَا فَحُفَّتْ بِالْمَكَارِهِ فَقَالَ اذْهَبْ إِلَيْهَا فَانْظُرْ إِلَيْهَا وَإِلَى مَا أَعْدَدْتُ لِأَهْلِهَا فِيهَا فَنَظَرَ إِلَيْهَا فَإِذَا هِيَ قَدْ حُفَّتْ بِالْمَكَارِهِ فَقَالَ وَعِزَّتِكَ لَقَدْ خَشِيتُ أَنْ لَا يَدْخُلَهَا أَحَدٌ قَالَ اذْهَبْ فَانْظُرْ إِلَى النَّارِ وَإِلَى مَا أَعْدَدْتُ لِأَهْلِهَا فِيهَا فَنَظَرَ إِلَيْهَا فَإِذَا هِيَ يَرْكَبُ بَعْضُهَا بَعْضًا فَرَجَعَ فَقَالَ وَعِزَّتِكَ لَا يَدْخُلُهَا أَحَدٌ فَأَمَرَ بِهَا فَحُفَّتْ بِالشَّهَوَاتِ فَقَالَ ارْجِعْ فَانْظُرْ إِلَيْهَا فَنَظَرَ إِلَيْهَا فَإِذَا هِيَ قَدْ حُفَّتْ بِالشَّهَوَاتِ فَرَجَعَ وَقَالَ وَعِزَّتِكَ لَقَدْ خَشِيتُ أَنْ لَا يَنْجُوَ مِنْهَا أَحَدٌ إِلَّا دَخَلَهَا","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] berkata; telah memberitakan kepada kami [Al Fadll bin Musa] berkata; telah menceritakan kepadaku [Muhammad bin 'Amru] berkata; telah menceritakan kepada kami [Abu Salamah] dari [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Tatkala Allah menciptakan Surga dan Neraka Dia mengirim Jibril 'alaihissalam ke Surga seraya berfirman: 'Lihatlah ke dalamnya dan apa yang telah Aku persiapkan untuk penghuninya' Kemudian Jibril melihat ke surga dan kembali seraya berkata, 'Demi kemuliaan-Mu, sungguh tidak ada seorangpun yang mendengarnya kecuali ia akan memasukinya.' Kemudian Allah memerintahkan (untuk menutupi surga dengan sesuatu yang dibenci), maka ditutupilah surga dengan sesuatu yang dibenci (oleh manusia). Allah lalu berfirman: 'Pergilah ke Surga dan lihatlah kepadanya dan apa yang telah Aku persiapkan untuk penghuninya.' Kemudian Jibril melihat kepadanya, ternyata Surga telah dikelilingi dengan perkara-perkara yang tidak menyenangkan. Jibril lalu berkata, \"Demi kemulian-Mu, sungguh aku khawatir tidak akan ada seorangpun yang akan memasukinya.' Allah kemudian berfirman: 'Pergi dan lihatlah ke dalam neraka dan kepada apa yang telah Aku persiapkan untuk penghuninya.' Kemudian ia melihat kepadanya dan ternyata sebagiannya berada di atas sebagian yang lain. Kemudian Jibril kembali dan berkata, 'Demi kemulian-Mu, tidak akan ada seorangpun yang memasukinya.' Kemudian Allah memerintahkan (untuk menutupi neraka dengan sesuatu yang menyenangkan), lalu ditutupilah neraka dengan hal yang menyenangkan nafsu syahwat. Lalu Allah berfirman; 'Lihatlah ke dalamnya.' Ternyata ia dikelilingi dengan nafsu syahwat, kemudian Jibril kembali dan berkata, 'Demi kemuliaan-Mu, sungguh aku khawatir tidak akan ada seorangpun yang selamat darinya kecuali ia pasti akan memasukinya'.\""},"3594":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ عَنْ إِسْمَعِيلَ وَهُوَ ابْنُ جَعْفَرٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ دِينَارٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ كَانَ حَالِفًا فَلَا يَحْلِفْ إِلَّا بِاللَّهِ وَكَانَتْ قُرَيْشٌ تَحْلِفُ بِآبَائِهَا فَقَالَ لَا تَحْلِفُوا بِآبَائِكُمْ","id":"Telah mengabarkan kepada kami [Ali bin Hujr] dari [Isma'il] -yaitu Abu Ja'far- berkata; telah menceritakan kepada kami [Abdullah bin Dinar] dari [Ibnu Umar] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa bersumpah maka hendaknya ia tidak bersumpah kecuali dengan Allah, dan dahulu orang-orang Quraisy bersumpah dengan nama bapak-bapak mereka.\" Kemudian beliau bersabda: \"Janganlah bersumpah dengan nama bapak-bapak kalian.\""},"3595":{"ar":"أَخْبَرَنِي زِيَادُ بْنُ أَيُّوبَ قَالَ حَدَّثَنَا ابْنُ عُلَيَّةَ قَالَ حَدَّثَنَا يَحْيَى بْنُ أَبِي إِسْحَقَ قَالَ حَدَّثَنِي رَجُلٌ مِنْ بَنِي غِفَارٍ فِي مَجْلِسِ سَالِمِ بْنِ عَبْدِ اللَّهِ قَالَ سَالِمُ بْنُ عَبْدِ اللَّهِ سَمِعْتُ عَبْدَ اللَّهِ يَعْنِي ابْنَ عُمَرَ وَهُوَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ يَنْهَاكُمْ أَنْ تَحْلِفُوا بِآبَائِكُمْ","id":"Telah mengabarkan kepada kami [Ziyad bin Ayyub] berkata; telah menceritakan kepada kami [Ibnu 'Aliyyah] berkata; telah menceritakan kepada kami [Yahya bin Abu Ishaq] berkata; telah menceritakan kepadaku [seorang laki-laki Bani Ghifar] dalam majelis Salim bin Abdullah, [Salim bin Abdullah] berkata; aku mendengar [Abdullah] -yaitu Ibnu Umar- berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah melarang kalian untuk bersumpah dengan nama bapak-bapak kalian.\""},"3596":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ وَقُتَيْبَةُ بْنُ سَعِيدٍ وَاللَّفْظُ لَهُ قَالَا حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِأَنَّهُ سَمِعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عُمَرَ مَرَّةً وَهُوَ يَقُولُ وَأَبِي وَأَبِي فَقَالَ إِنَّ اللَّهَ يَنْهَاكُمْ أَنْ تَحْلِفُوا بِآبَائِكُمْ فَوَاللَّهِ مَا حَلَفْتُ بِهَا بَعْدُ ذَاكِرًا وَلَا آثِرًا","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'id], dan [Qutaibah bin Sa'id] dan lafazhnya adalah lafazh Qutaibah, mereka berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Salim] dari [ayahnya], bahwa suatu kali Nabi shallallahu 'alaihi wasallam mendengar Umar berkata, \"Demi ayahku. Demi ayahku.\" Maka beliau pun bersabda: \"Sesungguhnya Allah melarang kalian bersumpah dengan nama bapak-bapak kalian.\" Umar berkata, \"Demi Allah, setelah itu aku tidak pernah bersumpah dengannya baik menyebutkannya ataupun menceritakannya.\""},"3597":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ يَزِيدَ وَسَعِيدُ بْنُ عَبْدِ الرَّحْمَنِ وَاللَّفْظُ لَهُ قَالَا حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِ عَنْ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ يَنْهَاكُمْ أَنْ تَحْلِفُوا بِآبَائِكُمْقَالَ عُمَرُ فَوَاللَّهِ مَا حَلَفْتُ بِهَا بَعْدُ ذَاكِرًا وَلَا آثِرًا","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin Yazid] dan [Sa'id bin 'Abdurrahman] dan lafazhnya adalah lafazh Sa'id, mereka berdua berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Salim] dari [ayahnya] dari [Umar] bahwa nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah melarang kalian untuk bersumpah dengan bapak-bapak kalian.\" Umar berkata, \"Demi Allah, aku tidak bersumpah dengannya sejak itu, baik dengan menyebutkan maupun menceritakan.\""},"3598":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عُثْمَانَ بْنِ سَعِيدٍ قَالَ أَنْبَأَنَا مُحَمَّدٌ وَهُوَ ابْنُ حَرْبٍ عَنْ الزُّبَيْدِيِّ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِ أَنَّهُ أَخْبَرَهُ عَنْ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ يَنْهَاكُمْ أَنْ تَحْلِفُوا بِآبَائِكُمْقَالَ عُمَرُ فَوَاللَّهِ مَا حَلَفْتُ بِهَا بَعْدُ ذَاكِرًا وَلَا آثِرًا","id":"Telah mengabarkan kepada kami ['Amru bin Utsman bin Sa'id] berkata; telah memberitakan kepada kami [Muhammad] -yaitu Ibnu Harb- dari [Az Zubaidi] dari [Az Zuhri] dari [Salim] dari [ayahnya] bahwa ia mengabarkan kepadanya, dari [Umar] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah melarang kalian untuk bersumpah dengan bapak-bapak kalian.\" Umar berkata, \"Demi Allah, aku tidak bersumpah dengannya sejak itu, baik dengan menyebutkan maupun menceritakan.\""},"3599":{"ar":"أَخْبَرَنَا أَبُو بَكْرِ بْنُ عَلِيٍّ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ قَالَ حَدَّثَنَا أَبِي قَالَ حَدَّثَنَا عَوْفٌ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَحْلِفُوا بِآبَائِكُمْ وَلَا بِأُمَّهَاتِكُمْ وَلَا بِالْأَنْدَادِ وَلَا تَحْلِفُوا إِلَّا بِاللَّهِ وَلَا تَحْلِفُوا إِلَّا وَأَنْتُمْ صَادِقُونَ","id":"Telah mengabarkan kepada kami [Abu Bakr bin Ali] berkata; telah menceritakan kepada kami ['Ubaidullah bin Mu'adz] berkata; telah menceritakan kepada kami [ayahku] berkata; telah menceritakan kepada kami ['Auf] dari [Muhammad bin Sirin] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian bersumpah dengan ayah dan ibu kalian, atau dengan barhala-berhala, dan janganlah kalian bersumpah kecuali kalian jujur.\""},"3600":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ خَالِدٍ ح وَأَنْبَأَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ بَزِيعٍ قَالَ حَدَّثَنَا يَزِيدُ قَالَ حَدَّثَنَا خَالِدٌ عَنْ أَبِي قِلَابَةَ عَنْ ثَابِتِ بْنِ الضَّحَّاكِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَلَفَ بِمِلَّةٍ سِوَى الْإِسْلَامِ كَاذِبًا فَهُوَ كَمَا قَالَ قَالَ قُتَيْبَةُ فِي حَدِيثِهِ مُتَعَمِّدًا وَقَالَ يَزِيدُ كَاذِبًا فَهُوَ كَمَا قَالَ وَمَنْ قَتَلَ نَفْسَهُ بِشَيْءٍ عَذَّبَهُ اللَّهُ بِهِ فِي نَارِ جَهَنَّمَ","id":"Telah mengabarkan kepada kami [Qutaibah] berkata; telah menceritakan kepada kami [Ibnu Abu Adi] dari [Khalid]. (dalam jalur lain disebutkan) Dan telah memberitakan kepada kami [Muhammad bin Abdullah bin Bazi'] berkata; telah menceritakan kepada kami [Yazid] berkata; telah menceritakan kepada kami [Khalid] dari [Abu Qilabah] dari [Tsabit bin Adh Dhahhak] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa bersumpah dengan agama selain Islam secara dusta, maka berlaku seperti apa yang ia katakan.\" [Qutaibah] menyebutkan dalam haditsnya; 'dengan sengaja.' Sedangkan [Yazid] menyebutkan, 'dengan dusta, maka berlaku seperti apa yang ia ucapkan. Dan barangsiapa membunuh dirinya dengan sesuatu maka Allah akan menyiksanya dengan sesuatu tersebut di Neraka Jahannam.\""},"3601":{"ar":"أَخْبَرَنِي مَحْمُودُ بْنُ خَالِدٍ قَالَ حَدَّثَنَا الْوَلِيدُ قَالَ حَدَّثَنَا أَبُو عَمْرٍو عَنْ يَحْيَى أَنَّهُ حَدَّثَهُ قَالَ حَدَّثَنِي أَبُو قِلَابَةَ قَالَ حَدَّثَنِي ثَابِتُ بْنُ الضَّحَّاكِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ حَلَفَ بِمِلَّةٍ سِوَى الْإِسْلَامِ كَاذِبًا فَهُوَ كَمَا قَالَ وَمَنْ قَتَلَ نَفْسَهُ بِشَيْءٍ عُذِّبَ بِهِ فِي الْآخِرَةِ","id":"Telah mengabarkan kepada kami [Mahmud bin Khalid] berkata; telah menceritakan kepada kami [Al Walid] berkata; telah menceritakan kepada kami [Abu 'Amru] dari [Yahya] bahwa ia menceritakan kepadanya, ia berkata; telah menceritakan kepadaku [Abu Qilabah] berkata; telah menceritakan kepadaku [Tsabit bin Adl Dlahhak], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda; \"Barangsiapa bersumpah dengan agama selain Islam secara dusta, maka berlaku seperti apa yang ia katakan. Dan barangsiapa membunuh dirinya dengan sesuatu maka ia akan disiksa di Akhirat.\""},"3602":{"ar":"أَخْبَرَنَا الْحُسَيْنُ بْنُ حُرَيْثٍ قَالَ حَدَّثَنَا الْفَضْلُ بْنُ مُوسَى عَنْ حُسَيْنِ بْنِ وَاقِدٍ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَالَ إِنِّي بَرِيءٌ مِنْ الْإِسْلَامِ فَإِنْ كَانَ كَاذِبًا فَهُوَ كَمَا قَالَ وَإِنْ كَانَ صَادِقًا لَمْ يَعُدْ إِلَى الْإِسْلَامِ سَالِمًا","id":"Telah mengabarkan kepada kami [Al Hasan bin Huraits] berkata; telah menceritakan kepada kami [Al Fadll bin Musa] dari [Husain bin Waqid] dari [Abdullah bin Buraidah] dari [ayahnya] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mengatakan, 'Aku berlepas diri dari Islam', apabila ia berdusta maka berlaku seperti apa yang ia katakan, dan apabila berkata benar maka ia tidak akan kembali kepada Islam dalam keadaan selamat.\""},"3603":{"ar":"أَخْبَرَنَا يُوسُفُ بْنُ عِيسَى قَالَ حَدَّثَنَا الْفَضْلُ بْنُ مُوسَى قَالَ حَدَّثَنَا مِسْعَرٌ عَنْ مَعْبَدِ بْنِ خَالِدٍ عَنْ عَبْدِ اللَّهِ بْنِ يَسَارٍ عَنْ قُتَيْلَةَ امْرَأَةٍ مِنْ جُهَيْنَةَأَنَّ يَهُودِيًّا أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّكُمْ تُنَدِّدُونَ وَإِنَّكُمْ تُشْرِكُونَ تَقُولُونَ مَا شَاءَ اللَّهُ وَشِئْتَ وَتَقُولُونَ وَالْكَعْبَةِ فَأَمَرَهُمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَرَادُوا أَنْ يَحْلِفُوا أَنْ يَقُولُوا وَرَبِّ الْكَعْبَةِ وَيَقُولُونَ مَا شَاءَ اللَّهُ ثُمَّ شِئْتَ","id":"Telah mengabarkan kepada kami [Yusuf bin Isa] berkata; telah menceritakan kepada kami [Al Fadll bin Musa] berkata; telah menceritakan kepada kami [Mis'ar] dari [Ma'bad bin Khalid] dari [Abdullah bin Yasar] dari [Qutailah] seorang wanita dari Juhainah, bahwa seorang Yahudi datang kepada Nabi shallallahu 'alaihi wasallam, lalu beliau bersabda: \"Sesungguhnya kalian membuat tandingan, dan sungguh kalian telah berbuat syirik. Kalian mengatakan, 'Atas kehendak Allah dan kehendak kamu'. Dan kalian katakan, 'Demi Ka'bah'.\" Kemudian Nabi shallallahu 'alaihi wasallam memerintahkan para sahabat apabila hendak bersumpah untuk mengucapkan, 'Demi Tuhan Pemilik Ka'bah', dan mengucapkan, 'Atas kehendak Allah, kemudian atas kehendak kamu'.\""},"3604":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا يَزِيدُ قَالَ أَنْبَأَنَا هِشَامٌ عَنْ الْحَسَنِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ سَمُرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَحْلِفُوا بِآبَائِكُمْ وَلَا بِالطَّوَاغِيتِ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] berkata; telah menceritakan kepada kami [Yazid] berkata; telah memberitakan kepada kami [Hisyam] dari [Al Hasan] dari ['Abdurrahman bin Samurah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Janganlah bersumpah dengan bapak-bapak kalian dan dengan sesembahan selain Allah.\""},"3605":{"ar":"أَخْبَرَنَا كَثِيرُ بْنُ عُبَيْدٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ حَرْبٍ عَنْ الزُّبَيْدِيِّ عَنْ الزُّهْرِيِّ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَلَفَ مِنْكُمْ فَقَالَ بِاللَّاتِ فَلْيَقُلْ لَا إِلَهَ إِلَّا اللَّهُ وَمَنْ قَالَ لِصَاحِبِهِ تَعَالَ أُقَامِرْكَ فَلْيَتَصَدَّقْ","id":"Telah mengabarkan kepada kami [Katsir bin 'Ubaid] berkata; telah menceritakan kepada kami [Muhammad bin Harb] dari [Az Zubaidi] dari [Az Zuhri] dari [Humaid bin 'Abdurrahman] dari [Abu Hurairah] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa di antara kalian bersumpah dan berkata 'Demi Lata', maka hendaknya ia mengatakan, 'LAA ILAAHA ILLALLAAH (Tidak ada tuhan yang berhak disembah selain Allah) '. Dan barangsiapa berkata kepada sahabatnya, 'Kemarilah aku akan mengundi (judi) kamu', maka hendaknya ia bersedekah.\""},"3606":{"ar":"أَخْبَرَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا الْحَسَنُ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا زُهَيْرٌ قَالَ حَدَّثَنَا أَبُو إِسْحَقَ عَنْ مُصْعَبِ بْنِ سَعْدٍ عَنْ أَبِيهِ قَالَكُنَّا نَذْكُرُ بَعْضَ الْأَمْرِ وَأَنَا حَدِيثُ عَهْدٍ بِالْجَاهِلِيَّةِ فَحَلَفْتُ بِاللَّاتِ وَالْعُزَّى فَقَالَ لِي أَصْحَابُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِئْسَ مَا قُلْتَ ائْتِ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبِرْهُ فَإِنَّا لَا نَرَاكَ إِلَّا قَدْ كَفَرْتَ فَأَتَيْتُهُ فَأَخْبَرْتُهُ فَقَالَ لِي قُلْ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ ثَلَاثَ مَرَّاتٍ وَتَعَوَّذْ بِاللَّهِ مِنْ الشَّيْطَانِ ثَلَاثَ مَرَّاتٍ وَاتْفُلْ عَنْ يَسَارِكَ ثَلَاثَ مَرَّاتٍ وَلَا تَعُدْ لَهُ","id":"Telah mengabarkan kepada kami [Abu Daud] berkata; telah menceritakan kepada kami [Al Hasan bin Muhammad] berkata; telah menceritakan kepada kami [Zuhair] berkata; telah menceritakan kepada kami [Abu Ishaq] dari [Mush'ab bin Sa'd] dari [ayahnya] berkata, \"Kami pernah mengingat sebagian perkara dan aku baru keluar dari masa jahiliyah, kemudian aku bersumpah dengan Lata dan 'Uzza. Lalu para sahabat Rasulullah shallallahu 'alaihi wasallam berkata kepadaku, \"Sungguh buruk apa yang engkau katakan. Datanglah kepada Rasulullah shallallahu 'alaihi wasallam dan kabarkan kepadanya, sungguh kami tidak melihat kecuali engkau telah kafir.\" Kemudian aku datang kepada beliau dan mengabarkan hal itu, maka beliau pun bersabda: \"Katakanlah, 'LAA ILAAHA ILLALLAAHU WAHDAHU LAA SYARIIKA LAH (Tidak ada tuhan yang berhak disembah selain Allah, dan tidak ada sekutu bagi-Nya) ' tiga kali dan berlindunglah engkau kepada Allah dari setan tiga kali, lalu meludahlah ke samping kirimu sebanyak tiga kali dan jangan engkau ulangi lagi (perbuatanmu).\""},"3607":{"ar":"أَخْبَرَنَا عَبْدُ الْحَمِيدِ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا مَخْلَدٌ قَالَ حَدَّثَنَا يُونُسُ بْنُ أَبِي إِسْحَقَ عَنْ أَبِيهِ قَالَ حَدَّثَنِي مُصْعَبُ بْنُ سَعْدٍ عَنْ أَبِيهِ قَالَحَلَفْتُ بِاللَّاتِ وَالْعُزَّى فَقَالَ لِي أَصْحَابِي بِئْسَ مَا قُلْتَ قُلْتَ هُجْرًا فَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرْتُ ذَلِكَ لَهُ فَقَالَ قُلْ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ وَهُوَ عَلَى كُلِّ شَيْءٍ قَدِيرٌ وَانْفُثْ عَنْ يَسَارِكَ ثَلَاثًا وَتَعَوَّذْ بِاللَّهِ مِنْ الشَّيْطَانِ ثُمَّ لَا تَعُدْ","id":"Telah mengabarkan kepada kami [Abdul Hamid bin Muhammad] berkata; telah menceritakan kepada kami [Makhlad] berkata; telah menceritakan kepada kami [Yunus bin Abu Ishaq] dari [ayahnya] berkata; telah menceritakan kepadaku [Mush'ab bin Sa'd] dari [ayahnya] ia berkata, \"Aku bersumpah dengan Lata dan 'Uzza, kemudian para sahabatku mengatakan, 'Sungguh buruk apa yang engkau katakan! ' Kemudian aku datang kepada Rasulullah shallallahu 'alaihi wasallam dan menyebutkan hal tersebut kepadanya. Maka beliau bersabda: \"Katakanlah, 'LAA ILAAHA ILLALLAAHU WAHDAHU LAA SYARIIKA LAHU LAHUL MULKU WA LAHUL HAMDU WA HUWA 'ALAA KULLI SYAIN QADIIR (Tidak ada tuhan yang berhak untuk disembah selain Allah semata, yang tidak ada sekutu bagi-Nya, bagi-Nya kerajaan dan pujian. Dan dia mampu atas segala sesuatu) '. Lalu meludahlah ke kirimu sebanyak tiga kali, kemudian berlindunglah kepada Allah dari setan dan jangan kamu ulangi lagi (perbuatanmu).\""},"3608":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَمُحَمَّدُ بْنُ بَشَّارٍ عَنْ مُحَمَّدٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ الْأَشْعَثِ بْنِ سُلَيْمٍ عَنْ مُعَاوِيَةَ بْنِ سُوَيْدِ بْنِ مُقَرِّنٍ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَأَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِسَبْعٍ أَمَرَنَا بِاتِّبَاعِ الْجَنَائِزِ وَعِيَادَةِ الْمَرِيضِ وَتَشْمِيتِ الْعَاطِسِ وَإِجَابَةِ الدَّاعِي وَنَصْرِ الْمَظْلُومِ وَإِبْرَارِ الْقَسَمِ وَرَدِّ السَّلَامِ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dan [Muhammad bin Basysyar] dan [Muhammad] berkata; telah menceritakan kepada kami [Syu'bah] dari [Al Asy'ats bin Sulaim] dari [Mu'awiyah bin Suwaid bin Muqarrin] dari [Al Bara` bin 'Azib] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam memerintahkan kami untuk melakukan tujuh perkara; mengantarkan jenazah, menjenguk orang sakit, menjawab orang yang bersin, memenuhi orang yang mengundang, menolong orang yang dizhalimi, berbuat baik saat membagi, dan membalas salam.\""},"3609":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ سُلَيْمَانَ عَنْ أَبِي السَّلِيلِ عَنْ زَهْدَمٍ عَنْ أَبِي مُوسَىعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا عَلَى الْأَرْضِ يَمِينٌ أَحْلِفُ عَلَيْهَا فَأَرَى غَيْرَهَا خَيْرًا مِنْهَا إِلَّا أَتَيْتُهُ","id":"Telah mengabarkan kepada kami [Qutaibah] berkata; telah menceritakan kepada kami [Ibnu Adi] dari [Sulaiman] dari [Abu As Salil] dari [Zahdam] dari [Abu Musa] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak ada di atas bumi ini sumpah yang aku ucapkan lalu aku melihat ada yang lebih baik darinya kecuali aku akan mendatanginya (melakukannya).\""},"3610":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ غَيْلَانَ بْنِ جَرِيرٍ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى الْأَشْعَرِيِّ قَالَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي رَهْطٍ مِنْ الْأَشْعَرِيِّينَ نَسْتَحْمِلُهُ فَقَالَ وَاللَّهِ لَا أَحْمِلُكُمْ وَمَا عِنْدِي مَا أَحْمِلُكُمْ ثُمَّ لَبِثْنَا مَا شَاءَ اللَّهُ فَأُتِيَ بِإِبِلٍ فَأَمَرَ لَنَا بِثَلَاثِ ذَوْدٍ فَلَمَّا انْطَلَقْنَا قَالَ بَعْضُنَا لِبَعْضٍ لَا يُبَارِكُ اللَّهُ لَنَا أَتَيْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَسْتَحْمِلُهُ فَحَلَفَ أَنْ لَا يَحْمِلَنَا قَالَ أَبُو مُوسَى فَأَتَيْنَا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرْنَا ذَلِكَ لَهُ فَقَالَ مَا أَنَا حَمَلْتُكُمْ بَلْ اللَّهُ حَمَلَكُمْ إِنِّي وَاللَّهِ لَا أَحْلِفُ عَلَى يَمِينٍ فَأَرَى غَيْرَهَا خَيْرًا مِنْهَا إِلَّا كَفَّرْتُ عَنْ يَمِينِي وَأَتَيْتُ الَّذِي هُوَ خَيْرٌ","id":"Telah mengabarkan kepada kami [Qutaibah] berkata; telah menceritakan kepada kami [Hammad] dari [Ghailan bin Jarir] dari [Abu Burdah] dari [Abu Musa Al Asy'ari] berkata, \"Aku datang kepada Rasulullah shallallahu 'alaihi wasallam bersama beberapa orang Asy'ari meminta agar beliau bisa membawa kami. Kemudian beliau bersabda: \"Demi Allah, aku tidak dapat membawa kalian dan tidak memiliki sesuatu yang dapat membawa kalian.\" Kemudian kami tinggal selama yang dikehendaki Allah. Kemudian beliau diberi unta dan memerintahkan agar kami diberi tiga unta. Kemudian tatkala kami pergi sebagian kami berkata kepada sebagian yang lain, 'Allah tidak memberikan berkah kepada kita, kita datang kepada Rasulullah shallallahu 'alaihi wasallam meminta sesuatu yang dapat membawa kita, kemudian beliau bersumpah untuk tidak membawa kita.' Abu Musa berkata, \"Kemudian kami datang kepada Nabi shallallahu 'alaihi wasallam dan menyebutkan hal tersebut kepadanya. Kemudian beliau bersabda: \"Aku tidak membawa kalian akan tetapi Allah yang membawa kalian. Demi Allah, aku tidak bersumpah dengan suatu sumpah kemudian melihat yang lainnya lebih baik darinya kecuali aku membatalkan sumpahku dan melakukan sesuatu yang lebih baik.\""},"3611":{"ar":"أَخْبَرَنَا ع��مْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ بْنِ الْأَخْنَسِ قَالَ حَدَّثَنَا عَمْرُو بْنُ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ حَلَفَ عَلَى يَمِينٍ فَرَأَى غَيْرَهَا خَيْرًا مِنْهَا فَلْيُكَفِّرْ عَنْ يَمِينِهِ وَلْيَأْتِ الَّذِي هُوَ خَيْرٌ","id":"Telah mengabarkan kepada kami ['Amru bin Ali] berkata; telah menceritakan kepada kami [Yahya] dari ['Ubaidullah bin Al Akhnas] berkata; telah menceritakan kepada kami ['Amru bin Syu'aib] dari [ayahnya] dari [kakeknya] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa bersumpah dengan suatu sumpah kemudian melihat yang lainnya lebih baik darinya, maka hendaknya ia membayar kafarah sumpahnya dan melakukan sesuatu yang lebih baik.\""},"3612":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا الْمُعْتَمِرُ عَنْ أَبِيهِ عَنْ الْحَسَنِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ سَمُرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا حَلَفَ أَحَدُكُمْ عَلَى يَمِينٍ فَرَأَى غَيْرَهَا خَيْرًا مِنْهَا فَلْيُكَفِّرْ عَنْ يَمِينِهِ وَلْيَنْظُرْ الَّذِي هُوَ خَيْرٌ فَلْيَأْتِهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la] berkata; telah menceritakan kepada kami [Al Mu'tamir] dari [ayahnya] dari [Al Hasan] dari ['Abdurrahman bin Samurah] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Apabila salah seorang di antara kalian bersumpah dengan suatu sumpah kemudian melihat yang lainnya lebih baik darinya, maka hendaknya ia membayar kafarah sumpahnya dan melakukan hal yang lebih baik.\""},"3613":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا عَفَّانُ قَالَ حَدَّثَنَا جَرِيرُ بْنُ حَازِمٍ قَالَ سَمِعْتُ الْحَسَنَ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ سَمُرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا حَلَفْتَ عَلَى يَمِينٍ فَكَفِّرْ عَنْ يَمِينِكَ ثُمَّ ائْتِ الَّذِي هُوَ خَيْرٌ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] berkata; telah menceritakan kepada kami ['Affan] berkata; telah menceritakan kepada kami [Jarir bin Hazim] berkata; aku mendengar [Al Hasan] berkata; telah menceritakan kepada kami ['Abdurrahman bin Samurah] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila engkau bersumpah dengan suatu sumpah, maka hendaklah kamu bayar kafarah sumpahmu kemudian lakukan yang lebih baik.\""},"3614":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ يَحْيَى الْقُطَعِيُّ عَنْ عَبْدِ الْأَعْلَى وَذَكَرَ كَلِمَةً مَعْنَاهَا حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ سَمُرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا حَلَفْتَ عَلَى يَمِينٍ فَرَأَيْتَ غَيْرَهَا خَيْرًا مِنْهَا فَكَفِّرْ عَنْ يَمِينِكَ وَأْتِ الَّذِي هُوَ خَيْرٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Yahya Al Qutha'I] dari [Abdul A'la] -dan ia menyebutkan sebuah kalimat yang maknanya- telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Al Hasan] dari ['Abdurrahman bin Samurah], bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Apabila engkau bersumpah dengan suatu sumpah kemudian melihat yang lainnya lebih baik darinya, maka hendaklah kamu bayar kafarah sumpahmu dan lakukan sesuatu yang lebih baik.\""},"3615":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ عَمْرٍو مَوْلَى الْحَسَنِ بْنِ عَلِيٍّ يُحَدِّثُ عَنْ عَدِيِّ بْنِ حَاتِمٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَلَفَ عَلَى يَمِينٍ فَرَأَى غَيْرَهَا خَيْرًا مِنْهَا فَلْيَأْتِ الَّذِي هُوَ خَيْرٌ وَلْيُكَفِّرْ عَنْ يَمِينِهِ","id":"Telah mengabarkan kepada kami [Ishaq bin Manshur] berkata; telah menceritakan kepada kami ['Abdurrahman] berkata; telah menceritakan kepada kami [Syu'bah] dari ['Amru bin Murrah] berkata; aku mendengar [Abdullah bin 'Amru] mantan budak Al Hasan bin Ali, menceritakan dari [Adi bin Hatim] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa bersumpah dengan suatu sumpah kemudian melihat yang lainnya lebih baik darinya, maka hendaknya ia melakukan sesuatu yang lebih baik dan membayar kafarah sumpahnya.\""},"3616":{"ar":"أَخْبَرَنَا هَنَّادُ بْنُ السَّرِيِّ عَنْ أَبِي بَكْرِ بْنِ عَيَّاشٍ عَنْ عَبْدِ الْعَزِيزِ بْنِ رُفَيْعٍ عَنْ تَمِيمِ بْنِ طَرَفَةَ عَنْ عَدِيِّ بْنِ حَاتِمٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَلَفَ عَلَى يَمِينٍ فَرَأَى غَيْرَهَا خَيْرًا مِنْهَا فَلْيَدَعْ يَمِينَهُ وَلْيَأْتِ الَّذِي هُوَ خَيْرٌ وَلْيُكَفِّرْهَا","id":"Telah mengabarkan kepada kami [Hannad bin As Sari] dari [Abu Bakr bin 'Ayyasy] dari [Abdul Aziz bin Rafi'] dari [Tamim bin Tharafah] dari [Adi bin Hatim] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa bersumpah dengan suatu sumpah kemudian melihat yang lainnya lebih baik darinya, maka hendaknya ia meninggalkan sumpahnya dan melakukan sesuatu yang lebih baik serta membayar kafarah sumpahnya.\""},"3617":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ يَزِيدَ قَالَ حَدَّثَنَا بَهْزُ بْنُ أَسَدٍ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي عَبْدُ الْعَزِيزِ بْنُ رُفَيْعٍ قَالَ سَمِعْتُ تَمِيمَ بْنَ طَرَفَةَ يُحَدِّثُ عَنْ عَدِيِّ بْنِ حَاتِمٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَلَفَ عَلَى يَمِينٍ فَرَأَى خَيْرًا مِنْهَا فَلْيَأْتِ الَّذِي هُوَ خَيْرٌ وَلْيَتْرُكْ يَمِينَهُ","id":"Telah mengabarkan kepada kami ['Amru bin Yazid] berkata; telah menceritakan kepada kami [Bahz bin Asad] berkata; telah menceritakan kepada kami [Syu'bah] berkata; telah mengabarkan kepada kami [Abdul Aziz bin Rafi'] berkata; aku mendengar [Tamim bin Tharafah] menceritakan dari [Adi bin Hatim] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa bersumpah dengan suatu sumpah kemudian melihat yang lainnya lebih baik, maka hendaknya ia melakukan sesuatu yang lebih baik dan meninggalkan sumpahnya.\""},"3618":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ عَنْ سُفْيَانَ قَالَ حَدَّثَنَا أَبُو الزَّعْرَاءِ عَنْ عَمِّهِ أَبِي الْأَحْوَصِ عَنْ أَبِيهِ قَالَقُلْتُ يَا رَسُولَ اللَّهِ أَرَأَيْتَ ابْنَ عَمٍّ لِي أَتَيْتُهُ أَسْأَلُهُ فَلَا يُعْطِينِي وَلَا يَصِلُنِي ثُمَّ يَحْتَاجُ إِلَيَّ فَيَأْتِينِي فَيَسْأَلُنِي وَقَدْ حَلَفْتُ أَنْ لَا أُعْطِيَهُ وَلَا أَصِلَهُ فَأَمَرَنِي أَنْ آتِيَ الَّذِي هُوَ خَيْرٌ وَأُكَفِّرَ عَنْ يَمِينِي","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur] dari [Sufyan] berkata; telah menceritakan kepada kami [Abu Az Za'ra`] dari pamannya [Abu Al Ahwash] dari [ayahnya] berkata, \"Aku berkata, \"Wahai Rasulullah, bagaimana pendapatmu mengenai anak pamanku, aku datang dan berharap kepadanya namun ia tidak memberiku, bahkan ia tidak menyambung kekerabatan denganku. Kemudian ia butuh pertolonganku, ia datang dan meminta kepadaku? Sedangkan aku telah bersumpah untuk tidak memberinya dan tidak menyambung hubungan kekerabatan dengannya.\" Kemudian beliau memerintahkan aku agar melakukan yang lebih baik dan membatalkan sumpahku.\""},"3619":{"ar":"أَخْبَرَنَا زِيَادُ بْنُ أَيُّوبَ قَالَ حَدَّثَنَا هُشَيْمٌ قَالَ أَنْبَأَنَا مَنْصُورٌ وَيُونُسُ عَنْ الْحَسَنِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ سَمُرَةَ قَالَقَالَ لِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا آلَيْتَ عَلَى يَمِينٍ فَرَأَيْتَ غَيْرَهَا خَيْرًا مِنْهَا فَأْتِ الَّذِي هُوَ خَيْرٌ وَكَفِّرْ عَنْ يَمِينِكَ","id":"Telah mengabarkan kepada kami [Ziyad bin Ayyub] berkata; telah menceritakan kepada kami [Husyaim] berkata; telah memberitakan kepada kami [Manshur] dan [Yunus] dari [Al Hasan] dari ['Abdurrahman bin Samurah] berkata, \"Nabi shallallahu 'alahi wa sallam bersabda kepadaku: \"Apabila engkau bersumpah dengan suatu sumpah kemudian melihat yang lainnya lebih baik, maka hendaknya engkau melakukan sesuatu yang lebih baik dan bayarlah kafarah sumpahmu.\""},"3620":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا ابْنُ عَوْنٍ عَنْ الْحَسَنِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ سَمُرَةَ قَالَقَالَ يَعْنِي رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا حَلَفْتَ عَلَى يَمِينٍ فَرَأَيْتَ غَيْرَهَا خَيْرًا مِنْهَا فَأْتِ الَّذِي هُوَ خَيْرٌ مِنْهَا وَكَفِّرْ عَنْ يَمِينِكَ","id":"Telah mengabarkan kepada kami ['Amru bin Ali] berkata; telah menceritakan kepada kami [Yahya] berkata; telah menceritakan kepada kami [Ibnu 'Aun] dari [Al Hasan] dari ['Abdurrahman bin Samurah] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila engkau bersumpah dengan suatu sumpah kemudian melihat yang lainnya lebih baik, maka hendaknya engkau melakukan sesuatu yang lebih baik dan bayarlah kafarah sumpahmu.\""},"3621":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ قُدَامَةَ فِي حَدِيثِهِ عَنْ جَرِيرٍ عَنْ مَنْصُورٍ عَنْ الْحَسَنِ الْبَصْرِيِّ قَالَ عَبْدُ الرَّحْمَنِ بْنُ سَمُرَةَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا حَلَفْتَ عَلَى يَمِينٍ فَرَأَيْتَ غَيْرَهَا خَيْرًا مِنْهَا فَأْتِ الَّذِي هُوَ خَيْرٌ وَكَفِّرْ عَنْ يَمِينِكَ","id":"Telah mengabarkan kepada kami [Muhammad bin Qudamah] dalam haditsnya, dari [Jarir] dari [Manshur] dari [Al Hasan Al Bashri], ['Abdurrahman bin Samurah] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku: \"Apabila engkau bersumpah dengan suatu sumpah kemudian melihat yang lainnya lebih baik darinya, maka hendaknya engkau melakukan sesuatu yang lebih baik dan membatalkan sumpahmu.\""},"3622":{"ar":"أَخْبَرَنَا إِبْرَاهِيمُ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ بْنِ الْأَخْنَسِ قَالَ أَخْبَرَنِي عَمْرُو بْنُ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا نَذْرَ وَلَا يَمِينَ فِيمَا لَا تَمْلِكُ وَلَا فِي مَعْصِيَةٍ وَلَا قَطِيعَةِ رَحِمٍ","id":"Telah mengabarkan kepada kami [Ibrahim bin Muhammad] berkata; telah menceritakan kepada kami [Yahya] dari ['Ubaidullah bin Al Akhnas] berkata; telah mengabarkan kepadaku ['Amru bin Syu'aib] dari [ayahnya] dari [kakeknya] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada nadzar dan tidak ada sumpah dalam perkara yang tidak engkau miliki, tidak dalam kemaksiatan dan tidak dalam memutuskan hubungan kekerabatan.\""},"3623":{"ar":"أَخْبَرَنِي أَحْمَدُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا حَبَّانُ قَالَ حَدَّثَنَا عَبْدُ الْوَارِثِ قَالَ حَدَّثَنَا أَيُّوبُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ حَلَفَ فَاسْتَثْنَى فَإِنْ شَاءَ مَضَى وَإِنْ شَاءَ تَرَكَ غَيْرَ حَنِثٍ","id":"Telah mengabarkan kepada kami [Ahmad bin Sa'id] berkata; telah menceritakan kepada kami [Habban] berkata; telah menceritakan kepada kami [Abdul Warits] berkata; telah menceritakan kepada kami [Ayyub] dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alahi wa sallam, beliau bersabda: \"Barangsiapa bersumpah kemudian mengecualikan, apabila ia menghendaki maka ia teruskan dan apabila menghendaki maka ia meninggalkannya tanpa ada dosa.\""},"3624":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا سُلَيْمَانُ بْنُ حَيَّانَ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ بْنِ وَقَّاصٍ عَنْ عُمَرَ بْنِ الْخَطَّابِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّمَا الْأَعْمَالُ بِالنِّيَّةِ وَإِنَّمَا لِامْرِئٍ مَا نَوَى فَمَنْ كَانَتْ هِجْرَتُهُ إِلَى اللَّهِ وَرَسُولِهِ فَهِجْرَتُهُ إِلَى اللَّهِ وَرَسُولِهِ وَمَنْ كَانَتْ هِجْرَتُهُ لِدُنْيَا يُصِيبُهَا أَوْ امْرَأَةٍ يَتَزَوَّجُهَا فَهِجْرَتُهُ إِلَى مَا هَاجَرَ إِلَيْهِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] berkata; telah memberitakan kepada kami [Sulaiman bin Hayyan] berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dari [Muhammad bin Ibrahim] dari ['Alqamah bin Waqqash] dari [Umar bin Al Khathab] dari Nabi shallallahu 'alahi wa sallam, beliau bersabda: \"Hanyasanya amalan itu tergantung pada niatnya, dan setiap orang akan mendapatkan sebagaimana yang ia niatkan. Barangsiapa hijrahnya kepada Allah dan rasul-Nya maka hijrahnya kepada Allah dan rasul-Nya, dan barangsiapa hijrahnya untuk dunia atau wanita yang akan dinikahinya maka hijrahnya kepada apa yang hijrah kepadanya.\""},"3625":{"ar":"أَخْبَرَنَا الْحَسَنُ بْنُ مُحَمَّدٍ الزَّعْفَرَانِيُّ قَالَ حَدَّثَنَا حَجَّاجٌ عَنْ ابْنِ جُرَيْجٍ قَالَ زَعَمَ عَطَاءٌ أَنَّهُ سَمِعَ عُبَيْدَ بْنَ عُمَيْرٍ يَقُولُسَمِعْتُ عَائِشَةَ تَزْعُمُ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَمْكُثُ عِنْدَ زَيْنَبَ بِنْتِ جَحْشٍ فَيَشْرَبُ عِنْدَهَا عَسَلًا فَتَوَاصَيْتُ أَنَا وَحَفْصَةُ أَنَّ أَيَّتُنَا دَخَلَ عَلَيْهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلْتَقُلْ إِنِّي أَجِدُ مِنْكَ رِيحَ مَغَافِيرَ أَكَلْتَ مَغَافِيرَ فَدَخَلَ عَلَى إِحْدَاهُمَا فَقَالَتْ ذَلِكَ لَهُ فَقَالَ لَا بَلْ شَرِبْتُ عَسَلًا عِنْدَ زَيْنَبَ بِنْتِ جَحْشٍ وَلَنْ أَعُودَ لَهُ فَنَزَلَتْ{ يَا أَيُّهَا النَّبِيُّ لِمَ تُحَرِّمُ مَا أَحَلَّ اللَّهُ لَكَ إِلَى إِنْ تَتُوبَا إِلَى اللَّهِ }عَائِشَةُ وَحَفْصَةُ{ وَإِذْ أَسَرَّ النَّبِيُّ إِلَى بَعْضِ أَزْوَاجِهِ حَدِيثًا }لِقَوْلِهِ بَلْ شَرِبْتُ عَسَلًا","id":"Telah mengabarkan kepada kami [Al Hasan bin Muhammad Az Za'farani] berkata; telah menceritakan kepada kami [Hajjaj] dari [Ibnu Juraij] berkata; ['Atha] mengaku bahwa ia mendengar ['Ubaid bin 'Umair] berkata; aku mendengar [Aisyah] mengaku, bahwa Nabi shallallahu 'alahi wa sallam pernah tinggal di rumah Zainab binti Jahsy kemudian minum madu di rumahnya. Lalu aku dan Hafshah bersepakat bahwa siapapun di antara kami yang ditemui Nabi shallallahu 'alahi wa sallam maka hendaknya ia berkata, 'Sesungguhnya aku mencium bau Maghafir (sejenis tumbuhan), engkau telah makan Maghafir.' Kemudian beliau menemui salah seorang di antara mereka berdua sehingga salah seorang dari mereka mengatakan perkataan tersebut kepada beliau. Kemudian beliau bersabda: \"Tidak, melainkan aku minum madu di rumah Zainab binti Jahsy, dan aku tidak akan mengulanginya.\" Kemudian turunlah ayat: '(Hai Nabi kenapa engkau haramkan apa yang Allah halalkan kepadamu) hingga firman-Nya (Jika kamu berdua bertaubat kepada Allah…) ' (Qs. AT Tahriim: 1-4), yaitu Aisyah dan Hafshah, serta ayat: '(Dan ingatlah ketika Nabi membicarakan secara rahasia kepada salah seorang isterinya (Hafsah) suatu peristiwa…) ' (Qs. At Tahriim: 3), yaitu karena perkataan beliau: 'melainkan aku minum madu'.\""},"3626":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا الْمُثَنَّى بْنُ سَعِيدٍ قَالَ حَدَّثَنَا طَلْحَةُ بْنُ نَافِعٍ عَنْ جَابِرٍ قَالَدَخَلْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْتَهُ فَإِذَا فِلَقٌ وَخَلٌّ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلْ فَنِعْمَ الْإِدَامُ الْخَلُّ","id":"Telah mengabarkan kepada kami ['Amru bin Ali] berkata; telah menceritakan kepada kami [Yahya] berkata; telah menceritakan kepada kami [Al Mutsanna bin Sa'id] berkata; telah menceritakan kepada kami [Thalhah bin Nafi'] dari [Jabir] berkata, \"Aku bersama Nabi shallallahu 'alahi wa sallam memasuki rumahnya, dan ternyata di dalam ada sepotong roti dan cuka, kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Makanlah, lauk yang paling enak adalah cuka.\""},"3627":{"ar":"أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ الْمَلِكِ عَنْ أَبِي وَائِلٍ عَنْ قَيْسِ بْنِ أَبِي غَرَزَةَ قَالَكُنَّا نُسَمَّى السَّمَاسِرَةَ فَأَتَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ نَبِيعُ فَسَمَّانَا بِاسْمٍ هُوَ خَيْرٌ مِنْ اسْمِنَا فَقَالَ يَا مَعْشَرَ التُّجَّارِ إِنَّ هَذَا الْبَيْعَ يَحْضُرُهُ الْحَلِفُ وَالْكَذِبُ فَشُوبُوا بَيْعَكُمْ بِالصَّدَقَةِ","id":"Telah mengabarkan kepada kami [Abdullah bin Muhammad bin 'Abdurrahman] berkata; telah menceritakan kepada kami [Sufyan] dari [Abdul Malik] dari [Abu Wail] dari [Qais bin Abu Gharazah] berkata, \"Kami dahulu dipanggil dengan sebutan samasirah (para calo), kemudian Rasulullah shallallahu 'alaihi wasallam datang kepada kami dan kami sedang berjualan, maka beliau pun menamakan kami dengan nama yang lebih baik daripada nama kami. Beliau bersabda: \"Wahai para pedagang, sesungguhnya perdagangan ini dihadiri oleh orang yang bersumpah dan pendusta maka campurlah perdagangan kalian dengan sedekah.\""},"3628":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ يَزِيدَ عَنْ سُفْيَانَ عَنْ عَبْدِ الْمَلِكِ وَعَاصِمٌ وَجَامِعٌ عَنْ أَبِي وَائِلٍ عَنْ قَيْسِ بْنِ أَبِي غَرَزَةَ قَالَكُنَّا نَبِيعُ بِالْبَقِيعِ فَأَتَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكُنَّا نُسَمَّى السَّمَاسِرَةَ فَقَالَ يَا مَعْشَرَ التُّجَّارِ فَسَمَّانَا بِاسْمٍ هُوَ خَيْرٌ مِنْ اسْمِنَا ثُمَّ قَالَ إِنَّ هَذَا الْبَيْعَ يَحْضُرُهُ الْحَلِفُ وَالْكَذِبُ فَشُوبُوهُ بِالصَّدَقَةِ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin Yazid] dari [Sufyan] dari [Abdul Malik] ['Ashim] dan [Jami'] dari [Abu Wail] dari [Qais bin Abu Gharazah] berkata, \"Kami berjual beli di Baqi', kemudian Rasulullah shallallahu 'alaihi wasallam mendatangi kami, kami dahulu dipanggil dengan sebutan para calo, kemudian beliau bersabda: \"Wahai para pedagang, \" kemudian beliau menamai kami dengan nama yang lebih baik daripada nama kami. Beliau bersabda: \"Sesungguhnya perdagangan ini dihadiri orang yang bersumpah dan pendusta, maka campurkanlah perdagangan tersebut dengan sedekah.\""},"3629":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ مُغِيرَةَ عَنْ أَبِي وَائِلٍ عَنْ قَيْسِ بْنِ أَبِي غَرَزَةَ قَالَأَتَانَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ فِي السُّوقِ فَقَالَ إِنَّ هَذِهِ السُّوقَ يُخَالِطُهَا اللَّغْوُ وَالْكَذِبُ فَشُوبُوهَا بِالصَّدَقَةِ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] berkata; telah menceritakan kepada kami [Syu'bah] dari [Mughirah] dari [Abu Wail] dari [Qais bin Abi Gharazah] berkata, \"Nabi shallallahu 'alahi wa sallam mendatangi kami saat kami sedang berada di pasar, kemudian beliau bersabda: \"Sesungguhnya pasar ini bercampur dengan perbuatan sia-sia dan kedustaan, maka campurlah dengan sedekah.\""},"3630":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ وَمُحَمَّدُ بْنُ قُدَامَةَ قَالَا حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ أَبِي وَائِلٍ عَنْ قَيْسِ بْنِ أَبِي غَرَزَةَ قَالَكُنَّا بِالْمَدِينَةِ نَبِيعُ الْأَوْسَاقَ وَنَبْتَاعُهَا وَكُنَّا نُسَمِّي أَنْفُسَنَا السَّمَاسِرَةَ وَيُسَمِّينَا النَّاسُ فَخَرَجَ إِلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ يَوْمٍ فَسَمَّانَا بِاسْمٍ هُوَ خَيْرٌ مِنْ الَّذِي سَمَّيْنَا أَنْفُسَنَا وَسَمَّانَا النَّاسُ فَقَالَ يَا مَعْشَرَ التُّجَّارِ إِنَّهُ يَشْهَدُ بَيْعَكُمْ الْحَلِفُ وَالْكَذِبُ فَشُوبُوهُ بِالصَّدَقَةِ","id":"Telah mengabarkan kepada kami [Ali bin Hujr] dan [Muhammad bin Qudamah] mereka berdua berkata; telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Abu Wail] dari [Qais bin Abu Gharazah] berkata, \"Kami pernah berada di Madinah menjual beberapa wasaq makanan dan membelinya. Dan kami menamai diri kami dengan sebutan para calo, demikian juga dengan orang-orang. Kemudian Rasulullah shallallahu 'alaihi wasallam keluar menemui kami pada suatu hari dan memberi kami dengan nama yang lebih baik daripada yang kami dan orang-orang memberi nama untuk diri kami. Setelah itu beliau bersabda: \"Wahai para pedagang, sesungguhnya jual beli kalian ini disaksikan oleh orang yang bersumpah dan pendusta, maka campurlah dengan sedekah.\""},"3631":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدٌ عَنْ شُعْبَةَ قَالَ أَخْبَرَنِي مَنْصُورٌ عَنْ عَبْدِ اللَّهِ بْنِ مُرَّةَ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ النَّذْرِ وَقَالَ إِنَّهُ لَا يَأْتِي بِخَيْرٍ إِنَّمَا يُسْتَخْرَجُ بِهِ مِنْ الْبَخِيلِ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] berkata; telah menceritakan kepada kami [Khalid] dari [Syu'bah] berkata; telah memberitakan kepada kami [Manshur] dari [Abdullah bin Murrah] dari [Abdullah bin Umar], bahwa Rasulullah shallallahu 'alaihi wasallam melarang dari nadzar, beliau bersabda: \"Sesungguhnya nadzar tidak membawa kebaikan, hanyasanya ia dikeluarkan dari orang yang bakhil.\""},"3632":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا أَبُو نُعَيْمٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ عَبْدِ اللَّهِ بْنِ مُرَّةَ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ النَّذْرِ وَقَالَ إِنَّهُ لَا يَرُدُّ شَيْئًا إِنَّمَا يُسْتَخْرَجُ بِهِ مِنْ الشَّحِيحِ","id":"Telah mengabarkan kepada kami ['Amru bin Manshur] berkata; telah menceritakan kepada kami [Abu Nu'aim] berkata; telah menceritakan kepada kami [Sufyan] dari [Manshur] dari [Abdullah bin Murrah] dari [Abdullah bin Umar] berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang dari nadzar, beliau bersabda: \"Sesungguhnya nadzar itu tidak mengembalikan sesuatupun, hanyasanya ia dikeluarkan dari orang yang kikir.\""},"3633":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ عَبْدِ اللَّهِ بْنِ مُرَّةَ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ النَّذْرُ لَا يُقَدِّمُ شَيْئًا وَلَا يُؤَخِّرُهُ إِنَّمَا هُوَ شَيْءٌ يُسْتَخْرَجُ بِهِ مِنْ الشَّحِيحِ","id":"Telah mengabarkan kepada kami ['Amru bin Ali] berkata; telah menceritakan kepada kami [Yahya] berkata; telah menceritakan kepada kami [Sufyan] dari [Manshur] dari [Abdullah bin Murrah] dari [Ibnu Umar] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Nadzar tidak dapat mendahulukan sesuatu atau mengakhirkannya, hanyasanya ia dikeluarkan dari orang yang kikir.\""},"3634":{"ar":"أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنَا أَبُو الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَأْتِي النَّذْرُ عَلَى ابْنِ آدَمَ شَيْئًا لَمْ أُقَدِّرْهُ عَلَيْهِ وَلَكِنَّهُ شَيْءٌ اسْتُخْرِجَ بِهِ مِنْ الْبَخِيلِ","id":"Telah mengabarkan kepada kami [Abdullah bin Muhammad bin 'Abdurrahman] berkata; telah menceritakan kepada kami [Sufyan] berkata; telah menceritakan kepada kami [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda (Allah berfirman): \"Nadzar sama sekali tidak bisa mendatangkan sesuatu yang tidak Aku takdirkan bagi anak Adam. dan nadzar hanyalah dikeluarkan dari orang bakhil.\""},"3635":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ عَنْ الْعَلَاءِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَنْذِرُوا فَإِنَّ النَّذْرَ لَا يُغْنِي مِنْ الْقَدَرِ شَيْئًا وَإِنَّمَا يُسْتَخْرَجُ بِهِ مِنْ الْبَخِيلِ","id":"Telah mengabarkan kepada kami [Qutaibah] berkata; telah menceritakan kepada kami [Abdul Aziz] dari [Al 'Ala] dari [ayahnya] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah bernadzar, sesungguhnya nadzar tidak mampu Manahan takdir sedikitpun, akan tetapi hal tersebut adalah sesuatu yang dikeluarkan dari orang yang bakhil.\""},"3636":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ طَلْحَةَ بْنِ عَبْدِ الْمَلِكِ عَنْ الْقَاسِمِ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ نَذَرَ أَنْ يُطِيعَ اللَّهَ فَلْيُطِعْهُ وَمَنْ نَذَرَ أَنْ يَعْصِيَ اللَّهَ فَلَا يَعْصِهِ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Thalhah bin Abdul Malik] dari [Al Qasim] dari [Aisyah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa bernadzar untuk mentaati Allah maka hendaknya ia mentaati-Nya, dan barangsiapa bernadzar untuk bermaksiat kepada Allah maka janganlah ia bermaksiat kepada-Nya.\""},"3637":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا مَالِكٌ قَالَ حَدَّثَنِي طَلْحَةُ بْنُ عَبْدِ الْمَلِكِ عَنْ الْقَاسِمِ عَنْ عَائِشَةَ قَالَتْسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ نَذَرَ أَنْ يُطِيعَ اللَّهَ فَلْيُطِعْهُ وَمَنْ نَذَرَ أَنْ يَعْصِيَ اللَّهَ فَلَا يَعْصِهِ","id":"Telah mengabarkan kepada kami ['Amru bin Ali] berkata; telah menceritakan kepada kami [Yahya] berkata; telah menceritakan kepada kami [Malik] berkata; telah menceritakan kepadaku [Thalhah bin Abdul Malik] dari [Al Qasim] dari [Aisyah] ia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa bernadzar untuk mentaati Allah maka hendaknya ia mentaati-Nya, dan barangsiapa bernadzar untuk bermaksiat kepada Allah maka janganlah ia bermaksiat kepada-Nya.\""},"3638":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْعَلَاءِ قَالَ حَدَّثَنَا ابْنُ إِدْرِيسَ عَنْ عُبَيْدِ اللَّهِ عَنْ طَلْحَةَ بْنِ عَبْدِ الْمَلِكِ عَنْ الْقَاسِمِ عَنْ عَائِشَةَ قَالَتْسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ نَذَرَ أَنْ يُطِيعَ اللَّهَ فَلْيُطِعْهُ وَمَنْ نَذَرَ أَنْ يَعْصِيَ اللَّهَ فَلَا يَعْصِهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Al 'Ala`] berkata; telah menceritakan kepada kami [Ibnu Idris] dari ['Ubaidullah] dari [Thalhah bin Abdul Malik] dari [Al Qasim] dari [Aisyah] berkata; aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \" Barangsiapa bernadzar untuk mentaati Allah maka hendaknya ia mentaatinya dan barangsiapa bernadzar untuk bermaksiat kepada Allah maka janganlah ia bermaksiat kepadanya.\""},"3639":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي جَمْرَةَ عَنْ زَهْدَمٍ قَالَ سَمِعْتُ عِمْرَانَ بْنَ حُصَيْنٍ يَذْكُرُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ خَيْرُكُمْ قَرْنِي ثُمَّ الَّذِينَ يَلُونَهُمْ ثُمَّ الَّذِينَ يَلُونَهُمْ ثُمَّ الَّذِينَ يَلُونَهُمْ فَلَا أَدْرِي أَذَكَرَ مَرَّتَيْنِ بَعْدَهُ أَوْ ثَلَاثًا ثُمَّ ذَكَرَ قَوْمًا يَخُونُونَ وَلَا يُؤْتَمَنُونَ وَيَشْهَدُونَ وَلَا يُسْتَشْهَدُونَ وَيُنْذِرُونَ وَلَا يُوفُونَ وَيَظْهَرُ فِيهِمْ السِّمَنُقَالَ أَبُو عَبْد الرَّحْمَنِ هَذَا نَصْرُ بْنُ عِمْرَانَ أَبُو جَمْرَةَ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la] berkata; telah menceritakan kepada kami [Khalid] berkata; telah menceritakan kepada kami [Syu'bah] dari [Abu Jamrah] dari [Zahdam] berkata; aku mendengar [Imran bin Hushain] menyebutkan, bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sebaik-baik kalian adalah generasiku, kemudian setelah mereka, kemudian setelah mereka, kemudian setelah mereka.\" Aku tidak mengerti apakah beliau menyebutkan dua kali setelah itu atau tiga kali. Kemudian beliau menyebutkan suatu kaum yang berkhianat dan tidak dapat dipercaya, mereka bersaksi padahal tidak diminta untuk bersaksi, bernadzar dan tidak menepatinya, dan terlihat pada mereka kegemukan.\" Abu 'Abdurrahman berkata, \"Ini adalah Nashr bin Imran Abu Hamzah.\""},"3640":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ عَنْ ابْنِ جُرَيْجٍ قَالَ حَدَّثَنِي سُلَيْمَانُ الْأَحْوَلُ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ قَالَمَرَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِرَجُلٍ يَقُودُ رَجُلًا فِي قَرَنٍ فَتَنَاوَلَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَطَعَهُ قَالَ إِنَّهُ نَذْرٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la] berkata; telah menceritakan kepada kami [Khalid] dari [Ibnu Juraij] berkata; telah menceritakan kepadaku [Sulaiman Al Ahwal] dari [Thawus] dari [Ibnu Abbas] berkata, \"Rasulullah shallallahu 'alaihi wasallam melewati seorang laki-laki yang menuntun seorang laki-laki yang lainnya dengan tali, kemudian Nabi shallallahu 'alaihi wasallam mengambil tali tersebut dan memotongnya. Orang tersebut lalu berkata, \"Sesungguhnya itu adalah nadzar.\""},"3641":{"ar":"أَخْبَرَنَا يُوسُفُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا حَجَّاجٌ عَنْ ابْنِ جُرَيْجٍ قَالَ أَخْبَرَنِي سُلَيْمَانُ الْأَحْوَلُ أَنَّ طَاوُسًا أَخْبَرَهُ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ بِرَجُلٍ وَهُوَ يَطُوفُ بِالْكَعْبَةِ يَقُودُهُ إِنْسَانٌ بِخِزَامَةٍ فِي أَنْفِهِ فَقَطَعَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَدِهِ ثُمَّ أَمَرَهُ أَنْ يَقُودَهُ بِيَدِهِقَالَ ابْنُ جُرَيْجٍ وَأَخْبَرَنِي سُلَيْمَانُ أَنَّ طَاوُسًا أَخْبَرَهُ عَنْ ابْنِ عَبَّاسٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ بِهِ وَهُوَ يَطُوفُ بِالْكَعْبَةِ وَإِنْسَانٌ قَدْ رَبَطَ يَدَهُ بِإِنْسَانٍ آخَرَ بِسَيْرٍ أَوْ خَيْطٍ أَوْ بِشَيْءٍ غَيْرِ ذَلِكَ فَقَطَعَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَدِهِ ثُمَّ قَالَ قُدْهُ بِيَدِكَ","id":"Telah mengabarkan kepada kami [Yusuf bin Sa'id] berkata; telah menceritakan kepada kami [Hajjaj] dari [Ibnu Juraij] berkata; telah mengabarkan kepadaku [Sulaiman Al Ahwal] bahwa [Thawus] telah mengabarkan kepadanya, dari [Ibnu Abbas] bahwa Nabi shallallahu 'alaihi wasallam melewati seorang laki-laki yang melakukan thawaf di Ka'bah dituntun oleh seseorang menggunakan tali pada hidungnya, lalu Nabi shallallahu 'alaihi wasallam memotong tali tersebut dengan tangannya, setelah itu beliau memerintahkan kepadanya agar menuntunnya dengan menggunakan tangan.\" [Ibnu Juraij] berkata, \"Dan telah mengabarkan kepadaku [Sulaiman] bahwa [Thawus] telah mengabarkan kepadanya dari [Ibnu Abbas], bahwa Nabi shallallahu 'alaihi wasallam melewatinya saat ia sedang thawaf di Ka'bah, sementara di situ juga terdapat seseorang yang mengikat tangannya dengan orang yang lain menggunakan tali kulit, atau benang, atau sesuatu yang lainnya. Kemudian Nabi shallallahu 'alaihi wasallam memotong tali tersebut menggunakan tangan lalu bersabda: \"Tuntunlah dia menggunakan tanganmu.\""},"3642":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنِي أَيُّوبُ قَالَ حَدَّثَنَا أَبُو قِلَابَةَ عَنْ عَمِّهِ عَنْ عِمْرَانَ بْنِ حُصَيْنٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا نَذْرَ فِي مَعْصِيَةِ اللَّهِ وَلَا فِيمَا لَا يَمْلِكُ ابْنُ آدَمَ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur] berkata; telah menceritakan kepada kami [Sufyan] berkata; telah menceritakan kepadaku [Ayyub] berkata; telah menceritakan kepada kami [Abu Qilabah] dari [pamannya] dari [Imran bin Hushain] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak boleh ada nadzar dalam bermaksiat kepada Allah dan dalam perkara yang tidak dimiliki anak Adam.\""},"3643":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا أَبُو الْمُغِيرَةِ قَالَ حَدَّثَنَا الْأَوْزَاعِيُّ قَالَ حَدَّثَنِي يَحْيَى عَنْ أَبِي قِلَابَةَ عَنْ ثَابِتِ بْنِ الضَّحَّاكِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَلَفَ بِمِلَّةٍ سِوَى مِلَّةِ الْإِسْلَامِ كَاذِبًا فَهُوَ كَمَا قَالَ وَمَنْ قَتَلَ نَفْسَهُ بِشَيْءٍ فِي الدُّنْيَا عُذِّبَ بِهِ يَوْمَ الْقِيَامَةِ وَلَيْسَ عَلَى رَجُلٍ نَذْرٌ فِيمَا لَا يَمْلِكُ","id":"Telah mengabarkan kepada kami [Ishaq bin Manshur] berkata; telah menceritakan kepada kami [Abu Al Mughirah] berkata; telah menceritakan kepada kami [Al Auza'i] berkata; telah menceritakan kepadaku [Yahya] dari [Abu Qilabah] dari [Tsabit bin Adl Dlahhak] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa bersumpah dengan agama selain Islam secara dusta, maka berlaku seperti apa yang ia katakan, dan barangsiapa membunuh dirinya dengan sesuatu di dunia maka akan diadzab dengannya pada Hari Kiamat, dan tidak ada nadzar atas seseorang dalam perkara yang tidak ia miliki.\""},"3644":{"ar":"أَخْبَرَنِي يُوسُفُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا حَجَّاجٌ عَنْ ابْنِ جُرَيْجٍ قَالَ حَدَّثَنِي سَعِيدُ بْنُ أَبِي أَيُّوبَ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ أَخْبَرَهُ أَنَّ أَبَا الْخَيْرِ حَدَّثَهُ عَنْ عُقْبَةَ بْنِ عَامِرٍ قَالَنَذَرَتْ أُخْتِي أَنْ تَمْشِيَ إِلَى بَيْتِ اللَّهِ فَأَمَرَتْنِي أَنْ أَسْتَفْتِيَ لَهَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاسْتَفْتَيْتُ لَهَا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لِتَمْشِ وَلْتَرْكَبْ","id":"Telah mengabarkan kepada kami [Yusuf bin Sa'id] berkata; telah menceritakan kepada kami [Hajjaj] dari [Ibnu Juraij] berkata; telah menceritakan kepadaku [Sa'id bin Abu Ayyub] dari [Yazid bin Abu Habib] ia telah mengabarkan kepadanya, bahwa [Abu Al Khair] menceritakan kepadanya dari ['Uqbah bin 'Amir] ia berkata, \"Saudara perempuanku bernadzar untuk berjalan menuju Ka'bah dan memerintahkan aku agar memintakan fatwa kepada Rasulullah shallallahu 'alaihi wasallam, kemudian aku memintakan fatwa kepada Nabi shallallahu 'alaihi wasallam, beliau pun bersabda: \"Hendaknya ia berjalan dan berkendaraan.\""},"3645":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ وَمُحَمَّدُ بْنُ الْمُثَنَّى قَالَا حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عُبَيْدِ اللَّهِ بْنِ زَحْرٍ وَقَالَ عَمْرٌو إِنَّ عُبَيْدَ اللَّهِ بْنَ زَحْرٍ أَخْبَرَهُ عَنْ عَبْدِ اللَّهِ بْنِ مَالِكٍ أَنَّ عُقْبَةَ بْنَ عَامِرٍ أَخْبَرَهُأَنَّهُ سَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ أُخْتٍ لَهُ نَذَرَتْ أَنْ تَمْشِيَ حَافِيَةً غَيْرَ مُخْتَمِرَةٍ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُرْهَا فَلْتَخْتَمِرْ وَلْتَرْكَبْ وَلْتَصُمْ ثَلَاثَةَ أَيَّامٍ","id":"Telah mengabarkan kepada kami ['Amru bin Ali] dan [Muhammad bin Al Mutsanna] keduanya berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dari [Yahya bin Sa'id] dari ['Ubaidullah bin Zahr], dan ['Amru] berkata; bahwa ['Ubaidullah bin Zahr] telah mengabarkan kepadanya dari [Abdullah bin Malik] bahwa ['Uqbah bin 'Amir] telah mengabarkan kepadanya, bahwa ia bertanya kepada Nabi shallallahu 'alaihi wasallam mengenai saudara perempuannya yang bernadzar untuk berjalan kaki tanpa menggunakan khimar (kerudung). Nabi shallallahu 'alaihi wasallam lalu bersabda kepadanya: \"Perintahkan kepadanya agar ia menggunakan khimar, naik kendaraan dan berpuasa tiga hari.\""},"3646":{"ar":"أَخْبَرَنَا بِشْرُ بْنُ خَالِدٍ الْعَسْكَرِيُّ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ عَنْ شُعْبَةَ قَالَ سَمِعْتُ سُلَيْمَانَ يُحَدِّثُ عَنْ مُسْلِمٍ الْبَطِينِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَرَكِبَتْ امْرَأَةٌ الْبَحْرَ فَنَذَرَتْ أَنْ تَصُومَ شَهْرًا فَمَاتَتْ قَبْلَ أَنْ تَصُومَ فَأَتَتْ أُخْتُهَا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَذَكَرَتْ ذَلِكَ لَهُ فَأَمَرَهَا أَنْ تَصُومَ عَنْهَا","id":"Telah mengabarkan kepada kami [Bisyr bin Khalid Al 'Askari] berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] dari [Syu'bah] berkata; aku mendengar [Sulaiman] menceritakan dari [Muslim Al Bathin] dari [Sa'id bin Jubair] dari [Ibnu Abbas] ia berkata, \"Seorang wanita mengarungi lautan dan bernadzar untuk berpuasa satu bulan, kemudian ia meninggal sebelum berpuasa. Lalu suadara perempuannya datang kepada Nabi shallallahu 'alaihi wasallam dan menceritakan hal tersebut kepadanya. Kemudian beliau memerintahkan kepadanya agar berpuasa untuk saudara perempuannya.\""},"3647":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ وَاللَّفْظُ لَهُ عَنْ سُفْيَانَ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍأَنَّ سَعْدَ بْنَ عُبَادَةَ اسْتَفْتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي نَذْرٍ كَانَ عَلَى أُمِّهِ تُوُفِّيَتْ قَبْلَ أَنْ تَقْضِيَهُ فَقَالَ اقْضِهِ عَنْهَا","id":"Telah mengabarkan kepada kami [Ali bin Hujr] dan [Al Harits bin Miskin] dengan membacakan riwayat dan aku mendengar, lafazhnya adalah lafazh Al Harits, dari [Sufyan] dari [Az Zuhri] dari ['Ubaidullah bin Abdullah] dari [Ibnu Abbas], bahwa Sa'd bin Ubadah meminta fatwa kepada Rasulullah shallallahu 'alaihi wasallam mengenai nadzar yang menjadi kewajiban atas ibunya yang telah meninggal sebelum menunaikannya. Maka beliau bersabda: \"Tunaikanlahj nadzar tersebut untuknya.\""},"3648":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ قَالَاسْتَفْتَى سَعْدُ بْنُ عُبَادَةَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي نَذْرٍ كَانَ عَلَى أُمِّهِ فَتُوُفِّيَتْ قَبْلَ أَنْ تَقْضِيَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْضِهِ عَنْهَا","id":"Telah mengabarkan kepada kami [Qutaibah] berkata; telah menceritakan kepada kami [Al Laits] dari [Ibnu Syihab] dari ['Ubaidullah bin Abdullah] dari [Ibnu Abbas] berkata, \"Sa'd bin 'Ubadah meminta fatwa kepada Rasulullah shallallahu 'alaihi wasallam mengenai nadzar yang menjadi kewajiban atas ibunya yang telah meninggal sebelum menunaikannya. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tunaikanlah nadzar tersebut untuknya.\""},"3649":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ آدَمَ وَهَارُونُ بْنُ إِسْحَقَ الْهَمْدَانِيُّ عَنْ عَبْدَةَ عَنْ هِشَامٍ وَهُوَ ابْنُ عُرْوَةَ عَنْ بَكْرِ بْنِ وَائِلٍ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ قَالَجَاءَ سَعْدُ بْنُ عُبَادَةَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ أُمِّي مَاتَتْ وَعَلَيْهَا نَذْرٌ فَلَمْ تَقْضِهِ قَالَ اقْضِهِ عَنْهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Adam] dan [Harun bin Ishaq Al Hamdani] dari ['Abdah] dari [Hisyam] -yaitu Ibnu 'Urwah- dari [Bakr bin Wail] dari [Az Zuhri] dari ['Ubaidullah bin Abdullah] dari [Ibnu Abbas] berkata, \"Sa'd bin 'Ubadah datang kepada Nabi shallallahu 'alaihi wasallam kemudian berkata, \"Sesungguhnya ibuku telah meninggal dan ia memiliki kewajiban nadzar yang belum sempat ia kerjakan. Maka beliau bersabda mengenai nadzar yang menjadi kewajiban ibunya dan belum sempat dikerjakan hingga meninggal, beliau katakan: \"Tunaikanlah nadzar tersebut untuknya.\""},"3650":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ مُوسَى قَالَ حَدَّثَنَا سُفْيَانُ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ عُمَرَأَنَّهُ كَانَ عَلَيْهِ لَيْلَةٌ نَذَرَ فِي الْجَاهِلِيَّةِ يَعْتَكِفُهَا فَسَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَهُ أَنْ يَعْتَكِفَ","id":"Telah mengabarkan kepada kami [Ishaq bin Musa] berkata; telah menceritakan kepada kami [Sufyan] dari [Ayyub] dari [Nafi'] dari [Ibnu Umar] dari [Umar], bahwa ia memiliki kewajiban nadzar untuk beri'tikaf satu malam pada masa jahiliyah, ketika ia bertanya kepada Rasulullah shallallahu 'alaihi wasallam, maka beliau pun memerintahkan kepadanya untuk beri'tikaf.\""},"3651":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ يَزِيدَ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَكَانَ عَلَى عُمَرَ نَذْرٌ فِي اعْتِكَافِ لَيْلَةٍ فِي الْمَسْجِدِ الْحَرَامِ فَسَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَلِكَ فَأَمَرَهُ أَنْ يَعْتَكِفَ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin Yazid] berkata; telah menceritakan kepada kami [Sufyan] dari [Ayyub] dari [Nafi'] dari [Ibnu Umar] berkata, \"Pernah Umar memiliki kewajiban nadzar untuk beri'tikaf satu malam di Masjid Al Haram, kemudian ia menanyakan hal itu kepada Rasulullah shallallahu 'alaihi wasallam, maka beliau memerintahkan kepadanya agar beri'tikaf.\""},"3652":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ بْنِ الْحَكَمِ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ عُبَيْدَ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ عُمَرَ كَانَ جَعَلَ عَلَيْهِ يَوْمًا يَعْتَكِفُهُ فِي الْجَاهِلِيَّةِ فَسَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَلِكَ فَأَمَرَهُ أَنْ يَعْتَكِفَهُ","id":"Telah mengabarkan kepada kami [Ahmad bin Abdullah bin Al Hakam] berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] berkata; telah menceritakan kepada kami [Syu'bah] berkata; aku mendengar ['Ubaidullah] dari [Nafi'] dari [Ibnu Umar], bahwa Umar pernah mewajibkan atas dirinya satu hari untuk beri'tikaf pada masa jahiliyah, kemudian ia bertanya kepada Rasulullah shallallahu 'alaihi wasallam mengenai hal tersebut. Maka beliau memerintahkan kepadanya agar beri'tikaf.\""},"3653":{"ar":"حَدَّثَنَا يُونُسُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ كَعْبِ بْنِ مَالِكٍ عَنْ أَبِيهِأَنَّهُ قَالَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ تِيبَ عَلَيْهِ يَا رَسُولَ اللَّهِ إِنِّي أَنْخَلِعُ مِنْ مَالِي صَدَقَةً إِلَى اللَّهِ وَرَسُولِهِ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمْسِكْ عَلَيْكَ بَعْضَ مَالِكَ فَهُوَ خَيْرٌ لَكَقَالَ أَبُو عَبْد الرَّحْمَنِ يُشْبِهُ أَنْ يَكُونَ الزُّهْرِيُّ سَمِعَ هَذَا الْحَدِيثَ مِنْ عَبْدِ اللَّهِ بْنِ كَعْبٍ وَمِنْ عَبْدِ الرَّحْمَنِ عَنْهُ فِي هَذَا الْحَدِيثِ الطَّوِيلِ تَوْبَةُ كَعْبٍ","id":"Telah mengabarkan kepada kami [Yunus bin Abdul A'la] berkata; telah menceritakan kepada kami [Ibnu Wahb] berkata; telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] berkata; telah mengabarkan kepadaku [Abdullah bin Ka'b] dari [ayahnya], bahwa ia berkata kepada Rasulullah shallallahu 'alaihi wasallam ketika ia mendapatkan taubat, \"Wahai Rasulullah, sesungguhnya aku memberikan hartaku sebagai sedekah kepada Allah dan Rasul-Nya. Maka Rasulullah shallallahu 'alaihi wasallam bersabda kepadanya: \"Tahanlah sebagian hartamu, hal itu lebih baik bagimu.\" Abu 'Abdurrahman berkata, \"Sepertinya Az Zuhri mendengar hadits ini dari Abdullah bin Ka'b dan dari 'Abdurrahman, dalam hadits yang panjang ini terdapat taubat Ka'b.\""},"3654":{"ar":"أَخْبَرَنَا سُلَيْمَانُ بْنُ دَاوُدَ قَالَ أَنْبَأَنَا ابْنُ وَهْبٍ عَنْ يُونُسَ قَالَ قَالَ ابْنُ شِهَابٍ فَأَخْبَرَنِي عَبْدُ الرَّحْمَنِ بْنُ كَعْبِ بْنِ مَالِكٍ أ��نَّ عَبْدَ اللَّهِ بْنَ كَعْبٍ قَالَ سَمِعْتُ كَعْبَ بْنَ مَالِكٍيُحَدِّثُ حَدِيثَهُ حِينَ تَخَلَّفَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزْوَةِ تَبُوكَ قَالَ فَلَمَّا جَلَسْتُ بَيْنَ يَدَيْهِ قُلْتُ يَا رَسُولَ اللَّهِ إِنَّ مِنْ تَوْبَتِي أَنْ أَنْخَلِعَ مِنْ مَالِي صَدَقَةً إِلَى اللَّهِ وَإِلَى رَسُولِهِ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمْسِكْ عَلَيْكَ بَعْضَ مَالِكَ فَهُوَ خَيْرٌ لَكَ فَقُلْتُ فَإِنِّي أُمْسِكُ سَهْمِي الَّذِي بِخَيْبَرَ مُخْتَصَرٌ","id":"Telah mengabarkan kepada kami [Sulaiman bin Daud] berkata; telah memberitakan kepada kami [Ibnu Wahb] dari [Yunus] berkata; [Ibnu Syihab] berkata; telah mengabarkan kepadaku ['Abdurrahman bin Ka'b bin Malik] bahwa [Abdullah bin Ka'b] berkata; aku mendengar [Ka'b bin Malik] menceritakan peristiwanya ketika tertinggal dari Rasulullah shallallahu 'alaihi wasallam dalam perang Tabuk. Ia berkata, \"Tatkala aku duduk di hadapannya, aku katakan, \"Wahai Rasulullah, sesungguhnya taubatku adalah melepaskan diri dari hartaku sebagai sedekah kepada Allah dan Rasul-Nya.\" Rasulullah shallallahu 'alaihi wasallam lalu bersabda: \"Tahanlah sebagian hartamu, hal tersebut lebih baik bagimu.\" Kemudian aku katakan, \"Sesungguhnya aku menahan sahamku yang ada di Khaibar.\""},"3655":{"ar":"أَخْبَرَنَا يُوسُفُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا حَجَّاجُ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا لَيْثُ بْنُ سَعْدٍ قَالَ حَدَّثَنِي عُقَيْلٌ عَنْ ابْنِ شِهَابٍ قَالَ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ بْنِ كَعْبٍ أَنَّ عَبْدَ اللَّهِ بْنَ كَعْبِ بْنِ مَالِكٍ قَالَ سَمِعْتُ كَعْبَ بْنَ مَالِكٍيُحَدِّثُ حَدِيثَهُ حِينَ تَخَلَّفَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزْوَةِ تَبُوكَ قُلْتُ يَا رَسُولَ اللَّهِ إِنَّ مِنْ تَوْبَتِي أَنْ أَنْخَلِعَ مِنْ مَالِي صَدَقَةً إِلَى اللَّهِ وَإِلَى رَسُولِهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمْسِكْ عَلَيْكَ مَالَكَ فَهُوَ خَيْرٌ لَكَ قُلْتُ فَإِنِّي أُمْسِكُ عَلَيَّ سَهْمِي الَّذِي بِخَيْبَرَ","id":"Telah mengabarkan kepada kami [Yusuf bin Sa'id] berkata; telah menceritakan kepada kami [Hajjaj bin Muhammad] berkata; telah menceritakan kepada kami [Laits bin Sa'd] berkata; telah menceritakan kepadaku ['Uqail] dari [Ibnu Syihab] berkata; telah menceritakan kepadaku ['Abdurrahman bin Abdullah bin Ka'b] bahwa [Abdullah bin Ka'b bin Malik] berkata, \"Aku mendengar [Ka'b bin Malik] menceritakan peristiwanya ketika tertinggal dari Rasulullah shallallahu 'alaihi wasallam dalam perang Tabuk. Aku berkata, \"Aku katakan, \"Wahai Rasulullah, sesungguhnya taubatku adalah melepaskan diri dari hartaku sebagai sedekah kepada Allah dan Rasul-Nya.\" Rasulullah shallallahu 'alaihi wasallam lalu bersabda: \"Tahanlah sebagian hartamu, hal tersebut lebih baik bagimu.\" Kemudian aku katakan, \"Sesungguhnya aku menahan sahamku yang ada di Khaibar.\""},"3656":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَعْدَانَ بْنِ عِيسَى قَالَ حَدَّثَنَا الْحَسَنُ بْنُ أَعْيَنَ قَالَ حَدَّثَنَا مَعْقِلٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ بْنِ كَعْبٍ عَنْ عَمِّهِ عُبَيْدِ اللَّهِ بْنِ كَعْبٍ قَالَ سَمِعْتُ أَبِي كَعْبَ بْنَ مَالِكٍ يُحَدِّثُ قَالَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّ اللَّهَ عَزَّ وَجَلَّ إِنَّمَا نَجَّانِي بِالصِّدْقِ وَإِنَّ مِنْ تَوْبَتِي أَنْ أَنْخَلِعَ مِنْ مَالِي صَدَقَةً إِلَى اللَّهِ وَإِلَى رَسُولِهِ فَقَالَ أَمْسِكْ عَلَيْكَ بَعْضَ مَالِكَ فَهُوَ خَيْرٌ لَكَ قُلْتُ فَإِنِّي أُمْسِكُ سَهْمِي الَّذِي بِخَيْبَرَ","id":"Telah mengabarkan kepada kami [Muhammad bin Ma'dan bin Isa] berkata; telah menceritakan kepada kami [Al Hasan bin A'yan] berkata; telah menceritakan kepada kami [Ma'qil] dari [Az Zuhri] berkata; telah mengabarkan kepadaku ['Abdurrahman bin Abdullah bin Ka'b] dari pamannya ['Ubaidullah bin Ka'b] berkata, Saya telah mendengar [bapakku, Ka'b bin Malik] menceritakan, dia berkata; \"Sesungguhnya Allah 'azza wajalla menyelamatkan aku karena bersedekah, dan di antara taubatku adalah melepaskan diri dari hartaku sebagai sedekah kepada Allah dan Rasul-Nya. Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tahanlah sebagian hartamu, hal tersebut lebih baik bagimu.\" Kemudian aku katakan, \"Sesungguhnya aku menahan sahamku yang ada di Khaibar.\""},"3657":{"ar":"قَالَ الْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ ابْنِ الْقَاسِمِ قَالَ حَدَّثَنِي مَالِكٌ عَنْ ثَوْرِ بْنِ زَيْدٍ عَنْ أَبِي الْغَيْثِ مَوْلَى ابْنِ مُطِيعٍ عَنْ أَبِي هُرَيْرَةَ قَالَكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَامَ خَيْبَرَ فَلَمْ نَغْنَمْ إِلَّا الْأَمْوَالَ وَالْمَتَاعَ وَالثِّيَابَ فَأَهْدَى رَجُلٌ مِنْ بَنِي الضُّبَيْبِ يُقَالُ لَهُ رِفَاعَةُ بْنُ زَيْدٍ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غُلَامًا أَسْوَدَ يُقَالُ لَهُ مِدْعَمٌ فَوُجِّهَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى وَادِي الْقُرَى حَتَّى إِذَا كُنَّا بِوَادِي الْقُرَى بَيْنَا مِدْعَمٌ يَحُطُّ رَحْلَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَاءَهُ سَهْمٌ فَأَصَابَهُ فَقَتَلَهُ فَقَالَ النَّاسُ هَنِيئًا لَكَ الْجَنَّةُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَلَّا وَالَّذِي نَفْسِي بِيَدِهِ إِنَّ الشَّمْلَةَ الَّتِي أَخَذَهَا يَوْمَ خَيْبَرَ مِنْ الْمَغَانِمِ لَتَشْتَعِلُ عَلَيْهِ نَارًا فَلَمَّا سَمِعَ النَّاسُ بِذَلِكَ جَاءَ رَجُلٌ بِشِرَاكٍ أَوْ بِشِرَاكَيْنِ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شِرَاكٌ أَوْ شِرَاكَانِ مِنْ نَارٍ","id":"Telah mengabarkan kepada kami [Al Harits bin Miskin] dengan membaca riwayat dan aku mendengar, dari [Ibnu Al Qasim] berkata; telah menceritakan kepadaku [Malik] dari [Tsaur bin Zaid] dari [Abu Al Ghaits] mantan budak Ibnu Muthi', dari [Abu Hurairah] ia berkata, \"Kami bersama Rasulullah shallallahu 'alaihi wasallam ketika perang Khaibar, dan kami tidak mendapatkan harta rampasan kecuali harta benda, barang-barang, dan pakaian. Kemudian seorang laki-laki dari Bani Adl Dlubaib yang dipanggil Rifa'ah bin Zaid memberikan hadiah kepada Rasulullah shallallahu 'alaihi wasallam berupa budak berkulit hitam yang dipanggil Mid'am. Rasulullah shallallahu 'alaihi wasallam lalu menuju ke lembah Al Qura hingga ketika kami sampai di lembah Al Qura, tatkala Mid'am menurunkan kendaraan Rasulullah shallallahu 'alaihi wasallam, tiba-tiba meluncurlah panah hingga mengenai dan membunuhnya, orang-orang pun berkata, \"Selamat, bagimu Surga.\" Rasulullah shallallahu 'alaihi wasallam lalu bersabda: \"Sekali-kali tidak! Demi jiwaku yang berada ditangan-Nya, sesungguhnya pakaian yang ia ambil ketika perang Khaibar akan menyala dengan api.\" Ketika orang-orang mendengar hal itu, seorang laki-laki datang kepada Rasulullah shallallahu 'alaihi wasallam dengan membawa satu atau dua pasang sandal, lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Satu atau dua sandal dari neraka.\""},"3658":{"ar":"أَخْبَرَنَا يُونُسُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ أَنَّ كَثِيرَ بْنَ فَرْقَدٍ حَدَّثَهُ أَنَّ نَافِعًا حَدَّثَهُمْ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَلَفَ فَقَالَ إِنْ شَاءَ اللَّهُ فَقَدْ اسْتَثْنَى","id":"Telah mengabarkan kepada kami [Yunus bin Abdul A'la] berkata; telah menceritakan kepada kami [Ibnu Wahb] berkata; telah mengabarkan kepadaku ['Amru bin Al Harits] bahwa [Katsir bin Farqad] menceritakan kepadanya, bahwa [Nafi'] menceritakan kepada mereka dari [Abdullah bin Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa bersumpah dan mengatakan, 'Insyaallah', maka ia telah mengucapkan pengecualian.\""},"3659":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَلَفَ فَقَالَ إِنْ شَاءَ اللَّهُ فَقَدْ اسْتَثْنَى","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur] berkata; telah menceritakan kepada kami [Sufyan] dari [Ayyub] dari [Nafi'] dari [Ibnu Umar] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa bersumpah dan mengatakan, 'Insyaallah', maka ia telah mengucapkan pengecualian.\""},"3660":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا عَفَّانُ قَالَ حَدَّثَنَا وُهَيْبٌ قَالَ حَدَّثَنَا أَيُّوبُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ حَلَفَ عَلَى يَمِينٍ فَقَالَ إِنْ شَاءَ اللَّهُ فَهُوَ بِالْخِيَارِ إِنْ شَاءَ أَمْضَى وَإِنْ شَاءَ تَرَكَ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] berkata; telah menceritakan kepada kami ['Affan] berkata; telah menceritakan kepada kami [Wuhaib] berkata; telah menceritakan kepada kami [Ayyub] dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa bersumpah dengan suatu sumpah dan berkata, 'insya Allah', maka ia memiliki pilihan; jika mau ia boleh meneruskannya, dan jika mau ia boleh meninggalkannya.\""},"3661":{"ar":"أَخْبَرَنَا عِمْرَانُ بْنُ بَكَّارٍ قَالَ حَدَّثَنَا عَلِيُّ بْنُ عَيَّاشٍ قَالَ أَنْبَأَنَا شُعَيْبٌ قَالَ حَدَّثَنِي أَبُو الزِّنَادِ مِمَّا حَدَّثَهُ عَبْدُ الرَّحْمَنِ الْأَعْرَجُ مِمَّا ذَكَرَ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يُحَدِّثُ بِهِعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قَالَ سُلَيْمَانُ بْنُ دَاوُدَ لَأَطُوفَنَّ اللَّيْلَةَ عَلَى تِسْعِينَ امْرَأَةً كُلُّهُنَّ يَأْتِي بِفَارِسٍ يُجَاهِدُ فِي سَبِيلِ اللَّهِ عَزَّ وَجَلَّ فَقَالَ لَهُ صَاحِبُهُ إِنْ شَاءَ اللَّهُ فَلَمْ يَقُلْ إِنْ شَاءَ اللَّهُ فَطَافَ عَلَيْهِنَّ جَمِيعًا فَلَمْ تَحْمِلْ مِنْهُنَّ إِلَّا امْرَأَةٌ وَاحِدَةٌ جَاءَتْ بِشِقِّ رَجُلٍ وَأَيْمُ الَّذِي نَفْسُ مُحَمَّدٍ بِيَدِهِ لَوْ قَالَ إِنْ شَاءَ اللَّهُ لَجَاهَدُوا فِي سَبِيلِ اللَّهِ فُرْسَانًا أَجْمَعِينَ","id":"Telah mengabarkan kepada kami ['Imran bin Bakkar] berkata; telah menceritakan kepada kami [Ali bin 'Ayyasy] berkata; telah memberitakan kepada kami [Syu'aib] berkata; telah menceritakan kepadaku [Abu Az Zinad] di antara apa yang diceritakan kepada ['Abdurrahman Al A'raj] di antara yang ia sebutkan adalah, bahwa ia mendengar [Abu Hurairah] menceritakan dengannya, dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Sulaiman bin Daud berkata, 'Sungguh, aku akan akan menggilir sembilan puluh isteri pada malam ini. Setiap mereka akan melahirkan seorang penunggang kuda yang akan berjihad di jalan Allah 'azza wajalla', salah seorang sahabatnya lalu berkata kepadanya, 'Insyaallah.' Namun Sulaiman tidak mengucapkan insya Allah. Setelah itu ia menggilir mereka semua, dan tidak ada seorang pun dari mereka yang hamil kecuali seorang wanita yang melahirkan anak setengah laki-laki. Demi Dzat yang jiwa Muhammad ada di tangan-Nya, seandainya ia mengucapkan 'insyaallah', niscaya mereka akan berjihad di jalan Allah sebagai penunggang kuda semuanya.\""},"3662":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ يَحْيَى بْنِ الْوَزِيرِ بْنِ سُلَيْمَانَ وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ ابْنِ وَهْبٍ قَالَ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ عَنْ كَعْبِ بْنِ عَلْقَمَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ شِمَاسَةَ عَنْ عُقْبَةَ بْنِ عَامِرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كَفَّارَةُ النَّذْرِ كَفَّارَةُ الْيَمِينِ","id":"Telah mengabarkan kepada kami [Ahmad bin Yahya bin Al Wazir bin Sulaiman] dan [Al Harits bin Miskin] dengan membacakan riwayat, dan aku mendengar dari [Ibnu Wahb] berkata; telah mengabarkan kepadaku ['Amru bin Al Harits] dari [Ka'b bin 'Alqamah] dari ['Abdurrahman bin Syimasah] dari ['Alqamah bin 'Amir], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kafarah nadzar adalah kafarah sumpah.\""},"3663":{"ar":"أَخْبَرَنَا كَثِيرُ بْنُ عُبَيْدٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ حَرْبٍ عَنْ الزُّبَيْدِيِّ عَنْ الزُّهْرِيِّ أَنَّهُ بَلَغَهُ عَنْ الْقَاسِمِ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا نَذْرَ فِي مَعْصِيَةٍ","id":"Telah mengabarkan kepada kami [Katsir bin 'Ubaid] berkata; telah menceritakan kepada kami [Muhammad bin Harb] dari [Az Zubaidi] dari [Az Zuhri] bahwa telah sampai kepadanya dari [Al Qasim] dari [Aisyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak boleh ada nadzar dalam kemaksiatan.\""},"3664":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ الْمُخَرِّمِيُّ قَالَ حَدَّثَنَا يَحْيَى بْنُ آدَمَ قَالَ حَدَّثَنَا ابْنُ الْمُبَارَكِ عَنْ يُونُسَ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا نَذْرَ فِي مَعْصِيَةٍ وَكَفَّارَتُهُ كَفَّارَةُ يَمِينٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin Al Mubarak Al Mukharrimi] berkata; telah menceritakan kepada kami [Yahya bin Adam] berkata; telah menceritakan kepada kami [Ibnu Al Mubarak] dari [Yunus] dari [Az Zuhri] dari [Abu Salamah] dari [Aisyah] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak boleh ada nadzar dalam kemaksiatan, dan kafarahnya adalah kafarah sumpah.\""},"3665":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ مَنْصُورٍ قَالَ أَنْبَأَنَا عُثْمَانُ بْنُ عُمَرَ قَالَ حَدَّثَنَا يُونُسُ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا نَذْرَ فِي مَعْصِيَةٍ وَكَفَّارَتُهُ كَفَّارَةُ يَمِينٍ","id":"Telah mengabarkan kepada kami [Ishaq bin Manshur] berkata; telah memberitakan kepada kami [Utsman bin Umar] berkata; telah menceritakan kepada kami [Yunus] dari [Az Zuhri] dari [Abu Salamah] dari [Aisyah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak boleh ada nadzar dalam kemaksiatan, dan kafarahnya adalah kafarah sumpah.\""},"3666":{"ar":"أَخْبَرَنَا هَارُونُ بْنُ مُوسَى الْفَرَوِيُّ قَالَ حَدَّثَنَا أَبُو ضَمْرَةَ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ قَالَ حَدَّثَنَا أَبُو سَلَمَةَ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا نَذْرَ فِي مَعْصِيَةٍ وَكَفَّارَتُهَا كَفَّارَةُ الْيَمِينِ","id":"Telah mengabarkan kepada kami [Harun bin Musa Al Farawi] berkata; telah menceritakan kepada kami [Abu Dlamrah] dari [Yunus] dari [Ibnu Syihab] berkata; telah menceritakan kepada kami [Abu Salamah] dari [Aisyah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak boleh ada nadzar dalam kemaksiatan, dan kafarahnya adalah kafarah sumpah.\""},"3667":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ التِّرْمِذِيُّ قَالَ حَدَّثَنَا أَيُّوبُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنِي أَبُو بَكْرِ بْنُ أَبِي أُوَيْسٍ قَالَ حَدَّثَنِي سُلَيْمَانُ بْنُ بِلَالٍ عَنْ مُحَمَّدِ بْنِ أَبِي عَتِيقٍ وَمُوسَى بْنِ عُقْبَةَ عَنْ ابْنِ شِهَابٍ عَنْ سُلَيْمَانَ بْنِ أَرْقَمَ أَنَّ يَحْيَى بْنَ أَبِي كَثِيرٍ الَّذِي كَانَ يَسْكُنُ الْيَمَامَةَ حَدَّثَهُ أَنَّهُ سَمِعَ أَبَا سَلَمَةَ يُخْبِرُ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا نَذْرَ فِي مَعْصِيَةٍ وَكَفَّارَتُهَا كَفَّارَةُ يَمِينٍقَالَ أَبُو عَبْد الرَّحْمَنِ سُلَيْمَانُ بْنُ أَرْقَمَ مَتْرُوكُ الْحَدِيثِ وَاللَّهُ أَعْلَمُ خَالَفَهُ غَيْرُ وَاحِدٍ مِنْ أَصْحَابِ يَحْيَى بْنِ أَبِي كَثِيرٍ فِي هَذَا الْحَدِيثِ","id":"Telah mengabarkan kepada kami [Muhammad bin Isma'il At Tirmidzi] berkata; telah menceritakan kepada kami [Ayyub bin Sulaiman] berkata; telah menceritakan kepadaku [Abu Bakr bin Abu Uwais] berkata; telah menceritakan kepadaku [Sulaiman bin Bilal] dari [Muhammad bin Abu 'Atiq], dan [Musa bin 'Uqbah] dari [Ibnu Syihab] dari [Sulaiman bin Arqam] bahwa [Yahya bin Abu Katsir] yang tinggal di Yamamah telah menceritakan kepadanya, bahwa ia mendengar [Abu Salamah] mengabarkan dari [Aisyah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak boleh ada nadzar dalam kemaksiatan, dan kafarahnya adalah kafarah sumpah.\" Abu 'Abdurrahman berkata, \"Sulaiman bin Arqam adalah orang yang ditinggalkan haditsnya. Wallahu A'lam. Dalam hadits ini, tidak hanya satu orang saja yang menyelisihinya di antara sahabat Yahya bin Katsir.\""},"3668":{"ar":"أَخْبَرَنَا هَنَّادُ بْنُ السَّرِيِّ عَنْ وَكِيعٍ عَنْ ابْنِ الْمُبَارَكِ وَهُوَ عَلِيٌّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ مُحَمَّدِ بْنِ الزُّبَيْرِ الْحَنْظَلِيِّ عَنْ أَبِيهِ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا نَذْرَ فِي مَعْصِيَةٍ وَكَفَّارَتُهُ كَفَّارَةُ يَمِينٍ","id":"Telah mengabarkan kepada kami [Hannad bin As Sari] dari [Waki'] dari [Ibnu Al Mubarak] -yaitu Ali- dari [Yahya bin Abu Katsir] dari [Muhammad bin Az Zubair Al Hanzhali] dari [ayahnya] dari [Imran bin Hushain] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak boleh ada nadzar dalam kemaksiatan, dan kafarahnya adalah kafarah sumpah.\""},"3669":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ مَيْمُونٍ قَالَ حَدَّثَنَا مَعْمَرُ بْنُ سُلَيْمَانَ عَنْ عَبْدِ اللَّهِ بْنِ بِشْرٍ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ مُحَمَّدٍ الْحَنْظَلِيِّ عَنْ أَبِيهِ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا نَذْرَ فِي غَضَبٍ وَكَفَّارَتُهُ كَفَّارَةُ الْيَمِينِقَالَ أَبُو عَبْد الرَّحْمَنِ مُحَمَّدُ بْنُ الزُّبَيْرِ ضَعِيفٌ لَا يَقُومُ بِمِثْلِهِ حُجَّةٌ وَقَدْ اخْتُلِفَ عَلَيْهِ فِي هَذَا الْحَدِيثِ","id":"Telah mengabarkan kepada kami [Ali bin Maimun] berkata; telah menceritakan kepada kami [Ma'mar bin Sulaiman] dari [Abdullah bin Bisyr] dari [Yahya bin Abu Katsir] dari [Muhammad Al Hanzhali] dari [ayahnya] dari [Imran bin Hushain] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak boleh ada nadzar dalam kemarahan, dan kafarahnya adalah kafarah sumpah.\" Abu 'Abdurrahman berkata, \"Muhammad bin Az Zubair adalah seorang yang lemah, haditsnya tidak bisa menjadi hujjah atas hadits lain yang semisal (kelemahannya), dan dalam hadits ini ia banyak diperselisihkan.\""},"3670":{"ar":"أَخْبَرَنِي إِبْرَاهِيمُ بْنُ يَعْقُوبَ قَالَ حَدَّثَنَا الْحَسَنُ بْنُ مُوسَى قَالَ حَدَّثَنَا شَيْبَانُ عَنْ يَحْيَى عَنْ مُحَمَّدِ بْنِ الزُّبَيْرِ عَنْ أَبِيهِ عَنْ عِمْرَانَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا نَذْرَ فِي غَضَبٍ وَكَفَّارَتُهُ كَفَّارَةُ الْيَمِينِ","id":"Telah mengabarkan kepada kami [Ibrahim bin Ya'qub] berkata; telah menceritakan kepada kami [Al Hasan bin Musa] berkata; telah menceritakan kepada kami [Syaiban] dari [Yahya] dari [Muhammad bin Az Zubair] dari [ayahnya] dari [Imran] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak boleh ada nadzar dalam kemarahan, dan kafarahnya adalah kafarah sumpah.\""},"3671":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ وَهْبٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ قَالَ حَدَّثَنِي ابْنُ إِسْحَقَ عَنْ مُحَمَّدِ بْنِ الزُّبَيْرِ عَنْ أَبِيهِ عَنْ رَجُلٍ مِنْ أَهْلِ الْبَصْرَةِ قَالَ صَحِبْتُ عِمْرَانَ بْنَ حُصَيْنٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ النَّذْرُ نَذْرَانِ فَمَا كَانَ مِنْ نَذْرٍ فِي طَاعَةِ اللَّهِ فَذَلِكَ لِلَّهِ وَفِيهِ الْوَفَاءُ وَمَا كَانَ مِنْ نَذْرٍ فِي مَعْصِيَةِ اللَّهِ فَذَلِكَ لِلشَّيْطَانِ وَلَا وَفَاءَ فِيهِ وَيُكَفِّرُهُ مَا يُكَفِّرُ الْيَمِينَ","id":"Telah mengabarkan kepada kami [Muhammad bin Wahb] berkata; telah menceritakan kepada kami [Muhammad bin Salamah] berkata; telah menceritakan kepadaku [Ibnu Ishaq] dari [Muhammad bin Az Zubair] dari [ayahnya] dari [seorang laki-laki] penduduk Bashrah, ia berkata; aku menemani [Imran bin Hushain] ia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Nadzar ada dua; nadzar dalam ketaatan kepada Allah, maka hal tersebut adalah untuk Allah dan harus ditunaikan, sedangkan nadzar dalam bermaksiat kepada Allah, maka hal tersebut adalah untuk setan dan tidak boleh ditunaikan, dan ia bisa dihapus oleh kafarah yang menghapus sumpah.\""},"3672":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا حَمَّادُ بْنُ مَسْعَدَةَ عَنْ حُمَيْدٍ عَنْ ثَابِتٍ عَنْ أَنَسٍ قَالَرَأَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلًا يُهَادَى بَيْنَ رَجُلَيْنِ فَقَالَ مَا هَذَا قَالُوا نَذَرَ أَنْ يَمْشِيَ إِلَى بَيْتِ اللَّهِ قَالَ إِنَّ اللَّهَ غَنِيٌّ عَنْ تَعْذِيبِ هَذَا نَفْسَهُ مُرْهُ فَلْيَرْكَبْ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] berkata; telah memberitakan kepada kami [Hammad bin Mas'adah] dari [Humaid] dari [Tsabit] dari [Anas] berkata, \"Nabi shallallahu 'alaihi wasallam melihat seorang laki-laki yang berjalan dengan diapit antara dua orang, kemudian beliau bertanya: \"Apa ini?\" mereka menjawab, \"Ia nadzar untuk berjalan menuju Ka'bah.\" Beliau bersabda: \"Sungguh, Allah tidak butuh kepada penyiksaan orang ini terhadap dirinya, perintahkan dia agar naik kendaraan.\""},"3673":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا حُمَيْدٌ عَنْ ثَابِتٍ عَنْ أَنَسٍ قَالَمَرَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِشَيْخٍ يُهَادَى بَيْنَ اثْنَيْنِ فَقَالَ مَا بَالُ هَذَا قَالُوا نَذَرَ أَنْ يَمْشِيَ قَالَ إِنَّ اللَّهَ غَنِيٌّ عَنْ تَعْذِيبِ هَذَا نَفْسَهُ مُرْهُ فَلْيَرْكَبْ فَأَمَرَهُ أَنْ يَرْكَبَ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] berkata; telah menceritakan kepada kami [Khalid] berkata; telah menceritakan kepada kami [Humaid] dari [Tsabit] dari [Anas] berkata, \"Rasulullah shallallahu 'alaihi wasallam melewati orang yang sudah tua berjalan di antara dua orang dengan cara diapit, kemudian beliau bersabda: \"Apa ini?\" Mereka menjawab, \"Ia bernadzar untuk berjalan menuju Ka'bah.\" Beliau pun bersabda: \"Sesungguhnya Allah tidak butuh kepada penyiksaan orang ini terhadap dirinya, perintahkan dia agar naik kendaraan.\" Beliau memerintahkan kepadanya agar naik kendaraan.\""},"3674":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ حَفْصٍ قَالَ حَدَّثَنِي أَبِي قَالَ حَدَّثَنِي إِبْرَاهِيمُ بْنُ طَهْمَانَ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ حُمَيْدٍ الطَّوِيلِ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَأَتَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى رَجُلٍ يُهَادَى بَيْنَ ابْنَيْهِ فَقَالَ مَا شَأْنُ هَذَا فَقِيلَ نَذَرَ أَنْ يَمْشِيَ إِلَى الْكَعْبَةِ فَقَالَ إِنَّ اللَّهَ لَا يَصْنَعُ بِتَعْذِيبِ هَذَا نَفْسَهُ شَيْئًا فَأَمَرَهُ أَنْ يَرْكَبَ","id":"Telah mengabarkan kepada kami [Ahmad bin Hafsh] berkata; telah menceritakan kepadaku [ayahku] berkata; telah menceritakan kepadaku [Ibrahim bin Thahman] dari [Yahya bin Sa'id] dari [Humaid Ath Thawil] dari [Anas bin Malik] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam datang kepada seorang laki-laki yang berjalan di antara dua orang anaknya dengan cara diapit, kemudian beliau bertanya: \"Ada apa orang ini?\" Maka dikatakan, \"Ia bernadzar untuk berjalan menuju Ka'bah.\" Kemudian beliau bersabda: \"Sesungguhnya Allah tidak berbuat sesuatupun dengan penyiksaan yang dilakukan orang ini terhadap dirinya.\" Kemudian beliau memerintahkan kepadanya agar naik kendaraan.\""},"3675":{"ar":"أَخْبَرَنَا نُوحُ بْنُ حَبِيبٍ قَالَ أَنْبَأَنَا عَبْدُ الرَّزَّاقِ قَالَ أَنْبَأَنَا مَعْمَرٌ عَنْ ابْنِ طَاوُسٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَلَفَ عَلَى يَمِينٍ فَقَالَ إِنْ شَاءَ اللَّهُ فَقَدْ اسْتَثْنَى","id":"Telah mengabarkan kepada kami [Nuh bin Habib] berkata; telah memberitakan kepada kami [Abdurrazaq] berkata; telah memberitakan kepada kami [Ma'mar] dari [Ibnu Thawus] dari [ayahnya] dari [Abu Hurairah] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa bersumpah dengan suatu sumpah kemudian berkata, 'Insyaallah', maka ia telah mengucapkan pengecualian.\""},"3676":{"ar":"أَخْبَرَنَا الْعَبَّاسُ بْنُ عَبْدِ الْعَظِيمِ قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَنْبَأَنَا مَعْمَرٌ عَنْ ابْنِ طَاوُسٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ رَفَعَهُقَالَ سُلَيْمَانُ لَأَطُوفَنَّ اللَّيْلَةَ عَلَى تِسْعِينَ امْرَأَةً تَلِدُ كُلُّ امْرَأَةٍ مِنْهُنَّ غُلَامًا يُقَاتِلُ فِي سَبِيلِ اللَّهِ فَقِيلَ لَهُ قُلْ إِنْ شَاءَ اللَّهُ فَلَمْ يَقُلْ فَطَافَ بِهِنَّ فَلَمْ تَلِدْ مِنْهُنَّ إِلَّا امْرَأَةٌ وَاحِدَةٌ نِصْفَ إِنْسَانٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ قَالَ إِنْ شَاءَ اللَّهُ لَمْ يَحْنَثْ وَكَانَ دَرَكًا لِحَاجَتِهِ","id":"Telah mengabarkan kepada kami [Al Abbas bin Abdul 'Azhim] berkata; telah menceritakan kepada kami [Abdurrazaq] berkata; telah memberitakan kepada kami [Ma'mar] dari [Ibnu Thawus] dari [ayahnya] dari [Abu Hurairah] dan ia memarfu'kannya, \"Sulaiman berkata, \"Sungguh, aku akan menggilir sembilan puluh isteri pada malam ini, setiap orang dari mereka akan melahirkan anak yang akan berperang di jalan Allah.\" Kemudian dikatakan kepadanya, 'Ucapkanlah 'Insyaallah'.' Namun Sulaiman tidak mengucapkannya, kemudian ia menggilir mereka dan tidak ada di antara mereka yang melahirkan kecuali seorang wanita yang melahirkan setengah manusia.\" Rasulullah shallallahu 'alaihi wasallam lalu bersabda: \"Seandainya Sulaiman mengucapkan, 'Insyaallah', maka ia tidak berdosa dan hal itu akan mewujudkan keperluannya.\""},"3677":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ حَاتِمٍ قَالَ أَنْبَأَنَا حِبَّانُ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ شُعْبَةَ عَنْ حَمَّادٍ عَنْ إِبْرَاهِيمَ عَنْ أَبِي سَعِيدٍ قَالَإِذَا اسْتَأْجَرْتَ أَجِيرًا فَأَعْلِمْهُ أَجْرَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Hatim] berkata; telah memberitakan kepada kami [Hibban] berkata; telah memberitakan kepada kami [Abdullah] dari [Syu'bah] dari [Hammad] dari [Ibrahim] dari [Abu Sa'id] berkata, \"Jika kamu memperkerjakan orang, maka beritahukanlah upahnya.\""},"3678":{"ar":"أَخْبَرَنَا مُحَمَّدٌ قَالَ أَنْبَأَنَا حِبَّانُ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ حَمَّادِ بْنِ سَلَمَةَ عَنْ يُونُسَ عَنْ الْحَسَنِأَنَّهُ كَرِهَ أَنْ يَسْتَأْجِرَ الرَّجُلَ حَتَّى يُعْلِمَهُ أَجْرَهُ","id":"Telah mengabarkan kepada kami [Muhammad] berkata; telah memberitakan kepada kami [Hibban] berkata; telah memberitakan kepada kami [Abdullah] dari [Hammad bin Salamah] dari [Yunus] dari [Al Hasan], bahwa ia membenci untuk menyewa orang hingga ia memberitahukan kepadanya jumlah upahnya.\""},"3679":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ حَاتِمٍ قَالَ أَنْبَأَنَا حِبَّانُ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ جَرِيرِ بْنِ حَازِمٍ عَنْ حَمَّادٍ هُوَ ابْنُ أَبِي سُلَيْمَانَأَنَّهُ سُئِلَ عَنْ رَجُلٍ اسْتَأْجَرَ أَجِيرًا عَلَى طَعَامِهِ قَالَ لَا حَتَّى تُعْلِمَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Hatim] berkata; telah memberitakan kepada kami [Hibban] berkata; telah memberitakan kepada kami [Abdullah] dari [Jarir bin Hazim] dari [Hammad] -yaitu Ibnu Abu Sulaiman-, bahwa ia pernah ditanya mengenai seseorang yang menyewa orang upahan dengan upah makanannya, maka ia menjawab, \"Tidak boleh, hingga ia memberitahukan jumlahnya.\""},"3680":{"ar":"أَخْبَرَنَا مُحَمَّدٌ قَالَ حَدَّثَنَا حِبَّانُ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ مَعْمَرٍ عَنْ حَمَّادٍ وَقَتَادَةَفِي رَجُلٍ قَالَ لِرَجُلٍ أَسْتَكْرِي مِنْكَ إِلَى مَكَّةَ بِكَذَا وَكَذَا فَإِنْ سِرْتُ شَهْرًا أَوْ كَذَا وَكَذَا شَيْئًا سَمَّاهُ فَلَكَ زِيَادَةُ كَذَا وَكَذَا فَلَمْ يَرَيَا بِهِ بَأْسًا وَكَرِهَا أَنْ يَقُولَ أَسْتَكْرِي مِنْكَ بِكَذَا وَكَذَا فَإِنْ سِرْتُ أَكْثَرَ مِنْ شَهْرٍ نَقَصْتُ مِنْ كِرَائِكَ كَذَا وَكَذَا","id":"Telah mengabarkan kepada kami [Muhammad] ia berkata; telah menceritakan kepada kami [Hibban] ia berkata; telah memberitakan kepada kami [Abdullah] dari [Ma'mar] dari [Hammad] dan [Qatadah] mengenai seorang laki-laki yang berkata kepada orang yang lain, 'Aku ingin menyewa kamu (untuk mengantar) menuju Makkah dengan upah sekian dan sekian, jika aku pergi selama sebulan. Atau sekian dan sekian -lalu ia menyebutkan lama waktunya-, maka kamu akan mendapatkan tambahan sekian dan sekian.' Mereka berdua memandang hal tersebut tidak mengapa, dan mereka tidak menyukai untuk mengatakan, 'Aku akan menyewa darimu dengan upah sekian dan sekian, jika aku berjalan lebih dari satu bulan maka aku akan mengurangi sewaanmu sekian dan sekian'.\""},"3681":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ حَاتِمٍ قَالَ أَنْبَأَنَا حِبَّانُ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ ابْنِ جُرَيْجٍ قِرَاءَةً قَالَ قُلْتُ لِعَطَاءٍعَبْدٌ أُؤَاجِرُهُ سَنَةً بِطَعَامِهِ وَسَنَةً أُخْرَى بِكَذَا وَكَذَا قَالَ لَا بَأْسَ بِهِ وَيُجْزِئُهُ اشْتِرَاطُكَ حِينَ تُؤَاجِرُهُ أَيَّامًا أَوْ آجَرْتَهُ وَقَدْ مَضَى بَعْضُ السَّنَةِ قَالَ إِنَّكَ لَا تُحَاسِبُنِي لِمَا مَضَى","id":"Telah mengabarkan kepada kami [Muhammad bin Hatim] telah memberitakan kepada kami [Hibban] telah memberitakan kepada kami [Abdullah] dari [Ibnu Juraij] dengan membacakan riwayat, dia berkata; \"Saya berkata kepada ['Atho']; ada seorang budak yang aku pekerjakan selama setahun dengan upah memberinya makanan, dan tahun yang lain dengan ini dan itu. Dia menjawab hal itu tidaklah mengapa dan cukup baginya dengan memberinya persyaratanmu ketika engkau mempekerjakannya selama beberapa hari atau engkau telah mempekerjakannya dan telah berjalan beberapa tahun, ia berkata sesungguhnya engkau tidak menghitungku dari apa yang telah berlalu."},"3682":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا خَالِدٌ هُوَ ابْنُ الْحَارِثِ قَالَ قَرَأْتُ عَلَى عَبْدِ الْحَمِيدِ بْنِ جَعْفَرٍ أَخْبَرَنِي أَبِي عَنْ رَافِعِ بْنِ أُسَيْدِ بْنِ ظُهَيْرٍ عَنْ أَبِيهِ أُسَيْدِ بْنِ ظُهَيْرٍأَنَّهُ خَرَجَ إِلَى قَوْمِهِ إِلَى بَنِي حَارِثَةَ فَقَالَ يَا بَنِي حَارِثَةَ لَقَدْ دَخَلَتْ عَلَيْكُمْ مُصِيبَةٌ قَالُوا مَا هِيَ قَالَ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ كِرَاءِ الْأَرْضِ قُلْنَا يَا رَسُولَ اللَّهِ إِذًا نُكْرِيهَا بِشَيْءٍ مِنْ الْحَبِّ قَالَ لَا قَالَ وَكُنَّا نُكْرِيهَا بِالتِّبْنِ فَقَالَ لَا وَكُنَّا نُكْرِيهَا بِمَا عَلَى الرَّبِيعِ السَّاقِي قَالَ لَا ازْرَعْهَا أَوْ امْنَحْهَا أَخَاكَخَالَفَهُ مُجَاهِدٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Ibrahim] telah memberitakan kepada kami [Khalid yaitu Ibnu Al Harits], dia berkata; \"Saya membacakan riwayat kepada [Abdul Hamid bin Ja'far], telah mengabarkan kepadaku [ayahku] dari [Rafi' bin Usaid bin Zhuhair] dari [ayahnya yaitu Usaid bin Zhuhair] bahwa dia keluar kepada kaumnya yaitu Bani Haritsah, lalu berkata; \"Wahai Bani Haritsah, sesungguhnya musibah telah menimpa kalian.\" Mereka bertanya; \"Apa itu?\" Dia menjawab; \"Rasulullah shallallahu 'alaihi wasallam melarang dari menyewakan tanah, kami berkata; wahai Rasulullah bagaimana jika kami menyewakan dengan sedikit biji-bijian, beliau menjawab: \" Tidak, \" ia berkata dan kami dahulu menyewakannya dengan jerami, beliau menjawab: \" Tidak, \" kami menyewakannya dengan sesuatu yang ditanam dengan pengairan sungai kecil, beliau bersabda: \" Tidak, tanamilah tanah tersebut atau berikan kepada saudaramu.\" Mujahid menyelisihi hadits tersebut."},"3683":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا مُحَمَّدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ مَنْصُورٍ سَمِعْتُ مُجَاهِدًا يُحَدِّثُ عَنْ أُسَيْدِ بْنِ ظُهَيْرٍ قَالَأَتَانَا رَافِعُ بْنُ خَدِيجٍ فَقَالَ نَهَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ أَمْرٍ كَانَ لَنَا نَافِعًا وَطَاعَةُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْرٌ لَكُمْ نَهَاكُمْ عَنْ الْحَقْلِ وَقَالَ مَنْ كَانَتْ لَهُ أَرْضٌ فَلْيَمْنَحْهَا أَوْ لِيَدَعْهَا وَنَهَى عَنْ الْمُزَابَنَةِ وَالْمُزَابَنَةُ الرَّجُلُ يَكُونُ لَهُ الْمَالُ الْعَظِيمُ مِنْ النَّخْلِ فَيَجِيءُ الرَّجُلُ فَيَأْخُذُهَا بِكَذَا وَكَذَا وَسْقًا مِنْ تَمْرٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Muhammad] telah menceritakan kepada kami [Syu'bah] dari [Manshur], saya mendengar [Mujahid] menceritakan dari [Usaid bin Zhuhair], dia berkata; telah datang kepada kami [Rafi' bin Khadij] kemudian berkata; \"Rasulullah shallallahu 'alaihi wasallam telah melarang kami dari perkara yang dahulu memberikan manfaat bagi kami, sedang mentaati Rasulullah shallallahu 'alaihi wasallam adalah lebih baik bagi kalian. Beliau telah melarang dari haql, beliau bersabda: \"Barang siapa yang memiliki tanah maka hendaknya dia memberikannya atau meninggalkannya.\" Dan beliau melarang dari muzabanah, dan muzabanah adalah seseorang memiliki banyak harta dari pohon kurma kemudian seseorang datang dan mengambilnya dengan sekian dan sekian wasaq dari buah kurma.\""},"3684":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ قُدَامَةَ قَالَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ مُجَاهِدٍ عَنْ أُسَيْدِ بْنِ ظُهَيْرٍ قَالَأَتَى عَلَيْنَا رَافِعُ بْنُ خَدِيجٍ فَقَالَ وَلَمْ أَفْهَمْ فَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَاكُمْ عَنْ أَمْرٍ كَانَ يَنْفَعُكُمْ وَطَاعَةُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْرٌ لَكُمْ مِمَّا يَنْفَعُكُمْ نَهَاكُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْحَقْلِ وَالْحَقْلُ الْمُزَارَعَةُ بِالثُّلُثِ وَالرُّبُعِ فَمَنْ كَانَ لَهُ أَرْضٌ فَاسْتَغْنَى عَنْهَا فَلْيَمْنَحْهَا أَخَاهُ أَوْ لِيَدَعْ وَنَهَاكُمْ عَنْ الْمُزَابَنَةِ وَالْمُزَابَنَةُ الرَّجُلُ يَجِيءُ إِلَى النَّخْلِ الْكَثِيرِ بِالْمَالِ الْعَظِيمِ فَيَقُولُ خُذْهُ بِكَذَا وَكَذَا وَسْقًا مِنْ تَمْرِ ذَلِكَ الْعَامِ","id":"Telah mengabarkan kepada kami [Muhammad bin Qudamah] telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Mujahid] dari [Usaid bin Zhuhair], dia berkata; telah datang kepada kami [Rafi' bin Khadij] kemudian berbicara dan saya belum faham, dia berkata; \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam telah melarang kalian dari perkara yang dahulu memberikan manfaat bagi kalian, dan mentaati Rasulullah shallallahu 'alaihi wasallam adalah lebih baik bagi kalian daripada sesuatu yang memberikan manfaat kepada kalian. Rasulullah shallallahu 'alaihi wasallam melarang kalian dari haql dan haql adalah mempekerjakan orang menggarap tanah dengan bagian sepertiga atau seperempat. Maka barang siapa yang memiliki tanah kemudian dia tidak membutuhkannya maka hendaknya dia memberikannya kepada saudaranya atau membiarkannya. Dan beliau melarang dari muzabanah, muzabanah adalah seseorang datang ke pohon kurma yang banyak dengan membawa harta yang banyak kemudian berkata; \"Ambillah dengan sekian dan sekian wasaq kurma tahun tersebut.\""},"3685":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ أَنْبَأَنَا عُبَيْدُ اللَّهِ يَعْنِي ابْنَ عَمْرٍو عَنْ عَبْدِ الْكَرِيمِ عَنْ مُجَاهِدٍ قَالَ أَخَذْتُ بِيَدِ طَاوُسٍ حَتَّى أَدْخَلْتُهُ عَلَى ابْنِ رَافِعِ بْنِ خَدِيجٍ فَحَدَّثَهُ عَنْ أَبِيهِعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ نَهَى عَنْ كِرَاءِ الْأَرْضِفَأَبَى طَاوُسٌ فَقَالَ سَمِعْتُ ابْنَ عَبَّاسٍ لَا يَرَى بِذَلِكَ بَأْسًا وَرَوَاهُ أَبُو عَوَانَةَ عَنْ أَبِي حَصِينٍ عَنْ مُجَاهِدٍ قَالَ قَالَ عَنْ رَافِعٍ مُرْسَلًا","id":"Telah mengabarkan kepada kami [Ali bin Hujr] telah memberitakan kepada kami ['Ubaidullah yaitu Ibnu 'Amru] dari [Abdul Karim] dari [Mujahid], dia berkata; \"Saya menggandeng tangan Thawus hingga saya menggamitkannya dengan [anak Rafi' bin Khadij], kemudian dia menceritakan kepadanya dari [ayahnya] dari Rasulullah shallallahu 'alaihi wasallam bahwa beliau melarang dari menyewakan tanah. Kemudian Thawus menolak dan berkata; \"Saya telah mendengar Ibnu Abbas bahwa dia melihat hal tersebut tidak mengapa.\" Dan hadits tersebut diriwayatkan oleh Abu 'Awanah dari Abu Hashin dari Mujahid, dia berkata; telah berkata Rafi'....secara mursal.\""},"3686":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ أَبِي حَصِينٍ عَنْ مُجَاهِدٍ قَالَقَالَ رَافِعُ بْنُ خَدِيجٍ نَهَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ أَمْرٍ كَانَ لَنَا نَافِعًا وَأَمْرُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الرَّأْسِ وَالْعَيْنِ نَهَانَا أَنْ نَتَقَبَّلَ الْأَرْضَ بِبَعْضِ خَرْجِهَاتَابَعَهُ إِبْرَاهِيمُ بْنُ مُهَاجِرٍ","id":"Telah mengabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Abu 'Awanah] dari [Abu Hashin] dari [Mujahid], ia berkata; telah berkata [Rafi' bin Khadij]; Rasulullah shallallahu 'alaihi wasallam telah melarang kita dari perkara yang dahulu bermanfaat bagi kita, dan perintah Rasulullah shallallahu 'alaihi wasallam adalah sesuatu yang wajib. Beliau telah melarang kita untuk menerima tanahdengan sebagian hasilnya. Hadits tersebut disetujui oleh Ibrahim bin Muhajir. "},"3687":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ عَنْ عُبَيْدِ اللَّهِ قَالَ حَدَّثَنَا إِسْرَائِيلُ عَنْ إِبْرَاهِيمَ بْنِ مُهَاجِرٍ عَنْ مُجَاهِدٍ عَنْ رَافِعِ بْنِ خَدِيجٍ قَالَمَرَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى أَرْضِ رَجُلٍ مِنْ الْأَنْصَارِ قَدْ عَرَفَ أَنَّهُ مُحْتَاجٌ فَقَالَ لِمَنْ هَذِهِ الْأَرْضُ قَالَ لِفُلَانٍ أَعْطَانِيهَا بِالْأَجْرِ فَقَالَ لَوْ مَنَحَهَا أَخَاهُ فَأَتَى رَافِعٌ الْأَنْصَارَ فَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَاكُمْ عَنْ أَمْرٍ كَانَ لَكُمْ نَافِعًا وَطَاعَةُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْفَعُ لَكُمْ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] dari ['Ubaidullah] telah menceritakan kepada kami [Israil] dari [Ibrahim bin Muhajir] dari [Mujahid] dari [Rafi' bin Khadij], dia berkata; \"Nabi shallallahu 'alaihi wasallam melewati tanah seorang laki-laki Anshar dan beliau telah mengetahui bahwa dia membutuhkan (tanah tersebut), kemudian beliau bersabda: \"Milik siapakah tanah ini?\" Dia berkata; \"Milik Fulan. Dia memberikannya kepadaku dengan upah (disewakan). Kemudian beliau bersabda; \"\"Andai saja dia (mau) memberikannya kepada saudaranya.\" Kemudian Rafi' mendatangi orang-orang Anshar lalu berkata; \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam melarang kalian dari perkara yang dahulu memberikan manfaat bagi kalian, dan ketaatan kepada Rasulullah shallallahu 'alaihi wasallam adalah lebih bermanfaat bagi kalian.\""},"3688":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ عَنْ خَالِدٍ وَهُوَ ابْنُ الْحَارِثِ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ الْمَلِكِ عَنْ مُجَاهِدٍ قَالَ حَدَّثَ رَافِعُ بْنُ خَدِيجٍ قَالَخَرَجَ إِلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَهَانَا عَنْ أَمْرٍ كَانَ لَنَا نَافِعًا فَقَالَ مَنْ كَانَ لَهُ أَرْضٌ فَلْيَزْرَعْهَا أَوْ يَمْنَحْهَا أَوْ يَذَرْهَا","id":"Telah mengabarkan kepada kami ['Amru bin Ali] dari [Khalid] yaitu Ibnu Al Harits telah menceritakan kepada kami [Syu'bah] dari [Abdul Malik] dari [Mujahid], dia berkata; [Rafi' bin Khadij] telah menceritakan, dia berkata; \"Rasulullah shallallahu 'alaihi wasallam keluar menemui kami kemudian melarang kami dari perkara yang dahulunya memberikan manfaat bagi kami. Beliau bersabda: \"Barang siapa yang memiliki tanah hendaknya dia menanaminya atau memberikannya atau membiarkannya.\""},"3689":{"ar":"أَخْبَرَنَا عَبْدُ الرَّحْمَنِ بْنُ خَالِدٍ قَالَ حَدَّثَنَا حَجَّاجٌ قَالَ حَدَّثَنِي شُعْبَةُ عَنْ عَبْدِ الْمَلِكِ عَنْ عَطَاءٍ وَطَاوُسٍ وَمُجَاهِدٍ عَنْ رَافِعِ بْنِ خَدِيجٍ قَالَخَرَجَ إِلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَهَانَا عَنْ أَمْرٍ كَانَ لَنَا نَافِعًا وَأَمْرُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْرٌ لَنَا قَالَ مَنْ كَانَ لَهُ أَرْضٌ فَلْيَزْرَعْهَا أَوْ لِيَذَرْهَا أَوْ لِيَمْنَحْهَاوَمِمَّا يَدُلُّ عَلَى أَنَّ طَاوُسًا لَمْ يَسْمَعْ هَذَا الْحَدِيثَ","id":"Telah mengabarkan kepada kami [Abdur Rahman bin Khalid] telah menceritakan kepada kami [Hajjaj] telah menceritakan kepadaku [Syu'bah] dari [Abdul Malik] dari ['Atho`] dan [Thawus] serta [Mujahid] dari [Rafi' bin Khadij], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam keluar menemui kami, kemudian melarang kami dari perkara yang dahulunya memberikan manfaat bagi kami, dan perintah Rasulullah shallallahu 'alaihi wasallam adalah lebih baik bagi kami. Beliau bersabda: \"Barang siapa yang memiliki tanah maka hendaknya dia menanaminya atau membiarkannya atau memberikanya.\" (Akan tetapi) ada beberapa hal yang menunjukkan bahwa Thawus tidak mendengar hadits ini."},"3690":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ قَالَ حَدَّثَنَا عَبْدُ الْمَلِكِ عَنْ عَطَاءٍ عَنْ جَابِرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ كَانَ لَهُ أَرْضٌ فَلْيَزْرَعْهَا فَإِنْ عَجَزَ أَنْ يَزْرَعَهَا فَلْيَمْنَحْهَا أَخَاهُ الْمُسْلِمَ وَلَا يُزْرِعْهَا إِيَّاهُ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] telah menceritakan kepada kami [Khalid bin Al Harits] telah menceritakan kepada kami [Abdul Malik] dari ['Atho`] dari [Jabir] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang memiliki tanah maka hendaknya ia menanaminya apabila tidak mampu untuk menanaminya maka hendaknya ia memberikannya kepada saudaranya yang muslim dan jangan memintanya untuk menanam untuk dirinya.\""},"3691":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا عَبْدُ الْمَلِكِ عَنْ عَطَاءٍ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ كَانَتْ لَهُ أَرْضٌ فَلْيَزْرَعْهَا أَوْ لِيَمْنَحْهَا أَخَاهُ وَلَا يُكْرِيهَاتَابَعَهُ عَبْدُ الرَّحْمَنِ بْنُ عَمْرٍو الْأَوْزَاعِيُّ","id":"Telah mengabarkan kepada kami ['Amru bin Ali] telah menceritakan kepada kami [Yahya] telah menceritakan kepada kami [Abdul Malik] dari ['Atho`] dari [Jabir], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \" Barang siapa yang memiliki tanah maka hendaknya dia menanaminya atau memberikannya kepada saudaranya dan janganlah dia menyewakannya.\" Hadits tersebut disetujui Abdur Rahman bin 'Amru Al Auza'i."},"3692":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ زُرَارَةَ قَالَ أَنْبَأَنَا إِسْمَعِيلُ قَالَ حَدَّثَنَا ابْنُ عَوْنٍ قَالَ كَانَ مُحَمَّدٌ يَقُولُالْأَرْضُ عِنْدِي مِثْلُ مَالِ الْمُضَارَبَةِ فَمَا صَلُحَ فِي مَالِ الْمُضَارَبَةِ صَلُحَ فِي الْأَرْضِ وَمَا لَمْ يَصْلُحْ فِي مَالِ الْمُضَارَبَةِ لَمْ يَصْلُحْ فِي الْأَرْضِ قَالَ وَكَانَ لَا يَرَى بَأْسًا أَنْ يَدْفَعَ أَرْضَهُ إِلَى الْأَكَّارِ عَلَى أَنْ يَعْمَلَ فِيهَا بِنَفْسِهِ وَوَلَدِهِ وَأَعْوَانِهِ وَبَقَرِهِ وَلَا يُنْفِقَ شَيْئًا وَتَكُونَ النَّفَقَةُ كُلُّهَا مِنْ رَبِّ الْأَرْضِ","id":"Telah mengabarkan kepada kami ['Amru bin Zurarah] telah memberitakan kepada kami [Isma'il] telah menceritakan kepada kami [Ibnu 'Aun], dia berkata; [Muhammad] pernah berkata; \"Tanahku seperti harta Mudharabah (kerjasama dagang dengan memberikan saham harta atau jasa), apa yang layak untuk harta mudharabah maka layak untuk tanahku dan apa yang tidak layak untuk harta mudharabah maka tak layak pula untuk tanahku. Dia memandang tidak mengapa jika dia menyerahkan tanahnya kepada pembajak tanah agar dikerjakan oleh pembajak tanah sendiri, anaknya dan orang-orang yang membantunya serta sapinya, pembajak tidak memberikan biaya sedikitpun, dan pembiayaannya semua dari pemilik tanah.\""},"3693":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَفَعَ إِلَى يَهُودِ خَيْبَرَ نَخْلَ خَيْبَرَ وَأَرْضَهَا عَلَى أَنْ يَعْمَلُوهَا مِنْ أَمْوَالِهِمْ وَأَنَّ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَطْرَ مَا يَخْرُجُ مِنْهَا","id":"Telah mengabarkan kepada kami [Qutaibah] telah menceritakan kepada kami [Al Laits] dari [Muhammad bin Abdur Rahman] dari [Nafi'] dari [Ibnu Umar radliallahu 'anhuma] bahwa Nabi shallallahu 'alaihi wasallam menyerahkan pohon kurma Khaibar dan tanahnya kepada orang-orang Yahudi agar mereka mengerjakannya dari harta mereka sedang Rasulullah shallallahu 'alaihi wasallam mendapatkan setengah dari apa yang keluar darinya. "},"3694":{"ar":"أَخْبَرَنَا عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ بْنِ عَبْدِ الْحَكَمِ قَالَ حَدَّثَنَا شُعَيْبُ بْنُ اللَّيْثِ قَالَ حَدَّثَنَا أَبِي عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَفَعَ إِلَى يَهُودِ خَيْبَرَ نَخْلَ خَيْبَرَ وَأَرْضَهَا عَلَى أَنْ يَعْمَلُوهَا بِأَمْوَالِهِمْ وَأَنَّ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَطْرَ ثَمَرَتِهَا","id":"Telah mengabarkan kepada kami [Abdur Rahman bin Abdullah bin Abdul Hakam] telah menceritakan kepada kami [Syu'aib bin Al Laits] telah menceritakan kepada kami [ayahku] dari [Muhammad bin Abdur Rahman] dari [Nafi'] dari [Ibnu Umar] bahwa Nabi shallallahu 'alaihi wasallam menyerahkan pohon kurma Khaibar dan tanahnya kepada orang-orang Yahudi agar mereka menggarapnya dari harta mereka sedang Rasulullah shallallahu 'alaihi wasallam mendapatkan setengah dari buahnya."},"3695":{"ar":"أَخْبَرَنَا عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ بْنِ عَبْدِ الْحَكَمِ قَالَ حَدَّثَنَا شُعَيْبُ بْنُ اللَّيْثِ عَنْ أَبِيهِ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ نَافِعٍ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ كَانَ يَقُولُكَانَتْ الْمَزَارِعُ تُكْرَى عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى أَنَّ لِرَبِّ الْأَرْضِ مَا عَلَى رَبِيعِ السَّاقِي مِنْ الزَّرْعِ وَطَائِفَةً مِنْ التِّبْنِ لَا أَدْرِي كَمْ هُوَ","id":"Telah mengabarkan kepada kami [Abdur Rahman bin Abdullah bin Abdul Hakam] telah menceritakan kepada kami [Syu'aib bin Al Laits] dari [ayahnya] dari [Muhammad bin Abdur Rahman] dari [Nafi'] bahwa [Abdullah bin Umar] berkata; \"Pada masa Rasulullah shallallahu 'alaihi wasallam dahulu sawah-sawah disewakan dan pemilik tanah berhak terhadap apa yang tumbuh di sekitar sungai kecil ladangnya dan sekelompok jerami, saya tidak tahu berapa itu.\""},"3696":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ أَنْبَأَنَا شَرِيكٌ عَنْ أَبِي إِسْحَقَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْأَسْوَدِ قَالَكَانَ عَمَّايَ يَزْرَعَانِ بِالثُّلُثِ وَالرُّبُعِ وَأَبِي شَرِيكَهُمَا وَعَلْقَمَةُ وَالْأَسْوَدُ يَعْلَمَانِ فَلَا يُغَيِّرَانِ","id":"Telah mengabarkan kepada kami [Ali bin Hujr] telah memberitakan kepada kami [Syarik] dari [Abu Ishaq] dari [Abdur Rahman bin Al Aswad], dia berkata; \"Dua orang pamanku bercocok tanam dengan mendapatkan sepertiga dan seperempat dan ayahku bekerjasama dengan keduanya, [Alqomah] dan [Al Aswad] mengetahui hal itu namun mereka tidak mengingkarinya.\""},"3697":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا الْمُعْتَمِرُ قَالَ سَمِعْتُ مَعْمَرًا عَنْ عَبْدِ الْكَرِيمِ الْجَزَرِيِّ قَالَ قَالَ سَعِيدُ بْنُ جُبَيْرٍ قَالَ ابْنُ عَبَّاسٍإِنَّ خَيْرَ مَا أَنْتُمْ صَانِعُونَ أَنْ يُؤَاجِرَ أَحَدُكُمْ أَرْضَهُ بِالذَّهَبِ وَالْوَرِقِ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la] telah menceritakan kepada kami [Al Mu'tamir], dia berkata; \"Saya mendengar [Ma'mar] dari [Abdul Karim Aljazary], dia berkata; [Said bin Jubair] berkata; [Ibnu Abbas] berkata; \"Sesungguhnya sebaik-baik apa yang kalian perbuat adalah seseorang di antara kalian menyewakan tanahnya dengan upah emas atau perak.\""},"3698":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ وَسَعِيدِ بْنِ جُبَيْرٍأَنَّهُمَا كَانَا لَا يَرَيَانِ بَأْسًا بِاسْتِئْجَارِ الْأَرْضِ الْبَيْضَاءِ","id":"Telah mengabarkan kepada kami [Qutaibah] telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Ibrahim] dan [Sa'id bin Jubair] bahwa keduanya berpendapat tidak mengapa menyewa tanah kosong."},"3699":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ زُرَارَةَ قَالَ حَدَّثَنَا إِسْمَعِيلُ عَنْ أَيُّوبَ عَنْ مُحَمَّدٍ قَالَ لَمْ أَعْلَمْ شُرَيْحًاكَانَ يَقْضِي فِي الْمُضَارِبِ إِلَّا بِقَضَاءَيْنِ كَانَ رُبَّمَا قَالَ لِلْمُضَارِبِ بَيِّنَتَكَ عَلَى مُصِيبَةٍ تُعْذَرُ بِهَا وَرُبَّمَا قَالَ لِصَاحِبِ الْمَالِ بَيِّنَتَكَ أَنَّ أَمِينَكَ خَائِنٌ وَإِلَّا فَيَمِينُهُ بِاللَّهِ مَا خَانَكَ","id":"Telah mengabarkan kepada kami ['Amru bin Zurarah] telah menceritakan kepada kami [Isma'il] dari [Ayyub] dari [Muhammad], dia berkata; \"Aku tidak tahu bahwa [Syuraih] memutuskan mengenai seseorang yang melakukan mudharabah kecuali dengan dua keputusan, suatu ketika dia mengatakan kepada pelaksana mudharabah; \"Berikanlah buktimu terhadap musibah yang dengannya engkau mendapatkan udzur\", atau suatu ketika dia mengatakan kepada pemilik harta; \"Berikan buktimu bahwa orang kepercayaanmu adalah orang yang berkhianat, jika tidak maka dia bersumpah dengan nama Allah bahwa dia tidak mengkhianatimu.\""},"3700":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ حَدَّثَنَا شَرِيكٌ عَنْ طَارِقٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ قَالَلَا بَأْسَ بِإِجَارَةِ الْأَرْضِ الْبَيْضَاءِ بِالذَّهَبِ وَالْفِضَّةِ وَقَالَ إِذَا دَفَعَ رَجُلٌ إِلَى رَجُلٍ مَالًا قِرَاضًا فَأَرَادَ أَنْ يَكْتُبَ عَلَيْهِ بِذَلِكَ كِتَابًا كَتَبَ هَذَا كِتَابٌ كَتَبَهُ فُلَانُ بْنُ فُلَانٍ طَوْعًا مِنْهُ فِي صِحَّةٍ مِنْهُ وَجَوَازِ أَمْرِهِ لِفُلَانِ بْنِ فُلَانٍ أَنَّكَ دَفَعْتَ إِلَيَّ مُسْتَهَلَّ شَهْرِ كَذَا مِنْ سَنَةِ كَذَا عَشَرَةَ آلَافِ دِرْهَمٍ وُضْحًا جِيَادًا وَزْنَ سَبْعَةٍ قِرَاضًا عَلَى تَقْوَى اللَّهِ فِي السِّرِّ وَالْعَلَانِيَةِ وَأَدَاءِ الْأَمَانَةِ عَلَى أَنْ أَشْتَرِيَ بِهَا مَا شِئْتُ مِنْهَا كُلَّ مَا أَرَى أَنْ أَشْتَرِيَهُ وَأَنْ أُصَرِّفَهَا وَمَا شِئْتُ مِنْهَا فِيمَا أَرَى أَنْ أُصَرِّفَهَا فِيهِ مِنْ صُنُوفِ التِّجَارَاتِ وَأَخْرُجَ بِمَا شِئْتُ مِنْهَا حَيْثُ شِئْتُ وَأَبِيعَ مَا أَرَى أَنْ أَبِيعَهُ مِمَّا أَشْتَرِيهِ بِنَقْدٍ رَأَيْتُ أَمْ بِنَسِيئَةٍ وَبِعَيْنٍ رَأَيْتُ أَمْ بِعَرْضٍ عَلَى أَنْ أَعْمَلَ فِي جَمِيعِ ذَلِكَ كُلِّهِ بِرَأْيِي وَأُوَكِّلَ فِي ذَلِكَ مَنْ رَأَيْتُ وَكُلُّ مَا رَزَقَ اللَّهُ فِي ذَلِكَ مِنْ فَضْلٍ وَرِبْحٍ بَعْدَ رَأْسِ الْمَالِ الَّذِي دَفَعْتَهُ الْمَذْكُورِ إِلَيَّ الْمُسَمَّى مَبْلَغُهُ فِي هَذَا الْكِتَابِ فَهُوَ بَيْنِي وَبَيْنَكَ نِصْفَيْنِ لَكَ مِنْهُ النِّصْفُ بِحَظِّ رَأْسِ مَالِكَ وَلِي فِيهِ النِّصْفُ تَامًّا بِعَمَلِي فِيهِ وَمَا كَانَ فِيهِ مِنْ وَضِيعَةٍ فَعَلَى رَأْسِ الْمَالِ فَقَبَضْتُ مِنْكَ هَذِهِ الْعَشَرَةَ آلَافِ دِرْهَمٍ الْوُضْحَ الْجِيَادَ مُسْتَهَلَّ شَهْرِ كَذَا فِي سَنَةِ كَذَا وَصَارَتْ لَكَ فِي يَدِي قِرَاضًا عَلَى الشُّرُوطِ الْمُشْتَرَطَةِ فِي هَذَا الْكِتَابِ أَقَرَّ فُلَانٌ وَفُلَانٌ وَإِذَا أَرَادَ أَنْ يُطْلِقَ لَهُ أَنْ يَشْتَرِيَ وَيَبِيعَ بِالنَّسِيئَةِ كَتَبَ وَقَدْ نَهَيْتَنِي أَنْ أَشْتَرِيَ وَأَبِيعَ بِالنَّسِيئَةِ","id":"Telah mengabarkan kepada kami ['Ali bin Hujr] telah menceritakan kepada kami [Syarik] dari [Thariq] dari [Sa'id bin Al Musayyab], dia berkata; \"Tidak mengapa menyewakan tanah kosong dengan upah emas atau perak.\" Dia juga berkata; \"Jika seseorang membayar harta kepada orang lain dengan qirod (pemberian modal untuk berdagang dengan memperoleh bagian laba) dan dia ingin menuliskannya dalam surat lalu dia menulis; Ini adalah surat yang ditulis oleh fulan bin fulan dengan kerelaan darinya dalam keadaan sehat dan lisensinya untuk Fulan bin Fulan, bahwa engkau telah menyerahkan kepadaku pada permulaan bulan dari tahun ini, sebanyak sepuluh ribu dirham secara jelas dan baik dengan berat tujuh qiradh atas dasar ketakwaan kepada Allah baik dalam keadaan tersembunyi ataupun terang-terangan, serta menunaikan amanah agar saya membeli dengannya menurut kehendakku segala apa yang ingin saya beli, dan aku akan mengaturnya sekiranya saya pandang perlu untuk mengaturnya dari berbagai jenis perdagangan, dan akan aku keluarkan apa yang saya kehendaki kemana saja yang saya kehendaki dan menjual apa yang ingin saya jual dari barang yang telah saya beli, baik secara kontan atau kredit, baik dengan uang atau dengan barang dengan dasar saya mengerjakan semua itu sesuai pendapatku, dan saya akan mewakilkan dalam itu kepada orang yang kehendaki, dan setiap apa yang dirizqikan Allah dalam hal itu berupa kelebihan dan keuntungan diluar modal tersebut yang telah engkau serahkan kepadaku yang tertera banyaknya, didalam surat ini, maka hal itu dibagi antara saya dan engkau menjadi dua bagian, untukmu setengah sesuai dengan bagian modalmu, dan untukku setengah sesuai dengan pekerjaanku secara penuh, jika ada sesuatu yang hilang maka hal itu menjadi tanggungan modal. Saya terima sebanyak sepuluh ribu dirham secara jelas dan baik pada permulaan bulan ini pada tahun ini, dan menjadi qiradh milikmu yang ada padaku dengan persyaratan yang tercantum dalam surat ini. Telah menyatakan Fulan dan Fulan. Jika ia ingin membebaskannya untuk membeli dan menjual secara kredit, maka ia menulis; dan engkau telah melarangku untuk membeli dan menjualnya dengan kredit.\""},"3701":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ سُفْيَانَ قَالَ حَدَّثَنِي أَبُو إِسْحَقَ عَنْ أَبِي عُبَيْدَةَ عَنْ عَبْدِ اللَّهِ قَالَاشْتَرَكْتُ أَنَا وَعَمَّارٌ وَسَعْدٌ يَوْمَ بَدْرٍ فَجَاءَ سَعْدٌ بِأَسِيرَيْنِ وَلَمْ أَجِئْ أَنَا وَلَا عَمَّارٌ بِشَيْءٍ","id":"Telah mengabarkan kepada kami ['Amru bin Ali] telah menceritakan kepada kami [Yahya bin Sa'id] dari [Sufyan] telah menceritakan kepadaku [Abu Ishaq] dari [Abu 'Ubaidah] dari [Abdullah], dia berkata; \"Saya, 'Ammar dan Sa, d bersekutu pada perang Badr, kemudian Sa'd datang membawa dua orang tawanan, sedangkan saya dan Ammar tidak membawa sesuatupun.\""},"3702":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ أَنْبَأَنَا ابْنُ الْمُبَارَكِ عَنْ يُونُسَ عَنْ الزُّهْرِيِّفِي عَبْدَيْنِ مُتَفَاوِضَيْنِ كَاتَبَ أَحَدُهُمَا قَالَ جَائِزٌ إِذَا كَانَا مُتَفَاوِضَيْنِ يَقْضِي أَحَدُهُمَا عَنْ الْآخَرِ","id":"Telah mengabarkan kepada kami [Ali bin Hujr] telah memberitakan kepada kami [Ibnu Al Mubarak] dari [Yunus] dari [Az Zuhri] mengenai dua orang budak yang bersekutu dengan syarat-syarat tertentu, salah seorang dari mereka berjanji akan menebus salah seorang dari mereka. Az Zuhri berkata; \"Boleh jika mereka berdua bersekutu salah seorang dari mereka menebus untuk yang lainnya.\""},"3703":{"ar":"حَدَّثَنِي الشَّيْخُ الْإِمَامُ أَبُو عَبْدِ الرَّحْمَنِ النَّسَائِيُّ قَالَ أَخْبَرَنَا الْحُسَيْنُ بْنُ عِيسَى الْقُوْمَسِيُّ قَالَ حَدَّثَنَا عَفَّانُ بْنُ مُسْلِمٍ قَالَ حَدَّثَنَا سَلَّامٌ أَبُو الْمُنْذِرِ عَنْ ثَابِتٍ عَنْ أَنَسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حُبِّبَ إِلَيَّ مِنْ الدُّنْيَا النِّسَاءُ وَالطِّيبُ وَجُعِلَ قُرَّةُ عَيْنِي فِي الصَّلَاةِ","id":"Telah mengabarkan kepada kami Syekh Imam Abu Abdur Rahman An Nasai telah mengabarkan kepada kami [Al Husain bin Isa Al Qumasi] telah menceritakan kepada kami ['Affan bin Muslim] telah menceritakan kepada kami [Sallam Abu Al Mundzir] dari [Tsabit] dari [Anas], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dijadikan kesenanganku dari dunia ada pada wanita dan minyak wangi, dan dijadikan penyejuk hatiku ada dalam shalat.\" "},"3704":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ مُسْلِمٍ الطُّوسِيُّ قَالَ حَدَّثَنَا سَيَّارٌ قَالَ حَدَّثَنَا جَعْفَرٌ قَالَ حَدَّثَنَا ثَابِتٌ عَنْ أَنَسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حُبِّبَ إِلَيَّ النِّسَاءُ وَالطِّيبُ وَجُعِلَتْ قُرَّةُ عَيْنِي فِي الصَّلَاةِ","id":"Telah mengabarkan kepada kami [Ali bin Muslim Ath Thusi] telah menceritakan kepada kami [Sayyar] telah menceritakan kepada kami [Ja'far] telah menceritakan kepada kami [Tsabit] dari [Anas], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dijadikan kesenanganku dari dunia ada pada wanita dan minyak wangi, dan dijadikan penyejuk hatiku ada dalam shalat.\" "},"3705":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ حَفْصِ بْنِ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي أَبِي قَالَ حَدَّثَنِي إِبْرَاهِيمُ بْنُ طَهْمَانَ عَنْ سَعِيدِ بْنِ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَلَمْ يَكُنْ شَيْءٌ أَحَبَّ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَ النِّسَاءِ مِنْ الْخَيْلِ","id":"Telah mengabarkan kepada kami [Ahmad bin Hafsh bin Abdullah] telah menceritakan kepadaku [ayahku] telah menceritakan kepadaku [Ibarahim bin Thahman] dari [Sa'id bin Abi 'Arubah] dari [Qatadah] dari [Anas bin Malik], dia berkata; \"Tidak ada sesuatu yang lebih disukai Rasulullah shallallahu 'alaihi wasallam setelah para isteri daripada kuda perang.\""},"3706":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنْ النَّضْرِ بْنِ أَنَسٍ عَنْ بَشِيرِ بْنِ نَهِيكٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ كَانَ لَهُ امْرَأَتَانِ يَمِيلُ لِإِحْدَاهُمَا عَلَى الْأُخْرَى جَاءَ يَوْمَ الْقِيَامَةِ أَحَدُ شِقَّيْهِ مَائِلٌ","id":"Telah mengabarkan kepada kami ['Amru bin Ali] telah menceritakan kepada kami [Abdur Rahman] telah menceritakan kepada kami [Hammam] dari [Qatadah] dari [An Nadhr bin Anas] dari [Basyir bin Nahik] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barang siapa yang memiliki dua orang isteri dan dia lebih condong kepada salah seorang di antara mereka maka dia akan datang pada Hari Kiamat dalam keadaan salah satu sisinya miring.\""},"3707":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ إِسْمَعِيلَ بْنِ إِبْرَاهِيمَ قَالَ حَدَّثَنَا يَزِيدُ قَالَ أَنْبَأَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ عَبْدِ اللَّهِ بْنِ يَزِيدَ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْسِمُ بَيْنَ نِسَائِهِ ثُمَّ يَعْدِلُ ثُمَّ يَقُولُ اللَّهُمَّ هَذَا فِعْلِي فِيمَا أَمْلِكُ فَلَا تَلُمْنِي فِيمَا تَمْلِكُ وَلَا أَمْلِكُأَرْسَلَهُ حَمَّادُ بْنُ زَيْدٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Isma'il bin Ibrahim] telah menceritakan kepada kami [Yazid] telah memberitakan kepada kami [Hammad bin Salamah] dari [Ayyub] dari [Abu Qilabah] dari [Abdullah bin Yazid] dari ['Aisyah], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam membagi di antara isteri-isteri beliau kemudian beliau berbuat adil dan bersabda: \"Ya Allah, inilah yang bisa saya lakukan dalam perkara yang saya mampu dan janganlah Engkau cela diriku dalam perkara yang Engkau mampu dan tidak saya mampu.\" Hadits tersebut dimursalkan oleh Hammad bin Zaid."},"3708":{"ar":"أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ سَعْدِ بْنِ إِبْرَاهِيمَ بْنِ سَعْدٍ قَالَ حَدَّثَنَا عَمِّي قَالَ حَدَّثَنَا أَبِي عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي مُحَمَّدُ بْنُ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ بْنِ هِشَامٍ أَنَّ عَائِشَةَ قَالَتْأَرْسَلَ أَزْوَاجُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاطِمَةَ بِنْتَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاسْتَأْذَنَتْ عَلَيْهِ وَهُوَ مُضْطَجِعٌ مَعِي فِي مِرْطِي فَأَذِنَ لَهَا فَقَالَتْ يَا رَسُولَ اللَّهِ إِنَّ أَزْوَاجَكَ أَرْسَلْنَنِي إِلَيْكَ يَسْأَلْنَكَ الْعَدْلَ فِي ابْنَةِ أَبِي قُحَافَةَ وَأَنَا سَاكِتَةٌ فَقَالَ لَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيْ بُنَيَّةُ أَلَسْتِ تُحِبِّينَ مَنْ أُحِبُّ قَالَتْ بَلَى قَالَ فَأَحِبِّي هَذِهِ فَقَامَتْ فَاطِمَةُ حِينَ سَمِعَتْ ذَلِكَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَجَعَتْ إِلَى أَزْوَاجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرَتْهُنَّ بِالَّذِي قَالَتْ وَالَّذِي قَالَ لَهَا فَقُلْنَ لَهَا مَا نَرَاكِ أَغْنَيْتِ عَنَّا مِنْ شَيْءٍ فَارْجِعِي إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُولِي لَهُ إِنَّ أَزْوَاجَكَ يَنْشُدْنَكَ الْعَدْلَ فِي ابْنَةِ أَبِي قُحَافَةَ قَالَتْ فَاطِمَةُ لَا وَاللَّهِ لَا أُكَلِّمُهُ فِيهَا أَبَدًا قَالَتْ عَائِشَةُ فَأَرْسَلَ أَزْوَاجُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَيْنَبَ بِنْتَ جَحْشٍ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهِيَ الَّتِي كَانَتْ تُسَامِينِي مِنْ أَزْوَاجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْمَنْزِلَةِ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَمْ أَرَ امْرَأَةً قَطُّ خَيْرًا فِي الدِّينِ مِنْ زَيْنَبَ وَأَتْقَى لِلَّهِ عَزَّ وَجَلَّ وَأَصْدَقَ حَدِيثًا وَأَوْصَلَ لِلرَّحِمِ وَأَعْظَمَ صَدَقَةً وَأَشَدَّ ابْتِذَالًا لِنَفْسِهَا فِي الْعَمَلِ الَّذِي تَصَدَّقُ بِهِ وَتَقَرَّبُ بِهِ مَا عَدَا سَوْرَةً مِنْ حِدَّةٍ كَانَتْ فِيهَا تُسْرِعُ مِنْهَا الْفَيْئَةَ فَاسْتَأْذَنَتْ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَعَ عَائِشَةَ فِي مِرْطِهَا عَلَى الْحَالِ الَّتِي كَانَتْ دَخَلَتْ فَاطِمَةُ عَلَيْهَا فَأَذِنَ لَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنَّ أَزْوَاجَكَ أَرْسَلْنَنِي يَسْأَلْنَكَ الْعَدْلَ فِي ابْنَةِ أَبِي قُحَافَةَ وَوَقَعَتْ بِي فَاسْتَطَالَتْ وَأَنَا أَرْقُبُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَرْقُبُ طَرْفَهُ هَلْ أَذِنَ لِي فِيهَا فَلَمْ تَبْرَحْ زَيْنَبُ حَتَّى عَرَفْتُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَكْرَهُ أَنْ أَنْتَصِرَ فَلَمَّا وَقَعْتُ بِهَا لَمْ أَنْشَبْهَا بِشَيْءٍ حَتَّى أَنْحَيْتُ عَلَيْهَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهَا ابْنَةُ أَبِي بَكْرٍأَخْبَرَنِي عِمْرَانُ بْنُ بَكَّارٍ الْحِمْصِيُّ قَالَ حَدَّثَنَا أَبُو الْيَمَانِ قَالَ أَنْبَأَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي مُحَمَّدُ بْنُ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ بْنِ هِشَامٍ أَنَّ عَائِشَةَ قَالَتْ فَذَكَرَتْ نَحْوَهُ وَقَالَتْ أَرْسَلَ أَزْوَاجُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَيْنَبَ فَاسْتَأْذَنَتْ فَأَذِنَ لَهَا فَدَخَلَتْ فَقَالَتْ نَحْوَهُ خَالَفَهُمَا مَعْمَرٌ رَوَاهُ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'd bin Ibrahim bin Sa'd] telah menceritakan kepada kami [pamanku] telah menceritakan kepada kami [ayahku] dari [Shalih] dari [Ibnu Syihab] telah mengabarkan kepadaku [Muhammad bin Abdur Rahman bin Al Harits bin Hisyam] bahwa [Aisyah] berkata; \"Para isteri Nabi shallallahu 'alaihi wasallam mengirim Fathimah binti Rasulullah shallallahu 'alaihi wasallam kepada Rasulullah shallallahu 'alaihi wasallam, kemudian dia meminta izin kepada beiau sedang beliau dalam keadaan berbaring bersamaku dalam pakaian buluku. Kemudian beliau memberikan izin kepadanya, lalu Fatimah berkata; \"Wahai Rasulullah, sesungguhnya para isteri Tuan mengirimku kepada Tuan, mereka meminta keadilan mengenai anak Abu Quhafah. Dan saya dalam keadaan diam, kemudian Rasulullah shallallahu 'alaihi wasallam bersabda kepadanya: \"Wahai anakku, bukankah engkau mencintai orang yang saya cintai?\" Dia berkata; \"Ya.' Beliau bersabda: \"Maka cintailah orang ini.\" Kemudian Fathimah bangkit ketika dia mendengar hal tersebut dari Rasulullah shallallahu 'alaihi wasallam. Kemudian dia kembali kepada para isteri Nabi shallallahu 'alaihi wasallam dan mengabarkan kepada mereka apa yang telah dia katakan dan apa yang beliau sabdakan kepadanya. Kemudian mereka berkata; kami tidak melihat dirimu memuaskan kami sedikitpun, maka kembalilah kepada Rasulullah shallallahu 'alaihi wasallam dan katakan kepada beliau; sesungguhnya isteri-isteri Tuan menuntut keadilan mengenai anak Abu Quhafah.\" Fathimah berkata; \"Tidak. Demi Allah saya tidak akan berbicara dengan beliau mengenainya selamanya. 'Aisyah berkata; \"Kemudian isteri-isteri Nabi shallallahu 'alaihi wasallam mengirim Zainab binti Jahsy kepada Rasulullah shallallahu 'alaihi wasallam dan dia adalah orang yang menjadi sainganku di antara isteri-isteri Nabi shallallahu 'alaihi wasallam di dalam kedudukan di sisi Rasulullah shallallahu 'alaihi wasallam, saya tidak melihat seorang wanita yang paling baik dalam agama lebih baik daripada Zainab dan lebih bertakwa kepada Allah 'azza wajalla, lebih jujur perkataannya, lebih sering menyambung ikatan kekerabatan, lebih besar sedekahnya, dan lebih rendah diri dalam hal amalan yang dia sedekahkan dan dia gunakan untuk mendekatkan diri kepada Allah selain cepat marah karena keras budi pekertinya, namun dia cepat menarik diri dari kemarahan. Dia meminta izin kepada Rasulullah shallallahu 'alaihi wasallam, sedang Rasulullah shallallahu 'alaihi wasallam tengah bersama Aisyah dalam baju bulunya sebagaimana ketika Fathimah menemui beliau. Kemudian Rasulullah shallallahu 'alaihi wasallam memberikan izin kepadanya, kemudian dia berkata; \"Wahai Rasulullah shallallahu 'alaihi wasallam, sesungguhnya isteri-isteri Tuan mengirimku, mereka meminta keadilan mengenai anak Abu Quhafah.\" Dan dia mencelaku, dia berbicara lama sedang saya memperhatikan Rasulullah shallallahu 'alaihi wasallam dan memperhatikan ujung matanya, apakah beliau mengizinkan saya (membalas) ucapannya. Zainab tidak kunjung pergi hingga saya mengetahui bahwa Rasulullah shallallahu 'alaihi wasallam tidak membenci saya jika saya membalasnya Kemudian tatkala saya mencelanya saya tidak diam begitu saja (mendengar celaannya) hingga (kemudian) saya menyerangnya. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya dia adalah anak Abu Bakar.\" [Imran bin Bakkar Al Himshi] telah mengabarkan kepadaku, dia berkata; telah menceritakan kepada kami [Abu Al Yaman] telah memberitakan kepada kami [Syu'aib] dari [Az Zuhri] telah mengabarkan kepadaku [Muhammad bin Abdur Rahman bin Al Harits bin Hisyam] bahwa [Aisyah] berkata;...(dia menyebutkan seperti di atas). Dan dia berkata; \"Para isteri Nabi shallallahu 'alaihi wasallam mengirim Zainab kemudian dia meminta izin dan beliau mengizinkannya kemudian dia masuk dan berkata seperti itu. Ma'mar menyelisihi keduanya, dia meriwayatkannya dari Az Zuhri dari 'Urwah dari 'Aisyah.\""},"3709":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ رَافِعٍ النَّيْسَابُورِيُّ الثِّقَةُ الْمَأْمُونُ قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْاجْتَمَعْنَ أَزْوَاجُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَرْسَلْنَ فَاطِمَةَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْنَ لَهَا إِنَّ نِسَاءَكَ وَذَكَرَ كَلِمَةً مَعْنَاهَا يَنْشُدْنَكَ الْعَدْلَ فِي ابْنَةِ أَبِي قُحَافَةَ قَالَتْ فَدَخَلَتْ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ مَعَ عَائِشَةَ فِي مِرْطِهَا فَقَالَتْ لَهُ إِنَّ نِسَاءَكَ أَرْسَلْنَنِي وَهُنَّ يَنْشُدْنَكَ الْعَدْلَ فِي ابْنَةِ أَبِي قُحَافَةَ فَقَالَ لَهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتُحِبِّينِي قَالَتْ نَعَمْ قَالَ فَأَحِبِّيهَا قَالَتْ فَرَجَعَتْ إِلَ��ْهِنَّ فَأَخْبَرَتْهُنَّ مَا قَالَ فَقُلْنَ لَهَا إِنَّكِ لَمْ تَصْنَعِي شَيْئًا فَارْجِعِي إِلَيْهِ فَقَالَتْ وَاللَّهِ لَا أَرْجِعُ إِلَيْهِ فِيهَا أَبَدًا وَكَانَتْ ابْنَةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَقًّا فَأَرْسَلْنَ زَيْنَبَ بِنْتَ جَحْشٍ قَالَتْ عَائِشَةُ وَهِيَ الَّتِي كَانَتْ تُسَامِينِي مِنْ أَزْوَاجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ أَزْوَاجُكَ أَرْسَلْنَنِي وَهُنَّ يَنْشُدْنَكَ الْعَدْلَ فِي ابْنَةِ أَبِي قُحَافَةَ ثُمَّ أَقْبَلَتْ عَلَيَّ تَشْتِمُنِي فَجَعَلْتُ أُرَاقِبُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنْظُرُ طَرْفَهُ هَلْ يَأْذَنُ لِي مِنْ أَنْ أَنْتَصِرَ مِنْهَا قَالَتْ فَشَتَمَتْنِي حَتَّى ظَنَنْتُ أَنَّهُ لَا يَكْرَهُ أَنْ أَنْتَصِرَ مِنْهَا فَاسْتَقْبَلْتُهَا فَلَمْ أَلْبَثْ أَنْ أَفْحَمْتُهَا فَقَالَ لَهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهَا ابْنَةُ أَبِي بَكْرٍ قَالَتْ عَائِشَةُ فَلَمْ أَرَ امْرَأَةً خَيْرًا وَلَا أَكْثَرَ صَدَقَةً وَلَا أَوْصَلَ لِلرَّحِمِ وَأَبْذَلَ لِنَفْسِهَا فِي كُلِّ شَيْءٍ يُتَقَرَّبُ بِهِ إِلَى اللَّهِ تَعَالَى مِنْ زَيْنَبَ مَا عَدَا سَوْرَةً مِنْ حِدَّةٍ كَانَتْ فِيهَا تُوشِكُ مِنْهَا الْفَيْئَةَقَالَ أَبُو عَبْد الرَّحْمَنِ هَذَا خَطَأٌ وَالصَّوَابُ الَّذِي قَبْلَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Rafi' An Naisaburi Ats Tsiqqah Al Makmun] telah menceritakan kepada kami [Abdur Razzaq] dari [Ma'mar] dari [Az Zuhri] dari ['Urwah] dari [Aisyah], dia berkata; \"Isteri-isteri Nabi shallallahu 'alaihi wasallam berkumpul dan mengirim Fathimah kepada Nabi shallallahu 'alaihi wasallam. Mereka berkata; \"Sesungguhnya isteri-isterimu..dan Az Zuhri menyebutkan suatu kalimat yang maknanya adalah; meminta keadilan mengenai anak Abi Quhafah. Aisyah berkata; kemudian Fathimah menemui Nabi shallallahu 'alaihi wasallam ketika beliau tengah bersama Aisyah dalam pakaian bulunya, kemudian dia berkata; \"Sesungguhnya para isteri Tuan mengirimku kepada Tuan, mereka meminta keadilan mengenai anak Abu Quhafah.\" Kemudian beliau bersabda kepadanya: \"Apakah engkau mencintaiku?\" Dia berkata; \"Ya.\" Beliau bersabda: \"Maka cintailah dia.\" Aisyah berkata; \"Kemudian Fathimah kembali kepada para isteri Nabi shallallahu 'alaihi wasallam dan mengabarkan kepada mereka apa yang beliau sabdakan. Kemudian mereka berkata; \"Sesungguhnya engkau belum melakukan apa-apa, maka kembalilah kepadanya.\" Fathimah berkata; \"Demi Allah, saya tidak akan kembali kepada beliau mengadukan tentang hal ini selamanya.\" dia adalah benar-benar puteri Nabi shallallahu 'alaihi wasallam yang sejati. Kemudian mereka mengirim Zainab binti Jahsy. Aisyah berkata; \"Dia adalah orang yang menjadi sainganku di antara isteri-isteri Nabi shallallahu 'alaihi wasallam. Kemudian dia berkata; \"Sesungguhnya isteri-isteri Tuan mengirimku, mereka meminta keadilan mengenai anak Abu Quhafah. Kemudian dia menghadap kepadaku dan mencelaku, saya memperhatikan Rasulullah shallallahu 'alaihi wasallam dan memperhatikan sudut matanya, apakah beliau mengizinkan saya untuk menanggapinya? Aisyah berkata; kemudian dia mencelaku hingga saya yakin bahwa beliau tidak membenci saya ketika saya menanggapinya. Kemudian saya menghadapinya dan tidak lama sayapun membuatnya tak berkutik. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya dia adalah anak Abu Bakar.\" Aisyah berkata; \"Saya belum melihat wanita yang lebih baik dan lebih banyak bersedekah, lebih sering menyambung hubungan kekerabatan, dan merendahkan diri dalam segala sesuatu untuk mendekatkan diri kepada Allah ta'ala dari Zainab selain sikap cepat marah karena kerasnya budi pekertinya, dan dia bersegera menarik diri darinya. Abu Abdur Rahman berkata; \"Ini adalah suatu kesalahan dan yang benar adalah yang sebelumnya.\""},"3710":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا بِشْرٌ يَعْنِي ابْنَ الْمُفَضَّلِ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ مُرَّةَ الْجُهَنِيِّ عَنْ أَبِي مُوسَىعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَضْلُ عَائِشَةَ عَلَى النِّسَاءِ كَفَضْلِ الثَّرِيدِ عَلَى سَائِرِ الطَّعَامِ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] telah menceritakan kepada kami [Bisyr yaitu Ibnu Al Mufadhdhal] telah menceritakan kepada kami [Syu'bah] dari ['Amru bin Murrah] dari [Murrah Al Juhani] dari [Abu Musa] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \" Keutamaan Aisyah atas wanita yang lain seperti keutamaan bubur atas makanan yang lain.\""},"3711":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ خَشْرَمٍ قَالَ أَنْبَأَنَا عِيسَى بْنُ يُونُسَ عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ الْحَارِثِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي سَلَمَةَ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَضْلُ عَائِشَةَ عَلَى النِّسَاءِ كَفَضْلِ الثَّرِيدِ عَلَى سَائِر الطَّعَامِ","id":"Telah mengabarkan kepada kami [Ali bin Khasyram] telah memberitakan kepada kami [Isa bin Yunus] dari [Ibnu Abu Dzi`b] dari [Al Harits bin Abdur Rahman] dari [Abu Salamah] dari [Aisyah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Keutamaan Aisyah atas wanita yang lain seperti keutamaan bubur atas makanan yang lain.\""},"3712":{"ar":"أَخْبَرَنَا أَبُو بَكْرِ بْنُ إِسْحَقَ الصَّغَانِيُّ قَالَ حَدَّثَنَا شَاذَانُ قَالَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أُمَّ سَلَمَةَ لَا تُؤْذِينِي فِي عَائِشَةَ فَإِنَّهُ وَاللَّهِ مَا أَتَانِي الْوَحْيُ فِي لِحَافِ امْرَأَةٍ مِنْكُنَّ إِلَّا هِيَ","id":"Telah mengabarkan kepada kami [Abu Bakar bin Ishaq Ash Shaghani] telah menceritakan kepada kami [Syadzan] telah menceritakan kepada kami [Hammad bin Zaid] dari [Hisyam bin 'Urwah] dari [ayahnya] dari [Aisyah], dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" wahai Ummu Salamah, janganlah engkau menyakitiku mengenai diri Aisyah, karena demi Allah, sesungguhnya tidaklah datang kepadaku wahyu dalam selimut seorang wanita diantara kalian kecuali dia.\""},"3713":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ آدَمَ عَنْ عَبْدَةَ عَنْ هِشَامٍ عَنْ عَوْفِ بْنِ الْحَارِثِ عَنْ رُمَيْثَةَ عَنْ أُمِّ سَلَمَةَأَنَّ نِسَاءَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَلَّمْنَهَا أَنْ تُكَلِّمَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ النَّاسَ كَانُوا يَتَحَرَّوْنَ بِهَدَايَاهُمْ يَوْمَ عَائِشَةَ وَتَقُولُ لَهُ إِنَّا نُحِبُّ الْخَيْرَ كَمَا تُحِبُّ عَائِشَةَ فَكَلَّمَتْهُ فَلَمْ يُجِبْهَا فَلَمَّا دَارَ عَلَيْهَا كَلَّمَتْهُ أَيْضًا فَلَمْ يُجِبْهَا وَقُلْنَ مَا رَدَّ عَلَيْكِ قَالَتْ لَمْ يُجِبْنِي قُلْنَ لَا تَدَعِيهِ حَتَّى يَرُدَّ عَلَيْكِ أَوْ تَنْظُرِينَ مَا يَقُولُ فَلَمَّا دَارَ عَلَيْهَا كَلَّمَتْهُ فَقَالَ لَا تُؤْذِينِي فِي عَائِشَةَ فَإِنَّهُ لَمْ يَنْزِلْ عَلَيَّ الْوَحْيُ وَأَنَا فِي لِحَافِ امْرَأَةٍ مِنْكُنَّ إِلَّا فِي لِحَافِ عَائِشَةَقَالَ أَبُو عَبْد الرَّحْمَنِ هَذَانِ الْحَدِيثَانِ صَحِيحَانِ عَنْ عَبْدَةَ","id":"Telah mengabarkan kepada kami [Muhammad bin Adam] dari ['Abdah] dari [Hisyam] dari ['Auf bin Al Harits] dari [Rumaitsah] dari [Ummu Salamah] bahwa para isteri Nabi shallallahu 'alaihi wasallam berbicara kepadanya agar dia berbicara kepada Nabi shallallahu 'alaihi wasallam bahwa orang-orang mengkhususkan hadiah mereka pada hari giliran Aisyah dan berkata kepada beliau; \"Sesungguhnya kami mencintai kebaikan sebagaimana Tuan mencintai Aisyah.\" Kemudian Ummu Salamah berbicara kepada beliau tetapi beliau tidak menjawabnya. Kemudian ketika tiba hari gilirannya, Ummu Salamah mengatakannya kembali kepada beliau, tetapi beliau tidak menjawabnya. Para isteri beliau berkata; \"Beliau tidak menjawabmu.\" Dia berkata; \"Beliau tidak menjawabku.\" Mereka berkata; \"Janganlah engkau tinggalkan beliau hingga beliau menjawabmu atau engkau melihat apa yang beliau katakan. Kemudian tatkala tiba hari gilirannya dia mengatakannya lagi kepada beliau. Kemudian beliau bersabda: \"Janganlah engkau menyakitiku mengenai diri Aisyah, demi Allah tidaklah datang kepadaku wahyu dalam selimut seorang wanita diantara kalian kecuali dia.\" Abu Abdur Rahman berkata; \"Ini adalah dua hadits shohih dari 'Abdah.\""},"3714":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عَبْدَةُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا هِشَامٌ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْكَانَ النَّاسُ يَتَحَرَّوْنَ بِهَدَايَاهُمْ يَوْمَ عَائِشَةَ يَبْتَغُونَ بِذَلِكَ مَرْضَاةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] telah memberitakan kepada kami ['Abdah bin Sulaiman] telah menceritakan kepada kami [Hisyam] dari [ayahnya] dari ['Aisyah], dia berkata; \"Orang-orang mengkhususkan hadiah mereka ketika hari giliran 'Aisyah, mereka mengharapkan keridhaan Rasulullah shallallahu 'alaihi wasallam.\""},"3715":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ آدَمَ عَنْ عَبْدَةَ عَنْ هِشَامٍ عَنْ صَالِحِ بْنِ رَبِيعَةَ بْنِ هُدَيْرٍ عَنْ عَائِشَةَ قَالَتْأَوْحَى اللَّهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا مَعَهُ فَقُمْتُ فَأَجَفْتُ الْبَابَ بَيْنِي وَبَيْنَهُ فَلَمَّا رُفِّهَ عَنْهُ قَالَ لِي يَا عَائِشَةُ إِنَّ جِبْرِيلَ يُقْرِئُكِ السَّلَامَ","id":"Telah mengabarkan kepada kami [Muhammad bin Adam] dari ['Abdah] dari [Hisyam] dari [Shalih bin Rabi'ah bin Hudair] dari [Aisyah], dia berkata; \"Allah mewahyukan kepada Nabi shallallahu 'alaihi wasallam ketika saya tengah bersama beliau kemudian saya berdiri dan menutup pintu antara diriku dan beliau, kemudian tatkala beliau beristirahat darinya (selesai menerima wahyu) beliau bersabda kepadaku: \"Wahai Aisyah, sesungguhnya Jibril mengucapkan salam kepadamu.\""},"3716":{"ar":"أَخْبَرَنَا نُوحُ بْنُ حَبِيبٍ قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَهَا إِنَّ جِبْرِيلَ يَقْرَأُ عَلَيْكِ السَّلَامَ قَالَتْ وَعَلَيْهِ السَّلَامُ وَرَحْمَةُ اللَّهِ وَبَرَكَاتُهُ تَرَى مَا لَا نَرَى","id":"Telah mengabarkan kepada kami [Nuh bin Habib] telah menceritakan kepada kami [Abdurrazzaq] telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari ['Urwah] dari [Aisyah] bahwa Nabi shallallahu 'alaihi wasallam bersabda kepadanya: \"sesungguhnya Jibril mengucapkan salam kepadamu.\" 'Aisyah berkata; wa 'alaihis salaam wa rahmatullaahi wa barakaatuh. Tuan melihat apa yang tidak kami lihat.\""},"3717":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا الْحَكَمُ بْنُ نَافِعٍ قَالَ أَنْبَأَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي أَبُو سَلَمَةَ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا عَائِشَةُ هَذَا جِبْرِيلُ وَهُوَ يَقْرَأُ عَلَيْكِ السَّلَامَ مِثْلَهُ سَوَاءٌقَالَ أَبُو عَبْد الرَّحْمَنِ هَذَا الصَّوَابُ وَالَّذِي قَبْلَهُ خَطَأٌ","id":"Telah mengabarkan kepada kami ['Amru bin Manshur] telah menceritakan kepada kami [Al Hakam bin Nafi'] telah memberitakan kepada kami [Syu'aib] dari [Az Zuhri] telah memberitakan kepada kami [Abu Salamah] dari ['Aisyah], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai Aisyah, ini Jibril dia mengucapkan salam kepadamu.\" sama seperti hadits sebelumnya. Abu Abdurrahman berkata; \"Ini adalah yang benar dan yang sebelumnya adalah salah.\""},"3718":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا حُمَيْدٌ قَالَ حَدَّثَنَا أَنَسٌ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَ إِحْدَى أُمَّهَاتِ الْمُؤْمِنِينَ فَأَرْسَلَتْ أُخْرَى بِقَصْعَةٍ فِيهَا طَعَامٌ فَضَرَبَتْ يَدَ الرَّسُولِ فَسَقَطَتْ الْقَصْعَةُ فَانْكَسَرَتْ فَأَخَذَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْكِسْرَتَيْنِ فَضَمَّ إِحْدَاهُمَا إِلَى الْأُخْرَى فَجَعَلَ يَجْمَعُ فِيهَا الطَّعَامَ وَيَقُولُ غَارَتْ أُمُّكُمْ كُلُوا فَأَكَلُوا فَأَمْسَكَ حَتَّى جَاءَتْ بِقَصْعَتِهَا الَّتِي فِي بَيْتِهَا فَدَفَعَ الْقَصْعَةَ الصَّحِيحَةَ إِلَى الرَّسُولِ وَتَرَكَ الْمَكْسُورَةَ فِي بَيْتِ الَّتِي كَسَرَتْهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Khalid] telah menceritakan kepada kami [Humaid] telah menceritakan kepada kami [Anas], dia berkata; \"Nabi shallallahu 'alaihi wasallam pernah berada pada salah satu Ummul mukminin, kemudian ummul mukminin yang lain mengirimkan nampan yang berisi makanan. Kemudian dia memukul tangan Rasulullah shallallahu 'alaihi wasallam sehingga nampan tersebut terjatuh dan pecah. Lalu Nabi shallallahu 'alaihi wasallam mengambil dua pecahan tersebut dan menggabungkan satu dengan yang lainnya. Kemudian beliau mengumpulkan makanan yang ada dalamnya dan bersabda: \"Ibu kalian telah cemburu, makanlah, makanlah.\" Kemudian beliau memegang hingga ummul mukminin datang membawa nampan yang ada di rumahnya. Kemudian beliau menyerahkan nampan yang baik kepada seorang utusan dan meninggalkan nampan yang pecah di rumah isteri beliau yang memecahkannya.\""},"3719":{"ar":"أَخْبَرَنَا الرَّبِيعُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا أَسَدُ بْنُ مُوسَى قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ ثَابِتٍ عَنْ أَبِي الْمُتَوَكِّلِ عَنْ أُمِّ سَلَمَةَأَنَّهَا يَعْنِي أَتَتْ بِطَعَامٍ فِي صَحْفَةٍ لَهَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَصْحَابِهِ فَجَاءَتْ عَائِشَةُ مُتَّزِرَةً بِكِسَاءٍ وَمَعَهَا فِهْرٌ فَفَلَقَتْ بِهِ الصَّحْفَةَ فَجَمَعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ فِلْقَتَيْ الصَّحْفَةِ وَيَقُولُ كُلُوا غَارَتْ أُمُّكُمْ مَرَّتَيْنِ ثُمَّ أَخَذَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَحْفَةَ عَائِشَةَ فَبَعَثَ بِهَا إِلَى أُمِّ سَلَمَةَ وَأَعْطَى صَحْفَةَ أُمِّ سَلَمَةَ عَائِشَةَ","id":"Telah mengabarkan kepada kami [Ar Rabi' bin Sulaiman] telah menceritakan kepada kami [Asad bin Musa] telah menceritakan kepada kami [Hammad bin Salamah] dari [Tsabit] dari [Abu Al Mutawakkil] dari [Ummu Salamah] bahwa dia datang dengan membawa makanan di atas piringnya kepada Rasulullah shallallahu 'alaihi wasallam dan para sahabat beliau, lalu datanglah 'Aisyah dengan bersarungkan pakaian, dia datang membawa batu, lalu memecah piring itu dengannya, kemudian Nabi shallallahu 'alaihi wasallam mengumpulkan dua pecahan piring dan bersabda: \" Makanlah, ibu kalian telah cemburu, \" dua kali, lalu Rasulullah shallallahu 'alaihi wasallam mengambil piring 'Aisyah dan mengirimnya kepada Ummu Salamah dan memberikan piring Ummu Salamah kepada 'Aisyah."},"3720":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى عَنْ عَبْدِ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ فُلَيْتٍ عَنْ جَسْرَةَ بِنْتِ دَجَاجَةَ عَنْ عَائِشَةَ قَالَتْمَا رَأَيْتُ صَانِعَةَ طَعَامٍ مِثْلَ صَفِيَّةَ أَهْدَتْ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَاءً فِيهِ طَعَامٌ فَمَا مَلَكْتُ نَفْسِي أَنْ كَسَرْتُهُ فَسَأَلْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ كَفَّارَتِهِ فَقَالَ إِنَاءٌ كَإِنَاءٍ وَطَعَامٌ كَطَعَامٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dari [Abdurrahman] dari [Sufyan] dari [Fulait] dari [Jasrah binti Dajajah] dari [Aisyah], dia berkata; \"Saya tidak melihat seorang wanita pembuat makanan seperti Shafiyah, dia memberikan hadiah kepada Nabi shallallahu 'alaihi wasallam bejana yang berisi makanan, kemudian saya tidak dapat menahan diriku untuk memecahkannya. Lalu saya bertanya kepada Nabi shallallahu 'alaihi wasallam mengenai kafarah hal tersebut maka beliau bersabda: \"Bejana seperti bejana dan makanan seperti makanan.\""},"3721":{"ar":"أَخْبَرَنَا الْحَسَنُ بْنُ مُحَمَّدٍ الزَّعْفَرَانِيُّ قَالَ حَدَّثَنَا حَجَّاجٌ عَنْ ابْنِ جُرَيْجٍ عَنْ عَطَاءٍ أَنَّهُ سَمِعَ عُبَيْدَ بْنَ عُمَيْرٍ يَقُولُ سَمِعْتُ عَائِشَةَ تَزْعُمُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَمْكُثُ عِنْدَ زَيْنَبَ بِنْتِ جَحْشٍ فَيَشْرَبُ عِنْدَهَا عَسَلًا فَتَوَاصَيْتُ أَنَا وَحَفْصَةُ أَنَّ أَيَّتُنَا دَخَلَ عَلَيْهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلْتَقُلْ إِنِّي أَجِدُ مِنْكَ رِيحَ مَغَافِيرَ أَكَلْتَ مَغَافِيرَ فَدَخَلَ عَلَى إِحْدَاهُمَا فَقَالَتْ ذَلِكَ لَهُ فَقَالَ لَا بَلْ شَرِبْتُ عَسَلًا عِنْدَ زَيْنَبَ بِنْتِ جَحْشٍ وَلَنْ أَعُودَ لَهُ فَنَزَلَتْ{ يَا أَيُّهَا النَّبِيُّ لِمَ تُحَرِّمُ مَا أَحَلَّ اللَّهُ لَكَ }{ إِنْ تَتُوبَا إِلَى اللَّهِ }لِعَائِشَةَ وَحَفْصَةَ{ وَإِذْ أَسَرَّ النَّبِيُّ إِلَى بَعْضِ أَزْوَاجِهِ حَدِيثًا }لِقَوْلِهِ بَلْ شَرِبْتُ عَسَلًا","id":"Telah mengabarkan kepada kami [Al Hasan bin Muhammad Az Za'farani] telah menceritakan kepada kami [Hajjaj] dari [Ibnu Juraij] dari ['Atho`] bahwa dia mendengar ['Ubaid bin 'Umair] berkata; \"Saya mendengar [Aisyah] mengaku bahwa Rasulullah shallallahu 'alaihi wasallam pernah tinggal di rumah Zainab binti Jahsy dan beliau minum madu di rumahnya. Kemudian saya dan Hafshah bersepakat bahwa siapapun diantara kami yang ditemui Nabi shallallahu 'alaihi wasallam hendaknya dia mengatakan; \"Sesungguhnya saya mendapatkan bau maghafir (tumbuhan bergetah yang manis rasanya tapi baunya tak sedap), Tuan telah memakan maghafir. Kemudian beliau menemui salah seorang dari mereka, kemudian dia mengatakan hal tersebut kepada beliau. Kemudian beliau bersabda: \"Tidak, melainkan saya minum madu di rumah Zainab binti Jahsy, dan saya tidak akan mengulanginya lagi.\" Kemudian turunlah ayat: \"Hai Nabi, mengapa kamu mengharamkan apa yang Allah halalkan bagimu' dan ayat 'Jika kamu berdua bertaubat kepada Allah..' untuk Aisyah dan Hafshah, serta ayat: 'Dan ingatlah ketika Nabi membicarakan secara rahasia kepada salah seorang isterinya (Hafsah) suatu peristiwa. Karena sabda beliau: melainkan saya minum madu. "},"3722":{"ar":"أَخْبَرَنِي إِبْرَاهِيمُ بْنُ يُونُسَ بْنِ مُحَمَّدٍ حَرَمِيٌّ هُوَ لَقَبُهُ قَالَ حَدَّثَنَا أَبِي قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ ثَابِتٍ عَنْ أَنَسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَتْ لَهُ أَمَةٌ يَطَؤُهَا فَلَمْ تَزَلْ بِهِ عَائِشَةُ وَحَفْصَةُ حَتَّى حَرَّمَهَا عَلَى نَفْسِهِ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ يَا أَيُّهَا النَّبِيُّ لِمَ تُحَرِّمُ مَا أَحَلَّ اللَّهُ لَكَ }إِلَى آخِرِ الْآيَةِ","id":"Telah mengabarkan kepada kami [Ibrahim bin Yunus bin Muhammad Harami] itu adalah julukannya, ia berkata; telah menceritakan kepada kami [ayahku], ia berkata; telah menceritakan kepada kami [Hammad bin Salamah] dari [Tsabit] dari [Anas] bahwa Rasulullah shallallahu 'alaihi wasallam memiliki budak yang beliau gauli, dan 'Aisyah serta Hafshoh masih berada bersama beliau hingga beliau mengharamkan atas diri beliau, kemudian Allah Azza wa jalla menurunkan ayat: Hai Nabi, mengapa kamu mengharamkan apa yang Allah halalkan bagimu... sampai akhir ayat. "},"3723":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ يَحْيَى هُوَ ابْنُ سَعِيدٍ الْأَنْصَارِيُّ عَنْ عُبَادَةَ بْنِ الْوَلِيدِ بْنِ عُبَادَةَ بْنِ الصَّامِتِ أَنَّ عَائِشَةَ قَالَتْالْتَمَسْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَدْخَلْتُ يَدِي فِي شَعْرِهِ فَقَالَ قَدْ جَاءَكِ شَيْطَانُكِ فَقُلْتُ أَمَا لَكَ شَيْطَانٌ فَقَالَ بَلَى وَلَكِنَّ اللَّهَ أَعَانَنِي عَلَيْهِ فَأَسْلَمَ","id":"Telah mengabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Al Laits] dari [Yahya bin Sa'id Al Anshari] dari ['Ubadah bin Al Walid bin 'Ubadah bin Ash Shamit] bahwa [Aisyah] berkata; saya mencari Rasulullah shallallahu 'alaihi wasallam kemudian memasukkan tanganku pada rambutnya, kemudian beliau bersabda: \"Telah datang kepadamu syetanmu.\" Kemudian saya katakan; apakah engkau memilki syetan? Beliau bersabda: \"Benar, akan tetapi Allah telah membantuku untuk menundukkannya sehingga ia masuk Islam.\""},"3724":{"ar":"أَخْبَرَنِي إِبْرَاهِيمُ بْنُ الْحَسَنِ الْمِقْسَمِيُّ عَنْ حَجَّاجٍ عَنْ ابْنِ جُرَيْجٍ عَنْ عَطَاءٍ أَخْبَرَنِي ابْنُ أَبِي مُلَيْكَةَ عَنْ عَائِشَةَ قَالَتْفَقَدْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ لَيْلَةٍ فَظَنَنْتُ أَنَّهُ ذَهَبَ إِلَى بَعْضِ نِسَائِهِ فَتَجَسَّسْتُهُ فَإِذَا هُوَ رَاكِعٌ أَوْ سَاجِدٌ يَقُولُ سُبْحَانَكَ وَبِحَمْدِكَ لَا إِلَهَ إِلَّا أَنْتَ فَقُلْتُ بِأَبِي وَأُمِّي إِنَّكَ لَفِي شَأْنٍ وَإِنِّي لَفِي شَأْنٍ آخَرَ","id":"Telah mengabarkan kepada kami [Ibrahim bin Al Hasan Al Miqsami] dari [Hajjaj] dari [Ibnu Juraij] dari ['Atho`], telah mengabarkan kepadaku [Ibnu Abi Mulaikah] dari [Aisyah], ia berkata; saya kehilangan Rasulullah shallallahu 'alaihi wasallam pada suatu malam, dan saya mengira bahwa beliau pergi kepada sebagian isterinya kemudian saya meraba-raba, ternyata beliau sedang melakukan ruku' atau sujud. Beliau mengucapkan: Subhaanaka wa bihamdika laa ilaaha illaa anta.\" Dan saya katakan; dengan ayah dan ibuku, sesungguhnya engkau berada dalam suatu keadaan dan saya dalam keadaan yang lain.\""},"3725":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَنْبَأَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي ابْنُ أَبِي مُلَيْكَةَ أَنَّ عَائِشَةَ قَالَتْافْتَقَدْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ لَيْلَةٍ فَظَنَنْتُ أَنَّهُ ذَهَبَ إِلَى بَعْضِ نِسَائِهِ فَتَجَسَّسْتُ ثُمَّ رَجَعْتُ فَإِذَا هُوَ رَاكِعٌ أَوْ سَاجِدٌ يَقُولُ سُبْحَانَكَ وَبِحَمْدِكَ لَا إِلَهَ إِلَّا أَنْتَ فَقُلْتُ بِأَبِي وَأُمِّي إِنَّكَ لَفِي شَأْنٍ وَإِنِّي لَفِي آخَرَ","id":"Telah mengabarkan kepada kami [Ishaq bin Manshur], ia berkata; telah menceritakan kepada kami [Abdur Razzaq], ia berkata; telah memberitakan kepada kami [Ibnu Juraij], ia berkata; telah mengabarkan kepadaku [Ibnu Mulaikah] bahwa [Aisyah] berkata; saya mencari-cari Rasulullah shallallahu 'alaihi wasallam pada suatu malam, dan saya mengira bahwa beliau pergi kepada sebagian isterinya kemudian saya meraba-raba kemudian kembali, ternyata beliau sedang melakukan ruku' atau sujud. Beliau mengucapkan: Subhaanaka wa bihamdika laa ilaaha illaa anta.\" Dan saya katakan; dengan ayah dan ibuku, sesungguhnya engkau berada dalam suatu keadaan dan saya dalam keadaan yang lain.\""},"3726":{"ar":"أَخْبَرَنَا سُلَيْمَانُ بْنُ دَاوُدَ قَالَ أَنْبَأَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي ابْنُ جُرَيْجٍ عَنْ عَبْدِ اللَّهِ بْنِ كَثِيرٍ أَنَّهُ سَمِعَ مُحَمَّدَ بْنَ قَيْسٍ يَقُولُ سَمِعْتُ عَائِشَةَ تَقُولُأَلَا أُحَدِّثُكُمْ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَنِّي قُلْنَا بَلَى قَالَتْ لَمَّا كَانَتْ لَيْلَتِي انْقَلَبَ فَوَضَعَ نَعْلَيْهِ عِنْدَ رِجْلَيْهِ وَوَضَعَ رِدَاءَهُ وَبَسَطَ إِزَارَهُ عَلَى فِرَاشِهِ وَلَمْ يَلْبَثْ إِلَّا رَيْثَمَا ظَنَّ أَنِّي قَدْ رَقَدْتُ ثُمَّ انْتَعَلَ رُوَيْدًا وَأَخَذَ رِدَاءَهُ رُوَيْدًا ثُمَّ فَتَحَ الْبَابَ رُوَيْدًا وَخَرَجَ وَأَجَافَهُ رُوَيْدًا وَجَعَلْتُ دِرْعِي فِي رَأْسِي فَاخْتَمَرْتُ وَتَقَنَّعْتُ إِزَارِي وَانْطَلَقْتُ فِي إِثْرِهِ حَتَّى جَاءَ الْبَقِيعَ فَرَفَعَ يَدَيْهِ ثَلَاثَ مَرَّاتٍ وَأَطَالَ الْقِيَامَ ثُمَّ انْحَرَفَ وَانْحَرَفْتُ فَأَسْرَعَ فَأَسْرَعْتُ فَهَرْوَلَ فَهَرْوَلْتُ فَأَحْضَرَ فَأَحْضَرْتُ وَسَبَقْتُهُ فَدَخَلْتُ وَلَيْسَ إِلَّا أَنْ اضْطَجَعْتُ فَدَخَلَ فَقَالَ مَا لَكِ يَا عَائِشُ رَابِيَةً قَالَ سُلَيْمَانُ حَسِبْتُهُ قَالَ حَشْيَا قَالَ لَتُخْبِرِنِّي أَوْ لَيُخْبِرَنِّي اللَّطِيفُ الْخَبِيرُ قُلْتُ يَا رَسُولَ اللَّهِ بِأَبِي أَنْتَ وَأُمِّي فَأَخْبَرْتُهُ الْخَبَرَ قَالَ أَنْتِ السَّوَادُ الَّذِي رَأَيْتُ أَمَامِي قُلْتُ نَعَمْ قَالَتْ فَلَهَدَنِي لَهْدَةً فِي صَدْرِي أَوْجَعَتْنِي قَالَ أَظَنَنْتِ أَنْ يَحِيفَ اللَّهُ عَلَيْكِ وَرَسُولُهُ قَالَتْ مَهْمَا يَكْتُمْ النَّاسُ فَقَدْ عَلِمَهُ اللَّهُ عَزَّ وَجَلَّ قَالَ نَعَمْ قَالَ فَإِنَّ جِبْرِيلَ عَلَيْهِ السَّلَام أَتَانِي حِينَ رَأَيْتِ وَلَمْ يَكُنْ يَدْخُلُ عَلَيْكِ وَقَدْ وَضَعْتِ ثِيَابَكِ فَنَادَانِي فَأَخْفَى مِنْكِ فَأَجَبْتُهُ وَأَخْفَيْتُهُ مِنْكِ وَظَنَنْتُ أَنَّكِ قَدْ رَقَدْتِ فَكَرِهْتُ أَنْ أُوقِظَكِ وَخَشِيتُ أَنْ تَسْتَوْحِشِي فَأَمَرَنِي أَنْ آتِيَ أَهْلَ الْبَقِيعِ فَأَسْتَغْفِرَ لَهُمْخَالَفَهُ حَجَّاجُ بْنُ مُحَمَّدٍ فَقَالَ عَنْ ابْنِ جُرَيْجٍ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ مُحَمَّدِ بْنِ قَيْسٍ","id":"Telah mengabarkan kepada kami [Sulaiman bin Daud], ia berkata; telah memberitakan kepada kami [Ibnu Wahb], ia berkata; telah mengabarkan kepadaku [Ibnu Juraij] dari [Abdullah bin Katsir] bahwa ia mendengar [Muhammad bin Qais] berkata; saya mendengar [Aisyah] berkata; maukah saya ceritakan kepada kalian mengenai Nabi shallallahu 'alaihi wasallam dan dariku? Kami mengatakan; ya. Ia berkata; ketika datang malam giliranku beliau berbalik kemudian beliau meletakkan kedua sandalnya di kedua kakinya, dan meletakkan selendangnya di tengah sarungnya di atas kasurnya. Dan tidak lama kemudian beliau menyangka bahwa saya telah tertidur kemudian beliau memakai sandalnya perlahan dan mengambil selendangnya kemudian membuka pintu perlahan, dan keluar dan menutupnya perlahan. Dan saya meletakkan bajuku di kepala dan menutupi kepalaku dengan sarungku, dan pergi menikuti beliau hingga beliau sampai di Baqi' kemudian mengangkat kedua tangannya tiga kali dan beliau berdiri lama. Kemudian beliau pergi dan berjalan cepat dan saya berjalan cepat, beliau berlari-lari kecil dan sayapun berlari-lari kecil. Kemudian sampai rumah dan sayapun telah sampai dan mendahului beliau. Beliau bersabda: \"Engkau terengah-engah, sungguh engkau memberitahuku atau Allah yang Maha Lembut dan Mengetahui akan memberitahuku?\" saya katakan; wahai Rasulullah, tebusanmu dengan ayah dan ibuku.... kemudian saya beritahu beliau. Beliau bersabda: \"Apakah engkau bayangan hitam yang saya lihat di depanku?\" saya katakan; ya. Aisyah berkata; kemudian beliau dadaku dengan pulukan yang membuatku merasa sakit. Beliau bersabda: \"Engkau menyangka bahwa Allah dan RasulullahNya akan berlaku sewenang-wenang kepadamu?\" Aisyah berkata; bagaimanapun orang menyembunyikan sungguh Allah 'azza wajalla telah mengetahuinya. Beliau bersabda: \"Ya, sesungguhnya Jibril 'alaihis salam telah datang kepadaku ketika engkau melihat dan ia tidak menemuimu sedang engkau telah meletakkan pakaianmu. Kemudian ia memanggilku dan menyembunyikannya darimu. Kemudian saya menjawabnya dan menyembunyikannya darimu. Saya mengira bahwa engkau telah tertidur, sehingga tidak inggin membangunkanmu karena khawatir engkau merasa kesepian. Kemudian ia memerintahkanku agar mendatangi penghuni Baqi' dan memintakan ampunan untuk mereka.\" Hajjaj bin Muhammad telah menyelisihinya, ia berkata; dari Ibnu Juraij dari Ibnu Mulaikah dari Muhammad bin Qais..... "},"3727":{"ar":"حَدَّثَنَا يُوسُفُ بْنُ سَعِيدِ بْنِ مُسْلِمٍ الْمِصِّيصِيُّ قَالَ حَدَّثَنَا حَجَّاجٌ عَنْ ابْنِ جُرَيْجٍ أَخْبَرَنِي عَبْدُ اللَّهِ ابْنُ أَبِي مُلَيْكَةَ أَنَّهُ سَمِعَ مُحَمَّدَ بْنَ قَيْسِ بْنِ مَخْرَمَةَ يَقُولُ سَمِعْتُ عَائِشَةَ تُحَدِّثُ قَالَتْأَلَا أُحَدِّثُكُمْ عَنِّي وَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْنَا بَلَى قَالَتْ لَمَّا كَانَتْ لَيْلَتِي الَّتِي هُوَ عِنْدِي تَعْنِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْقَلَبَ فَوَضَعَ نَعْلَيْهِ عِنْدَ رِجْلَيْهِ وَوَضَعَ رِدَاءَهُ وَبَسَطَ طَرَفَ إِزَارِهِ عَلَى فِرَاشِهِ فَلَمْ يَلْبَثْ إِلَّا رَيْثَمَا ظَنَّ أَنِّي قَدْ رَقَدْتُ ثُمَّ انْتَعَلَ رُوَيْدًا وَأَخَذَ رِدَاءَهُ رُوَيْدًا ثُمَّ فَتَحَ الْبَابَ رُوَيْدًا وَخَرَجَ وَأَجَافَهُ رُوَيْدًا وَجَعَلْتُ دِرْعِي فِي رَأْسِي وَاخْتَمَرْتُ وَتَقَنَّعْتُ إِزَارِي فَانْطَلَقْتُ فِي إِثْرِهِ حَتَّى جَاءَ الْبَقِيعَ فَرَفَعَ يَدَيْهِ ثَلَاثَ مَرَّاتٍ وَأَطَالَ الْقِيَامَ ثُمَّ انْحَرَفَ فَانْحَرَفْتُ فَأَسْرَعَ فَأَسْرَعْتُ فَهَرْوَلَ فَهَرْوَلْتُ فَأَحْضَرَ فَأَحْضَرْتُ وَسَبَقْتُهُ فَدَخَلْتُ فَلَيْسَ إِلَّا أَنْ اضْطَجَعْتُ فَدَخَلَ فَقَالَ مَا لَكِ يَا عَائِشَةُ حَشْيَا رَابِيَةً قَالَتْ لَا قَالَ لَتُخْبِرِنِّي أَوْ لَيُخْبِرَنِّي اللَّطِيفُ الْخَبِيرُ قُلْتُ يَا رَسُولَ اللَّهِ بِأَبِي أَنْتَ وَأُمِّي فَأَخْبَرْتُهُ الْخَبَرَ قَالَ فَأَنْتِ السَّوَادُ الَّذِي رَأَيْتُهُ أَمَامِي قَالَتْ نَعَمْ قَالَتْ فَلَهَدَنِي فِي صَدْرِي لَهْدَةً أَوْجَعَتْنِي ثُمَّ قَالَ أَظَنَنْتِ أَنْ يَحِيفَ اللَّهُ عَلَيْكِ وَرَسُولُهُ قَالَتْ مَهْمَا يَكْتُمْ النَّاسُ فَقَدْ عَلِمَهُ اللَّهُ قَالَ نَعَمْ قَالَ فَإِنَّ جِبْرِيلَ عَلَيْهِ السَّلَام أَتَانِي حِينَ رَأَيْتِ وَلَمْ يَكُنْ يَدْخُلُ عَلَيْكِ وَقَدْ وَضَعْتِ ثِيَابَكِ فَنَادَانِي فَأَخْفَى مِنْكِ فَأَجَبْتُهُ فَأَخْفَيْتُ مِنْكِ فَظَنَنْتُ أَنْ قَدْ رَقَدْتِ وَخَشِيتُ أَنْ تَسْتَوْحِشِي فَأَمَرَنِي أَنْ آتِيَ أَهْلَ الْبَقِيعِ فَأَسْتَغْفِرَ لَهُمْرَوَاهُ عَاصِمٌ عَنْ عَبْدِ اللَّهِ بْنِ عَامِرٍ عَنْ عَائِشَةَ عَلَى غَيْرِ هَذَا اللَّفْظِ أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ أَنْبَأَنَا شَرِيكٌ عَنْ عَاصِمٍ عَنْ عَبْدِ اللَّهِ بْنِ عَامِرِ بْنِ رَبِيعَةَ عَنْ عَائِشَةَ قَالَتْ فَقَدْتُهُ مِنْ اللَّيْلِ وَسَاقَ الْحَدِيثَ","id":"Telah mengabarkan kepada kami [Yusuf bin Sa'id bin Muslim Al Mishshishi], ia berkata; telah menceritakan kepada kami [Hajjaj] dari [Ibnu Juraij] telah mengabarkan kepadaku [Abdullah bin Abi Mulaikah] bahwa ia mendengar [Muhammad bin Qais bin Makhramah] berkata; saya mendengar [Aisyah] menceritakan, ia berkata; maukah kalian saya ceritakan kepada kalian mengenai diriku dan Rasulullah shallallahu 'alaihi wasallam? Kami mengatakan; ya. Ia berkata; di saat malamku yang mana beliau ada di sisiku yaitu Nabi shallallahu 'alaihi wasallam, beliau berbalik dan meletakkan kedua sandalnya di kedua kakinya dan meletakkan selendangnya di tengah ujung sarungnya di atas kasurnya. Dan tidak lama kemudian beliau menyangka bahwa saya telah tertidur kemudian beliau memakai sandalnya perlahan dan mengambil selendangnya kemudian membuka pintu perlahan, dan keluar dan menutupnya perlahan. Dan saya meletakkan bajuku di kepala dan menutupi kepalaku dengan sarungku, dan pergi menikuti beliau hingga beliau sampai di Baqi' kemudian mengangkat kedua tangannya tiga kali dan beliau berdiri lama. Kemudian beliau pergi dan berjalan cepat dan saya berjalan cepat, beliau berlari-lari kecil dan sayapun berlari-lari kecil. Kemudian sampai rumah dan sayapun telah sampai dan mendahului beliau. Beliau bersabda: \"Engkau terengah-engah, sungguh engkau memberitahuku atau Allah yang Maha Lembut dan Mengetahui akan memberitahuku?\" saya katakan; wahai Rasulullah, tebusanmu dengan ayah dan ibuku.... kemudian saya beritahu beliau. Beliau bersabda: \"Apakah engkau bayangan hitam yang saya lihat di depanku?\" saya katakan; ya. Aisyah berkata; kemudian beliau dadaku dengan pulukan yang membuatku merasa sakit. Beliau bersabda: \"Engkau menyangka bahwa Allah dan RasulullahNya akan berlaku sewenang-wenang kepadamu?\" Aisyah berkata; bagaimanapun orang menyembunyikan sungguh Allah 'azza wajalla telah mengetahuinya. Beliau bersabda: \"Ya, sesungguhnya Jibril 'alaihis salam telah datang kepadaku ketika engkau melihat dan ia tidak menemuimu sedang engkau telah meletakkan pakaianmu. Kemudian ia memanggilku dan menyembunyikannya darimu. Kemudian saya menjawabnya dan menyembunyikannya darimu. Saya mengira bahwa engkau telah tertidur, sehingga tidak inggin membangunkanmu karena khawatir engkau merasa kesepian. Kemudian ia memerintahkanku agar mendatangi penghuni Baqi' dan memintakan ampunan untuk mereka.\" Ashim telah meriwayatkannya dari Abdullah bin 'Amir bin Rabi'ah dari Aisyah dengan lafadz yang lain. Telah mengabarkan kepada kami [Ali bin Hujr] dia berkata; telah memberitakan kepada kami [Syarik] dari [Ashim] dari [Abdullah bin Amir bin Rabi'ah] dari [Aisyah], ia berkata; saya kehilangan beliau pada suatu malam....dan ia menyebutkan hadits tersebut. "},"3728":{"ar":"أَخْبَرَنَا هَارُونُ بْنُ مُحَمَّدِ بْنِ بَكَّارِ بْنِ بِلَالٍ عَنْ مُحَمَّدِ بْنِ عِيسَى وَهُوَ ابْنُ سُمَيْعٍ قَالَ حَدَّثَنَا حُمَيْدٌ الطَّوِيلُ عَنْ أَنَسِ بْنِ مَالِكٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أُمِرْتُ أَنْ أُقَاتِلَ الْمُشْرِكِينَ حَتَّى يَشْهَدُوا أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ فَإِذَا شَهِدُوا أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ وَصَلَّوْا صَلَاتَنَا وَاسْتَقْبَلُوا قِبْلَتَنَا وَأَكَلُوا ذَبَائِحَنَا فَقَدْ حَرُمَتْ عَلَيْنَا دِمَاؤُهُمْ وَأَمْوَالُهُمْ إِلَّا بِحَقِّهَا","id":"Telah mengabarkan kepada kami [Harun bin Muhammad bin Bakkar bin Bilal] dari [Muhammad bin Isa yaitu Ibu Sa'id], ia berkata; telah menceritakan kepada kami [Humaid Ath Thawil] dari [Anas bin Malik] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \" Aku diperintah untuk memerangi kaum musyrikin hingga mereka bersaksi bahwa tiada Tuhan yang patut disembah kecuali hanya Allah dan bahwa Muhammad adalah hamba dan rasulNya, jika mereka bersaksi bahwa tiada tuhan yang patut disembah kecuali hanya Allah dan bahwa Muhammad adalah hamba dan rasulNya, mereka sholat dengan sholat kita menghadap kiblat kita, makan hewan sembelihan kami maka darah dan harta mereka haram atas kita kecuali dengan haq.\""},"3729":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ حَاتِمِ بْنِ نُعَيْمٍ قَالَ أَنْبَأَنَا حِبَّانُ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ عَنْ حُمَيْدِ بْنِ الطَّوِيلِ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أُمِرْتُ أَنْ أُقَاتِلَ النَّاسَ حَتَّى يَشْهَدُوا أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنَّ مُحَمَّدًا رَسُولُ اللَّهِ فَإِذَا شَهِدُوا أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنَّ مُحَمَّدًا رَسُولُ اللَّهِ وَاسْتَقْبَلُوا قِبْلَتَنَا وَأَكَلُوا ذَبِيحَتَنَا وَصَلَّوْا صَلَاتَنَا فَقَدْ حَرُمَتْ عَلَيْنَا دِمَاؤُهُمْ وَأَمْوَالُهُمْ إِلَّا بِحَقِّهَا لَهُمْ مَا لِلْمُسْلِمِينَ وَعَلَيْهِمْ مَا عَلَيْهِمْ","id":"Telah mengabarkan kepada kami [Muhammad bin Hatim bin Nu'aim], ia berkata; telah memberitakan kepada kami [Habban], ia berkata; telah menceritakan kepada kami [Abdullah] dari [Humaid bin Ath Thawil] dari [Anas bin Malik] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Saya diperintahkan untuk memerangi manusia hingga mereka bersaksi bahwa tidak ada Tuhan yang berhak disembah kecuali Allah dan Muhammad adalah Rasulullah, maka apabila bersaksi bahwa tidak ada Tuhan yang berhak disembah kecuali Allah dan Muhammad adalah Rasulullah, menghadap ke kiblat kita, memakan sembelihan kita, dan melakukan shalat kita maka sungguh telah haram atas kita darah mereka dan harta mereka kecuali dengan haknya, bagi mereka apa yang menjadi hak orang-orang muslimin dan kewajiban mereka apa yang menjadi kewajiban atas orang-orang muslimin.\" "},"3730":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا عَمْرُو بْنُ عَاصِمٍ قَالَ حَدَّثَنَا عِمْرَانُ أَبُو الْعَوَّامِ قَالَ حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَلَمَّا تُوُفِّيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ارْتَدَّتْ الْعَرَبُ فَقَالَ عُمَرُ يَا أَبَا بَكْرٍ كَيْفَ تُقَاتِلُ الْعَرَبَ فَقَالَ أَبُو بَكْرٍ إِنَّمَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُمِرْتُ أَنْ أُقَاتِلَ النَّاسَ حَتَّى يَشْهَدُوا أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنِّي رَسُولُ اللَّهِ وَيُقِيمُوا الصَّلَاةَ وَيُؤْتُوا الزَّكَاةَ وَاللَّهِ لَوْ مَنَعُونِي عَنَاقًا مِمَّا كَانُوا يُعْطُونَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَقَاتَلْتُهُمْ عَلَيْهِقَالَ عُمَرُ فَلَمَّا رَأَيْتُ رَأْيَ أَبِي بَكْرٍ قَدْ شُرِحَ عَلِمْتُ أَنَّهُ الْحَقُّ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar], ia berkata; telah menceritakan kepada kami ['Amr bin 'Ashim], ia berkata; telah menceritakan kepada kami [Imran Abu Al 'Awwam], ia berkata; telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Anas bin Malik], ia berkata; tatkala Rasulullah shallallahu 'alaihi wasallam wafat orang-orang Arab keluar dari agama Islam, kemudian Umar berkata; wahai Abu Bakar, bagaimana engkau memerangi orang-orang Arab? Maka [Abu Bakar] berkata; sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Saya diperintahkan untuk memerangi manusia hingga mereka bersaksi bahwa tidak Tuhan Yang berhak disembah kecuali Allah dan dan saya adalah Rasulullah, menegakkan shalat dan menunaikan zakat.\" Demi Allah seandainya mereka menahanku mengambil satu anak kambing saja diantara apa yang dahulunya mereka berikan kepada Rasulullah shallallahu 'alaihi wasallam niscaya saya akan memerangi mereka karenanya. Umar berkata; tatkala saya melihat pendapat Abu Bakar telah diberi kelapangan maka saya melihat bahwa dia adalah yang benar."},"3731":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَ��ِيدٍ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ الزُّهْرِيِّ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ أَبِي هُرَيْرَةَ قَالَلَمَّا تُوُفِّيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاسْتُخْلِفَ أَبُو بَكْرٍ وَكَفَرَ مَنْ كَفَرَ مِنْ الْعَرَبِ قَالَ عُمَرُ لِأَبِي بَكْرٍ كَيْفَ تُقَاتِلُ النَّاسَ وَقَدْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُمِرْتُ أَنْ أُقَاتِلَ النَّاسَ حَتَّى يَقُولُوا لَا إِلَهَ إِلَّا اللَّهُ فَمَنْ قَالَ لَا إِلَهَ إِلَّا اللَّهُ عَصَمَ مِنِّي مَالَهُ وَنَفْسَهُ إِلَّا بِحَقِّهِ وَحِسَابُهُ عَلَى اللَّهِ قَالَ أَبُو بَكْرٍ وَاللَّهِ لَأُقَاتِلَنَّ مَنْ فَرَّقَ بَيْنَ الصَّلَاةِ وَالزَّكَاةِ فَإِنَّ الزَّكَاةَ حَقُّ الْمَالِ وَاللَّهِ لَوْ مَنَعُونِي عِقَالًا كَانُوا يُؤَدُّونَهُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَقَاتَلْتُهُمْ عَلَى مَنْعِهِقَالَ عُمَرُ فَوَاللَّهِ مَا هُوَ إِلَّا أَنِّي رَأَيْتُ اللَّهَ شَرَحَ صَدْرَ أَبِي بَكْرٍ لِلْقِتَالِ فَعَرَفْتُ أَنَّهُ الْحَقُّ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id], ia berkata; telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Az Zuhri] telah mengabarkan kepadaku ['Ubaidullah bin Abdullah bin 'Utbah] dari [Abu Hurairah], ia berkata; tatkala Rasulullah shallallahu 'alaihi wasallam wafat dan Abu Bakar dipilih menjadi penggantinya, telah kafirlah orang yang kafir dari kalangan orang-orang Arab. [Umar] berkata kepada Abu Bakar; bagaimana engkau memerangi manusia sedangkan Rasulullah shallallahu 'alaihi wasallam telah bersabda: \"Saya diperintahkan untuk memerangi manusia hingga mereka mengucapkan LAA ILAAHA ILLALLAAH, barang siapa yang mengucapkan LAA ILAAHA ILLALLAAH, maka ia telah melindungi jiwa dan hartanya dariku kecuali dengan haknya dan perhitungannya kepada Allah.\" Maka [Abu Bakar] berkata; sungguh saya akan memerangi orang yang memisahkan antara shalat dan zakat, karena sesungguhnya zakat adalah haknya harta. Demi Allah seandainya mereka menahanku mengambil satu tali pengikat unta saja yang dahulunya mereka menunaikannya kepada Rasulullah shallallahu 'alaihi wasallam niscaya saya akan memerangi mereka karena menolak untuk memberikannya. Umar berkata; Demi Allah tidak lain kecuali saya melihat Allah 'azza wajalla telah melapangkan hati Abu Bakar untuk memerangi mereka dan saya tahu bahwa ia adalah yang benar. "},"3732":{"ar":"أَخْبَرَنَا زِيَادُ بْنُ أَيُّوبَ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ يَزِيدَ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُمِرْتُ أَنْ أُقَاتِلَ النَّاسَ حَتَّى يَقُولُوا لَا إِلَهَ إِلَّا اللَّهُ فَإِذَا قَالُوهَا فَقَدْ عَصَمُوا مِنِّي دِمَاءَهُمْ وَأَمْوَالَهُمْ إِلَّا بِحَقِّهَا وَحِسَابُهُمْ عَلَى اللَّهِ فَلَمَّا كَانَتْ الرِّدَّةُ قَالَ عُمَرُ لِأَبِي بَكْرٍ أَتُقَاتِلُهُمْ وَقَدْ سَمِعْتَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ كَذَا وَكَذَا فَقَالَ وَاللَّهِ لَا أُفَرِّقُ بَيْنَ الصَّلَاةِ وَالزَّكَاةِ وَلَأُقَاتِلَنَّ مَنْ فَرَّقَ بَيْنَهُمَافَقَاتَلْنَا مَعَهُ فَرَأَيْنَا ذَلِكَ رُشْدًا قَالَ أَبُو عَبْد الرَّحْمَنِ سُفْيَانُ فِي الزُّهْرِيِّ لَيْسَ بِالْقَوِيِّ وَهُوَ سُفْيَانُ بْنُ حُسَيْنٍ","id":"Telah mengabarkan kepada kami [Ziyad bin Ayyub], ia berkata; telah menceritakan kepada kami [Muhammad bin Yazid], ia berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari ['Ubaidullah bin Abdullah bin 'Utbah] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"\"Saya diperintahkan untuk memerangi manusia hingga mereka mengucapkan LAA ILAAHA ILLALLAAH apabila mereka telah mengucapkannya maka sungguh mereka telah melindungi jiwa dan harta mereka dariku kecuali dengan haknya dan perhitungannya kepada Allah.\" Kemudian tatkala terjadi kemurtadan [Umar] berkata kepada Abu Bakar; apakah engkau akan memerangi mereka sedang saya telah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \" demikian dan demikian? Maka [Abu Bakar] berkata; demi Allah saya tidak akan memisahkan antara shalat dan zakat. Dan sungguh saya akan memerangi orang yang memisahkan antara keduanya. Kemudian kami memerangi bersamanya, dan kami melihat hal tersebut sebagai petunjuk. Abu Abdurrahman berkata; Sufyan dalam riwayat Az Zuhri tidaklah kuat dan ia adalah Sufyan bin Husain. "},"3733":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ الْمُغِيرَةِ قَالَ حَدَّثَنَا عُثْمَانُ عَنْ شُعَيْبٍ عَنْ الزُّهْرِيِّ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ عُتْبَةَ أَنَّ أَبَا هُرَيْرَةَ قَالَلَمَّا تُوُفِّيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ أَبُو بَكْرٍ بَعْدَهُ وَكَفَرَ مَنْ كَفَرَ مِنْ الْعَرَبِ قَالَ عُمَرُ يَا أَبَا بَكْرٍ كَيْفَ تُقَاتِلُ النَّاسَ وَقَدْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُمِرْتُ أَنْ أُقَاتِلَ النَّاسَ حَتَّى يَقُولُوا لَا إِلَهَ إِلَّا اللَّهُ فَمَنْ قَالَ لَا إِلَهَ إِلَّا اللَّهُ فَقَدْ عَصَمَ مِنِّي مَالَهُ وَنَفْسَهُ إِلَّا بِحَقِّهِ وَحِسَابُهُ عَلَى اللَّهِ عَزَّ وَجَلَّ قَالَ أَبُو بَكْرٍ لَأُقَاتِلَنَّ مَنْ فَرَّقَ بَيْنَ الصَّلَاةِ وَالزَّكَاةِ فَإِنَّ الزَّكَاةَ حَقُّ الْمَالِ فَوَاللَّهِ لَوْ مَنَعُونِي عَنَاقًا كَانُوا يُؤَدُّونَهَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَقَاتَلْتُهُمْ عَلَى مَنْعِهَاقَالَ عُمَرُ فَوَاللَّهِ مَا هُوَ إِلَّا أَنْ رَأَيْتُ اللَّهَ شَرَحَ صَدْرَ أَبِي بَكْرٍ لِلْقِتَالِ فَعَرَفْتُ أَنَّهُ الْحَقُّ","id":"Telah mengabarkan kepada kami [Ahmad bin Muhammad bin Al Mughirah], ia berkata; telah menceritakan kepada kami [Utsman] dari [Syu'aib] dari [Az Zuhri], ia berkata; telah menceritakan kepada kami ['Ubaidullah bin Abdullah bin 'Utbah] bahwa [Abu Hurairah] berkata; tatkala Rasulullah shallallahu 'alaihi wasallam wafat dan Abu Bakar menggantikan setelahnya serta telah kafir orang yang kafir dari kalangan orang-orang Arab, [Umar] berkata; wahai Abu Bakar, bagaimana engkau memerangi manusia sedangkan Rasulullah shallallahu 'alaihi wasallam telah bersabda: \"Saya diperintahkan untuk memerangi manusia hingga mereka mengucapkan LAA ILAAHA ILLALLAAH barang siapa yang mengucapkan LAA ILAAHA ILLALLAAH, maka ia telah melindungi harta dan jiwanya kecuali dengan haknya dan perhitungannya kepada Allah 'azza wajalla.\" Maka [Abu Bakar] berkata; sungguh saya akan memerangi orang yang memisahkan antara shalat dan zakat, karena sesungguhnya zakat adalah haknya harta. Demi Allah seandainya mereka menolak memberikan kepadaku satu anak kambing saja yang dahulunya mereka menunaikannya kepada Rasulullah shallallahu 'alaihi wasallam niscaya saya akan memerangi mereka karena penolakan tersebut. Demi Allah tidak lain kecuali saya melihat Allah telah melapangkan hati Abu Bakar untuk memerangi mereka dan saya tahu bahwa ia adalah yang benar."},"3734":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ الْمُغِيرَةِ قَالَ حَدَّثَنَا عُثْمَانُ عَنْ شُعَيْبٍ عَنْ الزُّهْرِيِّ قَالَ حَدَّثَنِي سَعِيدُ بْنُ الْمُسَيَّبِ أَنَّ أَبَا هُرَيْرَةَ أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أُمِرْتُ أَنْ أُقَاتِلَ النَّاسَ حَتَّى يَقُولُوا لَا إِلَهَ إِلَّا اللَّهُ فَمَنْ قَالَهَا فَقَدْ عَصَمَ مِنِّي نَفْسَهُ وَمَالَهُ إِلَّا بِحَقِّهِ وَحِسَابُهُ عَلَى اللَّهِخَالَفَهُ الْوَلِيدُ بْنُ مُسْلِمٍ","id":"Telah mengabarkan kepada kami [Ahmad bin Muhammad bin Al Mughirah], ia berkata; telah menceritakan kepada kami [Utsman], dari [Syu'aib] dari [Az Zuhri], ia berkata; telah menceritakan kepadaku [Sa'id bin Al Musayyab] bahwa [Abu Hurairah] telah mengabarkan kepadanya bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Saya diperintahkan untuk memerangi manusia hingga mereka mengucapkan; LAA ILAAHA ILLALLAAH barang siapa yang mengucapkannya maka ia telah melindungi jiwa dan hartanya dariku kecuali dengan haknya dan perhitungannya kepada Allah.\" Al Walid bin Muslim telah menyelisihinya. "},"3735":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ قَالَ حَدَّثَنَا أَبُو مُعَاوِيَةَ ح وَأَنْبَأَنَا أَحْمَدُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُمِرْتُ أَنْ أُقَاتِلَ النَّاسَ حَتَّى يَقُولُوا لَا إِلَهَ إِلَّا اللَّهُ فَإِذَا قَالُوهَا مَنَعُوا مِنِّي دِمَاءَهُمْ وَأَمْوَالَهُمْ إِلَّا بِحَقِّهَا وَحِسَابُهُمْ عَلَى اللَّهِ عَزَّ وَجَلَّ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin Mubarak], ia berkata; telah memberitakan kepada kami [Abu Mu'awiyah]. Diriwayatkan dari jalur lainnya, telah memberitakan kepada kami [Ahmad bin Harb] dari [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] mereka berdua berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Saya diperintahkan untuk memerangi manusia hingga mereka mengucapkan LAA ILAAHA ILLALLAAH, apabila mereka mengucapkannya maka mereka telah melindungi darah dan harta mereka dariku kecuali dengan haknya dan perhitungannya kepada Allah 'azza wajalla.\""},"3736":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا يَعْلَى بْنُ عُبَيْدٍ عَنْ الْأَعْمَشِ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرٍ وَعَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَاقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُمِرْتُ أَنْ أُقَاتِلَ النَّاسَ حَتَّى يَقُولُوا لَا إِلَهَ إِلَّا اللَّهُ فَإِذَا قَالُوهَا مَنَعُوا مِنِّي دِمَاءَهُمْ وَأَمْوَالَهُمْ إِلَّا بِحَقِّهَا وَحِسَابُهُمْ عَلَى اللَّهِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim], ia berkata; telah memberitakan kepada kami [Ya'la bin 'Ubaid] dari [Al A'masy] dari [Abu Sufyan] dari [Jabir] dan dari [Abu Shalih] dari [Abu Hurairah] mereka berdua berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Saya diperintahkan untuk memerangi manusia hingga mereka mengucapkan LAA ILAAHA ILLALLAAH, apabila mereka mengucapkannya maka mereka telah melindungi darah dan harta mereka dariku kecuali dengan haknya dan perhitungannya kepada Allah 'azza wajalla.\""},"3737":{"ar":"أَخْبَرَنَا الْقَاسِمُ بْنُ زَكَرِيَّا بْنِ دِينَارٍ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى قَالَ حَدَّثَنَا شَيْبَانُ عَنْ عَاصِمٍ عَنْ زِيَادِ بْنِ قَيْسٍ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نُقَاتِلُ النَّاسَ حَتَّى يَقُولُوا لَا إِلَهَ إِلَّا اللَّهُ فَإِذَا قَالُوا لَا إِلَهَ إِلَّا اللَّهُ حَرُمَتْ عَلَيْنَا دِمَاؤُهُمْ وَأَمْوَالُهُمْ إِلَّا بِحَقِّهَا وَحِسَابُهُمْ عَلَى اللَّهِ","id":"Telah mengabarkan kepada kami [Al Qasim bin Zakariya bin Dinar], ia berkata; telah menceritakan kepada kami ['Ubaidullah bin Musa], ia berkata; telah menceritakan kepada kami [Syaiban] dari ['Ashim] dari [Ziyad bin Qais] dari [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Kami memerangi manusia hingga mereka mengucapkan LAA ILAAHA ILLALLAAH, apabila mereka mengucapkan LAA ILAAHA ILLALLAAH maka diharamkan atas kami darah dan harta mereka kecuali dengan haknya dan perhitungannya kepada Allah.\""},"3738":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مُعَاوِيَةَ بْنِ مَالَجَ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ الْحَرَّانِيُّ عَنْ ابْنِ إِسْحَقَ عَنْ إِبْرَاهِيمَ بْنِ مُهَاجِرٍ عَنْ إِسْمَعِيلَ مَوْلَى عَبْدِ اللَّهِ بْنِ عَمْرٍو عَنْ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ الْعَاصِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالَّذِي نَفْسِي بِيَدِهِ لَقَتْلُ مُؤْمِنٍ أَعْظَمُ عِنْدَ اللَّهِ مِنْ زَوَالِ الدُّنْيَاقَالَ أَبُو عَبْد الرَّحْمَنِ إِبْرَاهِيمُ بْنُ الْمُهَاجِرِ لَيْسَ بِالْقَوِيِّ","id":"Telah mengabarkan kepada kami [Muhammad bin Mu'awiyah bin Malij], ia berkata; telah menceritakan kepada kami [Muhammad bin Salamah Al Harrani] dari [Ibnu Ishaq] dari [Ibrahim bin Muhajir] dari [Isma'il] mantan budak Abdullah bin Amru, dari [Abdullah bin Amru bin Al 'Ash], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Demi Dzat yang jiwaku berada ditanganNya, sungguh terbunuhnya seorang mukmin lebih besar disisi Allah daripada hilangnya dunia, \" Abu abdurrahman berkata; Ibrahim bin Al Muhajir tidak kuat."},"3739":{"ar":"أَخْبَرَنَا يَحْيَى بْنُ حَكِيمٍ الْبَصْرِيُّ قَالَ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ شُعْبَةَ عَنْ يَعْلَى بْنِ عَطَاءٍ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَزَوَالُ الدُّنْيَا أَهْوَنُ عِنْدَ اللَّهِ مِنْ قَتْلِ رَجُلٍ مُسْلِمٍ","id":"Telah mengabarkan kepada kami [Yahya bin Hakim Al Bashri], ia berkata; telah menceritakan kepada kami [Ibnu Adi] dari [Syu'bah] dari [Ya'la bin 'Atho`] dari [ayahnya] dari [Abdullah bin 'Amr] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \" Sungguh hilangnya dunia lebih ringan bagi Allah daripada terbunuhnya seorang muslim.\""},"3740":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ هِشَامٍ قَالَ حَدَّثَنَا مَخْلَدُ بْنُ يَزِيدَ عَنْ سُفْيَانَ عَنْ مَنْصُورٍ عَنْ يَعْلَى بْنِ عَطَاءٍ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَقَتْلُ الْمُؤْمِنِ أَعْظَمُ عِنْدَ اللَّهِ مِنْ زَوَالِ الدُّنْيَا","id":"Telah mengabarkan kepada kami ['Amr bin Hisyam], ia berkata; telah menceritakan kepada kami [Makhlad bin Yazid] dari [Sufyan] dari [Manshur] dari [Ya'la bin 'Atho`] dari [ayahnya] dari [Abdullah bin 'Amr], ia berkata; terbunuhnya seorang mukmin lebih besar bagi Allah daripada hilangnya dunia."},"3741":{"ar":"أَخْبَرَنَا الْحَسَنُ بْنُ إِسْحَقَ الْمَرْوَزِيُّ ثِقَةٌ حَدَّثَنِي خَالِدُ بْنُ خِدَاشٍ قَالَ حَدَّثَنَا حَاتِمُ بْنُ إِسْمَعِيلَ عَنْ بَشِيرِ بْنِ الْمُهَاجِرِ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَتْلُ الْمُؤْمِنِ أَعْظَمُ عِنْدَ اللَّهِ مِنْ زَوَالِ الدُّنْيَا","id":"Telah mengabarkan kepada kami [Al Hasan bin Ishaq Al Marwazi] ia adalah orang yang tsiqah, telah menceritakan kepadaku [Khalid bin Khidasy], ia berkata; telah menceritakan kepada kami [Hatim bin Isma'il] dari [Basyir bin Al Muhajir] dari [Abdullah bin Buraidah] dari [ayahnya] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Terbunuhnya seorang mukmin lebih besar bagi Allah daripada hilangnya dunia.\""},"3742":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى عَنْ خَالِدٍ حَدَّثَنَا شُعْبَةُ عَنْ سُلَيْمَانَ قَالَ سَمِعْتُ أَبَا وَائِلٍ يُحَدِّثُ عَنْ عَبْدِ اللَّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَوَّلُ مَا يُحْكَمُ بَيْنَ النَّاسِ فِي الدِّمَاءِ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la] dari [Khalid] telah menceritakan kepada kami [Syu'bah] dari [Sulaiman], ia berkata; saya mendengar [Abu Wail] menceritakan dari [Abdullah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesuatu pertama yang diputuskan diantara manusia adalah mengenai darah.\""},"3743":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا أَبُو دَاوُدَ عَنْ سُفْيَانَ عَنْ الْأَعْمَشِ عَنْ أَبِي وَائِلٍ قَالَ قَالَ عَبْدُ اللَّهِأَوَّلُ مَا يُقْضَى بَيْنَ النَّاسِ يَوْمَ الْقِيَامَةِ فِي الدِّمَاءِ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman], ia berkata; telah menceritakan kepada kami [Abu Daud] dari [Sufyan] dari [Al A'masy] dari [Abu Wail], ia berkata; [Abdullah] berkata; \"Sesuatu pertama yang diputuskan diantara manusia adalah mengenai darah.\""},"3744":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ حَفْصٍ قَالَ حَدَّثَنِي أَبِي قَالَ حَدَّثَنِي إِبْرَاهِيمُ بْنُ طَهْمَانَ عَنْ الْأَعْمَشِ عَنْ شَقِيقٍ ثُمَّ ذَكَرَ كَلِمَةً مَعْنَاهَا عَنْ عَمْرِو بْنِ شُرَحْبِيلَ عَنْ عَبْدِ اللَّهِ قَالَأَوَّلُ مَا يُقْضَى بَيْنَ النَّاسِ يَوْمَ الْقِيَامَةِ فِي الدِّمَاءِ","id":"Telah mengabarkan kepada kami [Ahmad bin Hafsh], ia berkata; telah menceritakan kepadaku [ayahku], ia berkata; telah menceritakan kepadaku [Ibrahim bin Thahman] dari [Al A'masy] dari [Syaqiq] kemudian ia menyebutkan satu kalimat yang maknanya adalah; dari ['Amr bin Syurahbil] dari [Abdullah], ia berkata; Sesuatu pertama yang diputuskan diantara manusia adalah mengenai darah."},"3745":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْعَلَاءِ قَالَ حَدَّثَنَا أَبُو مُعَاوِيَةَ قَالَ حَدَّثَنَا الْأَعْمَشُ عَنْ شَقِيقٍ عَنْ عَبْدِ اللَّهِ قَالَأَوَّلُ مَا يُقْضَى بَيْنَ النَّاسِ فِي الدِّمَاءِ","id":"Telah mengabarkan kepada kami [Muhammad bin Al 'Ala`], ia berkata; telah menceritakan kepada kami [Abu Mu'awiyah], ia berkata; telah menceritakan kepada kami [Al A'masy] dari [Syaqiq] dari [Abdullah], ia berkata; \"Sesuatu pertama yang diputuskan diantara manusia adalah mengenai darah.\""},"3746":{"ar":"أَخْبَرَنَا إِبْرَاهِيمُ بْنُ الْمُسْتَمِرِّ قَالَ حَدَّثَنَا عَمْرُو بْنُ عَاصِمٍ قَالَ حَدَّثَنَا مُعْتَمِرٌ عَنْ أَبِيهِ عَنْ الْأَعْمَشِ عَنْ شَقِيقِ بْنِ سَلَمَةَ عَنْ عَمْرِو بْنِ شُرَحْبِيلَ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَجِيءُ الرَّجُلُ آخِذًا بِيَدِ الرَّجُلِ فَيَقُولُ يَا رَبِّ هَذَا قَتَلَنِي فَيَقُولُ اللَّهُ لَهُ لِمَ قَتَلْتَهُ فَيَقُولُ قَتَلْتُهُ لِتَكُونَ الْعِزَّةُ لَكَ فَيَقُولُ فَإِنَّهَا لِي وَيَجِيءُ الرَّجُلُ آخِذًا بِيَدِ الرَّجُلِ فَيَقُولُ إِنَّ هَذَا قَتَلَنِي فَيَقُولُ اللَّهُ لَهُ لِمَ قَتَلْتَهُ فَيَقُولُ لِتَكُونَ الْعِزَّةُ لِفُلَانٍ فَيَقُولُ إِنَّهَا لَيْسَتْ لِفُلَانٍ فَيَبُوءُ بِإِثْمِهِ","id":"Telah mengabarkan kepada kami [Ibaraim bin Al Mustamir], ia berkata; telah menceritakan kepada kami ['Amr bin 'Ashim], ia berkata; telah menceritakan kepada kami [Mu'tamir] dari [ayahya] dari [Al A'masy] dari [Syaqiq bin Salamah] dari ['Amr bin Syurahbil], dari [Abdullah bin Mas'ud] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \" Seseorang datang dengan menggandeng tangan orang lain, lalu ia berkata; wahai Tuhanku, ia yang telah membunuhku. Kemudian Allah berfirman kepadanya; kenapa engkau membunuhnya? Ia menjawab; saya membunuhnya agar kemuliaan menjadi milikMu. Lalu Allah berfirman; sesungguhnya kemuliaan itu milikKu. Lalu seseorang datang dengan menggandeng orang lain dan berkata; sesungguhnya orang ini membunuhku. Kemudian Allah berfirman kepadanya; Kenapa engkau membunuhnya? Ia menjawab agar kemuliaan itu menjadi milik Fulan, lalu Allah berfirman: \"Sesungguhnya ia bukan milik Fulan.\" Maka ia kembali membawa dosanya."},"3747":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَمَّارٍ الدُّهْنِيِّ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ أَنَّ ابْنَ عَبَّاسٍسُئِلَ عَمَّنْ قَتَلَ مُؤْمِنًا مُتَعَمِّدًا ثُمَّ تَابَ وَآمَنَ وَعَمِلَ صَالِحًا ثُمَّ اهْتَدَى فَقَالَ ابْنُ عَبَّاسٍ وَأَنَّى لَهُ التَّوْبَةُ سَمِعْتُ نَبِيَّكُمْ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يَجِيءُ مُتَعَلِّقًا بِالْقَاتِلِ تَشْخَبُ أَوْدَاجُهُ دَمًا فَيَقُولُ أَيْ رَبِّ سَلْ هَذَا فِيمَ قَتَلَنِي ثُمَّ قَالَ وَاللَّهِ لَقَدْ أَنْزَلَهَا اللَّهُ ثُمَّ مَا نَسَخَهَا","id":"Telah mengabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Sufyan] dari ['Amar Ad Duhni] dari [Salim bin Abu Al Ja'd] bahwa [Ibnu Abbas] ditanya mengenai orang yang membunuh seorang mukmin secara sengaja kemudian ia bertaubat dan beriman serta beramal Shalih lalu ia mendapat petunjuk. Maka Ibn Abbas berkata; darimana datang taubatnya, saya mendengar Nabi kalian shallallahu 'alaihi wasallam bersabda: \"Ia akan datang bergantung kepada orang yang membunuh dan urat lehernya mengalirkan darah, ia berkata; wahai Tuhanku, tanyakan kepada orang ini kenapa ia membunuhku!\" Kemudian beliau bersabda: \"Demi Allah, sungguh Allah telah menurunkannya kemudian tidak menghapusnya.\""},"3748":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا بَقِيَّةُ قَالَ حَدَّثَنِي بَحِيرُ بْنُ سَعْدٍ عَنْ خَالِدِ بْنِ مَعْدَانَ أَنَّ أَبَا رُهْمٍ السَّمَعِيَّ حَدَّثَهُمْ أَنَّ أَبَا أَيُّوبَ الْأَنْصَارِيَّ حَدَّثَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ جَاءَ يَعْبُدُ اللَّهَ وَلَا يُشْرِكُ بِهِ شَيْئًا وَيُقِيمُ الصَّلَاةَ وَيُؤْتِي الزَّكَاةَ وَيَجْتَنِبُ الْكَبَائِرَ كَانَ لَهُ الْجَنَّةُ فَسَأَلُوهُ عَنْ الْكَبَائِرِ فَقَالَ الْإِشْرَاكُ بِاللَّهِ وَقَتْلُ النَّفْسِ الْمُسْلِمَةِ وَالْفِرَارُ يَوْمَ الزَّحْفِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim], ia berkata; telah memberitakan kepada kami [Baqiyah], ia berkata; telah menceritakan kepadaku [Bahir bin Sa'd] dari [Khalid bin Ma'dan] bahwa [Abu Ruhm As Sama'i] menceritakan kepada mereka bahwa [Abu Ayyub Al Anshari] telah menceritakan kepadanya bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang datang dalam keadaan menyembah Allah dan tidak menyekutukan sesuatupun denganNya, mendirikan shalat, menunaikan zakat, dan menjauhi dosa-dosa besar maka baginya Surga.\" Kemudian para sahabat bertanya kepadanya mengenai dosa-dosa besar, maka beliau bersabda: \"Mensekutukan Allah, membunuh jiwa muslimah serta lari pada saat perang.\" "},"3749":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي بَكْرٍ عَنْ أَنَسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ح وَأَنْبَأَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا النَّضْرُ بْنُ شُمَيْلٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي بَكْرٍ قَالَ سَمِعْتُ أَنَسًا يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْكَبَائِرُ الشِّرْكُ بِاللَّهِ وَعُقُوقُ الْوَالِدَيْنِ وَقَتْلُ النَّفْسِ وَقَوْلُ الزُّورِ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdul A'la], ia berkata; telah menceritakan kepada kami [Khalid], ia berkata; telah menceritakan kepada kami [Syu'bah] dari ['Ubaidullah bin Abu Bakar] dari [Anas] dari Nabi shallallahu 'alaihi wasallam. Telah menceritakan dan memberitakan kepada kami [Ishaq bin Ibrahim], ia berkata; telah memberitakan kepada kami [An Nadhr bin Syumail], ia berkata; telah menceritakan kepada kami [Syu'bah] dari ['Ubaidullah bin Abu Bakar], ia berkata; saya mendengar [Anas] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dosa-dosa besar adalah mensekutukan Allah, durhaka kepada orang tua, membunuh jiwa, dan berkata palsu.\""},"3750":{"ar":"أَخْبَرَنِي عَبْدَةُ بْنُ عَبْدِ الرَّحِيمِ قَالَ أَنْبَأَنَا ابْنُ شُمَيْلٍ قَالَ أَنْبَأَنَا شُعْبَةُ قَالَ حَدَّثَنَا فِرَاسٌ قَالَ سَمِعْتُ الشَّعْبِيَّ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْكَبَائِرُ الْإِشْرَاكُ بِاللَّهِ وَعُقُوقُ الْوَالِدَيْنِ وَقَتْلُ النَّفْسِ وَالْيَمِينُ الْغَمُوسُ","id":"Telah mengabarkan kepada kami ['Abdah bin Abdur Rahim], ia berkata; telah memberitakan kepada kami [Ibnu Syumail], ia berkata; telah memberitakan kepada kami [Syu'bah], ia berkata; telah menceritakan kepada kami [Firas], ia berkata; saya mendengar [Asy Sya'bi] dari [Abdullah bin 'Amr] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Dosa-dosa besar adalah mensekutukan Allah, durhaka kepada orang tua, membunuh jiwa, dan sumpah palsu.\""},"3751":{"ar":"أَخْبَرَنَا الْعَبَّاسُ بْنُ عَبْدِ الْعَظِيمِ قَالَ حَدَّثَنَا مُعَاذُ بْنُ هَانِئٍ قَالَ حَدَّثَنَا حَرْبُ بْنُ شَدَّادٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ عَبْدِ الْحَمِيدِ بْنِ سِنَانٍ عَنْ حَدِيثِ عُبَيْدِ بْنِ عُمَيْرٍ أَنَّهُ حَدَّثَهُ أَبُوهُ وَكَانَ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ رَجُلًا قَالَ يَا رَسُولَ اللَّهِ مَا الْكَبَائِرُ قَالَ هُنَّ سَبْعٌ أَعْظَمُهُنَّ إِشْرَاكٌ بِاللَّهِ وَقَتْلُ النَّفْسِ بِغَيْرِ حَقٍّ وَفِرَارٌ يَوْمَ الزَّحْفِ مُخْتَصَرٌ","id":"Telah mengabarkan kepada kami [Al Abbas bin Abdul 'Azhim], ia berkata; telah menceritakan kepada kami [Mu'adz bin Hani`], ia berkata; telah menceritakan kepada kami [Harb bin Syaddad], ia berkata; telah menceritakan kepada kami [Yahya bin Abu Katsir] dari [Abdul Hamid bin Sinan] dari hadits ['Ubaid bin 'Umair] bahwa [ayahnya] yang termasuk sahabat Nabi shallallahu 'alaihi wasallam telah menceritakan kepadanya bahwa seseorang berkata; wahai Rasulullah apakah dosa-dosa besar itu? Beliau menjawab: \" Dosa-dosa besar itu ada tujuh yang paling besar adalah menyekutukan Allah dan membunuh jiwa tanpa haq serta melarikan diri ketika perang, \" secara ringkas."},"3752":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ وَاصِلٍ عَنْ أَبِي وَائِلٍ عَنْ عَمْرِو بْنِ شُرَحْبِيلَ عَنْ عَبْدِ اللَّهِ قَالَقُلْتُ يَا رَسُولَ اللَّهِ أَيُّ الذَّنْبِ أَعْظَمُ قَالَ أَنْ تَجْعَلَ لِلَّهِ نِدًّا وَهُوَ خَلَقَكَ قُلْتُ ثُمَّ مَاذَا قَالَ أَنْ تَقْتُلَ وَلَدَكَ خَشْيَةَ أَنْ يَطْعَمَ مَعَكَ قُلْتُ ثُمَّ مَاذَا قَالَ أَنْ تُزَانِيَ بِحَلِيلَةِ جَارِكَ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar], ia berkata; telah menceritakan kepada kami [Abdurrahman], ia berkata; telah menceritakan kepada kami [Sufyan] dari [Washil] dari [Abu Wail] dari ['Amr bin Syurahbil] dari [Abdullah], ia berkata; saya berkata; wahai Rasulullah dosa apakah yang paling besar? Beliau menjawab: \"Engkau membuat tandingan bagi Allah, padahal Dia yang menciptakanmu.\" Saya katakan; kemudian apa? beliau bersabda: \" Engkau membunuh anakmu karena khawatir makan bersamamu.\" Saya katakan; kemudian apa? beliau bersabda: \" Engkau berzina dengan isteri tetanggamu.\""},"3753":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنِي وَاصِلٌ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ قَالَقُلْتُ يَا رَسُولَ اللَّهِ أَيُّ الذَّنْبِ أَعْظَمُ قَالَ أَنْ تَجْعَلَ لِلَّهِ نِدًّا وَهُوَ خَلَقَكَ قُلْتُ ثُمَّ أَيٌّ قَالَ أَنْ تَقْتُلَ وَلَدَكَ مِنْ أَجْلِ أَنْ يَطْعَمَ مَعَكَ قُلْتُ ثُمَّ أَيٌّ قَالَ ثُمَّ أَنْ تُزَانِيَ بِحَلِيلَةِ جَارِكَ","id":"Telah mengabarkan kepada kami ['Amr bin Ali], ia berkata; telah menceritakan kepada kami [Yahya], ia berkata; telah menceritakan kepada kami [Sufyan], ia berkata; telah menceritakan kepadaku [Washil] dari [Abu Wail] dari [Abdullah], ia berkata; saya berkata; wahai Rasulullah dosa apakah yang paling besar? Beliau menjawab: \"Engkau membuat tandingan bagi Allah, padahal Dia yang menciptakanmu.\" Saya katakan; kemudian apa? beliau bersabda: \"Engkau membunuh anakmu karena ia makan bersamamu.\" Saya katakan; kemudian apa? beliau bersabda: \" Engkau berzina dengan isteri tetanggamu.\""},"3754":{"ar":"أَخْبَرَنَا عَبْدَةُ قَالَ أَنْبَأَنَا يَزِيدُ قَالَ أَنْبَأَنَا شُعْبَةُ عَنْ عَاصِمٍ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ قَالَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّ الذَّنْبِ أَعْظَمُ قَالَ الشِّرْكُ أَنْ تَجْعَلَ لِلَّهِ نِدًّا وَأَنْ تُزَانِيَ بِحَلِيلَةِ جَارِكَ وَأَنْ تَقْتُلَ وَلَدَكَ مَخَافَةَ الْفَقْرِ أَنْ يَأْكُلَ مَعَكَثُمَّ قَرَأَ عَبْدُ اللَّهِ{ وَالَّذِينَ لَا يَدْعُونَ مَعَ اللَّهِ إِلَهًا آخَرَ }قَالَ أَبُو عَبْد الرَّحْمَنِ هَذَا خَطَأٌ وَالصَّوَابُ الَّذِي قَبْلَهُ وَحَدِيثُ يَزِيدَ هَذَا خَطَأٌ إِنَّمَا هُوَ وَاصِلٌ وَاللَّهُ تَعَالَى أَعْلَمُ","id":"Telah mengabarkan kepada kami ['Abdah], ia berkata; telah memberitakan kepada kami [Yazid], ia berkata; telah memberitakan kepada kami [Syu'bah] dari ['Ashim] dari [Abu Wail] dari [Abdullah], ia berkata; saya bertanya kepada Rasulullah shallallahu 'alaihi wasallam; dosa apakah yang paling besar? Beliau menjawab: \"Syirik yaitu engkau membuat tandingan bagi Allah, Engkau berzina dengan isteri tetanggamu dan engkau membunuh anakmu karena khawatir makan bersamamu.\" Kemudian Abdullah membaca ayat: Dan orang-orang yang tidak menyembah tuhan yang lain beserta Allah. Abu Abdurrahman berkata; hal ini adalah salah dan yang benar adalah yang sebelumnya, dan hadits Yazid ini adalah salah, sesungguhnya ia adalah Washil. Wallahu a'lam."},"3755":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ مَنْصُورٍ قَالَ أَنْبَأَنَا عَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ الْأَعْمَشِ عَنْ عَبْدِ اللَّهِ بْنِ مُرَّةَ عَنْ مَسْرُوقٍ عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالَّذِي لَا إِلَهَ غَيْرُهُ لَا يَحِلُّ دَمُ امْرِئٍ مُسْلِمٍ يَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنِّي رَسُولُ اللَّهِ إِلَّا ثَلَاثَةُ نَفَرٍ التَّارِكُ لِلْإِسْلَامِ مُفَارِقُ الْجَمَاعَةِ وَالثَّيِّبُ الزَّانِي وَالنَّفْسُ بِالنَّفْسِقَالَ الْأَعْمَشُ فَحَدَّثْتُ بِهِ إِبْرَاهِيمَ فَحَدَّثَنِي عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ بِمِثْلِهِ","id":"Telah mengabarkan kepada kami [Ishaq bin Manshur], ia berkata; telah memberitakan kepada kami [Abdurrahman] dari [Sufyan] dari [Al A'masy] dari [Abdullah bin Murrah] dari [Masruq] dari [Abdullah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Demi Dzat yang tidak ada Tuhan yang berhak disembah kecuali dia. Tidaklah halal darah seorang muslim yang bersaksi bahwa tidak ada Tuhan yang berhak disembah kecuali Allah dan saya adalah Rasulullah kecuali tiga orang, yaitu: orang yang meninggalkan Islam dan memisahkan diri dari jama'ah, seorang janda yang berbuat zina, dan membunuh jiwa.\" [Al A'masy] berkata; kemudian saya menceritakannya kepada [Ibrahim], kemudian Ia menceritakan kepadaku [Al Aswad] dari [Aisyah] dengan hadits seperti itu."},"3756":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنَا أَبُو إِسْحَقَ عَنْ عَمْرِو بْنِ غَالِبٍ قَالَ قَالَتْ عَائِشَةُأَمَا عَلِمْتَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَحِلُّ دَمُ امْرِئٍ مُسْلِمٍ إِلَّا رَجُلٌ زَنَى بَعْدَ إِحْصَانِهِ أَوْ كَفَرَ بَعْدَ إِسْلَامِهِ أَوْ النَّفْسُ بِالنَّفْسِوَقَّفَهُ زُهَيْرٌ أَخْبَرَنَا هِلَالُ بْنُ الْعَلَاءِ قَالَ حَدَّثَنَا حُسَيْنٌ قَالَ حَدَّثَنَا زُهَيْرٌ قَالَ حَدَّثَنَا أَبُو إِسْحَقَ عَنْ عَمْرِو بْنِ غَالِبٍ قَالَ قَالَتْ عَائِشَةُ يَا عَمَّارُ أَمَا إِنَّكَ تَعْلَمُ أَنَّهُ لَا يَحِلُّ دَمُ امْرِئٍ إِلَّا ثَلَاثَةٌ النَّفْسُ بِالنَّفْسِ أَوْ رَجُلٌ زَنَى بَعْدَ مَا أُحْصِنَ وَسَاقَ الْحَدِيثَ","id":"Telah mengabarkan kepada kami ['Amr bin Ali], ia berkata; telah menceritakan kepada kami [Yahya], ia berkata; telah menceritakan kepada kami [Sufyan], ia berkata; telah menceritakan kepada kami [Abu Ishaq] dari ['Amr bin Ghalib], ia berkata; [Aisyah] berkata; tidakkah engkau mengetahui bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak halal darah seorang muslim kecuali seorang laki-laki yang berzina setelah menikah, atau kafir setelah masuk Islam, serta membunuh jiwa.\" Hadits tersebut dimauqufkan oleh Zuhair. Telah mengabarkan kepada kami [Hilal bin Al 'Ala`], ia berkata; telah menceritakan kepada kami [Husain] berkata; telah menceritakan kepada kami [Zuhair], ia berkata; telah menceritakan kepada kami [Abu Ishaq] dari ['Amr bin Ghalib], ia berkata; [Aisyah] berkata; wahai Ammar, tidakkah engkau mengetahui bahwa tidak halal darah seseorang kecuali karena tiga perkara, yaitu: membunuh jiwa, atau seseorang yang berzina setelah menikah.. dan ia menyebutkan hadits."},"3757":{"ar":"أَخْبَرَنِي إِبْرَاهِيمُ بْنُ يَعْقُوبَ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى قَالَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ حَدَّثَنِي أَبُو أُمَامَةَ بْنُ سَهْلٍ وَعَبْدُ اللَّهِ بْنُ عَامِرِ بْنِ رَبِيعَةَ قَالَاكُنَّا مَعَ عُثْمَانَ وَهُوَ مَحْصُورٌ وَكُنَّا إِذَا دَخَلْنَا مَدْخَلًا نَسْمَعُ كَلَامَ مَنْ بِالْبَلَاطِ فَدَخَلَ عُثْمَانُ يَوْمًا ثُمَّ خَرَجَ فَقَالَ إِنَّهُمْ لَيَتَوَاعَدُونِّي بِالْقَتْلِ قُلْنَا يَكْفِيكَهُمُ اللَّهُ قَالَ فَلِمَ يَقْتُلُونِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَحِلُّ دَمُ امْرِئٍ مُسْلِمٍ إِلَّا بِإِحْدَى ثَلَاثٍ رَجُلٌ كَفَرَ بَعْدَ إِسْلَامِهِ أَوْ زَنَى بَعْدَ إِحْصَانِهِ أَوْ قَتَلَ نَفْسًا بِغَيْرِ نَفْسٍ فَوَاللَّهِ مَا زَنَيْتُ فِي جَاهِلِيَّةٍ وَلَا إِسْلَامٍ وَلَا تَمَنَّيْتُ أَنَّ لِي بِدِينِي بَدَلًا مُنْذُ هَدَانِيَ اللَّهُ وَلَا قَتَلْتُ نَفْسًا فَلِمَ يَقْتُلُونَنِي","id":"Telah mengabarkan kepadaku [Ibrahim bin Ya'qub], ia berkata; telah menceritakan kepada kami [Muhammad bin Isa], ia berkata; telah menceritakan kepada kami [Hammad bin Zaid], ia berkata; telah menceritakan kepada kami [Yahya bin Sa'd], ia berkata; telah menceritakan kepadaku [Abu Umamah bin Sahl] dan [Abdullah bin 'Amir bin Rabi'ah], mereka berdua berkata; kami bersama [Utsman] dan ia dalam keadaan terkepung. Dan kami apabila memasuki suatu tempat masuk maka kami mendengar perkataan orang di ubin. Kemudian Utsman pada suatu hari masuk kemudian keluar, dan berkata; sesungguhnya mereka mengancamku untuk dibunuh. Kami katakan; Allah akan menolongmu dari mereka. Ia berkata; kenapa mereka akan membunuhku? Saya telah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \" Tidak halal darah seorang muslim kecuali dengan tiga perkara; yaitu: seseorang yang kafir setelah masuk Islam, atau berzina setelah menikah, atau membunuh jiwa.\"Demi Allah, saya tidak pernah bezina pada masa jahiliyah dan Islam, dan saya tidak berharap memiliki ganti bagi agamaku setelah Allah memberiku hidayah, dan tidak pernah membunuh jiwa. Maka kenapa mereka akan membunuhku?\""},"3758":{"ar":"أَخْبَرَنِي أَحْمَدُ بْنُ يَحْيَى الصُّوفِيُّ قَالَ حَدَّثَنَا أَبُو نُعَيْمٍ قَالَ حَدَّثَنَا يَزِيدُ بْنُ مَرْدَانِبَةَ عَنْ زِيَادِ بْنِ عِلَاقَةَ عَنْ عَرْفَجَةَ بْنِ شُرَيْحٍ الْأَشْجَعِيِّ قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْمِنْبَرِ يَخْطُبُ النَّاسَ فَقَالَ إِنَّهُ سَيَكُونُ بَعْدِي هَنَاتٌ وَهَنَاتٌ فَمَنْ رَأَيْتُمُوهُ فَارَقَ الْجَمَاعَةَ أَوْ يُرِيدُ يُفَرِّقُ أَمْرَ أُمَّةِ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَائِنًا مَنْ كَانَ فَاقْتُلُوهُ فَإِنَّ يَدَ اللَّهِ عَلَى الْجَمَاعَةِ فَإِنَّ الشَّيْطَانَ مَعَ مَنْ فَارَقَ الْجَمَاعَةَ يَرْكُضُ","id":"Telah mengabarkan kepadaku [Ahmad bin Yahya Ash Shufi], ia berkata; telah menceritakan kepada kami [Abu Nu'aim], ia berkata; telah menceritakan kepada kami [Yazid bin Mardaniyah] dari [Ziyad bin 'Ilaqah] dari ['Arfajah bin Syuraih Al Asyja'i], ia berkata; saya melihat Nabi shallallahu 'alaihi wasallam berada di atas mimbar sedang berkhutbah kepada manusia, beliau bersabda: \"Sesungguhnya akan terjadi setelahku fitnah dan fitnah, maka siapa yang kalian lihat telah memisahkan diri dari jama'ah atau hendak memecah belah kesatuan umat Muhammad shallallahu 'alaihi wasallam siapapun dia maka bunuhlah dia. Sesungguhnya tangan Allah bersama jama'ah dan syetan bergerak bersama orang yang misahkan diri dari jama'ah. "},"3759":{"ar":"أَخْبَرَنَا أَبُو عَلِيٍّ مُحَمَّدُ بْنُ يَحْيَى الْمَرْوَزِيُّ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عُثْمَانَ عَنْ أَبِي حَمْزَةَ عَنْ زِيَادِ بْنِ عِلَاقَةَ عَنْ عَرْفَجَةَ بْنِ شُرَيْحٍ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهَا سَتَكُونُ بَعْدِي هَنَاتٌ وَهَنَاتٌ وَهَنَاتٌ وَرَفَعَ يَدَيْهِ فَمَنْ رَأَيْتُمُوهُ يُرِيدُ تَفْرِيقَ أَمْرِ أُمَّةِ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُمْ جَمِيعٌ فَاقْتُلُوهُ كَائِنًا مَنْ كَانَ مِنْ النَّاسِ","id":"Telah mengabarkan kepada kami [Abu Ali Muhammad bin Yahya Al Marwazi], Ia berkata; telah menceritakan kepada kami [Abdullah bin Utsman] dari [Abu Hamzah] dari [Ziyad bin 'Ilaqah] dari ['Arfajah bin Syuraih], ia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya akan terjadi setelahku fitnah dan fitnah -dan beliau mengangkat kedua tangannya- maka siapa yang kalian lihat telah ingin memecah belah keadaan umat sedang mereka telah bersatu maka bunuhlah dia siapapun dia.\" "},"3760":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا شُعْبَةُ قَالَ حَدَّثَنَا زِيَادُ بْنُ عِلَاقَةَ عَنْ عَرْفَجَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ سَتَكُونُ بَعْدِي هَنَاتٌ وَهَنَاتٌ فَمَنْ أَرَادَ أَنْ يُفَرِّقَ أَمْرَ أُمَّةِ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُمْ جَمْعٌ فَاضْرِبُوهُ بِالسَّيْفِ","id":"Telah mengabarkan kepada kami ['Amr bin Ali], ia berkata; telah menceritakan kepada kami [Yahya], ia berkata; telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Ziyad bin 'Ilaqah] dari ['Arfajah], ia berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Akan terjadi setelahku fitnah, dan fitnah, maka barang siapa yang ingin memecah belah keadaan Umat Muhammad dan mereka telah bersatu maka penggallah lehernya dengan pedang. "},"3761":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ قُدَامَةَ قَالَ حَدَّثَنَا جَرِيرٌ عَنْ زَيْدِ بْنِ عَطَاءِ بْنِ السَّائِبِ عَنْ زِيَادِ بْنِ عِلَاقَةَ عَنْ أُسَامَةَ بْنِ شَرِيكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّمَا رَجُلٍ خَرَجَ يُفَرِّقُ بَيْنَ أُمَّتِي فَاضْرِبُوا عُنُقَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Qudamah], ia berkata; telah menceritakan kepada kami [Jarir] dari [Zaid bin 'Atho` bin As Saib] dari [Ziyad bin 'Ilaqah] dari [Usamah bin Syarik], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Siapapun laki-laki yang keluar lalu ia memecah belah umatku maka penggallah lehernya.\""},"3762":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ عَنْ حَجَّاجٍ الصَّوَّافِ قَالَ حَدَّثَنَا أَبُو رَجَاءٍ مَوْلَى أَبِي قِلَابَةَ قَالَ حَدَّثَنَا أَبُو قِلَابَةَ قَالَ حَدَّثَنِي أَنَسُ بْنُ مَالِكٍأَنَّ نَفَرًا مِنْ عُكْلٍ ثَمَانِيَةً قَدِمُوا عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاسْتَوْخَمُوا الْمَدِينَةَ وَسَقِمَتْ أَجْسَامُهُمْ فَشَكَوْا ذَلِكَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَلَا تَخْرُجُونَ مَعَ رَاعِينَا فِي إِبِلِهِ فَتُصِيبُوا مِنْ أَلْبَانِهَا وَأَبْوَالِهَا قَالُوا بَلَى فَخَرَجُوا فَشَرِبُوا مِنْ أَلْبَانِهَا وَأَبْوَالِهَا فَصَحُّوا فَقَتَلُوا رَاعِيَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَبَعَثَ فَأَخَذُوهُمْ فَأُتِيَ بِهِمْ فَقَطَّعَ أَيْدِيَهُمْ وَأَرْجُلَهُمْ وَسَمَّرَ أَعْيُنَهُمْ وَنَبَذَهُمْ فِي الشَّمْسِ حَتَّى مَاتُوا","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud], ia berkata; telah menceritakan kepada kami [Yazid bin Zurai'] dari [Hajjaj Ash Shawwaf], ia berkata; telah menceritakan kepada kami [Abu Raja`] maula Abu Qilabah, ia berkata; telah menceritakan kepadaku [Abu Qilabah], ia berkata; telah menceritakan kepadaku [Anas bin Malik] bahwa beberapa orang dari 'ukl yang berjumlah delapan orang datang kepada Nabi shallallahu 'alaihi wasallam kemudian mereka memandang udaranya tidak cocok dan tubuh mereka menjadi sakit, lalu mereka mengadukan hal tersebut kepada Rasulullah shallallahu 'alaihi wasallam. Maka beliau bersabda: \"Tidakkah kalian keluar bersama penggembala kita dalam untanya? Kemudian kalian meminum susunya, dan air kencingnya? Mereka berkata; ya. Kemudian mereka keluar dan meminum sebagian susunya dan kencingnya sehingga mereka menjadi sembuh. Lalu mereka membunuh penggembala Rasulullah shallallahu 'alaihi wasallam. Lalu beliau mengirim utusan kemudian mereka menangkap orang-orang tersebut dan mereka didatangkan kepada beliau. Kemudian beliau memotong tangan dan kaki mereka serta mencungkil mata mreka, serta mencampakkan mereka dalam terik matahari hingga mati. "},"3763":{"ar":"أَخْبَرَنِي عَمْرُو بْنُ عُثْمَانَ بْنِ سَعِيدِ بْنِ كَثِيرِ بْنِ دِينَارٍ عَنْ الْوَلِيدِ عَنْ الْأَوْزَاعِيِّ عَنْ يَحْيَى عَنْ أَبِي قِلَابَةَ عَنْ أَنَسٍأَنَّ نَفَرًا مِنْ عُكْلٍ قَدِمُوا عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاجْتَوَوْا الْمَدِينَةَ فَأَمَرَهُمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَأْتُوا إِبِلَ الصَّدَقَةِ فَيَشْرَبُوا مِنْ أَبْوَالِهَا وَأَلْبَانِهَا فَفَعَلُوا فَقَتَلُوا رَاعِيَهَا وَاسْتَاقُوهَا فَبَعَثَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي طَلَبِهِمْ قَالَ فَأُتِيَ بِهِمْ فَقَطَّعَ أَيْدِيَهُمْ وَأَرْجُلَهُمْ وَسَمَّرَ أَعْيُنَهُمْ وَلَمْ يَحْسِمْهُمْ وَتَرَكَهُمْ حَتَّى مَاتُوا فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ إِنَّمَا جَزَاءُ الَّذِينَ يُحَارِبُونَ اللَّهَ وَرَسُولَهُ }الْآيَةَأَخْبَرَنَا إِسْحَقُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ قَالَ حَدَّثَنَا الْأَوْزَاعِيُّ قَالَ حَدَّثَنِي يَحْيَى بْنُ أَبِي كَثِيرٍ قَالَ حَدَّثَنِي أَبُو قِلَابَةَ عَنْ أَنَسٍ قَالَ قَدِمَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَمَانِيَةُ نَفَرٍ مِنْ عُكْلٍ فَذَكَرَ نَحْوَهُ إِلَى قَوْلِهِ لَمْ يَحْسِمْهُمْ وَقَالَ قَتَلُوا الرَّاعِيَ","id":"Telah mengabarkan kepada kami ['Amr bin Utsman bin Sa'id bin Katsir bin Dinar] dari [Al Walid] dari [Al Auza'i] dari [Yahya] dari [Abu Qilabah] dari [Anas] bahwa beberapa orang dari 'ukl datang kepada Nabi shallallahu 'alaihi wasallam kemudian mereka terkena penyakit paru-paru di Madinah. Lalu Nabi shallallahu 'alaihi wasallam memerintahkan mereka agar mendatangi unta shadaqah, dan meminum sebagian kencingnya, serta susunya. Kemudian mereka melakukannya dan membunuh orang yang menggembalanya serta menggiring unta tersebut. Maka Rasulullah shallallahu 'alaihi wasallam mengirimkan utusan untuk mencari mereka. Anas berkata; kemudian mereka dihadapkan kepada beliau. Lalu beliau memotong tangan dan kaki mereka serta mencungkil mata mereka, tidak memenggal mereka dan beliau meninggalkan mereka hingga mati. Kemudian Allah 'azza wajalla menurunkan ayat: Sesungguhnya pembalasan terhadap orang-orang yang memerangi Allah dan Rasul-Nya hingga akhir Ayat. Telah mengabarkan kepada kami [Ishaq bin Manshur], ia berkata; telah menceritakan kepada kami [Muhammad bin Yusuf], ia berkata; telah menceritakan kepada kami [Al Auza'i], ia berkata; telah menceritakan kepadaku [Yahya bin Abu Katsir], ia berkata; telah menceritakan kepadaku [Abu Qilabah] dari [Anas], ia berkata; telah datang kepada Rasulullah shallallahu 'alaihi wasallam delapan orang dari 'ukl.. kemudian ia menyebutkan hadits sama seperti itu hingga perkataannya tidak memenggal mereka. Dan ia berkata; mereka telah membunuh penggembala tersebut."},"3764":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ أَنَسٍ قَالَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَفَرٌ مِنْ عُكْلٍ أَوْ عُرَيْنَةَ فَأَمَرَ لَهُمْ وَاجْتَوَوْا الْمَدِينَةَ بِذَوْدٍ أَوْ لِقَاحٍ يَشْرَبُونَ أَلْبَانَهَا وَأَبْوَالَهَا فَقَتَلُوا الرَّاعِيَ وَاسْتَاقُوا الْإِبِلَ فَبَعَثَ فِي طَلَبِهِمْ فَقَطَّعَ أَيْدِيَهُمْ وَأَرْجُلَهُمْ وَسَمَّرَ أَعْيُنَهُمْ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman], ia berkata; telah menceritakan kepada kami [Muhammad bin Bisyr], ia berkata; telah menceritakan kepada kami [Sufyan] dari [Ayyub] dari [Abu Qilabah] dari [Anas bin Malik], ia berkata; telah datang kepada Nabi shallallahu 'alaihi wasallam beberapa orang dari 'Ukl atau 'Urainah. Mereka terkena penyakit paru-paru di Madinah, kemudian beliau memerintahkan agar didatangkan bagi mereka unta sehingga mereka dapat minum susunya dan air kencingnya. Kemudian mereka membunuh penggembala dan menggiring unta tersebut. Maka beliau mengirim utusan untuk mencari mereka, kemudian memotong tangan dan kaki mereka serta mencungkil mata mereka. "},"3765":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ قَالَ أَخْبَرَنِي ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ عُمَرَ وَغَيْرُهُ عَنْ حُمَيْدٍ الطَّوِيلِ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ نَاسًا مِنْ عُرَيْنَةَ قَدِمُوا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاجْتَوَوْا الْمَدِينَةَ فَبَعَثَهُمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى ذَوْدٍ لَهُ فَشَرِبُوا مِنْ أَلْبَانِهَا وَأَبْوَالِهَا فَلَمَّا صَحُّوا ارْتَدُّوا عَنْ الْإِسْلَامِ وَقَتَلُوا رَاعِيَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُؤْمِنًا وَاسْتَاقُوا الْإِبِلَ فَبَعَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي آثَارِهِمْ فَأُخِذُوا فَقَطَّعَ أَيْدِيَهُمْ وَأَرْجُلَهُمْ وَسَمَلَ أَعْيُنَهُمْ وَصَلَبَهُمْ","id":"Telah mengabarkan kepada kami [Ahmad bin 'Amr bin As Sarh], ia berkata; telah mengabarkan kepadaku [Ibnu Wahb], ia berkata; telah mengabarkan kepadaku [Abdullah bin Umar] dan yang lainnya dari [Humaid Ath Thawil] dari [Anas bin Malik] bahwa beberapa orang dari 'Urainah datang kepada Rasulullah shallallahu 'alaihi wasallam kemudian mereka terkena penyakit paru-paru di Madinah. Kemudian Nabi shallallahu 'alaihi wasallam mengirim mereka untuk mendatangi unta beliau dan minum sebagian susunya serta air kencingnya. Kemudian setelah sembuh mereka keluar dari Islam dan membunuh penggembala Rasulullah shallallahu 'alaihi wasallam yang beriman, dan menggiring unta tersebut. Maka Rasulullah shallallahu 'alaihi wasallam mengirim utusan untuk mengejar mereka, hingga mereka tertangkap kemudian beliau memotong tangan dan kaki mereka serta mencongkel mata mereka dan menyelip mereka. "},"3766":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ أَنْبَأَنَا إِسْمَعِيلُ عَنْ حُمَيْدٍ عَنْ أَنَسٍ قَالَقَدِمَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُنَاسٌ مِنْ عُرَيْنَةَ فَقَالَ لَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ خَرَجْتُمْ إِلَى ذَوْدِنَا فَكُنْتُمْ فِيهَا فَشَرِبْتُمْ مِنْ أَلْبَانِهَا وَأَبْوَالِهَا فَفَعَلُوا فَلَمَّا صَحُّوا قَامُوا إِلَى رَاعِي رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَتَلُوهُ وَرَجَعُوا كُفَّارًا وَاسْتَاقُوا ذَوْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَرْسَلَ فِي طَلَبِهِمْ فَأُتِيَ بِهِمْ فَقَطَّعَ أَيْدِيَهُمْ وَأَرْجُلَهُمْ وَسَمَلَ أَعْيُنَهُمْ","id":"Telah mengabarkan kepada kami [Ali bin Hujr], ia berkata; telah memberitakan kepada kami [Isma'il] dari [Humaid] dari [Anas], ia berkata; telah datang kepada Rasulullah shallallahu 'alaihi wasallam beberapa orang dari 'Urainah. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda kepada mereka: \"Seandainya kalian keluar menuju unta kami dan kalian berada padanya serta minum sebagian susunya dan air kencingnya.\" Maka mereka melakukannya. Kemudian setelah sehat, mereka bangkit menuju penggembala Rasulullah shallallahu 'alaihi wasallam dan membubuhnya serta menggiring unta Nabi shallallahu 'alaihi wasallam. Maka beliau mengirim utusan untuk mencari mereka hingga mereka didatangkan, kemudian beliau memotong tangan dan kaki mereka serta mencongkel mata mereka. "},"3767":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا حُمَيْدٌ عَنْ أَنَسٍ قَالَقَدِمَ نَاسٌ مِنْ عُرَيْنَةَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاجْتَوَوْا الْمَدِينَةَ فَقَالَ لَهُمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ خَرَجْتُمْ إِلَى ذَوْدِنَا فَشَرِبْتُمْ مِنْ أَلْبَانِهَا قَالَ وَقَالَ قَتَادَةُ وَأَبْوَالِهَا فَخَرَجُوا إِلَى ذَوْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا صَحُّوا كَفَرُوا بَعْدَ إِسْلَامِهِمْ وَقَتَلُوا رَاعِيَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُؤْمِنًا وَاسْتَاقُوا ذَوْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَانْطَلَقُوا مُحَارِبِينَ فَأَرْسَلَ فِي طَلَبِهِمْ فَأُخِذُوا فَقَطَّعَ أَيْدِيَهُمْ وَأَرْجُلَهُمْ وَسَمَّرَ أَعْيُنَهُمْ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna], ia berkata; telah menceritakan kepada kami [Khalid], ia berkata; telah menceritakan kepada kami [Humaid] dari [Anas], ia berkata; telah datang beberapa orang dari 'Urainah kepada Rasulullah shallallahu 'alaihi wasallam, kemudian mereka terkena penyakit paru-paru di Madinah. Lalu Nabi shallallahu 'alaihi wasallam bersabda kepada mereka: \"Seandainya kalian keluar menuju unta kami dan meminum sebagian susunya dan kencingnya.\" Qatadah berkata; dan air kencingnya. Kemudian mereka keluar menuju unta Rasulullah shallallahu 'alaihi wasallam. Kemudian setelah mereka sehat maka mereka kafir setelah masuk Islam dan membunuh penggembala Rasulullah shallallahu 'alaihi wasallam yang mukmin dan menggiring unta Rasulullah shallallahu 'alaihi wasallam serta pergi memerangi beliau. Maka beliau mengirim utusan untuk mencari mereka hingga mereka tertangkap kemudian beliau memotong tangan dan kaki mereka serta mencongkel mata mereka."},"3768":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي عَدِيٍّ قَالَ حَدَّثَنَا حُمَيْدٌ عَنْ أَنَسٍ قَالَأَسْلَمَ أُنَاسٌ مِنْ عُرَيْنَةَ فَاجْتَوَوْا الْمَدِينَةَ فَقَالَ لَهُمْ رَسُولُ اللَّهِ ��َلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ خَرَجْتُمْ إِلَى ذَوْدٍ لَنَا فَشَرِبْتُمْ مِنْ أَلْبَانِهَا قَالَ حُمَيْدٌ وَقَالَ قَتَادَةُ عَنْ أَنَسٍ وَأَبْوَالِهَا فَفَعَلُوا فَلَمَّا صَحُّوا كَفَرُوا بَعْدَ إِسْلَامِهِمْ وَقَتَلُوا رَاعِيَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُؤْمِنًا وَاسْتَاقُوا ذَوْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهَرَبُوا مُحَارِبِينَ فَأَرْسَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَتَى بِهِمْ فَأُخِذُوا فَقَطَّعَ أَيْدِيَهُمْ وَأَرْجُلَهُمْ وَسَمَّرَ أَعْيُنَهُمْ وَتَرَكَهُمْ فِي الْحَرَّةِ حَتَّى مَاتُوا","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna], ia berkata; telah menceritakan kepada kami [Muhammad bin Abu 'Adi], ia berkata; telah menceritakan kepada kami [Humaid] dari [Anas], ia berkata; beberapa orang dari 'Urainah telah masuk Islam kemudian mereka terkena penyakit paru-paru di Madinah. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda kepada mereka: \"Seandainya kalian keluar menunu unta kami dan meminum sebagian susunya.\" Humaid berkata; Qatadan berkata; dari Anas; dan kencingnya... lalu mereka melakukannya. Kemudian setelah sembuh maka mereka kafir setelah masuk Islam, dan membunuh penggembala Rasulullah shallallahu 'alaihi wasallam dan melarikan diri sebagai orang yang memerangi. Maka Rasulullah shallallahu 'alaihi wasallam mengutus orang yang dapat membawa mereka, hingga mereka tertangkap. Kemudian beliau memotong tangan dan kaki mereka serta mencongkel mata mereka dan meninggalkan mereka di daerah Al Harrah hingga mati. "},"3769":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا يَزِيدُ وَهُوَ ابْنُ زُرَيْعٍ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ حَدَّثَنَا قَتَادَةُ أَنَّ أَنَسَ بْنَ مَالِكٍ حَدَّثَهُمْأَنَّ نَاسًا أَوْ رِجَالًا مِنْ عُكْلٍ أَوْ عُرَيْنَةَ قَدِمُوا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا يَا رَسُولَ اللَّهِ إِنَّا أَهْلُ ضَرْعٍ وَلَمْ نَكُنْ أَهْلَ رِيفٍ فَاسْتَوْخَمُوا الْمَدِينَةَ فَأَمَرَ لَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِذَوْدٍ وَرَاعٍ وَأَمَرَهُمْ أَنْ يَخْرُجُوا فِيهَا فَيَشْرَبُوا مِنْ لَبَنِهَا وَأَبْوَالِهَا فَلَمَّا صَحُّوا وَكَانُوا بِنَاحِيَةِ الْحَرَّةِ كَفَرُوا بَعْدَ إِسْلَامِهِمْ وَقَتَلُوا رَاعِيَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاسْتَاقُوا الذَّوْدَ فَبَعَثَ الطَّلَبَ فِي آثَارِهِمْ فَأُتِيَ بِهِمْ فَسَمَّرَ أَعْيُنَهُمْ وَقَطَّعَ أَيْدِيَهُمْ وَأَرْجُلَهُمْ ثُمَّ تَرَكَهُمْ فِي الْحَرَّةِ عَلَى حَالِهِمْ حَتَّى مَاتُواأَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى عَنْ عَبْدِ الْأَعْلَى نَحْوَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la], ia berkata; telah menceritakan kepada kami [Yazid yaitu Ibnu Zurai'], ia berkata; telah menceritakan kepada kami [Syu'bah], ia berkata; telah menceritakan kepada kami [Qatadah] bahwa [Anas bin Malik] telah menceritakan kepada mereka bahwa beberapa orang atau laki-laki dari 'Ukl atau 'Urainah datang kepada Rasulullah shallallahu 'alaihi wasallam, dan berkata; wahai Rasulullah, sesungguhnya kami adalah para pemilik hewan ternak bukan pemilik tanaman. Dan mereka tidak cocok tinggal di Madinah. Kemudian Rasulullah shallallahu 'alaihi wasallam memerintahkan mereka agar datang kepada unta dan memerintahkan mereka agar keluar dan meminum sebagian susu dan kencingnya. Kemudian setelah mereka sembuh dan berada di pinggir daerah Al Harrah mereka kafir setelah masuk Islam, dan membunuh penggembala Rasulullah shallallahu 'alaihi wasallam dan menggiring unta tersebut. Kemudian beliau meningirimkan utusan untuk mengejar mereka, hingga mereka dapat didatangkan, kemudian beliau mencongkel mata mereka dan memotong tangan serta kaki mereka kemudian meninggalkan mereka di daerah Al Harrah dalam keadaan mereka hingga mati. [Muhammad bin Al Mutsanna] telah mengabarkan kepada kami seperti itu dari [Abdul A'la]. "},"3770":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ نَافِعٍ أَبُو بَكْرٍ قَالَ حَدَّثَنَا بَهْزٌ قَالَ حَدَّثَنَا حَمَّادٌ قَالَ حَدَّثَنَا قَتَادَةُ وَثَابِتٌ عَنْ أَنَسٍأَنَّ نَفَرًا مِنْ عُرَيْنَةَ نَزَلُوا فِي الْحَرَّةِ فَأَتَوْا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاجْتَوَوْا الْمَدِينَةَ فَأَمَرَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَكُونُوا فِي إِبِلِ الصَّدَقَةِ وَأَنْ يَشْرَبُوا مِنْ أَلْبَانِهَا وَأَبْوَالِهَا فَقَتَلُوا الرَّاعِيَ وَارْتَدُّوا عَنْ الْإِسْلَامِ وَاسْتَاقُوا الْإِبِلَ فَبَعَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي آثَارِهِمْ فَجِيءَ بِهِمْ فَقَطَّعَ أَيْدِيَهُمْ وَأَرْجُلَهُمْ وَسَمَّرَ أَعْيُنَهُمْ وَأَلْقَاهُمْ فِي الْحَرَّةِقَالَ أَنَسٌ فَلَقَدْ رَأَيْتُ أَحَدَهُمْ يَكْدُمُ الْأَرْضَ بِفِيهِ عَطَشًا حَتَّى مَاتُوا","id":"Telah mengabarkan kepada kami [Muhammad bin Nafi' Abu Bakar], ia berkata; telah menceritakan kepada kami [Bahz], ia berkata; telah menceritakan kepada kami [Hammad], ia berkata; telah menceritakan kepada kami [Qatadah] dan [Tsabit] dari [Anas] bahwa beberapa orang dari 'Urainah singgah di Al Harrah kemudian datang kepada Nabi shallallahu 'alaihi wasallam. Lalu mereka terkena penyakit paru-paru di Madinah. Kemudian Rasulullah shallallahu 'alaihi wasallam memerintahkan mereka agar mendatangi unta shadaqah dan meminum sebagian susunya serta kencingnya. Kemudian mereka membunuh penggembala unta tersebut dan keluar dari Islam serta menggiring unta. Maka Rasulullah shallallahu 'alaihi wasallam mengirim utusan untuk mengejar mereka hingga mereka dapat didatangkan. Kemudian beliau memotong tangan dan kaki mereka serta mencongkel mata mereka dan membuang mereka di daerah Al Harrah. Anas berkata; sungguh saya melihat salah seorang dari mereka menggigit tanah dengan mulutnya karena haus hingga mati. "},"3771":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ وَهْبٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ قَالَ حَدَّثَنِي أَبُو عَبْدِ الرَّحِيمِ قَالَ حَدَّثَنِي زَيْدُ بْنُ أَبِي أُنَيْسَةَ عَنْ طَلْحَةَ بْنِ مُصَرِّفٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَدِمَ أَعْرَابٌ مِنْ عُرَيْنَةَ إِلَى نَبِيِّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَسْلَمُوا فَاجْتَوَوْا الْمَدِينَةَ حَتَّى اصْفَرَّتْ أَلْوَانُهُمْ وَعَظُمَتْ بُطُونُهُمْ فَبَعَثَ بِهِمْ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى لِقَاحٍ لَهُ فَأَمَرَهُمْ أَنْ يَشْرَبُوا مِنْ أَلْبَانِهَا وَأَبْوَالِهَا حَتَّى صَحُّوا فَقَتَلُوا رُعَاتَهَا وَاسْتَاقُوا الْإِبِلَ فَبَعَثَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي طَلَبِهِمْ فَأُتِيَ بِهِمْ فَقَطَّعَ أَيْدِيَهُمْ وَأَرْجُلَهُمْ وَسَمَّرَ أَعْيُنَهُمْقَالَ أَمِيرُ الْمُؤْمِنِينَ عَبْدُ الْمَلِكِ لِأَنَسٍ وَهُوَ يُحَدِّثُهُ هَذَا الْحَدِيثَ بِكُفْرٍ أَوْ بِذَنْبٍ قَالَ بِكُفْرٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Wahb], ia berkata; telah menceritakan kepada kami [Muhammad bin Salamah], ia berkata; telah menceritakan kepadaku [Abu Abdur Rahim], ia berkata; telah menceritakan kepadaku [Zaid bin Abi Unaisah] dari [Thalhah bin Musharrif] dari [Yahya bin Sa'id] dari [Anas bin Malik], ia berkata; telah datang orang-orang badui dari 'Urainah kepada Nabi shallallahu 'alaihi wasallam kemudian masuk Islam, lalu mereka terkena penyakit paru-paru di Madinah hingga warna kulit mereka menguning, dan perut mereka membesar. Kemudian Nabi shallallahu 'alaihi wasallam mengirim mereka menuju unta beliau dan memerintahkan mereka agar minum sebagian susu dan kencingnya hingga mereka sehat. Lalu mereka membunuh penggembala unta tersebut dan menggiringnya. Lalu Nabi shallallahu 'alaihi wasallam mengirim utusan untuk mencari mereka hingga mereka dapat didatangkan. Kemudian beliau memotong tangan dan kaki mereka serta mencongkel mata mereka. Berkata Amirul mukminin Abdul Malik kepada Anas yang menceritakan hadits ini; karena kekafiran atau dosa? Anas berkata; karena kekafiran. "},"3772":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ قَالَ أَنْبَأَنَا ابْنُ وَهْبٍ قَالَ وَأَخْبَرَنِي يَحْيَى بْنُ أَيُّوبَ وَمُعَاوِيَةُ بْنُ صَالِحٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ قَالَقَدِمَ نَاسٌ مِنْ الْعَرَبِ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَسْلَمُوا ثُمَّ مَرِضُوا فَبَعَثَ بِهِمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى لِقَاحٍ لِيَشْرَبُوا مِنْ أَلْبَانِهَا فَكَانُوا فِيهَا ثُمَّ عَمَدُوا إِلَى الرَّاعِي غُلَامِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَتَلُوهُ وَاسْتَاقُوا اللِّقَاحَ فَزَعَمُوا أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اللَّهُمَّ عَطِّشْ مَنْ عَطَّشَ آلَ مُحَمَّدٍ اللَّيْلَةَ فَبَعَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي طَلَبِهِمْ فَأُخِذُوا فَقَطَّعَ أَيْدِيَهُمْ وَأَرْجُلَهُمْ وَسَمَلَ أَعْيُنَهُمْوَبَعْضُهُمْ يَزِيدُ عَلَى بَعْضٍ إِلَّا أَنَّ مُعَاوِيَةَ قَالَ فِي هَذَا الْحَدِيثِ اسْتَاقُوا إِلَى أَرْضِ الشِّرْكِ","id":"Telah mengabarkan kepada kami [Ahmad bin 'Amr bin As Sarh], ia berkata; telah memberitakan kepada kami [Ibnu Wahb], ia berkata; telah mengabarkan kepadaku [Yahya bin Ayyub] dan [Mu'awiyah bin Shalih] dari [Yahya bin Sa'id] dari [Sa'id bin Al Musayyab], ia berkata; telah datang beberapa orang Arab kepada Rasulullah shallallahu 'alaihi wasallam lalu mereka masuk Islam, kemudian sakit. Lalu Rasulullah shallallahu 'alaihi wasallam mengutus mereka untuk mendatangi unta agar meminum susunya, dan mereka berada padanya kemudian mereka mendatangi penggembalanya, ia adalah pembantu Rasulullah shallallahu 'alaihi wasallam, mereka membunuhnya dan menggiring unta. Mereka mengaku bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \" Ya Allah hauskanlah orang yang menghauskan keluarga Muhammad pada malam ini, \" Lalu Rasulullah shallallahu 'alaihi wasallam mengirimkan orang untuk mencari mereka, lalu mereka ditangkap dan beliau memotong tangan dan kaki mereka, beliau mencukil mata mereka, sebagian mereka menambah atas sebagian yang lain. Hanya saja Mua'awiyah berkata dalam hadits ini mereka menggiring menuju negeri syirik."},"3773":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الْخَلَنْجِيُّ قَالَ حَدَّثَنَا مَالِكُ بْنُ سُعَيْرٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْأَغَارَ قَوْمٌ عَلَى لِقَاحِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخَذَهُمْ فَقَطَّعَ أَيْدِيَهُمْ وَأَرْجُلَهُمْ وَسَمَلَ أَعْيُنَهُمْ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah Al Khalanji], ia berkata; telah menceritakan kepada kami [Malik bin Su'air] dari [Hisyam bin 'Urwah] dari [ayahnya] dari [Aisyah] radliallahu 'anha, ia berkata; beberapa orang menyerang unta Rasulullah shallallahu 'alaihi wasallam, kemudian menangkap mereka, dan memotong tangan serta kaki mereka dan mencongkel mata mereka."},"3774":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى عَنْ إِبْرَاهِيمَ بْنِ أَبِي الْوَزِيرِ قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ ح وَأَنْبَأَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ أَبِي الْوَزِيرِ قَالَ حَدَّثَنَا الدَّرَاوَرْدِيُّ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّ قَوْمًا أَغَارُوا عَلَى لِقَاحِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأُتِيَ بِهِمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَطَّعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيْدِيَهُمْ وَأَرْجُلَهُمْ وَسَمَلَ أَعْيُنَهُمْاللَّفْظُ لِابْنِ الْمُثَنَّى","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dari [Ibrahim bin Abu Al Wazir], ia berkata; telah menceritakan kepada kami [Abdul Aziz]. Telah menceritakan dan memberitahukan kepada kami [Muhammad bin Basysyar], ia berkata; telah menceritakan kepada kami [Ibrahim bin Abu Al Wazir], ia berkata; telah menceritakan kepada kami [Ad Darawardi] dari [Hisyam bin 'Urwah] dari [ayahnya] dari [Aisyah] bahwa beberapa orang telah menyerang unta Rasulullah shallallahu 'alaihi wasallam lalu mereka didatangkan kepada Nabi shallallahu 'alaihi wasallam kemudian beliau memotong tangan dan kaki mereka serta mencongkel mata mereka. Lafazh hadits tersebut adalah lafazh Ibnu Al Mutsanna. "},"3775":{"ar":"أَخْبَرَنَا عِيسَى بْنُ حَمَّادٍ قَالَ أَنْبَأَنَا اللَّيْثُ عَنْ هِشَامٍ عَنْ أَبِيهِأَنَّ قَوْمًا أَغَارُوا عَلَى إِبِلِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَطَّعَ أَيْدِيَهُمْ وَأَرْجُلَهُمْ وَسَمَلَ أَعْيُنَهُمْ","id":"Telah mengabarkan kepada kami [Isa bin Hammad], ia berkata; telah memberitakan kepada kami [Al Laits] dari [Hisyam] dari [ayahnya] bahwa beberapa orang telah menyerang unta Rasulullah shallallahu 'alaihi wasallam, kemudian beliau memotong tangan dan kaki mereka serta mencongkel mata mereka."},"3776":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ قَالَ أَخْبَرَنِي ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ عَنْ سَعِيدِ بْنِ أَبِي هِلَالٍ عَنْ أَبِي الزِّنَادِ عَنْ عَبْدِ اللَّهِ بْنِ عُبَيْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَزَلَتْ فِيهِمْ آيَةُ الْمُحَارَبَةِ","id":"Telah mengabarkan kepada kami [Ahmad bin 'Amr bin As Sarh], ia berkata; telah mengabarkan kepadaku [Ibnu Wahb], ia berkata; telah mengabarkan kepadaku ['Amr bin Al Harits] dari [Sa'id bin Abi Hilal] dari [Abu Az Zinad] dari [Abdullah bin 'Ubaidullah] dari [Abdullah bin Umar] dari Rasulullah shallallahu 'alaihi wasallam dan kepada mereka turun ayat perang."},"3777":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ قَالَ أَنْبَأَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي اللَّيْثُ عَنْ ابْنِ عَجْلَانَ عَنْ أَبِي الزِّنَادِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمَّا قَطَّعَ الَّذِينَ سَرَقُوا لِقَاحَهُ وَسَمَلَ أَعْيُنَهُمْ بِالنَّارِ عَاتَبَهُ اللَّهُ فِي ذَلِكَ فَأَنْزَلَ اللَّهُ تَعَالَى{ إِنَّمَا جَزَاءُ الَّذِينَ يُحَارِبُونَ اللَّهَ وَرَسُولَهُ }الْآيَةَ كُلَّهَا","id":"Telah mengabarkan kepada kami [Ahmad bin 'Amr bin As Sarh], ia berkata; telah memberitakan kepada kami [Ibnu Wahb], ia berkata; telah memberitakan kepadaku [Al Laits] dari [Ibnu 'Ajlan] dari [Abu Az Zinad] bahwa Rasulullah shallallahu 'alaihi wasallam ketika memotong tangan orang yang mencuri unta beliau dan mencongkel mata mereka dengan api, Allah mencela hal tersebut dan menurunkan ayat Sesungguhnya pembalasan terhadap orang-orang yang memerangi Allah dan Rasul-Nya dan membuat kerusakan di muka bumi, hanyalah mereka dibunuh atau disalib, atau dipotong tangan dan kaki mereka dengan bertimbal balik, atau dibuang dari negeri (tempat kediamannya). Yang demikian itu (sebagai) suatu penghinaan untuk mereka didunia, dan di akhirat mereka beroleh siksaan yang besar."},"3778":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي مُحَمَّدُ بْنُ عَمْرٍو عَنْ ابْنِ جُرَيْجٍ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَجُلًا مِنْ الْيَهُودِ قَتَلَ جَارِيَةً مِنْ الْأَنْصَارِ عَلَى حُلِيٍّ لَهَا وَأَلْقَاهَا فِي قَلِيبٍ وَرَضَخَ رَأْسَهَا بِالْحِجَارَةِ فَأُخِذَ فَأَمَرَ بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُرْجَمَ حَتَّى يَمُوتَ","id":"Telah mengabarkan kepada kami [Ahmad bin 'Amr bin As Sarh] dan [Al Harits bin Miskin] dengan membacakan riwayat dan saya mendengar, ia berkata; telah menceritakan kepada kami [Ibnu Wahb], ia berkata; telah mengabarkan kepadaku [Muhammad bin 'Amr] dari [Ibnu Juraij] dari [Ayyub] dari [Abu Qilabah] dari [Anas bin Malik] bahwa seorang laki-laki Yahudi membunuh seorang wanita Anshar untuk mengambil perhiasannya dan melemparkannya di sumur serta melempari kepalanya dengan batu, kemudian ia ditangkap dan beliau memerintahkan agar dirajam hingga mati. "},"3779":{"ar":"أَخْبَرَنَا يُوسُفُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا حَجَّاجٌ عَنْ ابْنِ جُرَيْجٍ قَالَ أَخْبَرَنِي مَعْمَرٌ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ أَنَسٍأَنَّ رَجُلًا قَتَلَ جَارِيَةً مِنْ الْأَنْصَارِ عَلَى حُلِيٍّ لَهَا ثُمَّ أَلْقَاهَا فِي قَلِيبٍ وَرَضَخَ رَأْسَهَا بِالْحِجَارَةِ فَأَمَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُرْجَمَ حَتَّى يَمُوتَ","id":"Telah mengabarkan kepada kami [Yusuf bin Sa'id], ia berkata; telah menceritakan kepada kami [Hajjaj] dari [Ibnu Juraij], ia berkata; telah mengabarkan kepadaku [Ma'mar] dari [Ayyub] dari [Abu Qilabah] dari [Anas] bahwa seorang laki-laki Yahudi membunuh seorang wanita Anshar untuk mengambil perhiasannya dan melemparkannya di sumur serta melempari kepalanya dengan batu, kemudian ia ditangkap dan beliau memerintahkan agar dirajam hingga mati. "},"3780":{"ar":"أَخْبَرَنَا زَكَرِيَّا بْنُ يَحْيَى قَالَ حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنِي عَلِيُّ بْنُ الْحُسَيْنِ بْنِ وَاقِدٍ قَالَ حَدَّثَنِي أَبِي قَالَ حَدَّثَنَا يَزِيدُ النَّحْوِيُّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍفِي قَوْلِهِ تَعَالَى{ إِنَّمَا جَزَاءُ الَّذِينَ يُحَارِبُونَ اللَّهَ وَرَسُولَهُ }الْآيَةَ قَالَ نَزَلَتْ هَذِهِ الْآيَةُ فِي الْمُشْرِكِينَ فَمَنْ تَابَ مِنْهُمْ قَبْلَ أَنْ يُقْدَرَ عَلَيْهِ لَمْ يَكُنْ عَلَيْهِ سَبِيلٌ وَلَيْسَتْ هَذِهِ الْآيَةُ لِلرَّجُلِ الْمُسْلِمِ فَمَنْ قَتَلَ وَأَفْسَدَ فِي الْأَرْضِ وَحَارَبَ اللَّهَ وَرَسُولَهُ ثُمَّ لَحِقَ بِالْكُفَّارِ قَبْلَ أَنْ يُقْدَرَ عَلَيْهِ لَمْ يَمْنَعْهُ ذَلِكَ أَنْ يُقَامَ فِيهِ الْحَدُّ الَّذِي أَصَابَ","id":"Telah mengabarkan kepada kami [Zakariya bin Yahya], ia berkata; telah menceritakan kepada kami [Ishaq bin Ibrahim], ia berkata; telah memberitakan kepada kami [Ali bin Al Husain bin Waqid], ia berkata; telah menceritakan kepadaku [ayahku], ia berkata; telah menceritakan kepada kami [Yazid An Nahwi] dari [Ikrimah] dari [Ibnu Abbas] mengenai firman Allah Ta'ala: Sesungguhnya pembalasan terhadap orang-orang yang memerangi Allah dan Rasul-Nya ia berkata; ayat ini mengenai orang-orang musyrik, dan barangsiapa diantara mereka yang bertaubat sebelum mereka ditangkap maka tidak ada jalan untuk membunuhnya, dan tidaklah ayat ini untuk seorang muslim, maka barangsiapa yang membunuh dan merusak didunia, memerangi Allah dan rasulNya lalu ia bertemu dengan orang kafir sebelum ditangkap maka hal itu tidak menghalanginya untuk ditegakkan hukuman pada apa yang ia lakukan."},"3781":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا عَبْدُ الصَّمَدِ قَالَ حَدَّثَنَا هِشَامٌ عَنْ قَتَادَةَ عَنْ أَنَسٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَحُثُّ فِي خُطْبَتِهِ عَلَى الصَّدَقَةِ وَيَنْهَى عَنْ الْمُثْلَةِ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna], ia berkata; telah menceritakan kepada kami [Abdushshamad], ia berkata; telah menceritakan kepada kami [Hisyam] dari [Qatadah] dari [Anas] ia berkata adalah Rasulullah shallallahu 'alaihi wasallam menganjurkan di khutbahnya untuk melakukan sedekah dan melarang dari mencincang mayat.\""},"3782":{"ar":"أَخْبَرَنَا الْعَبَّاسُ بْنُ مُحَمَّدٍ الدُّورِيُّ قَالَ حَدَّثَنَا أَبُو عَامِرٍ الْعَقَدِيُّ عَنْ إِبْرَاهِيمَ بْنِ طَهْمَانَ عَنْ عَبْدِ الْعَزِيزِ بْنِ رُفَيْعٍ عَنْ عُبَيْدِ بْنِ عُمَيْرٍ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَحِلُّ دَمُ امْرِئٍ مُسْلِمٍ إِلَّا بِإِحْدَى ثَلَاثِ خِصَالٍ زَانٍ مُحْصَنٌ يُرْجَمُ أَوْ رَجُلٌ قَتَلَ رَجُلًا مُتَعَمِّدًا فَيُقْتَلُ أَوْ رَجُلٌ يَخْرُجُ مِنْ الْإِسْلَامِ يُحَارِبُ اللَّهَ عَزَّ وَجَلَّ وَرَسُولَهُ فَيُقْتَلُ أَوْ يُصْلَبُ أَوْ يُنْفَى مِنْ الْأَرْضِ","id":"Telah mengabarkan kepada kami [Al Abbas bin Muhammad Ad Duri], ia berkata; telah menceritakan kepada kami [Abu 'Amir Al 'Aqadi] dari [Ibrahim bin Thahman] dari [Abdul Aziz bin Rafi'] dari ['Ubaid bin 'Umair] dari [Aisyah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak halal darah seorang muslim kecuali dengan salah satu dari tiga sifat, yaitu; pezina yang telah menikah, maka ia dirajam, atau seseorang yang membunuh orang lain dengan sengaja, maka ia dibunuh, atau seseorang yang keluar dari Islam, memerangi Allah 'azza wajalla dan RasulullahNya, maka ia dibunuh atau disalib atau disingkirkan dari negeri. "},"3783":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ غَيْلَانَ قَالَ حَدَّثَنَا أَبُو دَاوُدَ قَالَ أَنْبَأَنَا شُعْبَةُ عَنْ مَنْصُورٍ عَنْ الشَّعْبِيِّ عَنْ جَرِيرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَبَقَ الْعَبْدُ لَمْ تُقْبَلْ لَهُ صَلَاةٌ حَتَّى يَرْجِعَ إِلَى مَوَالِيهِ","id":"Telah mengabarkan kepada kami [Mahmud bin Ghailan], ia berkata; telah menceritakan kepada kami [Abu Daud], ia berkata; telah memberitakan kepada kami [Syu'bah] dari [Manshur] dari [Asy Sya'bi] dari [Jarir], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Jika seorang budak kabur maka tidak akan diterima sholatnya hingga ia kembali kepada majikannya.\""},"3784":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ قُدَامَةَ عَنْ جَرِيرٍ عَنْ مُغِيرَةَ عَنْ الشَّعْبِيِّ قَالَكَانَ جَرِيرٌ يُحَدِّثُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَبَقَ الْعَبْدُ لَمْ تُقْبَلْ لَهُ صَلَاةٌ وَإِنْ مَاتَ مَاتَ كَافِرًاوَأَبَقَ غُلَامٌ لِجَرِيرٍ فَأَخَذَهُ فَضَرَبَ عُنُقَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Qudamah] dari [Jarir] dari [Mughirah] dari [Asy Sya'bi], ia berkata; [Jarir] pernah menceritakan dari Nabi shallallahu 'alaihi wasallam: \" Jika seorang budak kabur maka tidak akan diterima sholatnya, apabila ia mati maka ia mati dalam keadaan kafir.\" Budak kecil Jarir kabur kemudian ia menangkapnya kemudian memenggal lehernya. "},"3785":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى قَالَ أَنْبَأَنَا إِسْرَائِيلُ عَنْ مُغِيرَةَ عَنْ الشَّعْبِيِّ عَنْ جَرِيرِ بْنِ عَبْدِ اللَّهِ قَالَإِذَا أَبَقَ الْعَبْدُ إِلَى أَرْضِ الشِّرْكِ فَلَا ذِمَّةَ لَهُ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman], ia berkata; telah menceritakan kepada kami [Ubaidullah bin Musa], ia berkata; telah memberitakan kepada kami [Israil] dari [Mughirah] dari [Asy Sya'bi] dari [Jarir bin Abdullah], ia berkata; apabila seorang budak kabur menuju negeri syirik maka ia tidak memiliki perlindungan."},"3786":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا حُمَيْدُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ أَبِي إِسْحَقَ عَنْ الشَّعْبِيِّ عَنْ جَرِيرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَبَقَ الْعَبْدُ إِلَى أَرْضِ الشِّرْكِ فَقَدْ حَلَّ دَمُهُ","id":"Telah mengabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Humaid bin Abdurrahman] dari [ayahnya] dari [Abu Ishaq] dari [Asy Sya'bi] dari [Jarir], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila seorang budak kabur menuju negeri syirik maka telah halal darahnya.\""},"3787":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا قَاسِمٌ قَالَ حَدَّثَنَا إِسْرَائِيلُ عَنْ أَبِي إِسْحَقَ عَنْ جَرِيرٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أَبَقَ الْعَبْدُ إِلَى أَرْضِ الشِّرْكِ فَقَدْ حَلَّ دَمُهُ","id":"Telah mengabarkan kepada kami [Ahmad bin Harb], ia berkata; telah memberitakan kepada kami [Qasim], ia berkata; telah menceritakan kepada kami [Israil] dari [Abu Ishaq] dari [Jarir] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Apabila seorang budak kabur menuju negeri syirik maka telah halal darahnya.\""},"3788":{"ar":"أَخْبَرَنَا الرَّبِيعُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا خَالِدُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَقَ عَنْ الشَّعْبِيِّ عَنْ جَرِيرٍ قَالَأَيُّمَا عَبْدٍ أَبَقَ إِلَى أَرْضِ الشِّرْكِ فَقَدْ حَلَّ دَمُهُ","id":"Telah mengabarkan kepada kami [Ar Rabi' bin Sulaiman], ia berkata; telah menceritakan kepada kami [Khalid bin Abdurrahman] dari [Israil] dari [Abu Ishaq] dari [Asy Sya'bi] dari [Jarir], ia berkata; siapapun budak yang kabur menuju negeri syirik maka telah halal darahnya."},"3789":{"ar":"أَخْبَرَنِي صَفْوَانُ بْنُ عَمْرٍو قَالَ حَدَّثَنَا أَحْمَدُ بْنُ خَالِدٍ قَالَ حَدَّثَنَا إِسْرَائِيلُ عَنْ أَبِي إِسْحَقَ عَنْ الشَّعْبِيِّ عَنْ جَرِيرٍ قَالَأَيُّمَا عَبْدٍ أَبَقَ إِلَى أَرْضِ الشِّرْكِ فَقَدْ حَلَّ دَمُهُ","id":"Telah mengabarkan kepada kami [Shafwan bin 'Amr], ia berkata; telah menceritakan kepada kami [Ahmad bin Khalid], ia berkata; telah menceritakan kepada kami [Israil] dari [Abu Ishaq] dari [Asy Sya'bi] dari [Jarir], ia berkata; siapapun budak yang kabur menuju negeri syirik maka telah halal darahnya."},"3790":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ حَدَّثَنَا شَرِيكٌ عَنْ أَبِي إِسْحَقَ عَنْ عَامِرٍ عَنْ جَرِيرٍ قَالَأَيُّمَا عَبْدٍ أَبَقَ مِنْ مَوَالِيهِ وَلَحِقَ بِالْعَدُوِّ فَقَدْ أَحَلَّ بِنَفْسِهِ","id":"Telah mengabarkan kepada kami [Ali bin Hujr], ia berkata; telah menceritakan kepada kami [Syarik] dari [Abu Ishaq] dari ['Amir] dari [Jarir], ia berkata; siapapun budak yang kabur dari tuannya dan bertemu dengan musuh maka sungguh ia telah menghalalkan dengan sendirinya."},"3791":{"ar":"أَخْبَرَنَا أَبُو الْأَزْهَرِ أَحْمَدُ بْنُ الْأَزْهَرِ النَّيْسَابُورِيُّ قَالَ حَدَّثَنَا إِسْحَقُ بْنُ سُلَيْمَانَ الرَّازِيُّ قَالَ أَنْبَأَنَا الْمُغِيرَةُ بْنُ مُسْلِمٍ عَنْ مَطَرٍ الْوَرَّاقِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ أَنَّ عُثْمَانَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَحِلُّ دَمُ امْرِئٍ مُسْلِمٍ إِلَّا بِإِحْدَى ثَلَاثٍ رَجُلٌ زَنَى بَعْدَ إِحْصَانِهِ فَعَلَيْهِ الرَّجْمُ أَوْ قَتَلَ عَمْدًا فَعَلَيْهِ الْقَوَدُ أَوْ ارْتَدَّ بَعْدَ إِسْلَامِهِ فَعَلَيْهِ الْقَتْلُ","id":"Telah mengabarkan kepada kami [Abu Al Azhar Ahmad bin Al Azhar An Naisaburi], ia berkata; telah menceritakan kepada kami [Ishaq bin Sulaiman Ar Razi], ia berkata; telah memberitakan kepada kami [Al Mughirah bin Muslim] dari [Mathar Al Warraq] dari [Nafi'] dari [Ibnu Umar] bahwa [Utsman] berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak halal darah seorang muslim kecuali dengan salah satu dari tiga perkara, yaitu; seseorang yang berzina setelah menikah, maka ia dirajam, atau membunuh dengan sengaja maka ia akan dibalas, atau murtad setelah masuk Islam maka ia dibunuh.\""},"3792":{"ar":"أَخْبَرَنَا مُؤَمَّلُ بْنُ إِهَابٍ قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَخْبَرَنِي ابْنُ جُرَيْجٍ عَنْ أَبِي النَّضْرِ عَنْ بُسْرِ بْنِ سَعِيدٍ عَنْ عُثْمَانَ بْنِ عَفَّانَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَحِلُّ دَمُ امْرِئٍ مُسْلِمٍ إِلَّا بِثَلَاثٍ أَنْ يَزْنِيَ بَعْدَ مَا أُحْصِنَ أَوْ يَقْتُلَ إِنْسَانًا فَيُقْتَلَ أَوْ يَكْفُرَ بَعْدَ إِسْلَامِهِ فَيُقْتَلَ","id":"Telah mengabarkan kepada kami [Muammal bin Ihab], ia berkata; telah menceritakan kepada kami [Abdur Razzaq], ia berkata; telah mengabarkan kepadaku [Ibnu Juraij] dari [Abu An Nadhr] dari [Busr bin Sa'id] dari [Utsman bin 'Affan], ia berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak halal darah seorang muslim kecuali dengan tiga perkara, yaitu; berzina setelah menikah, atau membunuh orang maka ia dibunuh atau kafir setelah masuk Islam maka ia dibunuh.\""},"3793":{"ar":"أَخْبَرَنَا عِمْرَانُ بْنُ مُوسَى قَالَ حَدَّثَنَا عَبْدُ الْوَارِثِ قَالَ حَدَّثَنَا أَيُّوبُ عَنْ عِكْرِمَةَ قَالَ قَالَ ابْنُ عَبَّاسٍقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ بَدَّلَ دِينَهُ فَاقْتُلُوهُ","id":"Telah mengabarkan kepada kami [Imran bin Musa], ia berkata; telah menceritakan kepada kami [Abdul Warits], ia berkata; telah menceritakan kepada kami [Ayyub] dari [Ikrimah], ia berkata; [Ibnu Abbas] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapa yang mengganti agamanya maka bunuhlah.\""},"3794":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ قَالَ حَدَّثَنَا أَبُو هِشَامٍ قَالَ حَدَّثَنَا وُهَيْبٌ قَالَ حَدَّثَنَا أَيُّوبُ عَنْ عِكْرِمَةَ أَنَّ نَاسًا ارْتَدُّوا عَنْ الْإِسْلَامِ فَحَرَّقَهُمْ عَلِيٌّ بِالنَّارِ قَالَ ابْنُ عَبَّاسٍ لَوْ كُنْتُ أَنَا لَمْ أُحَرِّقْهُمْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُعَذِّبُوا بِعَذَابِ اللَّهِ أَحَدًا وَلَوْ كُنْتُ أَنَا لَقَتَلْتُهُمْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ بَدَّلَ دِينَهُ فَاقْتُلُوهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin Al Mubarak], ia berkata; telah menceritakan kepada kami [Abu Hisyam], ia berkata; telah menceritakan kepada kami [Wuhaib], ia berkata; telah menceritakan kepada kami [Ayyub] dari ['Ikrimah] bahwa beberapa orang keluar dari Islam kemudian Ali membakar mereka dengan api. [Ibnu Abbas] berkata; seandainya saya maka saya tidak akan membakar mereka, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian menyiksa seseorang dengan siksaan Allah.\" Seandainya saya maka akan membunuh mereka, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapa yang mengganti agamanya maka bunuhlah.\""},"3795":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ غَيْلَانَ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ بَكْرٍ قَالَ أَنْبَأَنَا ابْنُ جُرَيْجٍ قَالَ أَنْبَأَنَا إِسْمَعِيلُ عَنْ مَعْمَرٍ عَنْ أَيُّوبَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ بَدَّلَ دِينَهُ فَاقْتُلُوهُ","id":"Telah mengabarkan kepada kami [Mahmud bin Ghailan], ia berkata; telah menceritakan kepada kami [Muhammad bin Bakr], ia berkata; telah memberitakan kepada kami [Ibnu Juraij], ia berkata; telah memberitakan kepada kami [Isma'il] dari [Ma'mar] dari [Ayyub] dari [Ikrimah] dari [Ibnu Abbas], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapa yang mengganti agamanya maka bunuhlah.\" "},"3796":{"ar":"أَخْبَرَنِي هِلَالُ بْنُ الْعَلَاءِ قَالَ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَبْدِ اللَّهِ بْنِ زُرَارَةَ قَالَ حَدَّثَنَا عَبَّادُ بْنُ الْعَوَّامِ قَالَ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ بَدَّلَ دِينَهُ فَاقْتُلُوهُ","id":"Telah mengabarkan kepada kami [Hilal bin Al 'Ala`], ia berkata; telah menceritakan kepada kami [Isma'il bin Abdullah bin Zurarah], ia berkata; telah menceritakan kepada kami ['Abbad bin Al 'Awwam], ia berkata; telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Ikrimah] dari [Ibnu Abbas], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapa yang mengganti agamanya maka bunuhlah.\""},"3797":{"ar":"أَخْبَرَنَا مُوسَى بْنُ عَبْدِ الرَّحْمَنِ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ قَالَ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ الْحَسَنِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ بَدَّلَ دِينَهُ فَاقْتُلُوهُقَالَ أَبُو عَبْد الرَّحْمَنِ وَهَذَا أَوْلَى بِالصَّوَابِ مِنْ حَدِيثِ عَبَّادٍ","id":"Telah mengabarkan kepada kami [Musa bin Abdurrahman], ia berkata; telah menceritakan kepada kami [Muhammad bin Bisy], ia berkata; telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Al Hasan], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"\"Siapa yang mengganti agamanya maka bunuhlah.\" Abu Abdurrahman berkata; ini lebih benar daripada hadits 'Abbad. "},"3798":{"ar":"أَخْبَرَنَا الْحُسَيْنُ بْنُ عِيسَى عَنْ عَبْدِ الصَّمَدِ قَالَ حَدَّثَنَا هِشَامٌ عَنْ قَتَادَةَ عَنْ أَنَسٍ أَنَّ ابْنَ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ بَدَّلَ دِينَهُ فَاقْتُلُوهُ","id":"Telah mengabarkan kepada kami [Al Husain bin Isa] dari [Abdush Shamad], ia berkata; telah menceritakan kepada kami [Hisyam] dari [Qatadah] dari [Anas] bahwa [Ibnu Abbas] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapa yang mengganti agamanya maka bunuhlah.\""},"3799":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ و حَدَّثَنِي حَمَّادُ بْنُ مَسْ��َدَةَ قَالَا حَدَّثَنَا قُرَّةُ بْنُ خَالِدٍ عَنْ حُمَيْدِ بْنِ هِلَالٍ عَنْ أَبِي بُرْدَةَ بْنِ أَبِي مُوسَى الْأَشْعَرِيِّ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَهُ إِلَى الْيَمَنِ ثُمَّ أَرْسَلَ مُعَاذَ بْنَ جَبَلٍ بَعْدَ ذَلِكَ فَلَمَّا قَدِمَ قَالَ أَيُّهَا النَّاسُ إِنِّي رَسُولُ رَسُولِ اللَّهِ إِلَيْكُمْ فَأَلْقَى لَهُ أَبُو مُوسَى وِسَادَةً لِيَجْلِسَ عَلَيْهَا فَأُتِيَ بِرَجُلٍ كَانَ يَهُودِيًّا فَأَسْلَمَ ثُمَّ كَفَرَ فَقَالَ مُعَاذٌ لَا أَجْلِسُ حَتَّى يُقْتَلَ قَضَاءُ اللَّهِ وَرَسُولِهِ ثَلَاثَ مَرَّاتٍ فَلَمَّا قُتِلَ قَعَدَ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] dan telah menceritakan kepada kami [Hammad bin Mas'adah] mereka berkata; telah menceritakan kepada kami [Qurrah bin Khalid] dari [Humaid bin Hilal] dari [Abu Burdah bin Abu Musa Al Asy'ari] dari [ayahnya] bahwa Nabi shallallahu 'alaihi wasallam mengutusnya ke Yaman kemudian mengirimkan Mu'adz bin Jabal setelah itu. Kemudian setelah sampai ia berkata; wahai manusia, sesungguhnya saya adalah utusan Rasulullah shallallahu 'alaihi wasallam kepada kalian. Kemudian Abu Musa melemparkan bantal untuknya agar ia duduk padanya. Kemudian didatangkan seorang laki-laki Yahudi yang masuk Islam kemudian kafir. Maka Mu'adz berkata; saya tidak akan duduk hingga ia dibunuh, inilah keputusan Allah dan RasulullahNya. Sebanyak tiga kali, kemudian setelah dibunuh iapun duduk. "},"3800":{"ar":"أَخْبَرَنَا الْقَاسِمُ بْنُ زَكَرِيَّا بْنِ دِينَارٍ قَالَ حَدَّثَنِي أَحْمَدُ بْنُ مُفَضَّلٍ قَالَ حَدَّثَنَا أَسْبَاطٌ قَالَ زَعَمَ السُّدِّيُّ عَنْ مُصْعَبِ بْنِ سَعْدٍ عَنْ أَبِيهِ قَالَلَمَّا كَانَ يَوْمُ فَتْحِ مَكَّةَ أَمَّنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ النَّاسَ إِلَّا أَرْبَعَةَ نَفَرٍ وَامْرَأَتَيْنِ وَقَالَ اقْتُلُوهُمْ وَإِنْ وَجَدْتُمُوهُمْ مُتَعَلِّقِينَ بِأَسْتَارِ الْكَعْبَةِ عِكْرِمَةُ بْنُ أَبِي جَهْلٍ وَعَبْدُ اللَّهِ بْنُ خَطَلٍ وَمَقِيسُ بْنُ صُبَابَةَ وَعَبْدُ اللَّهِ بْنُ سَعْدِ بْنِ أَبِي السَّرْحِ فَأَمَّا عَبْدُ اللَّهِ بْنُ خَطَلٍ فَأُدْرِكَ وَهُوَ مُتَعَلِّقٌ بِأَسْتَارِ الْكَعْبَةِ فَاسْتَبَقَ إِلَيْهِ سَعِيدُ بْنُ حُرَيْثٍ وَعَمَّارُ بْنُ يَاسِرٍ فَسَبَقَ سَعِيدٌ عَمَّارًا وَكَانَ أَشَبَّ الرَّجُلَيْنِ فَقَتَلَهُ وَأَمَّا مَقِيسُ بْنُ صُبَابَةَ فَأَدْرَكَهُ النَّاسُ فِي السُّوقِ فَقَتَلُوهُ وَأَمَّا عِكْرِمَةُ فَرَكِبَ الْبَحْرَ فَأَصَابَتْهُمْ عَاصِفٌ فَقَالَ أَصْحَابُ السَّفِينَةِ أَخْلِصُوا فَإِنَّ آلِهَتَكُمْ لَا تُغْنِي عَنْكُمْ شَيْئًا هَاهُنَا فَقَالَ عِكْرِمَةُ وَاللَّهِ لَئِنْ لَمْ يُنَجِّنِي مِنْ الْبَحْرِ إِلَّا الْإِخْلَاصُ لَا يُنَجِّينِي فِي الْبَرِّ غَيْرُهُ اللَّهُمَّ إِنَّ لَكَ عَلَيَّ عَهْدًا إِنْ أَنْتَ عَافَيْتَنِي مِمَّا أَنَا فِيهِ أَنْ آتِيَ مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى أَضَعَ يَدِي فِي يَدِهِ فَلَأَجِدَنَّهُ عَفُوًّا كَرِيمًا فَجَاءَ فَأَسْلَمَ وَأَمَّا عَبْدُ اللَّهِ بْنُ سَعْدِ بْنِ أَبِي السَّرْحِ فَإِنَّهُ اخْتَبَأَ عِنْدَ عُثْمَانَ بْنِ عَفَّانَ فَلَمَّا دَعَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ النَّاسَ إِلَى الْبَيْعَةِ جَاءَ بِهِ حَتَّى أَوْقَفَهُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَا رَسُولَ اللَّهِ بَايِعْ عَبْدَ اللَّهِ قَالَ فَرَفَعَ رَأْسَهُ فَنَظَرَ إِلَيْهِ ثَلَاثًا كُلَّ ذَلِكَ يَأْبَى فَبَايَعَهُ بَعْدَ ثَلَاثٍ ثُمَّ أَقْبَلَ عَلَى أَصْحَابِهِ فَقَالَ أَمَا كَانَ فِيكُمْ رَجُلٌ رَشِيدٌ يَقُومُ إِلَى هَذَا حَيْثُ رَآنِي كَفَفْتُ يَدِي عَنْ بَيْعَتِهِ فَيَقْتُلُهُ فَقَالُوا وَمَا يُدْرِينَا يَا رَسُولَ اللَّهِ مَا فِي نَفْسِكَ هَلَّا أَوْمَأْتَ إِلَيْنَا بِعَيْنِكَ قَالَ إِنَّهُ لَا يَنْبَغِي لِنَبِيٍّ أَنْ يَكُونَ لَهُ خَائِنَةُ أَعْيُنٍ","id":"Telah mengabarkan kepada kami [Al Qasim bin Zakariya bin Dinar], ia berkata; telah menceritakan kepada kami [Ahmad bin Mufadhdhal], ia berkata; telah menceritakan kepada kami [Asbath], ia berkata; [As Suddi] mengaku dari [Mush'ab bin Sa'd] dari [ayahnya], ia berkata; pada saat hari penaklukan Mekkah Rasulullah shallallahu 'alaihi wasallam memberi keamanan kepada orang-orang kecuali empat orang dan dua wanita, beliau bersabda: \"Bunuh mereka walaupun engkau dapati mereka bergantungan dikain penutup Ka'bah yaitu Ikrimah bin Abi Jahl, Abdullah bin Khathal, Maqis bin Shubabah, dan abdullah bin Sa'd bin Abi Sarh. Adapun Abdullah bin Khathal ketahuilah bahwa ia didapati bergantungan dikain penutup Ka'bah, lalu Sa'id bin Huraits dan Ammar bin Yasir bersaing untuk mendapatkannya, dan Sa'id bin Huraits mendahului Ammar karena ia lebih muda lalu ia membunuhnya, adapun Maqis bin Shubabah diketemukan orang-orang dipasar lalu mereka membunuhnya, adapun ikrimah ia berlayar lalu datanglah angin kencang, para awak kapal berkata ikhlaskan niat kalian karena tuhan-tuhan kalian tidak akan mampu menolong kalian disini, lalu Ikrimah berkata demi Allah jika tidak ada yang bisa menyelamatkanku dilaut kecuali ikhlas maka tidak ada yang bisa menyelamatkanku didaratan kecuali ikhlas, ya Allah sesungguhnya engkau memiliki janji atasku, jika engkau memaafkanku dari apa yang aku lakukan didalamnya maka aku akan mendatangi Muhammad shallallahu 'alaihi wasallam dan meletakkan tanganku ditangannya dan aku akan mendapatinya sebagai orang yang pemaaf dan bermurah hati, lalu ia datang dan masuk Islam, sedangkan Abdullah bin Sa'd bin Abi Sarh sesungguhnya ia sembunyi dirumah Utsman bin Affan, ketika Rasulullah shallallahu 'alaihi wasallam menyeru orang-orang untuk berbaiat, ia datang bersamanya, hingga ia dibawa kesisi Nabi shallallahu 'alaihi wasallam ia berkata; wahai Rasulullah, baiatlah Abdullah, lalu beliau mengangkat kepala beliau dan melihatnya tiga kali setiap kali melihat beliau enggan lalu beliau membaiatnya setelah ketiga kalinya, lalu beliau bertemu dengan sahabatnya dan bersabda: \"Adakah diantara kalian orang yang berakal, berdiri di sisi orang ini di tempat ia melihatku menahan tanganku untuk berbaiat kepadanya, lalu ia membunuhnya?\" para sahabat berkata; bagaimana kami tahu apa yang ada didalam hatimu wahai Rasulullah, tidakkah anda memberikan isyarat kepada kami? Beliau bersabda: \"Sesungguhnya tidak layak bagi seorang Nabi memiliki mata penipu.\""},"3801":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ بَزِيعٍ قَالَ حَدَّثَنَا يَزِيدُ وَهُوَ ابْنُ زُرَيْعٍ قَالَ أَنْبَأَنَا دَاوُدُ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ رَجُلٌ مِنْ الْأَنْصَارِ أَسْلَمَ ثُمَّ ارْتَدَّ وَلَحِقَ بِالشِّرْكِ ثُمَّ تَنَدَّمَ فَأَرْسَلَ إِلَى قَوْمِهِ سَلُوا لِي رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلْ لِي مِنْ تَوْبَةٍ فَجَاءَ قَوْمُهُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا إِنَّ فُلَانًا قَدْ نَدِمَ وَإِنَّهُ أَمَرَنَا أَنْ نَسْأَلَكَ هَلْ لَهُ مِنْ تَوْبَةٍ فَنَزَلَتْ{ كَيْفَ يَهْدِي اللَّهُ قَوْمًا كَفَرُوا بَعْدَ إِيمَانِهِمْ إِلَى قَوْلِهِ غَفُورٌ رَحِيمٌ }فَأَرْسَلَ إِلَيْهِ فَأَسْلَمَ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin Bazi'], ia berkata; telah menceritakan kepada kami [Yazid yaitu Ibnu Zurai'], ia berkata; telah memberitakan kepada kami [Daud] dari [Ikrimah] dari [Ibnu Abbas], ia berkata; ada seorang Anshor yang masuk Islam lalu ia murtad dan kembali begabung dengan kesyirikan, kemudian ia menyesal dan pergi menemui kaumnya tanyakan kepada Rasulullah shallallahu 'alaihi wasallam apakah saya bisa bertaubat? Lalu kaumnya datang menemui Rasulullah shallallahu 'alaihi wasallam dan berkata sesungguhnya Fulan menyesal dan ia menyuruh kami untuk bertanya kepadamu apakah ia masih bisa bertaubat, lalu turunlah ayat Bagaimana Allah akan menunjuki suatu kaum yang kafir sesudah mereka beriman hingga firmanNya Maha pengampun lagi Penyayang lalu beliau mengutus seseorang kepadanya dan iapun masuk Islam."},"3802":{"ar":"أَخْبَرَنَا زَكَرِيَّا بْنُ يَحْيَى قَالَ حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عَلِيُّ بْنُ الْحُسَيْنِ بْنِ وَاقِدٍ قَالَ أَخْبَرَنِي أَبِي عَنْ يَزِيدَ النَّحْوِيِّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَفِي سُورَةِ النَّحْلِ{ مَنْ كَفَرَ بِاللَّهِ مِنْ بَعْدِ إِيمَانِهِ إِلَّا مَنْ أُكْرِهَ إِلَى قَوْلِهِ لَهُمْ عَذَابٌ عَظِيمٌ }فَنُسِخَ وَاسْتَثْنَى مِنْ ذَلِكَ فَقَالَ{ ثُمَّ إِنَّ رَبَّكَ لِلَّذِينَ هَاجَرُوا مِنْ بَعْدِ مَا فُتِنُوا ثُمَّ جَاهَدُوا وَصَبَرُوا إِنَّ رَبَّكَ مِنْ بَعْدِهَا لَغَفُورٌ رَحِيمٌ }وَهُوَ عَبْدُ اللَّهِ بْنُ سَعْدِ بْنِ أَبِي سَرْحٍ الَّذِي كَانَ عَلَى مِصْرَ كَانَ يَكْتُبُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَزَلَّهُ الشَّيْطَانُ فَلَحِقَ بِالْكُفَّارِ فَأَمَرَ بِهِ أَنْ يُقْتَلَ يَوْمَ الْفَتْحِ فَاسْتَجَارَ لَهُ عُثْمَانُ بْنُ عَفَّانَ فَأَجَارَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Zakariya bin Yahya], ia berkata; telah menceritakan kepada kami [Ishaq bin Ibrahim], ia berkata; telah memberitakan kepada kami [Ali bin Al Hasan bin Waqid], ia berkata; telah mengabarkan kepadaku [ayahku] dari [Yazid An Nahwi] dari [Ikrimah] dari [Ibnu Abbas], ia berkata mengenai Surat Nahl: Barangsiapa yang kafir kepada Allah sesudah dia beriman (dia mendapat kemurkaan Allah), kecuali orang yang dipaksa kafir hingga firmanNya baginya azab yang besar kemudian dihapus dan Allah mengecualikan dari hal tersebut, Allah berfirman: Dan sesungguhnya Tuhanmu (pelindung) bagi orang-orang yang berhijrah sesudah menderita cobaan, kemudian mereka berjihad dan sabar; sesungguhnya Tuhanmu sesudah itu benar-benar Maha Pengampun lagi Maha Penyayang. Ia adalah abdullah bin Sa'd bin Abi Sarh yang dahulu berada di Mesir, ia menulis untuk Rasulullah shallallahu 'alaihi wasallam lalu syetan menghilangkannya dan ia kembali kepada kekafiran, maka beliau menyuruh untuk membunuhnya pada hari penaklukan Mekkah lalu Utsman bin Affan meminta untuk dilindungi dan Rasulullah shallallahu 'alaihi wasallam melindunginya. "},"3803":{"ar":"أَخْبَرَنَا عُثْمَانُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا عَبَّادُ بْنُ مُوسَى قَالَ حَدَّثَنَا إِسْمَعِيلُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنِي إِسْرَائِيلُ عَنْ عُثْمَانَ الشَّحَّامِ قَالَ كُنْتُ أَقُودُ رَجُلًا أَعْمَى فَانْتَهَيْتُ إِلَى عِكْرِمَةَ فَأَنْشَأَ يُحَدِّثُنَا قَالَ حَدَّثَنِي ابْنُ عَبَّاسٍأَنَّ أَعْمَى كَانَ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَتْ لَهُ أُمُّ وَلَدٍ وَكَانَ لَهُ مِنْهَا ابْنَانِ وَكَانَتْ تُكْثِرُ الْوَقِيعَةَ بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَتَسُبُّهُ فَيَزْجُرُهَا فَلَا تَنْزَجِرُ وَيَنْهَاهَا فَلَا تَنْتَهِي فَلَمَّا كَانَ ذَاتَ لَيْلَةٍ ذَكَرْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَوَقَعَتْ فِيهِ فَلَمْ أَصْبِرْ أَنْ قُمْتُ إِلَى الْمِغْوَلِ فَوَضَعْتُهُ فِي بَطْنِهَا فَاتَّكَأْتُ عَلَيْهِ فَقَتَلْتُهَا فَأَصْبَحَتْ قَتِيلًا فَذُكِرَ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَمَعَ النَّاسَ وَقَالَ أَنْشُدُ اللَّهَ رَجُلًا لِي عَلَيْهِ حَقٌّ فَعَلَ مَا فَعَلَ إِلَّا قَامَ فَأَقْبَلَ الْأَعْمَى يَتَدَلْدَلُ فَقَالَ يَا رَسُولَ اللَّهِ أَنَا صَاحِبُهَا كَانَتْ أُمَّ وَلَدِي وَكَانَتْ بِي لَطِيفَةً رَفِيقَةً وَلِي مِنْهَا ابْنَانِ مِثْلُ اللُّؤْلُؤَتَيْنِ وَلَكِنَّهَا كَانَتْ تُكْثِرُ الْوَقِيعَةَ فِيكَ وَتَشْتُمُكَ فَأَنْهَاهَا فَلَا تَنْتَهِي وَأَزْجُرُهَا فَلَا تَنْزَجِرُ فَلَمَّا كَانَتْ الْبَارِحَةُ ذَكَرْتُكَ فَوَقَعَتْ فِيكَ فَقُمْتُ إِلَى الْمِغْوَلِ فَوَضَعْتُهُ فِي بَطْنِهَا فَاتَّكَأْتُ عَلَيْهَا حَتَّى قَتَلْتُهَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا اشْهَدُوا أَنَّ دَمَهَا هَدَرٌ","id":"Telah mengabarkan kepada kami [Utsman bin Abdullah], ia berkata; telah menceritakan kepada kami ['Abbad bin Musa], ia berkata; telah menceritakan kepada kami [Isma'il bin Ja'far], ia berkata; telah menceritakan kepadaku [Israil] dari [Utsman Asy Syahham] ia berkata; aku menuntun seorang yang buta dan sampai kepada [Ikrimah], ia mulai mengajak kami bicara, ia berkata [Ibnu Abbas] menceritakan kepadaku bahwa dahulu ada orang buta dimasa Rasulullah shallallahu 'alaihi wasallam yang memiliki budak wanita, ia memiliki dua orang anak dari hubungan dengannya, budak tersebut banyak mencela Rasulullah shallallahu 'alaihi wasallam, ia selalu menghina beliau dan orang buta tersebut mencegahnya namun ia tetap tidak dapat dicegah dan ia melarangnya namun budak tersebut tidak berhenti, pada suatu malam aku menyebutkan Nabi Shallallahu Alaihi wa sallam lalu ia mencela beliau maka saya tidak sabar untuk mengambil sebuah cangkul dan aku letakkan di keperutnya dan menyandarinya hingga saya membunuhnya dan terbunuhlah ia, kemudian hal itu disampaikan kepada Nabi shallallahu 'alaihi wasallam lalu beliau mengumpulkan manusia dan bersabda: \" Aku bersumpah kepada Allah dan meminta seseorang yang aku memiliki hak atasnya, ia melakukan apa yang telah ia lakukan agar ia berdiri kemudian menghadaplah orang yang buta dan berjalan gontai dan berkata; wahai Rasulullah akulah pemiliknya, ia dulu adalah ibu dari anakku, ia adalah wanita yang lembut dan mesra terhadapku, aku memiliki dua anak seperti permata darinya, namun ia sering mencela dan menghinamu, aku melarangnya namun ia tidak berhenti dan aku mencegahnya tapi ia tetap dapat dicegah, tadi malam aku menyebut dirimu lalu ia mencelamu lalu aku bangkit untuk mengambil cangkul dan meletakkan diperutnya dan menyandarinya hingga aku membunuhnya, kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \" Saksikanlah bahwa darah wanita itu adalah sia-sia.\""},"3804":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا مُعَاذُ بْنُ مُعَاذٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ تَوْبَةَ الْعَنْبَرِيِّ عَنْ عَبْدِ اللَّهِ بْنِ قُدَامَةَ بْنِ عَنَزَةَ عَنْ أَبِي بَرْزَةَ الْأَسْلَمِيِّ قَالَأَغْلَظَ رَجُلٌ لِأَبِي بَكْرٍ الصِّدِّيقِ فَقُلْتُ أَقْتُلُهُ فَانْتَهَرَنِي وَقَالَ لَيْسَ هَذَا لِأَحَدٍ بَعْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami ['Amr bin Ali], ia berkata; telah menceritakan kepada kami [Mu'adz bin Mu'adz], ia berkata; telah menceritakan kepada kami [Syu'bah] dari [Taubah Al 'Anbari] dari [Abdullah bin Qudamah bin 'Anazah] dari [Abu Barzah Al Aslami], ia berkata; seseorang berbuat kasar kepada [Abu Bakar Ash Shiddiq] kemudian saya mengatakan kepadanya; apakah boleh saya membunuhnya? Lalu ia mencegahku dan berkata; hal ini bukan hak bagi seseorang setelah Nabi shallallahu 'alaihi wasallam. "},"3805":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْعَلَاءِ قَالَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ أَبِي بَرْزَةَ قَالَتَغَيَّظَ أَبُو بَكْرٍ عَلَى رَجُلٍ فَقُلْتُ مَنْ هُوَ يَا خَلِيفَةَ رَسُولِ اللَّهِ قَالَ لِمَ قُلْتُ لِأَضْرِبَ عُنْقَهُ إِنْ أَمَرْتَنِي بِذَلِكَ قَالَ أَفَكُنْتَ فَاعِلًا قُلْتُ نَعَمْ قَالَ فَوَاللَّهِ لَأَذْهَبَ عِظَمُ كَلِمَتِيَ الَّتِي قُلْتُ غَضَبَهُ ثُمَّ قَالَ مَا كَانَ لِأَحَدٍ بَعْدَ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Muhammad bin Al 'Ala`], ia berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari ['Amr bin Murrah] dari [Salim bin Abu Al Ja'd] dari [Abu Barzah], ia berkata; [Abu Bakar] marah kepada seseorang, kemudian saya katakan; siapakah ia wahai khalifah Rasulullah? ia berkata; untuk apa? Saya katakan; Agar saya penggal lehernya apabila engkau memerintahkan hal tersebut. Ia berkata; apakah engkau akan melakukannya? Saya katakan; ya. Ia berkata; demi Allah sungguh sebagian besar perkataanku yang saya katakan telah menghilangkan kemarahannya. Kemudian ia berkata; hal itu tidak boleh bagi seorangpun setelah Muhammad shallallahu 'alaihi wasallam. "},"3806":{"ar":"أَخْبَرَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا يَعْلَى قَالَ حَدَّثَنَا الْأَعْمَشُ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ أَبِي الْبَخْتَرِيِّ عَنْ أَبِي بَرْزَةَ قَالَمَرَرْتُ عَلَى أَبِي بَكْرٍ وَهُوَ مُتَغَيِّظٌ عَلَى رَجُلٍ مِنْ أَصْحَابِهِ فَقُلْتُ يَا خَلِيفَةَ رَسُولِ اللَّهِ مَنْ هَذَا الَّذِي تَغَيَّظُ عَلَيْهِ قَالَ وَلِمَ تَسْأَلُ قُلْتُ أَضْرِبُ عُنُقَهُ قَالَ فَوَاللَّهِ لَأَذْهَبَ عِظَمُ كَلِمَتِي غَضَبَهُ ثُمَّ قَالَ مَا كَانَتْ لِأَحَدٍ بَعْدَ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Abu Daud], ia berkata; telah menceritakan kepada kami [Ya'la], ia berkata; telah menceritakan kepada kami [Al A'masy] dari ['Amr bin Murrah] dari [Abu Al Bakhtari] dari [Abu Barzah], ia berkata; saya melewati [Abu Bakar] dan ia sedang marah kepada seseorang dari para sahabatnya. Kemudian saya katakan; wahai khalifah, siapakah orang yang engkau marah kepadanya? Ia berkata; kenapa engkau bertanya? Saya katakan; saya akan memenggal lehernya. Ia berkata; demi Allah sungguh sebagian besar perkataan yang saya katakan telah menghilangkan kemarahannya. Kemudian ia berkata; hal itu tidak boleh bagi seorangpun setelah Muhammad shallallahu 'alaihi wasallam."},"3807":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى عَنْ يَحْيَى بْنِ حَمَّادٍ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ سُلَيْمَانَ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ أَبِي الْبَخْتَرِيِّ عَنْ أَبِي بَرْزَةَ قَالَتَغَيَّظَ أَبُو بَكْرٍ عَلَى رَجُلٍ فَقَالَ لَوْ أَمَرْتَنِي لَفَعَلْتُ قَالَ أَمَا وَاللَّهِ مَا كَانَتْ لِبَشَرٍ بَعْدَ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dari [Yahya bin Hammad], ia berkata; telah menceritakan kepada kami [Abu 'Awanah] dari [Sulaiman] dari ['Amr bin Murrah] dari [Abu Al Bukhturi] dari [Abu Barzah], ia berkata; [Abu Bakar] marah kepada seseorang dari para sahabatnya. Kemudian Abu Barzah berkata; seandainya engkau memerintahkan kepadaku niscaya saya akan melakukannya. Abu Bakar berkata; demi Allah tidak hal tersebut tidak diperbolehkan bagi manusia setelah Muhammad shallallahu 'alaihi wasallam. "},"3808":{"ar":"أَخْبَرَنَا مُعَاوِيَةُ بْنُ صَالِحٍ الْأَشْعَرِيُّ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ زَيْدٍ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي بَرْزَةَ قَالَغَضِبَ أَبُو بَكْرٍ عَلَى رَجُلٍ غَضَبًا شَدِيدًا حَتَّى تَغَيَّرَ لَوْنُهُ قُلْتُ يَا خَلِيفَةَ رَسُولِ اللَّهِ وَاللَّهِ لَئِنْ أَمَرْتَنِي لَأَضْرِبَنَّ عُنُقَهُ فَكَأَنَّمَا صُبَّ عَلَيْهِ مَاءٌ بَارِدٌ فَذَهَبَ غَضَبُهُ عَنْ الرَّجُلِ قَالَ ثَكِلَتْكَ أُمُّكَ أَبَا بَرْزَةَ وَإِنَّهَا لَمْ تَكُنْ لِأَحَدٍ بَعْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ أَبُو عَبْد الرَّحْمَنِ هَذَا خَطَأٌ وَالصَّوَابُ أَبُو نَصْرٍ وَاسْمُهُ حُمَيْدُ بْنُ هِلَالٍ خَالَفَهُ شُعْبَةُ","id":"Telah mengabarkan kepada kami [Mu'awiyah bin Shaleh Al Asy'ari], ia berkata; telah menceritakan kepada kami [Abdullah bin Ja'far], ia berkata; telah menceritakan kepada kami ['Ubaidullah] dari [Zaid] dari ['Amr bin Murrah] dari [Abu Nadhrah] dari [Abu Barzah], ia berkata; [Abu Bakar] marah kepada seseorang dengan kemarahan yang sangat hingga warna kulitnya berubah. Saya mengatakan; wahai khalifah Rasulullah, demi Allah seandainya engkau memerintahkan saya sungguh akan saya penggal lehernya. Seolah-olah ia tersirami air dingin. Kemudian kemarahannya kepada orang tersebut hilang. Ia berkata; ibumu kehilangan dirimu, wahai Abu Barzah, sesungguhnya hal tersebut tidak boleh untuk seseorang setelah Rasulullah shallallahu 'alaihi wasallam. Abu Abdurrahman berkata; hal ini adalah suatu kesalahan, dan yang benar adalah Abu Nashr, namanya adalah Humaid bin Hilal. Dan Syu'bah menyelisihinya. "},"3809":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى عَنْ أَبِي دَاوُدَ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ قَالَ سَمِعْتُ أَبَا نَصْرٍ يُحَدِّثُ عَنْ أَبِي بَرْزَةَ قَالَأَتَيْتُ عَلَى أَبِي بَكْرٍ وَقَدْ أَغْلَظَ لِرَجُلٍ فَرَدَّ عَلَيْهِ فَقُلْتُ أَلَا أَضْرِبُ عُنُقَهُ فَانْتَهَرَنِي فَقَالَ إِنَّهَا لَيْسَتْ لِأَحَدٍ بَعْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ أَبُو عَبْد الرَّحْمَنِ أَبُو نَصْرٍ حُمَيْدُ بْنُ هِلَالٍ وَرَوَاهُ عَنْهُ يُونُسُ بْنُ عُبَيْدٍ فَأَسْنَدَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dari [Abu Daud], ia berkata; telah menceritakan kepada kami [Syu'bah] dari ['Amr bin Murrah], ia berkata; saya mendengar [Abu Nashr] menceritakan dari [Abu Barzah], ia berkata; saya datang kepada [Abu Bakar] dan ia telah marah kepada seseorang dan orang tersebut membalasnya. Kemudian saya katakan; tidakkah saya memenggal lehernya? Kemudian ia melarangku dan berkata; sesungguhnya hal tersebut tidak boleh untuk seseorang setelah Rasulullah shallallahu 'alaihi wasallam. Abu Abdurrahman berkata; Abu Nashr adalah Humaid bin Hilal. Yunus bin 'Ubaid meriwayatkan hadits tersebut darinya. "},"3810":{"ar":"أَخْبَرَنِي أَبُو دَاوُدَ قَالَ حَدَّثَنَا عَفَّانُ قَالَ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ قَالَ حَدَّثَنَا يُونُسُ بْنُ عُبَيْدٍ عَنْ حُمَيْدِ بْنِ هِلَالٍ عَنْ عَبْدِ اللَّهِ بْنِ مُطَرِّفِ بْنِ الشِّخِّيرِ عَنْ أَبِي بَرْزَةَ الْأَسْلَمِيِّ أَنَّهُ قَالَكُنَّا عِنْدَ أَبِي بَكْرٍ الصِّدِّيقِ فَغَضِبَ عَلَى رَجُلٍ مِنْ الْمُسْلِمِينَ فَاشْتَدَّ غَضَبُهُ عَلَيْهِ جِدًّا فَلَمَّا رَأَيْتُ ذَلِكَ قُلْتُ يَا خَلِيفَةَ رَسُولِ اللَّهِ أَضْرِبُ عُنُقَهُ فَلَمَّا ذَكَرْتُ الْقَتْلَ أَضْرَبَ عَنْ ذَلِكَ الْحَدِيثِ أَجْمَعَ إِلَى غَيْرِ ذَلِكَ مِنْ النَّحْوِ فَلَمَّا تَفَرَّقْنَا أَرْسَلَ إِلَيَّ فَقَالَ يَا أَبَا بَرْزَةَ مَا قُلْتَ وَنَسِيتُ الَّذِي قُلْتُ قُلْتُ ذَكِّرْنِيهِ قَالَ أَمَا تَذْكُرُ مَا قُلْتَ قُلْتُ لَا وَاللَّهِ قَالَ أَرَأَيْتَ حِينَ رَأَيْتَنِي غَضِبْتُ عَلَى رَجُلٍ فَقُلْتَ أَضْرِبُ عُنُقَهُ يَا خَلِيفَةَ رَسُولِ اللَّهِ أَمَا تَذْكُرُ ذَلِكَ أَوَ كُنْتَ فَاعِلًا ذَلِكَ قُلْتُ نَعَمْ وَاللَّهِ وَالْآنَ إِنْ أَمَرْتَنِي فَعَلْتُ قَالَ وَاللَّهِ مَا هِيَ لِأَحَدٍ بَعْدَ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ أَبُو عَبْد الرَّحْمَنِ هَذَا الْحَدِيثُ أَحْسَنُ الْأَحَادِيثِ وَأَجْوَدُهَا وَاللَّهُ تَعَالَى أَعْلَمُ","id":"Telah mengabarkan kepada kami [Abu Daud], ia berkata; telah menceritakan kepada kami [Affan], ia berkata; telah menceritakan kepada kami [Yazid bin Zurai'], ia berkata; telah menceritakan kepada kami [Yunus bin 'Ubaid] dari [Humaid bin Hilal] dari [Abdullah bin Mutharrif bin Asy Syakhir] dari [Abu Barzah Al Aslami] bahwa Ia berkata kami pernah bersama [Abu Bakar Ash Shiddiq] kemudian ia marah kepada seseorang dari orang-orang muslim, dan kemarahannya sangat keras. Tatkala saya melihat hal tersebut saya katakan; wahai khalifah Rasulullah, bolehkah saya penggal lehernya? Kemudian tatkala saya menyebutkan pembunuhan maka ia berpaling dari peristiwa tersebut dan berniat untuk mengarah ke selain hal tersebut. Kemudian setelah kami bubar ia mengirim utusan kepadaku dan berkata; wahai Abu Barzah, apa yang engkau katakan? Dan saya lupa yang saya katakan, saya katakan; inggatkan saya. Ia berkata; tidakkah engkau ingat apa yang engkau katakan? Saya katakan; tidak, demi Allah. Ia berkata; tidakkah engkau melihat ketika engkau melihatku marah kepada seseorang kemudian engkau mengatakan; bolehkan saya memenggal lehernya wahai khalifah Rasulullah? Apakah engkau mengingat hal tersebut atau engkau akan melakukan hal tersebut? Saya katakan; ya, demi Allah. Dan sekarang jika engkau memerintahkan saya maka saya akan melakukannya. Ia berkata; demi Allah hal tersebut tidak boleh bagi seseorang setelah Muhammad shallallahu 'alaihi wasallam. Abu Abdurrahman berkata; hadits ini adalah hadits yang terbaik. Allah ta'ala a'lam."},"3811":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْعَلَاءِ عَنْ ابْنِ إِدْرِيسَ قَالَ أَنْبَأَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ عَبْدِ اللَّهِ بْنِ سَلَمَةَ عَنْ صَفْوَانَ بْنِ عَسَّالٍ قَالَقَالَ يَهُودِيٌّ لِصَاحِبِهِ اذْهَبْ بِنَا إِلَى هَذَا النَّبِيِّ قَالَ لَهُ صَاحِبُهُ لَا تَقُلْ نَبِيٌّ لَوْ سَمِعَكَ كَانَ لَهُ أَرْبَعَةُ أَعْيُنٍ فَأَتَيَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَسَأَلَاهُ عَنْ تِسْعِ آيَاتٍ بَيِّنَاتٍ فَقَالَ لَهُمْ لَا تُشْرِكُوا بِاللَّهِ شَيْئًا وَلَا تَسْرِقُوا وَلَا تَزْنُوا وَلَا تَقْتُلُوا النَّفْسَ الَّتِي حَرَّمَ اللَّهُ إِلَّا بِالْحَقِّ وَلَا تَمْشُوا بِبَرِيءٍ إِلَى ذِي سُلْطَانٍ وَلَا تَسْحَرُوا وَلَا تَأْكُلُوا الرِّبَا وَلَا تَقْذِفُوا الْمُحْصَنَةَ وَلَا تَوَلَّوْا يَوْمَ الزَّحْفِ وَعَلَيْكُمْ خَاصَّةً يَهُودُ أَنْ لَا تَعْدُوا فِي السَّبْتِ فَقَبَّلُوا يَدَيْهِ وَرِجْلَيْهِ وَقَالُوا نَشْهَدُ أَنَّكَ نَبِيٌّ قَالَ فَمَا يَمْنَعُكُمْ أَنْ تَتَّبِعُونِي قَالُوا إِنَّ دَاوُدَ دَعَا بِأَنْ لَا يَزَالَ مِنْ ذُرِّيَّتِهِ نَبِيٌّ وَإِنَّا نَخَافُ إِنْ اتَّبَعْنَاكَ أَنْ تَقْتُلَنَا يَهُودُ","id":"Telah mengabarkan kepada kami [Muhammad bin Al 'Ala`] dari [Ibnu Idris], ia berkata; telah memberitakan kepada kami [Syu'bah] dari ['Amr bin Murrah] dari [Abdullah bin Salamah] dari [Shafwan bin 'Assal] ia berkata; seorang Yahudi berkata kepada temannya; pergilah bersama kami kepada Nabi ini. Lalu temannya berkata kepadanya; jangan engkau katakan Nabi, jika ia mendengarmu ia memiliki empat mata. Lalu mereka berdua mendatangi Rasulullah shallallahu 'alaihi wasallam dan bertanya mengenai sembilan ayat yang jelas, lalu beliau bersabda kepada mereka: \"Janganlah kalian menyekutukan Allah dengan sesuatupun, janganlah kalian mencuri, janganlah kalian berzina, janganlah kalian membunuh jiwa yang diharamkan Allah kecuali dengan haq, janganlah kalian berjalan membawa orang yang tidak bersalah kepada yang penguasa, janganlah kalian berbuat sihir, janganlah kalian makan harta riba, janganlah kalian menuduh seorang yang suci berbuat zina, janganlah kalian berpaling dihari bertemu dengan musuh, dan wajib khusus bagi kalian hai orang yahudi agar tidak melampaui batas pada hari sabtu. Lalu mereka mencium tangan dan kaki beliau dan berkata; kami bersaksi bahwa engkau adalah Nabi, kemudian beliau bersabda: \" Lalu apa yang menghalangi kalian untuk mengikutiku, \" mereka menjawab karena Dawud menyeru bahwa masih ada Nabi dari keturunannya, dan kami khawatir jika kami mengikutimu maka orang-orang yahudi akan membunuh kami."},"3812":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا عَبَّادُ بْنُ مَيْسَرَةَ الْمَنْقَرِيُّ عَنْ الْحَسَنِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ عَقَدَ عُقْدَةً ثُمَّ نَفَثَ فِيهَا فَقَدْ سَحَرَ وَمَنْ سَحَرَ فَقَدْ أَشْرَكَ وَمَنْ تَعَلَّقَ شَيْئًا وُكِلَ إِلَيْهِ","id":"Telah mengabarkan kepada kami ['Amr bin Ali], ia berkata; telah menceritakan kepada kami [Abu Daud], ia berkata; telah menceritakan kepada kami ['Abbad bin Maisarah Al Manqari] dari [Al Hasan] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Barang siapa yang mengikat buhul kemudian meniupnya sungguh ia telah berbuat sihir, dan barang siapa yang melakukan sihir maka sungguh ia telah berbuat syirik dan barang siapa yang menggantungkan sesuatu maka ia akan diserahkan kepadanya."},"3813":{"ar":"أَخْبَرَنَا هَنَّادُ بْنُ السَّرِيِّ عَنْ أَبِي مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ ابْنِ حَيَّانَ يَعْنِي يَزِيدَ عَنْ زَيْدِ بْنِ أَرْقَمَ قَالَسَحَرَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلٌ مِنْ الْيَهُودِ فَاشْتَكَى لِذَلِكَ أَيَّامًا فَأَتَاهُ جِبْرِيلُ عَلَيْهِ السَّلَام فَقَالَ إِنَّ رَجُلًا مِنْ الْيَهُودِ سَحَرَكَ عَقَدَ لَكَ عُقَدًا فِي بِئْرِ كَذَا وَكَذَا فَأَرْسَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاسْتَخْرَجُوهَا فَجِيءَ بِهَا فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَأَنَّمَا نُشِطَ مِنْ عِقَالٍ فَمَا ذَكَرَ ذَلِكَ لِذَلِكَ الْيَهُودِيِّ وَلَا رَآهُ فِي وَجْهِهِ قَطُّ","id":"Telah mengabarkan kepada kami [Hannad bin As Sari] dari [Abu Mu'awiyah] dari [Al A'masy] dari [Ibnu Hayyan yaitu Yazid] dari [Zaid bin Arqam], ia berkata; terdapat seorang laki-laki dari kalangan Yahudi yang menyihir Nabi shallallahu 'alaihi wasallam, sehingga beliau beberapa hari sakit Karena hal tersebut. Kemudian beliau di datangi Jibril 'alaihissalam dan berkata; sesungguhnya terdapat seorang laki-laki dari kalangan Yahudi Yang menyihimu. Ia mengikat buhul di sebuah sumur ini, dan ini. Kemudian Rasulullah shallallahu 'alaihi wasallam mengirimkan orang dan mereka mengeluarkannya dan didatangkan kepada beliau. Kemudian Rasulullah shallallahu 'alaihi wasallam berdiri seolah-olah beliau terbebas dari ikatan. Dan beliau tidak menyebutkan hal tersebut kepada orang Yahudi itu dan beliau tidak melihatnya di wajahnya sama sekali. "},"3814":{"ar":"أَخْبَرَنَا هَنَّادُ بْنُ السَّرِيِّ فِي حَدِيثِهِ عَنْ أَبِي الْأَحْوَصِ عَنْ سِمَاكٍ عَنْ قَابُوسَ عَنْ أَبِيهِ قَالَ جَاءَ رَجُلٌ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ح و أَخْبَرَنِي عَلِيُّ بْنُ مُحَمَّدِ بْنِ عَلِيٍّ قَالَ حَدَّثَنَا خَلَفُ بْنُ تَمِيمٍ قَالَ حَدَّثَنَا أَبُو الْأَحْوَصِ قَالَ حَدَّثَنَا سِمَاكُ بْنُ حَرْبٍ عَنْ قَابُوسَ بْنِ مُخَارِقٍ عَنْ أَبِيهِ قَالَ وَسَمِعْتُ سُفْيَانَ الثَّوْرِيَّ يُحَدِّثُ بِهَذَا الْحَدِيثِ قَالَجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ الرَّجُلُ يَأْتِينِي فَيُرِيدُ مَالِي قَالَ ذَكِّرْهُ بِاللَّهِ قَالَ فَإِنْ لَمْ يَذَّكَّرْ قَالَ فَاسْتَعِنْ عَلَيْهِ مَنْ حَوْلَكَ مِنْ الْمُسْلِمِينَ قَالَ فَإِنْ لَمْ يَكُنْ حَوْلِي أَحَدٌ مِنْ الْمُسْلِمِينَ قَالَ فَاسْتَعِنْ عَلَيْهِ بِالسُّلْطَانِ قَالَ فَإِنْ نَأَى السُّلْطَانُ عَنِّي قَالَ قَاتِلْ دُونَ مَالِكَ حَتَّى تَكُونَ مِنْ شُهَدَاءِ الْآخِرَةِ أَوْ تَمْنَعَ مَالَكَ","id":"Telah mengabarkan kepada kami [Hannad bin As Sari] dalam haditsnya dari [Abu Al Ahwash] dari [Simak] dari [Qabus] dari [ayahnya], ia berkata; telah datang seorang laki-laki kepada Rasulullah shallallahu 'alaihi wasallam... telah menceritakan dan mengabarkan kepadaku [Ali bin Muhammad bin Ali], ia berkata; telah menceritakan kepada kami [Khalaf bin Tamim], ia berkata; telah menceritakan kepada kami [Abu Al Ahwash], ia berkata; telah menceritakan kepada kami [Simak bin Harb] dari [Qabus bin Mukhariq] dari [ayahnya], ia berkata; saya mendengar [Sufyan Ats Tsauri] menceritakan dengan hadits ini, ia berkata; telah datang seorang laki-laki kepada Nabi shallallahu 'alaihi wasallam kemudian ia berkata; ada seseorang yang datang kepadaku menginginkan hartaku. beliau bersabda: \" Ingatkan dia kepada Allah.\" Kemudian apabila ia tidak dapat diberi pengitan? Mintalah orang-orang disekitarmu dari kalangan orang-orang muslim untuk menghadapinya. Ia berkata; apabila sekitarku tidak ada seorangpun dari kalangan orang muslim. Ia berkata; Apabila penguasa pergi dariku? beliau bersabda: \"Perangilah demi hartamu hingga engkau menjadi bagian dari orang-orang yang mati syahid pada hari Akhir atau engkau menolak hartamu.\""},"3815":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ الْهَادِ عَنْ عَمْرِو بْنِ قُهَيْدٍ الْغِفَارِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَجَاءَ رَجُلٌ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ أَرَأَيْتَ إِنْ عُدِيَ عَلَى مَالِي قَالَ فَانْشُدْ بِاللَّهِ قَالَ فَإِنْ أَبَوْا عَلَيَّ قَالَ فَانْشُدْ بِاللَّهِ قَالَ فَإِنْ أَبَوْا عَلَيَّ قَالَ فَانْشُدْ بِاللَّهِ قَالَ فَإِنْ أَبَوْا عَلَيَّ قَالَ فَقَاتِلْ فَإِنْ قُتِلْتَ فَفِي الْجَنَّةِ وَإِنْ قَتَلْتَ فَفِي النَّارِ","id":"Telah mengabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Al Laits] dari [Ibnu Al Had] dari ['Amr bin Quhaid Al Ghifari] dari [Abu Hurairah], ia berkata; telah datang seseorang kepada Rasulullah shallallahu 'alaihi wasallam dan berkata; wahai Rasulullah, bagaimana pendapatmu apabila hartaku diganggu? Beliau bersabda: \"Bersumpahlah dengan nama Allah dan mintalah kepadanya. Ia berkata; Apabila mereka menolak? Beliau bersabda: \" Bersumpahlah dengan nama Allah dan mintalah kepadanya.\" Ia berkata; Apabila mereka menolak? Beliau bersabda: \" Bersumpahlah dengan nama Allah dan mintalah kepadanya.\" Ia berkata; Apabila mereka menolak? Beliau bersabda: \"Perangilah mereka, apabila engkau terbunuh maka engkau di Surga dan jika engkau membunuh maka mereka berada di Neraka. "},"3816":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ عَبْدِ الْحَكَمِ عَنْ شُعَيْبِ بْنِ اللَّيْثِ قَالَ أَنْبَأَنَا اللَّيْثُ عَنْ ابْنِ الْهَادِ عَنْ قُهَيْدِ بْنِ مُطَرِّفٍ الْغِفَارِيِّ عَنْ أَبِي هُرَيْرَةَأَنَّ رَجُلًا جَاءَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ أَرَأَيْتَ إِنْ عُدِيَ عَلَى مَالِي قَالَ فَانْشُدْ بِاللَّهِ قَالَ فَإِنْ أَبَوْا عَلَيَّ قَالَ فَانْشُدْ بِاللَّهِ قَالَ فَإِنْ أَبَوْا عَلَيَّ قَالَ فَانْشُدْ بِاللَّهِ قَالَ فَإِنْ أَبَوْا عَلَيَّ قَالَ فَقَاتِلْ فَإِنْ قُتِلْتَ فَفِي الْجَنَّةِ وَإِنْ قَتَلْتَ فَفِي النَّارِ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin Abdul Hakam] dari [Syu'bah bin Al Laits], ia berkata; telah memberitakan kepada kami [Al Laits] dari [Ibnu Al Had] dari [Quhaid bin Muthorrif Al Ghifari] dari [Abu Hurairah] bahwa Seorang laki-laki datang kepada Rasulullah shallallahu 'alaihi wasallam dan berkata; wahai Rasulullah, bagaimana pendapatmu apabila hartaku diganggu? Beliau bersabda: \"Bersumpahlah dengan nama Allah dan mintalah kepadanya. Ia berkata; Apabila mereka menolak? Beliau bersabda: \" Bersumpahlah dengan nama Allah dan mintalah kepadanya.\" Ia berkata; Apabila mereka menolak? Beliau bersabda: \" Bersumpahlah dengan nama Allah dan mintalah kepadanya.\" Ia berkata; Apabila mereka menolak? Beliau bersabda: \"Perangilah mereka, apabila engkau terbunuh maka engkau di Surga dan jika engkau membunuh maka mereka berada di Neraka. "},"3817":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا حَاتِمٌ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ قَاتَلَ دُونَ مَالِهِ فَقُتِلَ فَهُوَ شَهِيدٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul Al A'la], ia berkata; telah menceritakan kepada kami [Khalid], ia berkata; telah menceritakan kepada kami [Hatim] dari ['Amr bin Dinar] dari [Abdullah bin 'Amr], ia berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang berperang mempertahankan hartanya kemudian terbunuh maka ia adalah orang yang syahid.\""},"3818":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ بَزِيعٍ قَالَ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ عَنْ أَبِي يُونُسَ الْقُشَيْرِيِّ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ عَبْدِ اللَّهِ بْنِ صَفْوَانَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ قَاتَلَ دُونَ مَالِهِ فَقُتِلَ فَهُوَ شَهِيدٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin Bazi'], ia berkata; telah menceritakan kepada kami [Bisyr bin Al Mufadhdhal] dari [Abu Yunus Al Qusyari] dari ['Amr bin Dinar] dari [Abdullah bin Shafwan] dari [Abdullah bin 'Amr], ia berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang berperang mempertahankan hartanya kemudian terbunuh maka ia adalah orang yang syahid.\""},"3819":{"ar":"أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ فَضَالَةَ بْنِ إِبْرَاهِيمَ النَّيْسَابُورِيُّ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ قَالَ حَدَّثَنَا سَعِيدٌ قَالَ أَنْبَأَنَا أَبُو الْأَسْوَدِ مُحَمَّدُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ عِكْرِمَةَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ الْعَاصِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قُتِلَ دُونَ مَالِهِ مَظْلُومًا فَلَهُ الْجَنَّةُ","id":"Telah mengabarkan kepadaku [Abdullah bin Fadhalah bin Ibrahim An Naisaburi], ia berkata; telah memberitakan kepada kami [Abdullah], ia berkata; telah menceritakan kepada kami [Sa'id], ia berkata; telah memberitakan kepada kami [Abu Al Aswad Muhammad bin Abdurrahman] dari [Ikrimah] dari [Abdullah bin 'Amr bin Al 'Ash] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang terbunuh mempertahankan hartanya dalam keadaan dizhalimi maka baginya Surga.\""},"3820":{"ar":"أَخْبَرَنَا جَعْفَرُ بْنُ مُحَمَّدِ بْنِ الْهُذَيْلِ قَالَ حَدَّثَنَا عَاصِمُ بْنُ يُوسُفَ قَالَ حَدَّثَنَا سُعَيْرُ بْنُ الْخِمْسِ عَنْ عَبْدِ اللَّهِ بْنِ الْحَسَنِ عَنْ عِكْرِمَةَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قُتِلَ دُونَ مَالِهِ فَهُوَ شَهِيدٌ","id":"Telah mengabarkan kepada kami [Ja'far bin Muhammad Al Hudzali], ia berkata; telah menceritakan kepada kami ['Ashim bin Yusuf], ia berkata; telah menceritakan kepada kami [Su'air bin Al Khims] dari [Abdullah bin Al Hasan] dari [Ikrimah] dari [Abdullah bin 'Amr], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang terbunuh mempertahankan hartanya maka ia adalah syahid.\""},"3821":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ حَسَنٍ عَنْ إِبْرَاهِيمَ بْنِ مُحَمَّدِ بْنِ طَلْحَةَ أَنَّهُ سَمِعَ عَبْدَ اللَّهِ بْنَ عَمْرٍو يُحَدِّثُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أُرِيدَ مَالُهُ بِغَيْرِ حَقٍّ فَقَاتَلَ فَقُتِلَ فَهُوَ شَهِيدٌهَذَا خَطَأٌ وَالصَّوَابُ حَدِيثُ سُعَيْرِ بْنِ الْخِمْسِ","id":"Telah mengabarkan kepada kami ['Amr bin Ali], ia berkata; telah menceritakan kepada kami [Yahya bin Sa'id], ia berkata; telah menceritakan kepada kami [Sufyan], ia berkata; telah menceritakan kepadaku [Abdullah bin Hasan] dari [Ibrahim bin Muhammad bin Thalhah] bahwa ia mendengar [Abdullah bin 'Amr] menceritakan dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barang siapa yang hartanya dikehendaki tanpa hak, kemudian ia mempertahankan dan terbunuh maka ia adalah syahid.\" Hal ini adalah salah dan yang benar adalah hadits Su'air bin Al Khims."},"3822":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا مُعَاوِيَةُ بْنُ هِشَامٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ اللَّهِ بْنِ الْحَسَنِ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ بْنِ طَلْحَةَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قُتِلَ دُونَ مَالِهِ فَهُوَ شَهِيدٌ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman], ia berkata; telah menceritakan kepada kami [Mu'awiyah bin Hisyam], ia berkata; telah menceritakan kepada kami [Sufyan] dari [Abdullah bin Al Hasan] dari [Muhammad bin Ibrahim bin Thalhah] dari [Abdullah bin 'Amr], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang terbunuh mempertahankan hartanya maka ia adalah syahid.\""},"3823":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ وَقُتَيْبَةُ وَاللَّفْظُ لِإِسْحَقَ قَالَا أَنْبَأَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ طَلْحَةَ بْنِ عَبْدِ اللَّهِ بْنِ عَوْفٍ عَنْ سَعِيدِ بْنِ زَيْدٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قُتِلَ دُونَ مَالِهِ فَهُوَ شَهِيدٌ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dan [Qutaibah], lafazhnya adalah lafazh Ishaq, mereka berdua mengatakan; telah memberitakan kepada kami [Sufyan] dari [Az Zuhri] dari [Thalhah bin Abdullah bin 'Auf] dari [Sa'id bin Zaid] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Barang siapa yang terbunuh mempertahankan hartanya maka ia adalah syahid.\""},"3824":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عَبْدَةُ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَقَ عَنْ الزُّهْرِيِّ عَنْ طَلْحَةَ بْنِ عَبْدِ اللَّهِ بْنِ عَوْفٍ عَنْ سَعِيدِ بْنِ زَيْدٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَاتَلَ دُونَ مَالِهِ فَهُوَ شَهِيدٌ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim], ia berkata; telah memberitakan kepada kami ['Abdah], ia berkata; telah menceritakan kepada kami [Muhammad bin Ishaq] dari [Az Zuhri] dari [Thalhah bin Abdullah bin 'Auf] dari [Sa'id bin Zaid] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Barang siapa yang berperang mempertahankan hartanya maka ia adalah syahid.\" "},"3825":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ نَصْرٍ قَالَ حَدَّثَنَا الْمُؤَمَّلُ عَنْ سُفْيَانَ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ عَنْ سُلَيْمَانَ بْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قُتِلَ دُونَ مَالِهِ فَهُوَ شَهِيدٌ","id":"Telah mengabarkan kepada kami [Ahmad bin Nashr], ia berkata; telah menceritakan kepada kami [Al Muammal] dari [Sufyan] dari ['Alqamah bin Martsad] dari [Sulaiman bin Buraidah] dari [ayahnya] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang terbunuh mempertahankan hartanya maka ia adalah syahid.\""},"3826":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَلْقَمَةَ عَنْ أَبِي جَعْفَرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قُتِلَ دُونَ مَظْلَمَتِهِ فَهُوَ شَهِيدٌقَالَ أَبُو عَبْد الرَّحْمَنِ حَدِيثُ الْمُؤَمَّلِ خَط��أٌ وَالصَّوَابُ حَدِيثُ عَبْدِ الرَّحْمَنِ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna], ia berkata; telah menceritakan kepada kami [Abdurrahman], ia berkata; telah menceritakan kepada kami [Sufyan] dari ['Alqamah] dari [Abu Ja'far], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Barangsiapa yang terbunuh mempertahankan sesuatu yang dizhalimi darinya maka ia adalah syahid, \" Abu abdurrahman berkata hadits Al Muammal salah dan yang benar adalah hadits Abdurrahman."},"3827":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ قَالَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ أَبِيهِ عَنْ أَبِي عُبَيْدَةَ بْنِ مُحَمَّدٍ عَنْ طَلْحَةَ بْنِ عَبْدِ اللَّهِ بْنِ عَوْفٍ عَنْ سَعِيدِ بْنِ زَيْدٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَاتَلَ دُونَ مَالِهِ فَقُتِلَ فَهُوَ شَهِيدٌ وَمَنْ قَاتَلَ دُونَ دَمِهِ فَهُوَ شَهِيدٌ وَمَنْ قَاتَلَ دُونَ أَهْلِهِ فَهُوَ شَهِيدٌ","id":"Telah mengabarkan kepada kami ['Amr bin Ali], ia berkata; telah menceritakan kepada kami [Abdurrahman bin Mahdi], ia berkata; telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [ayahnya] dari [Abu 'Ubaidah bin Muhammad] dari [Thalhah bin Abdullah bin 'Auf] dari [Sa'id bin Zaid] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Barang siapa yang berperang mempertahankan hartanya kemudian terbunuh maka ia adalah syahid, barang siapa yang berperang mempertahankan darahnya maka ia adalah syahid dan barang siapa yang berperang mempertahankan keluarganya maka ia adalah syahid.\" "},"3828":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ رَافِعٍ وَمُحَمَّدُ بْنُ إِسْمَعِيلَ بْنِ إِبْرَاهِيمَ قَالَا حَدَّثَنَا سُلَيْمَانُ يَعْنِي ابْنَ دَاوُدَ الْهَاشِمِيَّ قَالَ حَدَّثَنَا إِبْرَاهِيمُ عَنْ أَبِيهِ عَنْ أَبِي عُبَيْدَةَ بْنِ مُحَمَّدِ بْنِ عَمَّارِ بْنِ يَاسِرٍ عَنْ طَلْحَةَ بْنِ عَبْدِ اللَّهِ بْنِ عَوْفٍ عَنْ سَعِيدِ بْنِ زَيْدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قُتِلَ دُونَ مَالِهِ فَهُوَ شَهِيدٌ وَمَنْ قُتِلَ دُونَ أَهْلِهِ فَهُوَ شَهِيدٌ وَمَنْ قُتِلَ دُونَ دِينِهِ فَهُوَ شَهِيدٌ وَمَنْ قُتِلَ دُونَ دَمِهِ فَهُوَ شَهِيدٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Rafi'] dan [Muhammad bin Isma'il bin Ibrahim] mereka berdua mengatakan; telah menceritakan kepada kami [Sulaiman yaitu Ibnu Daud Al Hasyimi], ia berkata; telah menceritakan kepada kami [Ibrahim] dari [ayahnya] dari [Abu 'Ubaidah bin Muhammad bin 'Ammar bin Yasir] dari [Thalhah bin Abdullah bin 'Auf] dari [Sa'id bin Zaid], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang terbunuh mempertahankan hartanya maka ia adalah syahid, barang siapa yang terbunuh mempertahankan keluarganya maka ia adalah syahid, barang siapa yang terbunuh mempertahankan agamanya ia adalah syahid dan barang siapa yang terbunuh mempertahankan darahnya maka ia adalah syahid.\""},"3829":{"ar":"أَخْبَرَنَا الْقَاسِمُ بْنُ زَكَرِيَّا بْنِ دِينَارٍ قَالَ حَدَّثَنَا سَعِيدُ بْنُ عَمْرٍو الْأَشْعَثِيُّ قَالَ حَدَّثَنَا عَبْثَرٌ عَنْ مُطَرِّفٍ عَنْ سَوَادَةَ بْنِ أَبِي الْجَعْدِ عَنْ أَبِي جَعْفَرٍ قَالَكُنْتُ جَالِسًا عِنْدَ سُوَيْدِ بْنِ مُقَرِّنٍ فَقَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قُتِلَ دُونَ مَظْلَمَتِهِ فَهُوَ شَهِيدٌ","id":"Telah mengabarkan kepada kami [Al Qasim bin Zakariya bin Dinar], ia berkata; telah menceritakan kepada kami [Sa'id bin 'Amr Al Asy'ats], ia berkata; telah menceritakan kepada kami ['Abtsar] dari [Mutharrif] dari [Sawadah bin Abu Al Ja'd] dari [Abu Ja'far] ia berkata; aku duduk disisi [Suwaid bin Muqorrin] lalu ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang terbunuh mempertahankan sesuatu yang dizhalimi darinya maka ia adalah syahid.\""},"3830":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا الْفَضْلُ بْنُ مُوسَى قَالَ حَدَّثَنَا مَعْمَرٌ عَنْ ابْنِ طَاوُسٍ عَنْ أَبِيهِ عَنْ ابْنِ الزُّبَيْرِعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ شَهَرَ سَيْفَهُ ثُمَّ وَضَعَهُ فَدَمُهُ هَدَرٌأَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عَبْدُ الرَّزَّاقِ بِهَذَا الْإِسْنَادِ مِثْلَهُ وَلَمْ يَرْفَعْهُ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim], ia berkata; telah memberitakan kepada kami [Al Fadhl bin Musa], ia berkata; telah menceritakan kepada kami [Ma'mar] dari [Ibnu Thawus] dari [ayahnya] dari [Ibnu Az zubair] dari Rasulullah shallallahu 'alaihi wasallam beliau bersabda: \"Barangsiapa yang memperlihatkan pedangnya lalu ia meletakkannya maka darahnya sia-sia.\" Telah mengabarkan kepada kami [Ishaq bin Ibrahim], ia berkata; telah memberitakan kepada kami [Abdur Razzaq] dengan sanad seperti ini namun ia tidak memarfu'kannya."},"3831":{"ar":"أَخْبَرَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ عَنْ ابْنِ طَاوُسٍ عَنْ أَبِيهِ عَنْ ابْنِ الزُّبَيْرِ قَالَمَنْ رَفَعَ السِّلَاحَ ثُمَّ وَضَعَهُ فَدَمُهُ هَدَرٌ","id":"Telah mengabarkan kepada kami [Abu Daud], ia berkata; telah menceritakan kepada kami [Abu 'Ashim] dari [Ibnu Juraij] dari [Ibnu Thawus] dari [ayahnya] dari [Ibnu Az Zubair], ia berkata; barang siapa yang mengangkat senjata kemudian meletakkannya maka darahnya sia-sia."},"3832":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ قَالَ أَنْبَأَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي مَالِكٌ وَعَبْدُ اللَّهِ بْنُ عُمَرَ وَأُسَامَةُ بْنُ زَيْدٍ وَيُونُسُ بْنُ يَزِيدَ أَنَّ نَافِعًا أَخْبَرَهُمْ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ حَمَلَ عَلَيْنَا السِّلَاحَ فَلَيْسَ مِنَّا","id":"Telah mengabarkan kepada kami [Ahmad bin 'Amr bin As Sarh], ia berkata; telah memberitakan kepada kami [Ibnu Wahb], ia berkata; telah memberitakan kepadaku [Malik] dan [Abdullah bin Umar], [Usamah bin Zaid], dan [Yunus bin Yazid] bahwa [Nafi'] telah mengabarkan kepada mereka dari [Abdullah bin Umar] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang mengarahkan senjata kepada kami maka ia bukan dari golongan kami.\""},"3833":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ غَيْلَانَ قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَنْبَأَنَا الثَّوْرِيُّ عَنْ أَبِيهِ عَنْ ابْنِ أَبِي نُعْمٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَبَعَثَ عَلِيٌّ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ بِالْيَمَنِ بِذُهَيْبَةٍ فِي تُرْبَتِهَا فَقَسَمَهَا بَيْنَ الْأَقْرَعِ بْنِ حَابِسٍ الْحَنْظَلِيِّ ثُمَّ أَحَدِ بَنِي مُجَاشِعٍ وَبَيْنَ عُيَيْنَةَ بْنِ بَدْرٍ الْفَزَارِيِّ وَبَيْنَ عَلْقَمَةَ بْنِ عُلَاثَةَ الْعَامِرِيِّ ثُمَّ أَحَدِ بَنِي كِلَابٍ وَبَيْنَ زَيْدِ الْخَيْلِ الطَّائِيِّ ثُمَّ أَحَدِ بَنِي نَبْهَانَ قَالَ فَغَضِبَتْ قُرَيْشٌ وَالْأَنْصَارُ وَقَالُوا يُعْطِي صَنَادِيدَ أَهْلِ نَجْدٍ وَيَدَعُنَا فَقَالَ إِنَّمَا أَتَأَلَّفُهُمْ فَأَقْبَلَ رَجُلٌ غَائِرَ الْعَيْنَيْنِ نَاتِئَ الْوَجْنَتَيْنِ كَثَّ اللِّحْيَةِ مَحْلُوقَ الرَّأْسِ فَقَالَ يَا مُحَمَّدُ اتَّقِ اللَّهَ قَالَ مَنْ يُطِعْ اللَّهَ إِذَا عَصَيْتُهُ أَيَأْمَنُنِي عَلَى أَهْلِ الْأَرْضِ وَلَا تَأْمَنُونِي فَسَأَلَ رَجُلٌ مِنْ الْقَوْمِ قَتْلَهُ فَمَنَعَهُ فَلَمَّا وَلَّى قَالَ إِنَّ مِنْ ضِئْضِئِ هَذَا قَوْمًا يَخْرُجُونَ يَقْرَءُونَ الْقُرْآنَ لَا يُجَاوِزُ حَنَاجِرَهُمْ يَمْرُقُونَ مِنْ الدِّينِ مُرُوقَ السَّهْمِ مِنْ الرَّمِيَّةِ يَقْتُلُونَ أَهْلَ الْإِسْلَامِ وَيَدَعُونَ أَهْلَ الْأَوْثَانِ لَئِنْ أَنَا أَدْرَكْتُهُمْ لَأَقْتُلَنَّهُمْ قَتْلَ عَادٍ","id":"Telah mengabarkan kepada kami [Mahmud bin Ghailan], ia berkata; telah menceritakan kepada kami [Abdur Razzaq], ia berkata; telah memberitakan kepada kami [Ats Tsauri] dari [ayahnya] dari [Ibnu Abu Nu'aim] dari [Abu Sa'id Al Khudri], ia berkata; Ali mengirim seseorang kepada Nabi shallallahu 'alaihi wasallam sedangkan ia berada di Yaman membawa emas yang masih dalam tanahnya, kemudian beliau membaginya antara Al Aqra` bin Habis Al Hanzhali kemudian salah seorang dari Bani Mujasyim dan antara 'Uyainah bin Badr Al Fazari dan 'Alqamah bin 'Ulatsah Al 'Amiri, kemudian salah seorang dari Bani Kilab dan antara Zaid Al Khail Ath Thai, kemudian salah seorang dari Bani Nabhan. Abu Sa'id berkata; kemudian orang-orang Quraisy dan Anshar marah dan berkata; beliau memberikan kepada pembesar-pembesar Najed dan meninggalkan kita. Maka beliau bersabda: \"Sesungguhnya saya melunakkan hati mereka.\" Kemudian terdapat seorang laki-laki yang cekung matanya, bagian atas pipinya menonjol, lebat jenggotnya, dan gundul rambutnya, kemudian ia berkata; wahai Muhammad, bertakwalah kepada Allah! Beliau bersabda: \"Siapakah yang taat kepada Allah apabila aku durhaka kepadaNya? Apakah Dia mempercayaiku atas penduduk bumi dan kalian tidak mempercayaiku?\" kemudian terdapat seseorang dari orang-orang tersebut yang meminta untuk membunuhnya. Lalu beliau melarangnya, kemudian setelah ia pergi beliau bersabda: \"Sesungguhnya dari keturunan orang ini akan ada orang-orang yang keluar membaca Al Qur'an dan tidak melewati tenggorokan mereka, mereka melesat dari agama seperti melesatnya anak panah dari busur. Mereka akan membunuh orang Islam, dan membiarkan penyembah berhala, sungguh apabila aku menjumpai mereka niscaya akan aku perangi mereka seperti membunuh kaum 'Ad. "},"3834":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ خَيْثَمَةَ عَنْ سُوَيْدِ بْنِ غَفَلَةَ عَنْ عَلِيٍّ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يَخْرُجُ قَوْمٌ فِي آخِرِ الزَّمَانِ أَحْدَاثُ الْأَسْنَانِ سُفَهَاءُ الْأَحْلَامِ يَقُولُونَ مِنْ خَيْرِ قَوْلِ الْبَرِيَّةِ لَا يُجَاوِزُ إِيمَانُهُمْ حَنَاجِرَهُمْ يَمْرُقُونَ مِنْ الدِّينِ كَمَا يَمْرُقُ السَّهْمُ مِنْ الرَّمِيَّةِ فَإِذَا لَقِيتُمُوهُمْ فَاقْتُلُوهُمْ فَإِنَّ قَتْلَهُمْ أَجْرٌ لِمَنْ قَتَلَهُمْ يَوْمَ الْقِيَامَةِ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar], ia berkata; telah menceritakan kepada kami [Abdurrahman], ia berkata; telah menceritakan kepada kami [Sufyan] dari [Al A'masy] dari [Khaitsamah] dari [Suwaid bin Ghafalah] dari [Ali], ia berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Akan keluar suatu kaum pada akhir zaman orang-orang yang muda umurnya dan lemah akalnya, mereka menceritakan mengenai perkataan manusia terbaik, keimanan mereka tidak melampaui tenggorokan. Mereka melesat dari agama seperti melesatnya anak panah dari busurnya, apabila kalian menjumpai mereka maka bunuhlah mereka. Sesungguhnya membunuh mereka adalah pahala bagi orang yang membunuhnya pada Hari Kiamat.\" "},"3835":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَعْمَرٍ الْبَصْرِيُّ الْحَرَّانِيُّ قَالَ حَدَّثَنَا أَبُو دَاوُدَ الطَّيَالِسِيُّ قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ الْأَزْرَقِ بْنِ قَيْسٍ عَنْ شَرِيكِ بْنِ شِهَابٍ قَالَكُنْتُ أَتَمَنَّى أَنْ أَلْقَى رَجُلًا مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَسْأَلُهُ عَنْ الْخَوَارِجِ فَلَقِيتُ أَبَا بَرْزَةَ فِي يَوْمِ عِيدٍ فِي نَفَرٍ مِنْ أَصْحَابِهِ فَقُلْتُ لَهُ هَلْ سَمِعْتَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَذْكُرُ الْخَوَارِجَ فَقَالَ نَعَمْ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِأُذُنِي وَرَأَيْتُهُ بِعَيْنِي أُتِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَالٍ فَقَسَمَهُ فَأَعْطَى مَنْ عَنْ يَمِينِهِ وَمَنْ عَنْ شِمَالِهِ وَلَمْ يُعْطِ مَنْ وَرَاءَهُ شَيْئًا فَقَامَ رَجُلٌ مِنْ وَرَائِهِ فَقَالَ يَا مُحَمَّدُ مَا عَدَلْتَ فِي الْقِسْمَةِ رَجُلٌ أَسْوَدُ مَطْمُومُ الشَّعْرِ عَلَيْهِ ثَوْبَانِ أَبْيَضَانِ فَغَضِبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَضَبًا شَدِيدًا وَقَالَ وَاللَّهِ لَا تَجِدُونَ بَعْدِي رَجُلًا هُوَ أَعْدَلُ مِنِّي ثُمَّ قَالَ يَخْرُجُ فِي آخِرِ الزَّمَانِ قَوْمٌ كَأَنَّ هَذَا مِنْهُمْ يَقْرَءُونَ الْقُرْآنَ لَا يُجَاوِزُ تَرَاقِيَهُمْ يَمْرُقُونَ مِنْ الْإِسْلَامِ كَمَا يَمْرُقُ السَّهْمُ مِنْ الرَّمِيَّةِ سِيمَاهُمْ التَّحْلِيقُ لَا يَزَالُونَ يَخْرُجُونَ حَتَّى يَخْرُجَ آخِرُهُمْ مَعَ الْمَسِيحِ الدَّجَّالِ فَإِذَا لَقِيتُمُوهُمْ فَاقْتُلُوهُمْ هُمْ شَرُّ الْخَلْقِ وَالْخَلِيقَةِقَالَ أَبُو عَبْد الرَّحْمَنِ رَحِمَهُ اللَّهُ شَرِيكُ بْنُ شِهَابٍ لَيْسَ بِذَلِكَ الْمَشْهُورِ","id":"Telah mengabarkan kepada kami [Muhammad bin Ma'mar Al Bashri Al Harrani], ia berkata; telah menceritakan kepada kami [Abu Daud Athayalisi], ia berkata; telah menceritakan kepada kami [Hammad bin Salamah] dari [Al Azraq bin Qais] dari [Syarik bin Syihab] ia berkata; dahulu saya berharap untuk bertemu dengan seorang sahabat Nabi shallallahu 'alaihi wasallam dan bertanya kepadanya mengenai Khawarij, lalu aku bertemu dengan [Abu Barzah] pada hari 'Id diantara beberapa orang dari sahabatnya, saya katakan kepadanya; apakah engkau mendengar Rasulullah shallallahu 'alaihi wasallam menyebutkan mengenai khowarij? Ia menjawab; ya. Saya mendengar Rasulullah shallallahu 'alaihi wasallam dengan dua telingaku dan melihat dengan kedua mataku, didatangkan kepada Rasulullah Shallallahu Alaihi wa sallam suatu harta lalu beliau mulai membagi untuk orang yang berada disebelah kanan dan kiri beliau, dan beliau tidak memberi yang berada dibelakannya sedikitpun, lalu seseorang yang berada dibelakang beliau berdiri dan berkata; wahai Muhammad, engkau tidak adil dalam membagi, ia adalah orang yang hitam, rambutnya dicukur, ia mengenakan dua kain putih, lalu Rasulullah shallallahu 'alaihi wasallam marah dan bersabda: \"Demi Allah kalian tidak akan mendapati seorangpun yang lebih adil setelahku, \" lalu beliau bersabda: \" akan keluar pada akhir zaman, suatu kaum seakan-akan orang ini termasuk darinya, yang mereka membaca quran tidak melebihi kerongkongan mereka, mereka melesat dari Islam seperti melesatnya anak panah dari busurnya, ciri-ciri mereka adalah bercukur, mereka senantiasa keluar hingga keluar akhir dari mereka bersama Al Masih Ad Dajjal, jika kalian bertemu dengan mereka maka bunuhlah mereka, mereka adalah seburuk-buruk makhluk dan ciptaan, \" Abu Abdurrahman rahimahullah berkata Syarik bin Syihab bukanlah Syarik yang terkenal itu."},"3836":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عَبْدُ الرَّزَّاقِ قَالَ حَدَّثَنَا مَعْمَرٌ عَنْ أَبِي إِسْحَقَ عَنْ عُمَرَ بْنِ سَعْدٍ قَالَ حَدَّثَنَا سَعْدُ بْنُ أَبِي وَقَّاصٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قِتَالُ الْمُسْلِمِ كُفْرٌ وَسِبَابُهُ فُسُوقٌ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim], ia berkata; telah memberitakan kepada kami [Abdur Razzaq], ia berkata; telah menceritakan kepada kami [Ma'mar] dari [Abu Ishaq] dari [Umar bin Sa'd], ia berkata; telah menceritakan kepada kami [Sa'd bin Abu Waqqash] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Membunuh orang muslim adalah kekafiran dan mencelanya adalah kefasikan.\""},"3837":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَقَ قَالَ سَمِعْتُ أَبَا الْأَحْوَصِ عَنْ عَبْدِ اللَّهِ قَالَسِبَابُ الْمُسْلِمِ فُسُوقٌ وَقِتَالُهُ كُفْرٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar], ia berkata; telah menceritakan kepada kami [Abdurrahman], ia berkata; telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq], ia berkata; saya mendengar [Abu Al Ahwash] dari [Abdullah] ia berkata; mencela seorang muslim adalah kefasikan dan membunuhnya adalah kekafiran."},"3838":{"ar":"أَخْبَرَنَا يَحْيَى بْنُ حَكِيمٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ شُعْبَةَ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي الْأَحْوَصِ عَنْ عَبْدِ اللَّهِ قَالَسِبَابُ الْمُسْلِمِ فِسْقٌ وَقِتَالُهُ كُفْرٌفَقَالَ لَهُ أَبَانُ يَا أَبَا إِسْحَقَ أَمَا سَمِعْتَهُ إِلَّا مِنْ أَبِي الْأَحْوَصِ قَالَ بَلْ سَمِعْتُهُ مِنْ الْأَسْوَدِ وَهُبَيْرَةَ","id":"Telah mengabarkan kepada kami [Yahya bin Hakim], ia berkata; telah menceritakan kepada kami [Abdurrahman bin Mahdi] dari [Syu'bah] dari [Abu Ishaq] dari [Abu Al Ahwash] dari [Abdullah], ia berkata; mencela seorang muslim adalah kefasikan dan membunuhnya adalah kekafiran. Kemudian Aban berkata; kepadanya; wahai Abu Ishaq, apakah engkau tidak mendengarnya kecuali dari Abu Al Ahwash? Ia berkata; bahkan saya mendengarnya dari [Al Aswad] dan [Hubairah]. "},"3839":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ أَبِي الزَّعْرَاءِ عَنْ عَمِّهِ أَبِي الْأَحْوَصِ عَنْ عَبْدِ اللَّهِ قَالَسِبَابُ الْمُسْلِمِ فُسُوقٌ وَقِتَالُهُ كُفْرٌ","id":"Telah mengabarkan kepada kami [Ahmad bin Harb], ia berkata; telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Abu Az Za'ra`] dari [pamannya yaitu Abu Al Ahwash] dari [Abdullah], ia berkata; mencela seorang muslim adalah kefasikan dan membunuhnya adalah kekafiran."},"3840":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ غَيْلَانَ قَالَ حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ قَالَ حَدَّثَنَا أَبِي قَالَ سَمِعْتُ عَبْدَ الْمَلِكِ بْنَ عُمَيْرٍ يُحَدِّثُهُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ سِبَابُ الْمُسْلِمِ فُسُوقٌ وَقِتَالُهُ كُفْرٌ","id":"Telah mengabarkan kepada kami [Mahmud bin Ghailan], ia berkata; telah menceritakan kepada kami [Wahb bin Jarir], ia berkata; telah menceritakan kepada kami [ayahku], saya mendengar [Abdul Malik bin 'Umair] menceritakan kepadanya dari [Abdurrahman bin Abdullah] dari [ayahnya] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Mencela seorang muslim adalah kefasikan dan membunuhnya adalah kekafiran.\""},"3841":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ غَيْلَانَ قَالَ حَدَّثَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ قُلْتُ لِحَمَّادٍ سَمِعْتُ مَنْصُورًا وَسُلَيْمَانَ وَزُبَيْدًا يُحَدِّثُونَ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ سِبَابُ الْمُسْلِمِ فُسُوقٌ وَقِتَالُهُ كُفْرٌمَنْ تَتَّهِمُ أَتَتَّهِمُ مَنْصُورًا أَتَتَّهِمُ زُبَيْدًا أَتَتَّهِمُ سُلَيْمَانَ قَالَ لَا وَلَكِنِّي أَتَّهِمُ أَبَا وَائِلٍ","id":"Telah mengabarkan kepada kami [Mahmud bin Ghailan], ia berkata; telah menceritakan kepada kami [Abu Daud], ia berkata; telah menceritakan kepada kami [Syu'bah], ia berkata; saya berkata kepada Hammad; saya mendengar [Manshur] dan [Sulaiman] serta [Zubaid] menceritakan dari [Abu Wa'il] dari [Abdullah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Mencela seorang muslim adalah kefasikan dan membunuhnya adalah kekafiran.\" Siapakah yang engkau sangka? Saya menyangka Manshur. Apakah engkau menyangka Zaid, apakah engkau menyangka Sulaiman? Ia berkata; tidak akan tetapi saya menyangka Abu Wail."},"3842":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ غَيْلَانَ قَالَ حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ زُبَيْدٍ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سِبَابُ الْمُسْلِمِ فُسُوقٌ وَقِتَالُهُ كُفْرٌقُلْتُ لِأَبِي وَائِلٍ سَمِعْتَهُ مِنْ عَبْدِ اللَّهِ قَالَ نَعَمْ","id":"Telah mengabarkan kepada kami [Mahmud bin Ghailan], ia berkata; telah menceritakan kepada kami [Waki'], ia berkata; telah menceritakan kepada kami [Sufyan] dari [Zaid] dari [Abu Wail] dari [Abdullah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Mencela seorang muslim adalah kefasikan dan membunuhnya adalah kekafiran.\""},"3843":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ غَيْلَانَ قَالَ حَدَّثَنَا مُعَاوِيَةُ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سِبَابُ الْمُسْلِمِ فُسُوقٌ وَقِتَالُهُ كُفْرٌ","id":"Telah mengabarkan kepada kami [Mahmud bin Ghailan], ia berkata; telah menceritakan kepada kami [Mu'awiyah], ia berkata; telah menceritakan kepada kami [Sufyan] dari [Manshur] dari [Abu Wail] dari [Abdullah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Mencela seorang muslim adalah kefasikan dan membunuhnya adalah kekafiran.\""},"3844":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ أَبِي وَائِلٍ قَالَ قَالَ عَبْدُ اللَّهِسِبَابُ الْمُسْلِمِ فُسُوقٌ وَقِتَالُهُ كُفْرٌ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id], ia berkata; telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Abu Wail], ia berkata; [Abdullah] berkata; Mencela seorang muslim adalah kefasikan dan membunuhnya adalah kekafiran."},"3845":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْعَلَاءِ عَنْ أَبِي مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ شَقِيقٍ عَنْ عَبْدِ اللَّهِ قَالَقِتَالُ الْمُؤْمِنِ كُفْرٌ وَسِبَابُهُ فُسُوقٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Al 'Ala`] dari [Abu Mu'awiyah] dari [Al A'masy] dari [Syaqiq] dari [Abdullah], ia berkata; membunuh orang mukmin adalah kekafiran dan mencelanya adalah kefasikan."},"3846":{"ar":"أَخْبَرَنَا بِشْرُ بْنُ هِلَالٍ الصَّوَّافُ قَالَ حَدَّثَنَا عَبْدُ الْوَارِثِ قَالَ حَدَّثَنَا أَيُّوبُ عَنْ غَيْلَانَ بْنِ جَرِيرٍ عَنْ زِيَادِ بْنِ رِيَاحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ خَرَجَ مِنْ الطَّاعَةِ وَفَارَقَ الْجَمَاعَةَ فَمَاتَ مَاتَ مِيتَةً جَاهِلِيَّةً وَمَنْ خَرَجَ عَلَى أُمَّتِي يَضْرِبُ بَرَّهَا وَفَاجِرَهَا لَا يَتَحَاشَى مِنْ مُؤْمِنِهَا وَلَا يَفِي لِذِي عَهْدِهَا فَلَيْسَ مِنِّي وَمَنْ قَاتَلَ تَحْتَ رَايَةٍ عُمِّيَّةٍ يَدْعُو إِلَى عَصَبِيَّةٍ أَوْ يَغْضَبُ لِعَصَبِيَّةٍ فَقُتِلَ فَقِتْلَةٌ جَاهِلِيَّةٌ","id":"Telah mengabarkan kepada kami [Bisyr bin Hilal Ash Shawwaf], ia berkata; telah menceritakan kepada kami [Abdul Warits], ia berkata; telah menceritakan kepada kami [Ayyub] dari [Ghailan bin Jarir] dari [Ziyad bin Riyah] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang keluar dari ketaatan dan memisahkan diri dari jama'ah kemudian mati maka ia mati dengan kematian jahiliyah, dan barang siapa yang menyerang umatku dan membunuh orang yang baik dan pelaku dosa dan tidak menjauhi orang mukminnya dan tidak menepati janji orang yang memiliki janki maka ia bukan dari golonganku, dan barang siapa yang berperang dibawah bendera ketidak jelasan dan menyeru kepada kefanatikan atau marah karena fanatik kemudian terbunuh maka terbunuhnya adalah terbunuh secara jahiliyah.\" "},"3847":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى عَنْ عَبْدِ الرَّحْمَنِ قَالَ حَدَّثَنَا عِمْرَانُ الْقَطَّانُ عَنْ قَتَادَةَ عَنْ أَبِي مِجْلَزٍ عَنْ جُنْدُبِ بْنِ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَاتَلَ تَحْتَ رَايَةٍ عُمِّيَّةٍ يُقَاتِلُ عَصَبِيَّةً وَيَغْضَبُ لِعَصَبِيَّةٍ فَقِتْلَتُهُ جَاهِلِيَّةٌقَالَ أَبُو عَبْد الرَّحْمَنِ عِمْرَانُ الْقَطَّانُ لَيْسَ بِالْقَوِيِّ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dari [Abdurrahman], ia berkata; telah menceritakan kepada kami [Imran Al Qaththan] dari [Qatadah] dari [Abu Mijlaz] dari [Jundub bin Abdullah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang berperang dibawah bendera ketidak jelasan, ia berperang karena kefanatikan dan marah karena kefanatikan maka terbunuhnya adalah terbunuh secara jahiliyah.\" Abu abdurrahman berkata Imron Al Qaththan bukan orang yang kuat."},"3848":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ غَيْلَانَ قَالَ حَدَّثَنَا أَبُو دَاوُدَ عَنْ شُعْبَةَ قَالَ أَخْبَرَنِي مَنْصُورٌ قَالَ سَمِعْتُ رِبْعِيًّا يُحَدِّثُ عَنْ أَبِي بَكْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَشَارَ الْمُسْلِمُ عَلَى أَخِيهِ الْمُسْلِمِ بِالسِّلَاحِ فَهُمَا عَلَى جُرُفِ جَهَنَّمَ فَإِذَا قَتَلَهُ خَرَّا جَمِيعًا فِيهَا","id":"Telah mengabarkan kepada kami [Mahmud bin Ghailan], ia berkata; telah menceritakan kepada kami [Abu Daud] dari [Syu'bah], ia berkata; telah mengabarkan kepadaku [Manshur], ia berkata; saya mendengar [Rab'i] menceritakan dari [Abu Bakarah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila seorang muslim menunjuk saudara muslimnya menggunakan senjata maka mereka berada di atas jurang Jahannam, kemudian apabila ia membunuhnya maka mereka berdua terjatuh ke dalamnya.\""},"3849":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا يَعْلَى قَالَ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ رِبْعِيٍّ عَنْ أَبِي بَكْرَةَ قَالَإِذَا حَمَلَ الرَّجُلَانِ الْمُسْلِمَانِ السِّلَاحَ أَحَدُهُمَا عَلَى الْآخَرِ فَهُمَا عَلَى جُرُفِ جَهَنَّمَ فَإِذَا قَتَلَ أَحَدُهُمَا الْآخَرَ فَهُمَا فِي النَّارِ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman], ia berkata; telah menceritakan kepada kami [Ya'la], ia berkata; telah menceritakan kepada kami [Sufyan] dari [Manshur] dari [Rib'i] dari [Abu Bakarah], ia berkata; apabila dua orang muslim membawa senjata salah satunya mengarahkan kepada yang lainnya maka mereka berdua berada di atas jurang Jahannam, dan apabila salah satunya membunuh yang lain maka mereka berdua berada di Neraka."},"3850":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ إِسْمَعِيلَ بْنِ إِبْرَاهِيمَ عَنْ يَزِيدَ عَنْ سُلَيْمَانَ التَّيْمِيِّ عَنْ الْحَسَنِ عَنْ أَبِي مُوسَىعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا تَوَاجَهَ الْمُسْلِمَانِ بِسَيْفَيْهِمَا فَقَتَلَ أَحَدُهُمَا صَاحِبَهُ فَهُمَا فِي النَّارِ قِيلَ يَا رَسُولَ اللَّهِ هَذَا الْقَاتِلُ فَمَا بَالُ الْمَقْتُولِ قَالَ أَرَادَ قَتْلَ صَاحِبِهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Isma'il bin Ibrahim] dari [Yazid] dari [Sulaiman At Taimi] dari [Al Hasan] dari [Abu Musa] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Apabila dua orang muslim saling berhadapan dengan pedang mereka kemudian salah seorang dari mereka membunuh sahabatnya maka mereka berada dalam Neraka.\" Kemudian beliau ditanya; wahai Rasulullah, ini orang yang membunuh, maka bagaimana dengan orang yang dibunuh? beliau bersabda: \"Ia ingin membunuh sahabatnya.\""},"3851":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ مُحَمَّدِ بْنِ عَلِيٍّ الْمِصِّيصِيُّ قَالَ حَدَّثَنَا خَلَفٌ عَنْ زَائِدَةَ عَنْ هِشَامٍ عَنْ الْحَسَنِ عَنْ أَبِي بَكْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا تَوَاجَهَ الْمُسْلِمَانِ بِسَيْفَيْهِمَا كُلُّ وَاحِدٍ مِنْهُمَا يُرِيدُ قَتْلَ صَاحِبِهِ فَهُمَا فِي النَّارِ قِيلَ لَهُ يَا رَسُولَ اللَّهِ هَذَا الْقَاتِلُ فَمَا بَالُ الْمَقْتُولِ قَالَ إِنَّهُ كَانَ حَرِيصًا عَلَى قَتْلِ صَاحِبِهِ","id":"Telah mengabarkan kepada kami [Ali bin Muhammad bin Ali Al Mishshishi], ia berkata; telah menceritakan kepada kami [Khalaf] dari [Zaidah] dari [Hisyam] dari [Al Hasan] dari [Abu Bakarah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Apabila dua orang muslim saling berhadapan dengan pedang mereka setiap orang ingin membunuh sahabatnya maka mereka berada dalam Neraka.\" Kemudian beliau ditanya; wahai Rasulullah, ini orang yang membunuh, maka bagaimana dengan orang yang dibunuh? beliau bersabda: \"Ia berusaha membunuh sahabatnya.\""},"3852":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا الْخَلِيلُ بْنُ عُمَرَ بْنِ إِبْرَاهِيمَ قَالَ حَدَّثَنِي أَبِي قَالَ حَدَّثَنِي قَتَادَةُ عَنْ الْحَسَنِ عَنْ أَبِي بَكْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا الْتَقَى الْمُسْلِمَانِ بِسَيْفَيْهِمَا فَقَتَلَ أَحَدُهُمَا صَاحِبَهُ فَالْقَاتِلُ وَالْمَقْتُولُ فِي النَّارِ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna], ia berkata; telah menceritakan kepada kami [Al Khalil bin Umar bin Ibrahim], ia berkata; telah menceritakan kepadaku [ayahku], ia berkata; telah menceritakan kepadaku [Qatadah] dari [Al Hasan] dari [Abu Bakarah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Apabila dua orang muslim bertemu dengan pedang mereka kemudian salah seorang diantara mereka membunuh sahabatnya maka orang yang membunuh dan yang dibunuh berada dalam Neraka.\" "},"3853":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عَبْدَةَ عَنْ حَمَّادٍ عَنْ أَيُّوبَ وَيُونُسَ وَالْعَلَاءِ بْنِ زِيَادٍ عَنْ الْحَسَنِ عَنْ الْأَحْنَفِ بْنِ قَيْسٍ عَنْ أَبِي بَكْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا الْتَقَى الْمُسْلِمَانِ بِسَيْفَيْهِمَا فَقَتَلَ أَحَدُهُمَا صَاحِبَهُ فَالْقَاتِلُ وَالْمَقْتُولُ فِي النَّارِ","id":"Telah mengabarkan kepada kami [Ahmad bin 'Abdah] dari [Hammad] dari [Ayyub] dan [Yunus] serta [Al 'Ala` bin Ziyad] dari [Al Hasan] dari [Al Ahnaf bin Qais] dari [Abu Bakarah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Apabila dua orang muslim bertemu dengan pedang mereka kemudian salah seorang diantara mereka membunuh sahabatnya maka orang yang membunuh dan yang dibunuh berada dalam Neraka.\""},"3854":{"ar":"أَخْبَرَنَا مُجَاهِدُ بْنُ مُوسَى قَالَ حَدَّثَنَا إِسْمَعِيلُ وَهُوَ ابْنُ عُلَيَّةَ عَنْ يُونُسَ عَنْ الْحَسَنِ عَنْ أَبِي مُوسَى الْأَشْعَرِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا تَوَاجَهَ الْمُسْلِمَانِ بِسَيْفَيْهِمَا فَقَتَلَ أَحَدُهُمَا صَاحِبَهُ فَالْقَاتِلُ وَالْمَقْتُولُ فِي النَّارِ قَالَ رَجُلٌ يَا رَسُولَ اللَّهِ هَذَا الْقَاتِلُ فَمَا بَالُ الْمَقْتُولِ قَالَ إِنَّهُ أَرَادَ قَتْلَ صَاحِبِهِ","id":"Telah mengabarkan kepada kami [Mujahid bin Musa], ia berkata; telah menceritakan kepada kami [Isma'il yaitu Ibnu 'Aliyah] dari [Yunus] dari [Al Hasan] dari [Abu Musa Al Asy'ari] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila dua orang muslim saling berhadapan dengan pedang mereka kemudian salah seorang dari mereka membunuh sahabatnya maka mereka berada dalam Neraka.\" Seorang laki-laki berkata; wahai Rasulullah, ini orang yang membunuh, bagaimana dengan orang yang dibunuh? Beliau bersabda: \"Ia ingin membunuh sahabatnya.\" "},"3855":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ بْنِ الْحَكَمِ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ وَاقِدِ بْنِ مُحَمَّدِ بْنِ زَيْدٍ أَنَّهُ سَمِعَ أَبَاهُ يُحَدِّثُ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَرْجِعُوا بَعْدِي كُفَّارًا يَضْرِبُ بَعْضُكُمْ رِقَابَ بَعْضٍ","id":"Telah mengabarkan kepada kami [Ahmad bin Abdullah bin Al Hakam], ia berkata; telah menceritakan kepada kami [Muhammad bin Ja'far], ia berkata; telah menceritakan kepada kami [Syu'bah] dari [Waqid bin Muhammad bin Zaid] bahwa Ia mendengar [ayahnya] menceritakan dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Janganlah kalian kembali setelahku sebagai orang kafir, sebagian kalian membunuh sebagian yang lain.\" "},"3856":{"ar":"أَخْبَرَنَا إِبْرَاهِيمُ بْنُ يَعْقُوبَ قَالَ حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ قَالَ حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ عَنْ الْأَعْمَشِ عَنْ مُسْلِمٍ عَنْ مَسْرُوقٍ عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَرْجِعُوا بَعْدِي كُفَّارًا يَضْرِبُ بَعْضُكُمْ رِقَابَ بَعْضٍ وَلَا يُؤْخَذُ الرَّجُلُ بِجَرِيرَةِ أَبِيهِ وَلَا بِجَرِيرَةِ أَخِيهِ","id":"Telah mengabarkan kepada kami [Ibrahim bin Ya'qub], ia berkata; telah menceritakan kepada kami [Ahmad bin Yunus], ia berkata; telah menceritakan kepada kami [Abu Bakar bin 'Ayyasy] dari [Al A'masy] dari [Muslim] dari [Masruq] dari [Abdullah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Janganlah kalian kembali kafir setelahku, sebagian kalian membunuhsebagian yang lain tidaklah seseorang menanggung kejahatan ayahnya serta kejahatan saudaranya.\""},"3857":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْعَلَاءِ قَالَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ مُسْلِمٍ عَنْ مَسْرُوقٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا أُلْفِيَنَّكُمْ تَرْجِعُونَ بَعْدِي كُفَّارًا يَضْرِبُ بَعْضُكُمْ رِقَابَ بَعْضٍ لَا يُؤْخَذُ الرَّجُلُ بِجَرِيرَةِ أَبِيهِ وَلَا بِجَرِيرَةِ أَخِيهِ هَذَا الصَّوَابُ","id":"Telah mengabarkan kepada kami [Muhammad bin Al 'Alaa'], ia berkata; telah menceritakan kepada kami [Abu Mu'awiyah], ia berkata; telah menceritakan kepada kami [Al A'masy] dari [Muslim] dari [Masruq] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh jangan sampai aku mendapati kalian kembali kafir setelahku, sebagian kalian membunuh sebagian yang lain, tidaklah seseorang menanggung kejahatan ayahnya serta kejahatan saudaranya.\" ini yang benar. "},"3858":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَزِيدُ وَهُوَ ابْنُ هَارُونَ قَالَ أَنْبَأَنَا مُحَمَّدُ بْنُ إِسْحَقَ عَنْ الزُّهْرِيِّ وَمُحَمَّدُ بْنُ عَلِيٍّ عَنْ يَزِيدَ بْنِ هُرْمُزَ قَالَكَتَبَ نَجْدَةُ إِلَى ابْنِ عَبَّاسٍ يَسْأَلُهُ عَنْ سَهْمِ ذِي الْقُرْبَى لِمَنْ هُوَ قَالَ يَزِيدُ بْنُ هُرْمُزَ وَأَنَا كَتَبْتُ كِتَابَ ابْنِ عَبَّاسٍ إِلَى نَجْدَةَ كَتَبْتُ إِلَيْهِ كَتَبْتَ تَسْأَلُنِي عَنْ سَهْمِ ذِي الْقُرْبَى لِمَنْ هُوَ وَهُوَ لَنَا أَهْلَ الْبَيْتِ وَقَدْ كَانَ عُمَرُ دَعَانَا إِلَى أَنْ يُنْكِحَ مِنْهُ أَيِّمَنَا وَيُحْذِيَ مِنْهُ عَائِلَنَا وَيَقْضِيَ مِنْهُ عَنْ غَارِمِنَا فَأَبَيْنَا إِلَّا أَنْ يُسَلِّمَهُ لَنَا وَأَبَى ذَلِكَ فَتَرَكْنَاهُ عَلَيْهِ","id":"Telah mengabarkan kepada kami ['Amr bin Ali], ia berkata; telah menceritakan kepada kami [Yazid yaitu Ibnu Harun], ia berkata; telah memberitakan kepada kami [Muhammad bin Ishaq] dari [Az Zuhri] dan [Muhammad bin Ali] dari [Yazid bin Hurmuz], ia berkata; Najdah menulis surat kepada [Ibnu Abbas] bertanya mengenai saham kaum kerabat, untuk siapakah saham tersebut? Yazid bin Hurmuz berkata; dan saya yang menulis surat Ibnu Abbas kepada Najdah. Ia berkata; saya menulis kepadanya; engkau telah menulis surat kepadaku menanyakan mengenai saham kaum kerabat, untuk siapa saham tersebut? Saham tersebut untuk kami ahli bait. Dahulu Umar mengajak kami agar ia menikahkan janda kami dan memberi sebagian rampasan perang kepada orang miskin kami, serta membayar hutang orang yang memberi hutang diantara kami, kemudian kami menolak kecuali ia menyerahkannya kepada kami. Namun ia menolak sehingga kami meninggalkannya seperti itu. "},"3859":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ يَحْيَى قَالَ حَدَّثَنَا مَحْبُوبٌ يَعْنِي ابْنَ مُوسَى قَالَ أَنْبَأَنَا أَبُو إِسْحَقَ وَهُوَ الْفَزَارِيُّ عَنْ الْأَوْزَاعِيِّ قَالَكَتَبَ عُمَرُ بْنُ عَبْدِ الْعَزِيزِ إِلَى عُمَرَ بْنِ الْوَلِيدِ كِتَابًا فِيهِ وَقَسْمُ أَبِيكَ لَكَ الْخُمُسُ كُلُّهُ وَإِنَّمَا سَهْمُ أَبِيكَ كَسَهْمِ رَجُلٍ مِنْ الْمُسْلِمِينَ وَفِيهِ حَقُّ اللَّهِ وَحَقُّ الرَّسُولِ وَذِي الْقُرْبَى وَالْيَتَامَى وَالْمَسَاكِينِ وَابْنِ السَّبِيلِ فَمَا أَكْثَرَ خُصَمَاءَ أَبِيكَ يَوْمَ الْقِيَامَةِ فَكَيْفَ يَنْجُو مَنْ كَثُرَتْ خُصَمَاؤُهُ وَإِظْهَارُكَ الْمَعَازِفَ وَالْمِزْمَارَ بِدْعَةٌ فِي الْإِسْلَامِ وَلَقَدْ هَمَمْتُ أَنْ أَبْعَثَ إِلَيْكَ مَنْ يَجُزُّ جُمَّتَكَ جُمَّةَ السُّوءِ","id":"Telah mengabarkan kepada kami ['Amr bin Yahya], ia berkata; telah menceritakan kepada kami [Mahbub yaitu Ibnu Musa], ia berkata; telah memberitakan kepada kami [Abu Ishaq yaitu Al Fazari] dari [Al Auza'I], ia berkata; [Umar bin Abdul Aziz] mengirim surat kepada Umar bin Walid yang isinya adalah: dan pembagian ayahmu kepadamu seperlima seluruhnya, sesungguhnya bagian ayahmu seperti bagian seseorang dari kaum muslimin dan didalamnya ada haq Allah dan haq rasul, kaum kerabat, anak-anak yatim, orang-orang miskin, dan Ibn Sabil, maka betapa banyak penuntut ayahmu pada hari kiamat kelak, dan bagaimana ia bisa selamat orang yang banyak penututnya, dan engkau menampakkan alat musik dan seruling adalah bid'ah didalam Islam dan sungguh aku ingin mengirim seseorang kepadamu untuk memotong rambutmu yaitu rambut yang buruk."},"3860":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ أَنْبَأَنَا مُحَمَّدُ بْنُ إِسْحَقَ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ جُبَيْرِ بْنِ مُطْعِمٍ قَالَلَمَّا قَسَمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَهْمَ ذِي الْقُرْبَى بَيْنَ بَنِي هَاشِمٍ وَبَنِي الْمُطَّلِبِ أَتَيْتُهُ أَنَا وَعُثْمَانُ بْنُ عَفَّانَ فَقُلْنَا يَا رَسُولَ اللَّهِ هَؤُلَاءِ بَنُو هَاشِمٍ لَا نُنْكِرُ فَضْلَهُمْ لِمَكَانِكَ الَّذِي جَعَلَكَ اللَّهُ بِهِ مِنْهُمْ أَرَأَيْتَ بَنِي الْمُطَّلِبِ أَعْطَيْتَهُمْ وَمَنَعْتَنَا فَإِنَّمَا نَحْنُ وَهُمْ مِنْكَ بِمَنْزِلَةٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهُمْ لَمْ يُفَارِقُونِي فِي جَاهِلِيَّةٍ وَلَا إِسْلَامٍ إِنَّمَا بَنُو هَاشِمٍ وَبَنُو الْمُطَّلِبِ شَيْءٌ وَاحِدٌ وَشَبَّكَ بَيْنَ أَصَابِعِهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna], ia berkata; telah menceritakan kepada kami [Yazid bin Harun], ia berkata; telah memberitakan kepada kami [Muhammad bin Ishaq] dari [Az Zuhri] dari [Sa'id bin Al Musayyab] dari [Jubair bin Muth'im], ia berkata; tatkala Rasulullah shallallahu 'alaihi wasallam membagi saham para kerabat antara Bani Hasyim dan Bani Al Muththalib, saya datang kepada beliau bersama Utsman bin Affan. Kami berkata; wahai Rasulullah, mereka orang-orang Bani Hasyim, kami tidak mengingkari keutamaan mereka karena posisimu yang Allah telah menjadikan dirimu yang telah Allah berikan kepadamu diantara mereka. Bagaimana pendapat anda mengenai Bani Al Muththalib, anda telah memberikan kepada mereka dan menahan kami, sesungguhnya kami dan mereka adalah satu tingkat di sisimu. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya mereka tidak meningalkan aku baik pada masa jahiliyah maupun Islam. Sesungguhnya Bani Hasyim dan Bani Al Muththalib adalah sesuatu yang satu.\" Dan beliau menjalin antara jari-jari tangannya. "},"3861":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ يَحْيَى بْنِ الْحَارِثِ قَالَ حَدَّثَنَا مَحْبُوبٌ يَعْنِي ابْنَ مُوسَى قَالَ أَنْبَأَنَا أَبُو إِسْحَقَ وَهُوَ الْفَزَارِيُّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَيَّاشٍ عَنْ سُلَيْمَانَ بْنِ مُوسَى عَنْ مَكْحُولٍ عَنْ أَبِي سَلَّامٍ عَنْ أَبِي أُمَامَةَ الْبَاهِلِيِّ عَنْ عُبَادَةَ بْنِ الصَّامِتِ قَالَأَخَذَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ حُنَيْنٍ وَبَرَةً مِنْ جَنْبِ بَعِيرٍ فَقَالَ يَا أَيُّهَا النَّاسُ إِنَّهُ لَا يَحِلُّ لِي مِمَّا أَفَاءَ اللَّهُ عَلَيْكُمْ قَدْرُ هَذِهِ إِلَّا الْخُمُسُ وَالْخُمُسُ مَرْدُودٌ عَلَيْكُمْقَالَ أَبُو عَبْد الرَّحْمَنِ اسْمُ أَبِي سَلَّامٍ مَمْطُورٌ وَهُوَ حَبَشِيٌّ وَاسْمُ أَبِي أُمَامَةَ صُدَيُّ بْنُ عَجْلَانَ وَاللَّهُ تَعَالَى أَعْلَمُ","id":"Telah mengabarkan kepada kami ['Amr bin Yahya bin Al Harits], ia berkata; telah menceritakan kepada kami [Mahbub yaitu Ibnu Musa], ia berkata; telah memberitakan kepada kami [Abu Ishaq yaitu Al Fazari] dari [Abdurrahman bin 'Ayyasy] dari [Sulaiman bin Musa] dari [Makhul] dari [Abu Sallam] dari [Abu Umamah Al Bahili] dari ['Ubadah bin Ash Shamit], ia berkata; Rasulullah shallallahu 'alaihi wasallam usai perang Hunain mengambil bulu di samping unta dan bersabda: \"wahai sekalian manusia, sesungguhnya tidak halal bagiku dari apa yang Allah berikan kepada kalian sebanyak rambut ini kecuali hanya seperlima, dan seperlima akan dikembalikan kepada kalian, \" Abu Abdurrahman berkata nama Abi Salam adalah Mamthur ia orang Habasyah dan nama Abu Umamah adalah Shudai bin 'Ajlan, wallahu ta'ala a'lam. "},"3862":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ يَزِيدَ قَالَ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَى بَعِيرًا فَأَخَذَ مِنْ سَنَامِهِ وَبَرَةً بَيْنَ إِصْبَعَيْهِ ثُمَّ قَالَ إِنَّهُ لَيْسَ لِي مِنْ الْفَيْءِ شَيْءٌ وَلَا هَذِهِ إِلَّا الْخُمُسُ وَالْخُمُسُ مَرْدُودٌ فِيكُمْ","id":"Telah mengabarkan kepada kami ['Amr bin Yazid], ia berkata; telah menceritakan kepada kami [Ibnu Abi 'Adi], ia berkata; telah menceritakan kepada kami [Hammad bin Salamah] dari [Muhammad bin Ishaq] dari ['Amr bin Syu'aib] dari [ayahnya] dari [kakeknya] bahwa Rasulullah shallallahu 'alaihi wasallam mendatangi seekor onta kemudian mengambil bulu dari punuknya diantara dua jarinya, kemudian bersabda: \"Sesungguhnya tidak ada sesutupun dari harta fai` ini untukku, dan tidak pula bulu ini kecuali seperlima dan seperlima dikembalikan kepada kalian.\""},"3863":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ يَحْيَى بْنِ الْحَارِثِ قَالَ حَدَّثَنَا مَحْبُوبٌ يَعْنِي ابْنَ مُوسَى قَالَ أَنْبَأَنَا أَبُو إِسْحَقَ هُوَ الْفَزَارِيُّ عَنْ شُعَيْبِ بْنِ أَبِي حَمْزَةَ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَأَنَّ فَاطِمَةَ أَرْسَلَتْ إِلَى أَبِي بَكْرٍ تَسْأَلُهُ مِيرَاثَهَا مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ صَدَقَتِهِ وَمِمَّا تَرَكَ مِنْ خُمُسِ خَيْبَرَ قَالَ أَبُو بَكْرٍ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا نُورَثُ","id":"Telah mengabarkan kepada kami ['Amr bin Yahya bin Al Harits], ia berkata; telah menceritakan kepada kami [Mahbub yaitu Ibnu Musa], Ia berkata; telah memberitakan kepada kami [Abu Ishaq yaitu Al Fazari] dari [Syu'aib bin Abu Hamzah] dari [Az Zuhri] dari ['Urwah bin Az Zubair] dari [Aisyah] bahwa Fathimah mengirim surat kepada Abu Bakar menanyakan warisannya kepada Nabi shallallahu 'alaihi wasallam dari nafkahnya dan sebagian dari apa yang beliau tinggalkan dari bagian seperlima dari Khaibar. [Abu Bakar] berkata; sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kami tidak diwarisi.\""},"3864":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ يَحْيَى قَالَ حَدَّثَنَا مَحْبُوبٌ قَالَ أَنْبَأَنَا أَبُو إِسْحَقَ عَنْ زَائِدَةَ عَنْ عَبْدِ الْمَلِكِ بْنِ أَبِي سُلَيْمَانَ عَنْ عَطَاءٍفِي قَوْلِهِ عَزَّ وَجَلَّ{ وَاعْلَمُوا أَنَّمَا غَنِمْتُمْ مِنْ شَيْءٍ فَأَنَّ لِلَّهِ خُمُسَهُ وَلِلرَّسُولِ وَلِذِي الْقُرْبَى }قَالَ خُمُسُ اللَّهِ وَخُمُسُ رَسُولِهِ وَاحِدٌ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَحْمِلُ مِنْهُ وَيُعْطِي مِنْهُ وَيَضَعُهُ حَيْثُ شَاءَ وَيَصْنَعُ بِهِ مَا شَاءَ","id":"Telah mengabarkan kepada kami ['Amr bin Yahya], ia berkata; telah menceritakan kepada kami [Mahbub], ia berkata; telah memberitakan kepada kami [Abu Ishaq] dari [Zaidah] dari [Abdul Malik bin Abu Sulaiman] dari ['Atha`] mengenai firman Allah \"azza wa jalla: Ketahuilah, sesungguhnya apa saja yang dapat kamu peroleh sebagai rampasan perang, maka sesungguhnya seperlima untuk Allah, Rasul, kerabat Rasul. Ia berkata; seperlima untuk Allah dan rasulNya adalah satu, dulu Rasulullah shallallahu 'alaihi wasallam membawa darinya, memberi darinya dan meletakkannya dimana beliau mau dan berbuat dengannya apa yang beliau mau."},"3865":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ يَحْيَى بْنِ الْحَارِثِ قَالَ حَدَّثَنَا مَحْبُوبٌ قَالَ أَنْبَأَنَا أَبُو إِسْحَقَ عَنْ مُوسَى بْنِ أَبِي عَائِشَةَ قَالَ سَأَلْتُ يَحْيَى بْنَ الْجَزَّارِعَنْ هَذِهِ الْآيَةِ{ وَاعْلَمُوا أَنَّمَا غَنِمْتُمْ مِنْ شَيْءٍ فَأَنَّ لِلَّهِ خُمُسَهُ وَلِلرَّسُولِ }قَالَ قُلْتُ كَمْ كَانَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْخُمُسِ قَالَ خُمُسُ الْخُمُسِ","id":"Telah mengabarkan kepada kami ['Amr bin Yahya bin Al Harits], ia berkata; telah menceritakan kepada kami [Mahbub], ia berkata; telah memberitakan kepada kami [Abu Ishaq] dari [Musa bin Abu 'Aisyah] ia berkata; saya bertanya kepada [Yahya bin Al Jazzar] tentang ayat ini: Ketahuilah, sesungguhnya apa saja yang dapat kamu peroleh sebagai rampasan perang, maka sesungguhnya seperlima untuk Allah, Rasul, kerabat Rasul. Ia berkata aku berkata; berapa jatah untuk Nabi shallallahu 'alaihi wasallam dari seperlima itu? Ia menjawab seperlima dari seperlima."},"3866":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ يَحْيَى بْنِ الْحَارِثِ قَالَ حَدَّثَنَا مَحْبُوبٌ قَالَ أَنْبَأَنَا أَبُو إِسْحَقَ عَنْ مُطَرِّفٍ قَالَ سُئِلَ الشَّعْبِيُّعَنْ سَهْمِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَصَفِيِّهِ فَقَالَ أَمَّا سَهْمُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَسَهْمِ رَجُلٍ مِنْ الْمُسْلِمِينَ وَأَمَّا سَهْمُ الصَّفِيِّ فَغُرَّةٌ تُخْتَارُ مِنْ أَيِّ شَيْءٍ شَاءَ","id":"Telah mengabarkan kepada kami ['Amr bin Yahya bin Al Harits], ia berkata; telah menceritakan kepada kami [Mahbub], ia berkata; telah memberitakan kepada kami [Abu Ishaq] dari [Mutharrif] ia berkata; [Asy Sya'bi] ditanya mengenai saham Nabi shallallahu 'alaihi wasallam dan pilihan beliau, ia menjawab adapun saham Nabi shallallahu 'alaihi wasallam seperti jatah seorang dari kaum muslimin dan harta pilihannya adalah budak yang dipilih sesuai keinginannya. "},"3867":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ يَحْيَى قَالَ حَدَّثَنَا مَحْبُوبٌ قَالَ أَنْبَأَنَا أَبُو إِسْحَقَ عَنْ سَعِيدٍ الْجُرَيْرِيِّ عَنْ يَزِيدَ بْنِ الشِّخِّيرِ قَالَبَيْنَا أَنَا مَعَ مُطَرِّفٍ بِالْمِرْبَدِ إِذْ دَخَلَ رَجُلٌ مَعَهُ قِطْعَةُ أَدَمٍ قَالَ كَتَبَ لِي هَذِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَهَلْ أَحَدٌ مِنْكُمْ يَقْرَأُ قَالَ قُلْتُ أَنَا أَقْرَأُ فَإِذَا فِيهَا مِنْ مُحَمَّدٍ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِبَنِي زُهَيْرِ بْنِ أُقَيْشٍ أَنَّهُمْ إِنْ شَهِدُوا أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنَّ مُحَمَّدًا رَسُولُ اللَّهِ وَفَارَقُوا الْمُشْرِكِينَ وَأَقَرُّوا بِالْخُمُسِ فِي غَنَائِمِهِمْ وَسَهْمِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَصَفِيِّهِ فَإِنَّهُمْ آمِنُونَ بِأَمَانِ اللَّهِ وَرَسُولِهِ","id":"Telah mengabarkan kepada kami ['Amr bin Yahya], ia berkata; telah menceritakan kepada kami [Mahbub], ia berkata; telah memberitakan kepada kami [Abu Ishaq] dari [Sa'id Al Jurairi] dari [Yazid bin Syikhir] ia berkata; ketika saya bersama Mutharrif di tempat dikumpulkannya kurma tiba-tiba datanglah [seseorang] yang membawa potongan kulit, ia berkata Rasulullah shallallahu 'alaihi wasallam menuliskan ini untukku, adakah diantara kalian yang bisa membaca, saya menjawab; saya bisa membaca, ternyata didalamnya: \"dari Muhammad seorang Nabi shallallahu 'alaihi wasallam untuk Bani Zuhair bin Aqaisy bahwa jika mereka bersaksi bahwa tiada Tuhan yang berhak disembah kecuali hanya Allah dan Muhammad adalah Rasulullah dan mereka meninggalkan orang-orang musyrik, dan menetapkan seperlima pada harta rampasan mereka dan saham Nabi shallallahu 'alaihi wasallam serta pilihannya maka sesungguhnya mereka aman dengan keamanan dari Allah dan RasulNya.\""},"3868":{"ar":"أَخْبَرَنَا الْإِمَامُ أَبُو عَبْدِ الرَّحْمَنِ النَّسَائِيُّ مِنْ لَفْظِهِ قَالَ أَنْبَأَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عُبَادَةَ بْنِ الْوَلِيدِ بْنِ عُبَادَةَ بْنِ الصَّامِتِ عَنْ عُبَادَةَ بْنِ الصَّامِتِ قَالَبَايَعْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى السَّمْعِ وَالطَّاعَةِ فِي الْيُسْرِ وَالْعُسْرِ وَالْمَنْشَطِ وَالْمَكْرَهِ وَأَنْ لَا نُنَازِعَ الْأَمْرَ أَهْلَهُ وَأَنْ نَقُومَ بِالْحَقِّ حَيْثُ كُنَّا لَا نَخَافُ لَوْمَةَ لَائِمٍأَخْبَرَنَا عِيسَى بْنُ حَمَّادٍ قَالَ أَنْبَأَنَا اللَّيْثُ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عُبَادَةَ بْنِ الْوَلِيدِ بْنِ عُبَادَةَ بْنِ الصَّامِتِ عَنْ أَبِيهِ أَنَّ عُبَادَةَ بْنَ الصَّامِتِ قَالَ بَايَعْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى السَّمْعِ وَالطَّاعَةِ فِي الْعُسْرِ وَالْيُسْرِ وَذَكَرَ مِثْلَهُ","id":"Telah mengabarkan kepada kami Imam Abu Abdurrahman An Nasai dari lafazhnya, ia berkata; telah memberitakan kepada kami [Qutaibah bin Sa'id], ia berkata; telah menceritakan kepada kami [Al Laits] dari [Yahya bin Sa'id] dari ['Ubadah bin Al Walid bin 'Ubadah bin Ash Shamit] dari ['Ubadah bin Ash Shamit], ia berkata; kami membaiat Rasulullah shallallahu 'alaihi wasallam untuk mendengar dan taat dalam keadaan mudah dan sulit, kami senangi maupun kami benci, dan tidak merebut kekuasaan dari pemiliknya, dan melakukan kebenaran dimanapun kami berada, tidak takut kepada celaan orang yang mencela. Telah mengabarkan kepada kami [Isa bin Hammad], ia berkata; telah memberitakan kepada kami [Al Laits] dari [Yahya bin Sa'id] dari ['Ubadah bin Al Walid bin 'Ubadah bin Ash Shamit] dari [ayahnya] bahwa ['Ubadah bin Ash Shamit] berkata; kami membaiat Rasulullah shallallahu 'alaihi wasallam untuk mendengar dan taat dalam keadaan susah dan mudah... dan ia menyebutkan hadits seperti itu. "},"3869":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ ابْنِ الْقَاسِمِ قَالَ حَدَّثَنِي مَالِكٌ عَنْ يَحْيَى بْنِ سَعِيدٍ قَالَ أَخْبَرَنِي عُبَادَةُ بْنُ الْوَلِيدِ بْنِ عُبَادَةَ قَالَ حَدَّثَنِي أَبِي عَنْ عُبَادَةَ قَالَبَايَعْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ ع��لَيْهِ وَسَلَّمَ عَلَى السَّمْعِ وَالطَّاعَةِ فِي الْيُسْرِ وَالْعُسْرِ وَالْمَنْشَطِ وَالْمَكْرَهِ وَأَنْ لَا نُنَازِعَ الْأَمْرَ أَهْلَهُ وَأَنْ نَقُولَ أَوْ نَقُومَ بِالْحَقِّ حَيْثُمَا كُنَّا لَا نَخَافُ لَوْمَةَ لَائِمٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dan [Al Harits bin Miskin] dengan membacakan riwayat dan saya mendengar dari [Ibnu Al Qasim], ia berkata; telah menceritakan kepadaku [Malik] dari [Yahya bin Sa'id], ia berkata; telah mengabarkan kepadaku ['Ubadah bin Al Walid bin 'Ubadah], ia berkata; telah menceritakan kepadaku [ayahku] dari ['Ubadah], ia berkata; kami membaiat Rasulullah shallallahu 'alaihi wasallam untuk mendengar dan taat dalam keadaan mudah dan sulit, kami senangi maupun kami benci, dan tidak merebut kekuasaan dari pemiliknya, dan mengatakan atau melakukan kebenaran dimanapun kami berada, tidak takut kepada celaan orang yang mencela. "},"3870":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ أَيُّوبَ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ عَنْ ابْنِ إِسْحَقَ وَيَحْيَى بْنُ سَعِيدٍ عَنْ عُبَادَةَ بْنِ الْوَلِيدِ بْنِ عُبَادَةَ بْنِ الصَّامِتِ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَبَايَعْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى السَّمْعِ وَالطَّاعَةِ فِي الْعُسْرِ وَالْيُسْرِ وَالْمَنْشَطِ وَالْمَكْرَهِ وَأَنْ لَا نُنَازِعَ الْأَمْرَ أَهْلَهُ وَعَلَى أَنْ نَقُولَ بِالْحَقِّ حَيْثُ كُنَّا","id":"Telah mengabarkan kepada kami [Muhammad bin Yahya bin Ayyub], ia berkata; telah menceritakan kepada kami [Abdullah bin Idris] dari [Ibnu Ishaq] dan [Yahya bin Sa'id] dari ['Ubadah bin Al Walid bin Ash Shamit] dari [ayahya] dari [kakeknya], ia berkata; kami membaiat Rasulullah shallallahu 'alaihi wasallam untuk mendengar dan taat dalam keadaan sulit dan mudah, kami senangi maupun kami benci, dan tidak merebut kekuasaan dari pemiliknya, dan melakukan kebenaran dimanapun kami berada, tidak takut kepada celaan orang yang mencela. "},"3871":{"ar":"أَخْبَرَنِي هَارُونُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا أَبُو أُسَامَةَ قَالَ حَدَّثَنِي الْوَلِيدُ بْنُ كَثِيرٍ قَالَ حَدَّثَنِي عُبَادَةُ بْنُ الْوَلِيدِ أَنَّ أَبَاهُ الْوَلِيدَ حَدَّثَهُ عَنْ جَدِّهِ عُبَادَةَ بْنِ الصَّامِتِ قَالَبَايَعْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى السَّمْعِ وَالطَّاعَةِ فِي عُسْرِنَا وَيُسْرِنَا وَمَنْشَطِنَا وَمَكَارِهِنَا وَعَلَى أَنْ لَا نُنَازِعَ الْأَمْرَ أَهْلَهُ وَعَلَى أَنْ نَقُولَ بِالْعَدْلِ أَيْنَ كُنَّا لَا نَخَافُ فِي اللَّهِ لَوْمَةَ لَائِمٍ","id":"Telah mengabarkan kepada kami [Harun bin Abdullah], ia berkata; telah menceritakan kepada kami [Abu Usamah], ia berkata; telah menceritakan kepadaku [Al Walid bin Katsir], ia berkata; telah menceritakan kepadaku ['Ubadah bin Al Walid] bahwa [ayahnya] telah menceritakan kepadanya dari [kakeknya yaitu 'Ubadah bin Ash Shamit], ia berkata; kami membaiat Rasulullah shallallahu 'alaihi wasallam untuk mendengar dan taat dalam keadaan sulit dan mudah, kami senangi maupun kami benci, dan tidak merebut kekuasaan dari pemiliknya, dan melakukan kebenaran dimanapun kami berada, tidak takut kepada celaan orang yang mencela."},"3872":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْوَلِيدِ قَالَ حَدَّثَنَا مُحَمَّدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ سَيَّارٍ وَيَحْيَى بْنِ سَعِيدٍ أَنَّهُمَا سَمِعَا عُبَادَةَ بْنَ الْوَلِيدِ يُحَدِّثُ عَنْ أَبِيهِ أَمَّا سَيَّارٌ فَقَالَ عَنْ أَبِيهِ وَأَمَّا يَحْيَى فَقَالَ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَبَايَعْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى السَّمْعِ وَالطَّاعَةِ فِي عُسْرِنَا وَيُسْرِنَا وَمَنْشَطِنَا وَمَكْرَهِنَا وَأَثَرَةٍ عَلَيْنَا وَأَنْ لَا نُنَازِعَ الْأَمْرَ أَهْلَهُ وَأَنْ نَقُومَ بِالْحَقِّ حَيْثُمَا كَانَ لَا نَخَافُ فِي اللَّهِ لَوْمَةَ لَائِمٍقَالَ شُعْبَةُ سَيَّارٌ لَمْ يَذْكُرْ هَذَا الْحَرْفَ حَيْثُمَا كَانَ وَذَكَرَهُ يَحْيَى قَالَ شُعْبَةُ إِنْ كُنْتُ زِدْتُ فِيهِ شَيْئًا فَهُوَ عَنْ سَيَّارٍ أَوْ عَنْ يَحْيَى","id":"Telah mengabarkan kepada kami [Muhammad bin Al Walid], ia berkata; telah menceritakan kepada kami [Muhammad], ia berkata; telah menceritakan kepada kami [Syu'bah] dari [Sayyar] dan [Yahya bin Sa'id] bahwa keduanya telah mendengar ['Ubadah bin Al Walid] menceritakan dari [ayahnya]... adapun Sayyar, ia berkata; dari ayahya. Sedangkan Yahya, ia berkata; dari [ayahnya] dari [kakeknya], ia berkata; kami membaiat Rasulullah shallallahu 'alaihi wasallam untuk mendengar dan taat dalam keadaan sulit dan mudah, kami senangi maupun kami benci, dan mendahulukan atas diri kami dan tidak merebut kekuasaan dari pemiliknya, dan melakukan kebenaran dimanapun kami berada, tidak takut kepada celaan orang yang mencela."},"3873":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا يَعْقُوبُ عَنْ أَبِي حَازِمٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ عَلَيْكَ بِالطَّاعَةِ فِي مَنْشَطِكَ وَمَكْرَهِكَ وَعُسْرِكَ وَيُسْرِكَ وَأَثَرَةٍ عَلَيْكَ","id":"Telah mengabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Ya'qub] dari [Abu Hazim] dari [Abu Shaleh] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kewajibanmu untuk taat dalam perkara yang kamu senangi maupun kamu benci dalam keadaan sulit maupun mudah serta mengutamakan atas dirimu.\""},"3874":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ يَزِيدَ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ زِيَادِ بْنِ عِلَاقَةَ عَنْ جَرِيرٍ قَالَبَايَعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى النُّصْحِ لِكُلِّ مُسْلِمٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin Yazid], ia berkata; telah menceritakan kepada kami [Sufyan] dari [Ziyad bin 'Ilaqah] dari [Jarir], ia berkata; saya membaiat Rasulullah shallallahu 'alaihi wasallam untuk menasehati setiap muslim."},"3875":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا ابْنُ عُلَيَّةَ عَنْ يُونُسَ عَنْ عَمْرِو بْنِ سَعِيدٍ عَنْ أَبِي زُرْعَةَ بْنِ عَمْرِو بْنِ جَرِيرٍ قَالَ جَرِيرٌبَايَعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى السَّمْعِ وَالطَّاعَةِ وَأَنْ أَنْصَحَ لِكُلِّ مُسْلِمٍ","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim], ia berkata; telah menceritakan kepada kami [Ibnu Ulayyah] dari [Yunus] dari ['Amr bin Sa'id] dari [Abu Zur'ah bin 'Amr bin Jarir], [Jarir] berkata; saya membaiat Nabi shallallahu 'alaihi wasallam untuk mendengar dan mentaati dan menasehati setiap muslim. "},"3876":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي الزُّبَيْرِ سَمِعَ جَابِرًا يَقُولُلَمْ نُبَايِعْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْمَوْتِ إِنَّمَا بَايَعْنَاهُ عَلَى أَنْ لَا نَفِرَّ","id":"Telah mengabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Sufyan] dari [Abu Az Zubair], ia mendengar [Jabir] berkata; kami tidak membait Rasulullah shallallahu 'alaihi wasallam untuk mati, sesungguhnya kami membaiat beliau untuk tidak lari dari perang. "},"3877":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا حَاتِمُ بْنُ إِسْمَعِيلَ عَنْ يَزِيدَ بْنِ أَبِي عُبَيْدٍ قَالَ قُلْتُ لِسَلَمَةَ بْنِ الْأَكْوَعِعَلَى أَيِّ شَيْءٍ بَايَعْتُمْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْحُدَيْبِيَةِ قَالَ عَلَى الْمَوْتِ","id":"Telah mengabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Hatim bin Isma'il] dari [Yazid bin Abu 'Ubaid], ia berkata; saya berkata kepada [Salamah bin Al Akwa']; untuk sesuatu apakah kalian membaiat Nabi shallallahu 'alaihi wasallam pada hari di Hudaibiyah? Ia berkata; untuk mati. "},"3878":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ عَنْ ابْنِ شِهَابٍ أَنَّ عَمْرَو بْنَ عَبْدِ الرَّحْمَنِ بْنِ أُمَيَّةَ ابْنَ أَخِي يَعْلَى بْنِ أُمَيَّةَ حَدَّثَهُ أَنَّ أَبَاهُ أَخْبَرَهُ أَنَّ يَعْلَى بْنَ أُمَيَّةَ قَالَجِئْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِأَبِي أُمَيَّةَ يَوْمَ الْفَتْحِ فَقُلْتُ يَا رَسُولَ اللَّهِ بَايِعْ أَبِي عَلَى الْهِجْرَةِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُبَايِعُهُ عَلَى الْجِهَادِ وَقَدْ انْقَطَعَتْ الْهِجْرَةُ","id":"Telah mengabarkan kepada kami [Ahmad bin 'Amr bin As Sarh], ia berkata; telah menceritakan kepada kami [Ibnu Wahb], ia berkata; telah mengabarkan kepadaku ['Amr bin Al Harits] dari [Ibnu Syihab] bahwa ['Amr bin Abdurrahman bin Umayyah] anak saudara Ya'la bin Umayyah bahwa [ayahnya] mengabarkan kepadanya bahwa [Ya'la bin Umayyah] berkata; aku mendatangi Rasulullah shallallahu 'alaihi wasallam bersama Abu Umayyah ketika hari penaklukan Mekkah lalu aku berkata; wahai Rasulullah baitlah ayahku berhijrah, kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku membaitnya untuk berjihad karena hijrah telah terputus.\""},"3879":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعْدِ بْنِ إِبْرَاهِيمَ بْنِ سَعْدٍ قَالَ حَدَّثَنِي عَمِّي قَالَ حَدَّثَنَا أَبِي عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ قَالَ حَدَّثَنِي أَبُو إِدْرِيسَ الْخَوْلَانِيُّ أَنَّ عُبَادَةَ بْنَ الصَّامِتِ قَالَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَحَوْلَهُ عِصَابَةٌ مِنْ أَصْحَابِهِ تُبَايِعُونِي عَلَى أَنْ لَا تُشْرِكُوا بِاللَّهِ شَيْئًا وَلَا تَسْرِقُوا وَلَا تَزْنُوا وَلَا تَقْتُلُوا أَوْلَادَكُمْ وَلَا تَأْتُوا بِبُهْتَانٍ تَفْتَرُونَهُ بَيْنَ أَيْدِيكُمْ وَأَرْجُلِكُمْ وَلَا تَعْصُونِي فِي مَعْرُوفٍ فَمَنْ وَفَّى فَأَجْرُهُ عَلَى اللَّهِ وَمَنْ أَصَابَ مِنْكُمْ شَيْئًا فَعُوقِبَ بِهِ فَهُوَ لَهُ كَفَّارَةٌ وَمَنْ أَصَابَ مِنْ ذَلِكَ شَيْئًا ثُمَّ سَتَرَهُ اللَّهُ فَأَمْرُهُ إِلَى اللَّهِ إِنْ شَاءَ عَفَا عَنْهُ وَإِنْ شَاءَ عَاقَبَهُخَالَفَهُ أَحْمَدُ بْنُ سَعِيدٍ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'd bin Ibrahim bin Sa'd], ia berkata; telah menceritakan kepadaku [pamanku], ia berkata; telah menceritakan kepada kami [ayahku] dari [Shalih] dari [Ibnu Syihab], ia berkata; telah menceritakan kepadaku [Abu Idris Al Khaulani] bahwa ['Ubadah bin Ash Shamit] berkata; sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda dan disekitarnya terdapat beberapa orang sahabatnya: \"Apakah kalian membaitku untuk tidka mensekutukan Sesuatu dengan Allah, tidak mencuri, tidak berzina tidak membunuh anak kalian, tidak berbuat dusta yang mereka ada-adakan antara tangan dan kaki kalian, tidak mendurhakaiku dalam perkara yang ma'ruf. Dan barang siapa yang melakukan sebagian dari hal tersebut kemudian Allah menutupinya maka perkaranya kembali kepada Allah, apabila Allah menghendaki maka Allah memaafkannya dan apabila Allah menghendaki maka Allah menghukumnya.\" Ahmad bin Sa'id menyelisihi hal tersebut. "},"3880":{"ar":"أَخْبَرَنِي أَحْمَدُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا يَعْقُوبُ قَالَ حَدَّثَنَا أَبِي عَنْ صَالِحِ بْنِ كَيْسَانَ عَنْ الْحَارِثِ بْنِ فُضَيْلٍ أَنَّ ابْنَ شِهَابٍ حَدَّثَهُ عَنْ عُبَادَةَ بْنِ الصَّامِتِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَلَا تُبَايِعُونِي عَلَى مَا بَايَعَ عَلَيْهِ النِّسَاءُ أَنْ لَا تُشْرِكُوا بِاللَّهِ شَيْئًا وَلَا تَسْرِقُوا وَلَا تَزْنُوا وَلَا تَقْتُلُوا أَوْلَادَكُمْ وَلَا تَأْتُوا بِبُهْتَانٍ تَفْتَرُونَهُ بَيْنَ أَيْدِيكُمْ وَأَرْجُلِكُمْ وَلَا تَعْصُونِي فِي مَعْرُوفٍ قُلْنَا بَلَى يَا رَسُولَ اللَّهِ فَبَايَعْنَاهُ عَلَى ذَلِكَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَنْ أَصَابَ بَعْدَ ذَلِكَ شَيْئًا فَنَالَتْهُ عُقُوبَةٌ فَهُوَ كَفَّارَةٌ وَمَنْ لَمْ تَنَلْهُ عُقُوبَةٌ فَأَمْرُهُ إِلَى اللَّهِ إِنْ شَاءَ غَفَرَ لَهُ وَإِنْ شَاءَ عَاقَبَهُ","id":"Telah mengabarkan kepada kami [Ahmad bin Sa'id], ia berkata; telah menceritakan kepada kami [Ya'qub], ia berkata; telah menceritakan kepada kami [ayahku] dari [Shaleh bin Kaisan] dari [Al Harits bin Fudhail] bahwa [Ibnu Syihab] menceritakan kepadanya dari ['Ubadah bin Ash Shamit] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidakkah kalian membaitku sebagaimana para wanita membaitku, agar tidak akan menyekutukan Allah, tidak akan mencuri, tidak akan berzina, tidak akan membunuh anak-anak kalian, tidak akan berbuat dusta yang kalian ada-adakan antara tangan dan kaki kalian dan tidak akan mendurhakaiku dalam urusan yang baik.\" Maka kami mengatakan; ya, wahai Rasulullah. Kemudian kami membait beliau untuk hal tersebut. Lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang setelah itu melakukan sesuatu kemudian mendapatkan hukuman maka hal tersebut merupakan kafarah, dan barang siapa yang belum mendapatkan hukuman maka urusannya kembali kepada Allah, apabila Allah menghendaki maka Allah akan mengampuninya dan apabila Allah menghendaki maka Allah menghukumnya.\" "},"3881":{"ar":"أَخْبَرَنَا يَحْيَى بْنُ حَبِيبِ بْنِ عَرَبِيٍّ قَالَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوأَنَّ رَجُلًا أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنِّي جِئْتُ أُبَايِعُكَ عَلَى الْهِجْرَةِ وَلَقَدْ تَرَكْتُ أَبَوَيَّ يَبْكِيَانِ قَالَ ارْجِعْ إِلَيْهِمَا فَأَضْحِكْهُمَا كَمَا أَبْكَيْتَهُمَا","id":"Telah mengabarkan kepada kami [Yahya bin Habib bin 'Arabi], ia berkata; telah menceritakan kepada kami [Hammad bin Zaid] dari ['Atho` bin As Saib] dari [ayahnya] dari [Abdullah bin 'Amr] bahwa seseorang datang kepada Nabi shallallahu 'alaihi wasallam kemudian berkata; saya datang berbaiat kepadamu untuk berhijrah dan sungguh saya telah meninggalkan kedua orangtuaku yang menangis, beliau bersabda: \"Kembalilah kepada keduanya buatlah mereka tertawa seperti engkau membuat mereka menangis.\""},"3882":{"ar":"أَخْبَرَنَا الْحُسَيْنُ بْنُ حُرَيْثٍ قَالَ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ قَالَ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ الزُّهْرِيِّ عَنْ عَطَاءِ بْنِ يَزِيدَ اللَّيْثِيِّ عَنْ أَبِي سَعِيدٍأَنَّ أَعْرَابِيًّا سَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْهِجْرَةِ فَقَالَ وَيْحَكَ إِنَّ شَأْنَ الْهِجْرَةِ شَدِيدٌ فَهَلْ لَكَ مِنْ إِبِلٍ قَالَ نَعَمْ قَالَ فَهَلْ تُؤَدِّي صَدَقَتَهَا قَالَ نَعَمْ قَالَ فَاعْمَلْ مِنْ وَرَاءِ الْبِحَارِ فَإِنَّ اللَّهَ عَزَّ وَجَلَّ لَنْ يَتِرَكَ مِنْ عَمَلِكَ شَيْئًا","id":"Telah mengabarkan kepada kami [Al Husain bin Huraits], ia berkata; telah menceritakan kepada kami [Al Walid bin Muslim], ia berkata; telah menceritakan kepada kami [Al Auza'i] dari [Az Zuhri] dari ['Atho` bin Yazid Al Laitsi] dari [Abu Sa'id] bahwa Seorang badui bertanya kepada Rasulullah shallallahu 'alaihi wasallam mengenai hijrah, kemudian beliau bersabda: \"Sesungguhnya perkara hijrah sangatlah keras, apakah engkau memiliki onta?\" Ia berkata; ya. beliau bersabda: \"Apakah engkau telah menunaikan sedekah?\" Ia berkata; ya. beliau bersabda: \"Beramallah dibalik lautan sesungguhnya Allah 'azza wajalla tidak akan meninggalkan sesuatupun dari amalanmu.\""},"3883":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ بْنِ الْحَكَمِ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ عَنْ أَبِي كَثِيرٍ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ أَيُّ الْهِجْرَةِ أَفْضَلُ قَالَ أَنْ تَهْجُرَ مَا كَرِهَ رَبُّكَ عَزَّ وَجَلَّ وَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْهِجْرَةُ هِجْرَتَانِ هِجْرَةُ الْحَاضِرِ وَهِجْرَةُ الْبَادِي فَأَمَّا الْبَادِي فَيُجِيبُ إِذَا دُعِيَ وَيُطِيعُ إِذَا أُمِرَ وَأَمَّا الْحَاضِرُ فَهُوَ أَعْظَمُهُمَا بَلِيَّةً وَأَعْظَمُهُمَا أَجْرًا","id":"Telah mengabarkan kepada kami [Ahmad bin Abdullah bin Al Hakam], ia berkata; telah menceritakan kepada kami [Muhammad bin Ja'far], ia berkata; telah menceritakan kepada kami [Syu'bah] dari ['Amr bin Murrah] dari [Abdullah bin Al Harits] dari [Abu Katsir] dari [Abdullah bin 'Amr], ia berkata; seseorang berkata; wahai Rasulullah; hijrah apa yang paling utama, beliau menjawab: \"Engkau meninggalkan apa yang Tuhanmu Azza wa jalla benci, \" dan Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hijrah itu ada dua yaitu hijrah orang yang hadir dan yang tinggal di pelosok, adapun yang tinggal di pelosok maka ia akan menjawab jika diseru, ia akan taat jika diperintah, sedangkan hijrah orang yang hadir maka hal itu Adalah yang paling besar cobaan dan pahalanya.\""},"3884":{"ar":"أَخْبَرَنَا الْحُسَيْنُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا مُبَشِّرُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا سُفْيَانُ بْنُ حُسَيْنٍ عَنْ يَعْلَى بْنِ مُسْلِمٍ عَنْ جَابِرِ بْنِ زَيْدٍ قَالَ قَالَ ابْنُ عَبَّاسٍإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبَا بَكْرٍ وَعُمَرَ كَانُوا مِنْ الْمُهَاجِرِينَ لِأَنَّهُمْ هَجَرُوا الْمُشْرِكِينَ وَكَانَ مِنْ الْأَنْصَارِ مُهَاجِرُونَ لِأَنَّ الْمَدِينَةَ كَانَتْ دَارَ شِرْكٍ فَجَاءُوا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْلَةَ الْعَقَبَةِ","id":"Telah mengabarkan kepada kami [Al Husain bin Manshur], ia berkata; telah menceritakan kepada kami [Mubasysyir bin Abdullah], ia berkata; telah menceritakan kepada kami [Sufyan bin Husain] dari [Ya'la bin Muslim] dari [Jabir bin Zaid], ia berkata; [Ibnu Abbas] berkata; sesungguhnya Rasulullah shallallahu 'alaihi wasallam, Abu Bakar dan Umar adalah termasuk kaum Muhajirin karena mereka meninggalkan kaum musyrikin, dan diantara kaum Anshar ada kaum Muhajirin karena Madinah dahulu adalah wilayah syirik, lalu mereka menemui Rasulullah shallallahu 'alaihi wasallam ketika malam Aqobah."},"3885":{"ar":"أَخْبَرَنِي هَارُونُ بْنُ مُحَمَّدِ بْنِ بَكَّارِ بْنِ بِلَالٍ عَنْ مُحَمَّدٍ وَهُوَ ابْنُ عِيسَى بْنِ سُمَيْعٍ قَالَ حَدَّثَنَا زَيْدُ بْنُ وَاقِدٍ عَنْ كَثِيرِ بْنِ مُرَّةَ أَنَّ أَبَا فَاطِمَةَ حَدَّثَهُأَنَّهُ قَالَ يَا رَسُولَ اللَّهِ حَدِّثْنِي بِعَمَلٍ أَسْتَقِيمُ عَلَيْهِ وَأَعْمَلُهُ قَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْكَ بِالْهِجْرَةِ فَإِنَّهُ لَا مِثْلَ لَهَا","id":"Telah mengabarkan kepada kami [Harun bin Muhammad bin Bakkar bin Bilal] dari [Muhammad yaitu Ibnu Isa bin Sumai'], ia berkata; telah menceritakan kepada kami [Zaid bin Waqid] dari [Katsir bin Marrah] bahwa [Abu Fathimah] telah menceritakan bahwa ia berkata; wahai Rasulullah, beritahukan kepadaku suatu amalan yang aku bisa beristiqomah dalam mengamalkannya, Rasulullah shallallahu 'alaihi wasallam bersabda kepadanya: \"Hendaknya engkau hijrah karena sesungguhnya tidak ada yang menyamainya.\""},"3886":{"ar":"أَخْبَرَنَا عَبْدُ الْمَلِكِ بْنُ شُعَيْبِ بْنِ اللَّيْثِ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَ حَدَّثَنِي عُقَيْلٌ عَنْ ابْنِ شِهَابٍ عَنْ عَمْرِو بْنِ عَبْدِ الرَّحْمَنِ بْنِ أُمَيَّةَ أَنَّ أَبَاهُ أَخْبَرَهُ أَنَّ يَعْلَى قَالَجِئْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِأَبِي يَوْمَ الْفَتْحِ فَقُلْتُ يَا رَسُولَ اللَّهِ بَايِعْ أَبِي عَلَى الْهِجْرَةِ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُبَايِعُهُ عَلَى الْجِهَادِ وَقَدْ انْقَطَعَتْ الْهِجْرَةُ","id":"Telah mengabarkan kepada kami [Abdul Malik bin Syu'aib bin Al Laits] dari [ayahnya] dari [kakeknya], ia berkata; telah menceritakan kepadaku ['Uqail] dari [Ibnu Syihab] dari ['Amr bin Abdurrahman bin Umayyah] bahwa [ayahnya] telah memberitakan kepadanya bahwa [Ya'la] berkata; saya datang kepada Rasulullah shallallahu 'alaihi wasallam bersama ayahku pada saat penaklukan Mekkah kemudian saya katakan; wahai Rasulullah baitlah ayahku untuk berhijrah! Rasulullah shallallahu 'alaihi wasallam bersabda: \"Saya baiat dia untuk berhijrah Karena hijrah telah terputus.\""},"3887":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ دَاوُدَ قَالَ حَدَّثَنَا مُعَلَّى بْنُ أَسَدٍ قَالَ حَدَّثَنَا وُهَيْبُ بْنُ خَالِدٍ عَنْ عَبْدِ اللَّهِ بْنِ طَاوُسٍ عَنْ أَبِيهِ عَنْ صَفْوَانَ بْنِ أُمَيَّةَ قَالَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّهُمْ يَقُولُونَ إِنَّ الْجَنَّةَ لَا يَدْخُلُهَا إِلَّا مُهَاجِرٌ قَالَ لَا هِجْرَةَ بَعْدَ فَتْحِ مَكَّةَ وَلَكِنْ جِهَادٌ وَنِيَّةٌ فَإِذَا اسْتُنْفِرْتُمْ فَانْفِرُوا","id":"Telah mengabarkan kepadaku [Muhammad bin Daud], ia berkata; telah menceritakan kepada kami [Mu'alla bin Asad], ia berkata; telah menceritakan kepada kami [Wuhaib bin Khalid] dari [Abdullah bin Thawus] dari [ayahnya] dari [Shofwan bin Umayyah] ia berkata; saya berkata; wahai Rasulullah sungguh mereka mengatakan; sesungguhnya Surga tidak ada yang memasukinya kecuali orang Muhajir, beliau bersabda \"Tidak ada hijrah setelah penaklukan Mekkah namun hanya jihad dan niat, jika kalian diperintah untuk berangkat berjihad maka berangkatlah.\""},"3888":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ سُفْيَانَ قَالَ حَدَّثَنِي مَنْصُورٌ عَنْ مُجَاهِدٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْفَتْحِ لَا هِجْرَةَ وَلَكِنْ جِهَادٌ وَنِيَّةٌ فَإِذَا اسْتُنْفِرْتُمْ فَانْفِرُوا","id":"Telah mengabarkan kepada kami [Ishaq bin Manshur], ia berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dari [Sufyan], ia berkata; telah menceritakan kepadaku [Manshur] dari [Mujahid] dari [Thawus] dari [Ibnu Abbas], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda pada saat penaklukan Mekkah: \"Tidak ada hijrah, akan tetapi jihad dan niat. Apabila kalian diperintah untuk berangkat berjihad maka berangkatlah.\""},"3889":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ عَنْ عَبْدِ الرَّحْمَنِ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ يَحْيَى بْنِ هَانِئٍ عَنْ نُعَيْمِ بْنِ دَجَاجَةَ قَالَ سَمِعْتُ عُمَرَ بْنَ الْخَطَّابِ يَقُولُلَا هِجْرَةَ بَعْدَ وَفَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami ['Amr bin Ali] dari [Abdurrahman], ia berkata; telah menceritakan kepada kami [Syu'bah] dari [Yahya bin Hani`] dari [Nu'aim bin Dajajah] ia berkata; saya mendengar [Umar bin Khathab] berkata; tidak ada hijrah setelah wafatnya Rasulullah shallallahu 'alaihi wasallam."},"3890":{"ar":"أَخْبَرَنَا عِيسَى بْنُ مُسَاوِرٍ قَالَ حَدَّثَنَا الْوَلِيدُ عَنْ عَبْدِ اللَّهِ بْنِ الْعَلَاءِ بْنِ زَبْرٍ عَنْ بُسْرِ بْنِ عُبَيْدِ اللَّهِ عَنْ أَبِي إِدْرِيسَ الْخَوْلَانِيِّ عَنْ عَبْدِ اللَّهِ بْنِ وَقْدَانَ السَّعْدِيِّ قَالَوَفَدْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي وَفْدٍ كُلُّنَا يَطْلُبُ حَاجَةً وَكُنْتُ آخِرَهُمْ دُخُولًا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنِّي تَرَكْتُ مَنْ خَلْفِي وَهُمْ يَزْعُمُونَ أَنَّ الْهِجْرَةَ قَدْ انْقَطَعَتْ قَالَ لَا تَنْقَطِعُ الْهِجْرَةُ مَا قُوتِلَ الْكُفَّارُ","id":"Telah mengabarkan kepada kami [Isa bin Musawir], ia berkata; telah menceritakan kepada kami [Al Walid] dari [Abdullah bin Al 'Ala` bin Zabr] dari [Busr bin 'Ubaidullah] dari [Abu Idris Al Khaulani] dari [Abdullah bin Waqdan As Sa'dan As Sa'di], ia berkata; saya menjadi utusan kepada Rasulullah shallallahu 'alaihi wasallam dalam sekelompok utusan yang semuanya menuntut suatu kebutuhan, dan saya adalah orang terakhir yang menemui Rasulullah shallallahu 'alaihi wasallam, kemudian saya katakan; wahai Rasulullah, sesungguhnya saya meninggalkan orang-orang di belakangku dan mereka mengklaim bahwa hijrah telah terputus. beliau bersabda: \" Hijrah tidak terputus selama orang-orang kafir masih diperangi.\""},"3891":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ خَالِدٍ قَالَ حَدَّثَنَا مَرْوَانُ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْعَلَاءِ بْنِ زَبْرٍ قَالَ حَدَّثَنِي بُسْرُ بْنُ عُبَيْدِ اللَّهِ عَنْ أَبِي إِدْرِيسَ الْخَوْلَانِيِّ عَنْ حَسَّانَ بْنِ عَبْدِ اللَّهِ الضَّمْرِيِّ عَنْ عَبْدِ اللَّهِ بْنِ السَّعْدِيِّ قَالَوَفَدْنَا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَدَخَلَ أَصْحَابِي فَقَضَى حَاجَتَهُمْ وَكُنْتُ آخِرَهُمْ دُخُولًا فَقَالَ حَاجَتُكَ فَقُلْتُ يَا رَسُولَ اللَّهِ مَتَى تَنْقَطِعُ الْهِجْرَةُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَنْقَطِعُ الْهِجْرَةُ مَا قُوتِلَ الْكُفَّارُ","id":"Telah mengabarkan kepada kami [Mahmud bin Khalid], ia berkata; telah menceritakan kepada kami [Marwan bin Muhammad], ia berkata; telah menceritakan kepada kami [Abdullah bin Al 'Ala`bin Zubr], ia berkata; telah menceritakan kepadaku [Busr bin 'Ubaidullah] dari [Abu Idris Al Khaulani] dari [Hassan bin Abdullah Adh Dhamri] dari [Abdullah bin As Sa'di], ia berkata; kami menjadi utusan kepada Rasulullah shallallahu 'alaihi wasallam kemudian para sahabatku menemui Rasulullah shallallahu 'alaihi wasallam dan menunaikan keperluannya, sedangkan saya adalah orang yang terakhir masuknya. Kemudian beliau bersabda: \"Apakah keperluanmu?\" Saya katakan; wahai Rasulullah, kapankah hijrah terputus? Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hijrah tidak terputus selama orang-orang kafir masih diperangi.\" "},"3892":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ قُدَامَةَ عَنْ جَرِيرٍ عَنْ مُغِيرَةَ عَنْ أَبِي وَائِلٍ وَالشَّعْبِيِّ قَالَا قَالَ جَرِيرٌأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ لَهُ أُبَايِعُكَ عَلَى السَّمْعِ وَالطَّاعَةِ فِيمَا أَحْبَبْتُ وَفِيمَا كَرِهْتُ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوَ تَسْتَطِيعُ ذَلِكَ يَا جَرِيرُ أَوَ تُطِيقُ ذَلِكَ قَالَ قُلْ فِيمَا اسْتَطَعْتُ فَبَايَعَنِي وَالنُّصْحِ لِكُلِّ مُسْلِمٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Qudamah] dari [Jarir] dari [Mughirah] dari [Abu Wail] dan [Asy Sya'bi] mereka berkata; [Jarir] berkata; saya datang kepada Nabi shallallahu 'alaihi wasallam, dan berkata kepadanya; saya berbai'at kepadamu untuk mendengar dan taat dalam perkara yang saya senangi dan perkara yang saya benci. Nabi shallallahu 'alaihi wasallam bersabda: \" Apakah engkau mampu melakukan hal itu wahai Jarij?\" Beliau bersabda: \"Katakan dalam perkara yang saya mampu.\" Maka beliau membai'at saya untuk menasehati setiap muslim."},"3893":{"ar":"أَخْبَرَنَا بِشْرُ بْنُ خَالِدٍ قَالَ حَدَّثَنَا غُنْدَرٌ عَنْ شُعْبَةَ عَنْ سُلَيْمَانَ عَنْ أَبِي وَائِلٍ عَنْ جَرِيرٍ قَالَبَايَعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى إِقَامِ الصَّلَاةِ وَإِيتَاءِ الزَّكَاةِ وَالنُّصْحِ لِكُلِّ مُسْلِمٍ وَعَلَى فِرَاقِ الْمُشْرِكِأَخْبَرَنِي مُحَمَّدُ بْنُ يَحْيَى بْنِ مُحَمَّدٍ قَالَ حَدَّثَنَا الْحَسَنُ بْنُ الرَّبِيعِ قَالَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ الْأَعْمَشِ عَنْ أَبِي وَائِلٍ عَنْ أَبِي نُخَيْلَةَ عَنْ جَرِيرٍ قَالَ أَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ نَحْوَهُ","id":"Telah mengabarkan kepada kami [Bisyr bin Khalid], ia berkata; telah menceritakan kepada kami [Ghundar] dari [Syu'bah] dari [Sulaiman] dari [Abu Wail] dari [Jarir], ia berkata; saya berbai'at kepada Rasulullah shallallahu 'alaihi wasallam untuk mendirikan shalat, membayar zakat dan menasehati setiap orang muslim, serta meninggalkan orang musyrik. Telah mengabarkan kepadaku [Muhammad bin Yahya bin Muhammad], Ia berkata; telah menceritakan kepada kami [Al Hasan bin Ar Rabi'], ia berkata; telah menceritakan kepada kami [Abu Al Ahwash] dari [Al A'masy] dari [Abu Wail] dari [Abu Nukhailah] dari [Jarir], ia berkata; saya datang kepada Rasulullah shallallahu 'alaihi wasallam...kemudian ia menyebutkan hadits seperti itu. "},"3894":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ قُدَامَةَ قَالَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ أَبِي وَائِلٍ عَنْ أَبِي نُخَيْلَةَ الْبَجَلِيِّ قَالَ قَالَ جَرِيرٌأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يُبَايِعُ فَقُلْتُ يَا رَسُولَ اللَّهِ ابْسُطْ يَدَكَ حَتَّى أُبَايِعَكَ وَاشْتَرِطْ عَلَيَّ فَأَنْتَ أَعْلَمُ قَالَ أُبَايِعُكَ عَلَى أَنْ تَعْبُدَ اللَّهَ وَتُقِيمَ الصَّلَاةَ وَتُؤْتِيَ الزَّكَاةَ وَتُنَاصِحَ الْمُسْلِمِينَ وَتُفَارِقَ الْمُشْرِكِينَ","id":"Telah mengabarkan kepada kami [Muhammad bin Qudamah], ia berkata; telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Abu Wail] dari [Abu Nukhailah Al Bajili], ia berkata; [Jarir] berkata; saya datang kepada Nabi shallallahu 'alaihi wasallam dan beliau sedang membai'at. Kemudian saya katakan; wahai Rasulullah, hamparkan tanganmu hingga saya berbai'at kepadamu dan memintalah syarat kepadaku, engkau lebih mengetahui. beliau bersabda: \" Saya bai'at engkau untuk beribadah kepada Allah, mendirikan shalat, menunaikan zakat, saling menasehati diantara orang-orang muslim, dan meninggalkan orang-orang musyrik.\""},"3895":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا غُنْدَرٌ قَالَ أَنْبَأَنَا مَعْمَرٌ قَالَ أَنْبَأَنَا ابْنُ شِهَابٍ عَنْ أَبِي إِدْرِيسَ الْخَوْلَانِيِّ قَالَ سَمِعْتُ عُبَادَةَ بْنَ الصَّامِتِ قَالَبَايَعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي رَهْطٍ فَقَالَ أُبَايِعُكُمْ عَلَى أَنْ لَا تُشْرِكُوا بِاللَّهِ شَيْئًا وَلَا تَسْرِقُوا وَلَا تَزْنُوا وَلَا تَقْتُلُوا أَوْلَادَكُمْ وَلَا تَأْتُوا بِبُهْتَانٍ تَفْتَرُونَهُ بَيْنَ أَيْدِيكُمْ وَأَرْجُلِكُمْ وَلَا تَعْصُونِي فِي مَعْرُوفٍ فَمَنْ وَفَّى مِنْكُمْ فَأَجْرُهُ عَلَى اللَّهِ وَمَنْ أَصَابَ مِنْ ذَلِكَ شَيْئًا فَعُوقِبَ فِيهِ فَهُوَ طَهُورُهُ وَمَنْ سَتَرَهُ اللَّهُ فَذَاكَ إِلَى اللَّهِ إِنْ شَاءَ عَذَّبَهُ وَإِنْ شَاءَ غَفَرَ لَهُ","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim], ia berkata; telah menceritakan kepada kami telah menceritakan kepada kami [Ghundar], ia berkata; telah memberitakan kepada kami [Ma'mar], ia berkata; telah memberitakan kepada kami [Ibnu Syihab] dari [Abu Idris Al Khaulani], ia berkata; saya mendengar ['Ubadah bin Ash Shamit], ia berkata; saya membai'at Rasulullah shallallahu 'alaihi wasallam dalam sekelompok orang, kemudian beliau bersabda: \"Saya membai'at kalian untuk tidak mensekutukan Allah dengan sesuatu. Tidak mencuri, tidak berzina tidak membunuh anak-anak kalian tidak melakukan kedustaan yang kalian ada- adakan diantara ke dua tangannya di antara kedua tangan dan kaki kami dan tidak berbuat durha kepadaku dalam perkara yang baik, barang siapa diantara kalian menunaikannya maka pahala kepada Allah. Barang siapa yang melakukan sesuatu dari hal tersebut kemudian dihukum maka hal tersebut merupakan pencuci baginya, dan barang siapa Allah tutupi dirinya maka hal tersebut kembali kepada Allah, apabila Allah menghendaki maka Allah akan mengadzabnya dan apabila Allah menghendaki maka Allah mengampuninya.\" "},"3896":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ أَيُّوبَ عَنْ مُحَمَّدٍ عَنْ أُمِّ عَطِيَّةَ قَالَتْلَمَّا أَرَدْتُ أَنْ أُبَايِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْتُ يَا رَسُولَ اللَّهِ إِنَّ امْرَأَةً أَسْعَدَتْنِي فِي الْجَاهِلِيَّةِ فَأَذْهَبُ فَأُسْعِدُهَا ثُمَّ أَجِيئُكَ فَأُبَايِعُكَ قَالَ اذْهَبِي فَأَسْعِدِيهَا قَالَتْ فَذَهَبْتُ فَسَاعَدْتُهَا ثُمَّ جِئْتُ فَبَايَعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur], ia berkata; telah menceritakan kepada kami [Sufyan] dari [Ayyub] dari [Muhammad] dari [Ummu 'Athiyah], ia berkata; tatkala saya ingin membai'at Rasulullah shallallahu 'alaihi wasallam saya katakan; wahai Rasulullah, sesungguhnya terdapat seorang wanita yang membantuku melakukan ratapan pada masa jahiliyah lalu saya pergi untuk membantunya melakukan ratapan, kemudian saya datang kepadamu untuk berbai'at. Beliau bersabda: \"Pergilah dan bantulah dia melakukan ratapan.\" Kemudian saya pergi dan membantu melakukan ratapan kemudian saya datang dan membai'at Rasulullah shallallahu 'alaihi wasallam. "},"3897":{"ar":"أَخْبَرَنَا الْحَسَنُ بْنُ أَحْمَدَ قَالَ حَدَّثَنَا أَبُو الرَّبِيعِ قَالَ أَنْبَأَنَا حَمَّادٌ قَالَ حَدَّثَنَا أَيُّوبُ عَنْ مُحَمَّدٍ عَنْ أُمِّ عَطِيَّةَ قَالَتْأَخَذَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْبَيْعَةَ عَلَى أَنْ لَا نَنُوحَ","id":"Telah mengabarkan kepada kami [Al Hasan bin Ahmad], ia berkata; telah menceritakan kepada kami [Abu Ar Rabi'], ia berkata; telah memberitakan kepada kami [Hammad], ia berkata; telah menceritakan kepada kami [Ayyub] dari [Muhammad] dari [Ummu 'Athiyah], ia berkata; Rasulullah shallallahu 'alaihi wasallam mengambil bai'at dari kami agar tidak melakukan ratapan."},"3898":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ أُمَيْمَةَ بِنْتِ رُقَيْقَةَ أَنَّهَا قَالَتْأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي نِسْوَةٍ مِنْ الْأَنْصَارِ نُبَايِعُهُ فَقُلْنَا يَا رَسُولَ اللَّهِ نُبَايِعُكَ عَلَى أَنْ لَا نُشْرِكَ بِاللَّهِ شَيْئًا وَلَا نَسْرِقَ وَلَا نَزْنِيَ وَلَا نَأْتِيَ بِبُهْتَانٍ نَفْتَرِيهِ بَيْنَ أَيْدِينَا وَأَرْجُلِنَا وَلَا نَعْصِيكَ فِي مَعْرُوفٍ قَالَ فِيمَا اسْتَطَعْتُنَّ وَأَطَقْتُنَّ قَالَتْ قُلْنَا اللَّهُ وَرَسُولُهُ أَرْحَمُ بِنَا هَلُمَّ نُبَايِعْكَ يَا رَسُولَ اللَّهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي لَا أُصَافِحُ النِّسَاءَ إِنَّمَا قَوْلِي لِمِائَةِ امْرَأَةٍ كَقَوْلِي لِامْرَأَةٍ وَاحِدَةٍ أَوْ مِثْلُ قَوْلِي لِامْرَأَةٍ وَاحِدَةٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar], ia berkata; telah menceritakan kepada kami [Abdurrahman], ia berkata; telah menceritakan kepada kami [Sufyan] dari [Muhammad bin Al Munkadir] dari [Umaimah binti Ruqaiqah] bahwa ia berkata; saya datang kepada Nabi shallallahu 'alaihi wasallam diantara beberapa wanita Anshar, kami berbai'at kepadanya dan berkata; wahai Rasulullah, kami berbai'a kepadamu untuk tidak mensekutukan Allah dengan sesuatu, tidak mencuri, tidak berzina, tidak melakukan kedustaan yang diadakan diantara kedua tangan dan kaki kami, tidak mendurhakaimu dalam perkara yang baik. Beliau bersabda: \"Dalam perkara yang kalian mampu.\" Ia berkata; maka kami katakan; Allah dan RasulullahNya lebih sayang kepada kami. Mari kami baiat engkau wahai Rasulullah. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya saya tidak bersalaman dengan wanita. Sesungguhnya perkataanku kepada seratus orang wanita seperti perkataanku kepada satu orang wanita atau seperti perkataanku kepada satu orang wanita.\""},"3899":{"ar":"أَخْبَرَنَا زِيَادُ بْنُ أَيُّوبَ قَالَ حَدَّثَنَا هُشَيْمٌ عَنْ يَعْلَى بْنِ عَطَاءٍ عَنْ رَجُلٍ مِنْ يُقَالُ الشَّرِيدِ لَهُ كَانَ عَمْرٌو عَنْ أَبِيهِ قَالَفِي وَفْدِ وَفْدِ ثَقِيفٍ رَجُلٌ مَجْذُومٌ فَأَرْسَلَ إِلَيْهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ارْجِعْ فَقَدْ بَايَعْتُكَ","id":"Telah mengabarkan kepada kami [Ziyad bin Ayyub], ia berkata; telah menceritakan kepada kami [Husyaim] dari [Ya'la bin 'Atho`] dari seorang laki-laki yang dipanggil dari yuqal asy syarid lahu, ['Amr] berkata dari [Ayahnya] berkata; di antara utusan orang-orang Tsaqif terdapat seorang laki-laki yang mengidap penyakit lepra kemudian Rasulullah shallallahu 'alaihi wasallam mengirimkan utusan kepadanya dan bersabda: \"Kembalilah, sungguh saya telah membai'atmu.\""},"3900":{"ar":"أَخْبَرَنَا عَبْدُ الرَّحْمَنِ بْنُ مُحَمَّدِ بْنِ سَلَّامٍ قَالَ حَدَّثَنَا عُمَرُ بْنُ يُونُسَ عَنْ عِكْرِمَةَ بْنِ عَمَّارٍ عَنْ الْهِرْمَاسِ بْنِ زِيَادٍ قَالَمَدَدْتُ يَدِي إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا غُلَامٌ لِيُبَايِعَنِي فَلَمْ يُبَايِعْنِي","id":"Telah mengabarkan kepada kami [Abdurrahman bin Muhammad bin Sallam], ia berkata; telah menceritakan kepada kami [Umar bin Yunus] dari [Ikrimah bin 'Ammar] dari [Al Hirmas bin Ziyad], ia berkata; saya mengulurkan tanganku kepada Nabi shallallahu 'alaihi wasallam dan ketika itu saya adalah seorang anak kecil, agar saya membai'at beliau namun beliau tidak menerimaku."},"3901":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَجَاءَ عَبْدٌ فَبَايَعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْهِجْرَةِ وَلَا يَشْعُرُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ عَبْدٌ فَجَاءَ سَيِّدُهُ يُرِيدُهُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِعْنِيهِ فَاشْتَرَاهُ بِعَبْدَيْنِ أَسْوَدَيْنِ ثُمَّ لَمْ يُبَايِعْ أَحَدًا حَتَّى يَسْأَلَهُ أَعَبْدٌ هُوَ","id":"Telah mengabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Al Laits] dari [Abu Az Zubair] dari [Jabir], ia berkata; telah datang seorang budak kemudian ia membai'at Nabi shallallahu 'alaihi wasallam untuk berhijrah dan Nabi shallallahu 'alaihi wasallam tidak merasakan bahwa ia adalah budak kemudian tuannya datang hendak mengambilnya. Lalu Nabi shallallahu 'alaihi wasallam bersabda: \"Juallah ia kepadaku.\" Kemudian beliau membelinya dengan dua budak hitam. Kemudian beliau tidak membai'at seseorang hingga bertanya kepadanya apakah ia seorang budak? "},"3902":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ أَعْرَابِيًّا بَايَعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْإِسْلَامِ فَأَصَابَ الْأَعْرَابِيَّ وَعْكٌ بِالْمَدِينَةِ فَجَاءَ الْأَعْرَابِيُّ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ أَقِلْنِي بَيْعَتِي فَأَبَى ثُمَّ جَاءَهُ فَقَالَ أَقِلْنِي بَيْعَتِي فَأَبَى فَخَرَجَ الْأَعْرَابِيُّ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا الْمَدِينَةُ كَالْكِيرِ تَنْفِي خَبَثَهَا وَتَنْصَعُ طِيبَهَا","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Muhammad bin Al Munkadir] dari [Jabir bin Abdullah] bahwa seorang badui membai'at Rasulullah shallallahu 'alaihi wasallam untuk masuk Islam. Kemudian orang badui tersebut tertimpa penyakit demam di Madinah kemudian orang badui tersebut kepada Rasulullah shallallahu 'alaihi wasallam dan berkata; wahai Rasulullah, batalkan bai'atku, kemudian beliau menolak, kemudian ia datang kepada beliau dan berkata; batalkan bai'atku. Kemudian beliau menolak, lalu orang badui tersebut keluar. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Madinah seperti alat peniup api tukang besi yang menghilangkan kotoran serta memurnikan yang baiknya.\""},"3903":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا حَاتِمُ بْنُ إِسْمَعِيلَ عَنْ يَزِيدَ بْنِ أَبِي عُبَيْدٍ عَنْ سَلَمَةَ بْنِ الْأَكْوَعِأَنَّهُ دَخَلَ عَلَى الْحَجَّاجِ فَقَالَ يَا ابْنَ الْأَكْوَعِ ارْتَدَدْتَ عَلَى عَقِبَيْكَ وَذَكَرَ كَلِمَةً مَعْنَاهَا وَبَدَوْتَ قَالَ لَا وَلَكِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَذِنَ لِي فِي الْبُدُوِّ","id":"Telah mengabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Hatim bin Isma'il] dari [Yazid bin Abu 'Ubaid] dari [Salamah bin Al Akwa'] bahwa ia menemui Al Hajjaj, kemudian ia berkata; wahai anak Al Akwa', engkau telah keluar dari negeri hijrah. Dan ia menyebutkan suatu kata yang maknanya adalah; dan engkau telah tinggal di pelosok. Salamah berkata; tidak akan tetapi Rasulullah shallallahu 'alaihi wasallam telah mengizinkanku untuk tinggal di pelosok. "},"3904":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ ح و أَخْبَرَنِي عَلِيُّ بْنُ حُجْرٍ عَنْ إِسْمَعِيلَ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَ قَالَكُنَّا نُبَايِعُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى السَّمْعِ وَالطَّاعَةِ ثُمَّ يَقُولُ فِيمَا اسْتَطَعْتَ وَقَالَ عَلِيٌّ فِيمَا اسْتَطَعْتُمْ","id":"Telah mengabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Sufyan] dari [Abdullah bin Dinar], telah menceritakan serta mengabarkan kepadaku [Ali bin Hujr] dari [Isma'il] dari [Abdullah bin Dinar] dari [Ibnu Umar], ia berkata; dahulu kami membai'at Rasulullah shallallahu 'alaihi wasallam untuk mendengar dan taat, kemudian beliau bersabda: \"Dalam perkara yang engkau mampu.\" Dan Ali mengatakan; dalam perkara yang kalian mampu. "},"3905":{"ar":"أَخْبَرَنَا الْحَسَنُ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا حَجَّاجٌ عَنْ ابْنِ جُرَيْجٍ قَالَ أَخْبَرَنِي مُوسَى بْنُ عُقْبَةَ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَ قَالَكُنَّا حِينَ نُبَايِعُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى السَّمْعِ وَالطَّاعَةِ يَقُولُ لَنَا فِيمَا اسْتَطَعْتُمْ","id":"Telah mengabarkan kepada kami [Al Hasan bin Muhammad], ia berkata; telah menceritakan kepada kami [Hajjaj] dari [Ibnu Juraij], ia berkata; telah mengabarkan kepadaku [Musa bin 'Uqbah] dari [Abdullah bin Dinar] dari [Ibnu Umar], ia berkata; kami ketika membai'at Rasulullah shallallahu 'alaihi wasallam untuk mendengar dan taat. beliau bersabda kepada kami: \"Dalam perkara yang kalian mampu. "},"3906":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا هُشَيْمٌ قَالَ حَدَّثَنَا سَيَّارٌ عَنْ الشَّعْبِيِّ عَنْ جَرِيرِ بْنِ عَبْدِ اللَّهِ قَالَبَايَعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى السَّمْعِ وَالطَّاعَةِ فَلَقَّنَنِي فِيمَا اسْتَطَعْتَ وَالنُّصْحِ لِكُلِّ مُسْلِمٍ","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim], ia berkata; telah menceritakan kepada kami [Husyaim], ia berkata; telah menceritakan kepada kami [Sayyar] dari [Asy Sya'bi] dari [Jarir bin Abdullah], ia berkata; saya membai'at Rasulullah shallallahu 'alaihi wasallam untuk mendengar dan taat, kemudian beliau membisikkan kepadaku: \"Dalam perkara yang engaku mampu\". Serta menasehati setiap muslim. "},"3907":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ أُمَيْمَةَ بِنْتِ رُقَيْقَةَ قَالَتْبَايَعْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي نِسْوَةٍ فَقَالَ لَنَا فِيمَا اسْتَطَعْتُنَّ وَأَطَقْتُنَّ","id":"Telah mengabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Sufyan] dari [Muhammad bin Al Munkadir] dari [Umaimah binti Ruqaiqah], ia berkata; kami berbai'at kepada Rasulullah shallallahu 'alaihi wasallam diantara beberapa orang wanita, kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dalam perkara yang kalian mampu.\""},"3908":{"ar":"أَخْبَرَنَا هَنَّادُ بْنُ السَّرِيِّ عَنْ أَبِي مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ زَيْدِ بْنِ وَهْبٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ رَبِّ الْكَعْبَةِ قَالَانْتَهَيْتُ إِلَى عَبْدِ اللَّهِ بْنِ عَمْرٍو وَهُوَ جَالِسٌ فِي ظِلِّ الْكَعْبَةِ وَالنَّاسُ عَلَيْهِ مُجْتَمِعُونَ قَالَ فَسَمِعْتُهُ يَقُولُ بَيْنَا نَحْنُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ إِذْ نَزَلْنَا مَنْزِلًا فَمِنَّا مَنْ يَضْرِبُ خِبَاءَهُ وَمِنَّا مَنْ يَنْتَضِلُ وَمِنَّا مَنْ هُوَ فِي جَشْرَتِهِ إِذْ نَادَى مُنَادِي النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصَّلَاةُ جَامِعَةٌ فَاجْتَمَعْنَا فَقَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَخَطَبَنَا فَقَالَ إِنَّهُ لَمْ يَكُنْ نَبِيٌّ قَبْلِي إِلَّا كَانَ حَقًّا عَلَيْهِ أَنْ يَدُلَّ أُمَّتَهُ عَلَى مَا يَعْلَمُهُ خَيْرًا لَهُمْ وَيُنْذِرَهُمْ مَا يَعْلَمُهُ شَرًّا لَهُمْ وَإِنَّ أُمَّتَكُمْ هَذِهِ جُعِلَتْ عَافِيَتُهَا فِي أَوَّلِهَا وَإِنَّ آخِرَهَا سَيُصِيبُهُمْ بَلَاءٌ وَأُمُورٌ يُنْكِرُونَهَا تَجِيءُ فِتَنٌ فَيُدَقِّقُ بَعْضُهَا لِبَعْضٍ فَتَجِيءُ الْفِتْنَةُ فَيَقُولُ الْمُؤْمِنُ هَذِهِ مُهْلِكَتِي ثُمَّ تَنْكَشِفُ ثُمَّ تَجِيءُ فَيَقُولُ هَذِهِ مُهْلِكَتِي ثُمَّ تَنْكَشِفُ فَمَنْ أَحَبَّ مِنْكُمْ أَنْ يُزَحْزَحَ عَنْ النَّارِ وَيُدْخَلَ الْجَنَّةَ فَلْتُدْرِكْهُ مَوْتَتُهُ وَهُوَ مُؤْمِنٌ بِاللَّهِ وَالْيَوْمِ الْآخِرِ وَلْيَأْتِ إِلَى النَّاسِ مَا يُحِبُّ أَنْ يُؤْتَى إِلَيْهِ وَمَنْ بَايَعَ إِمَامًا فَأَعْطَاهُ صَفْقَةَ يَدِهِ وَثَمَرَةَ قَلْبِهِ فَلْيُطِعْهُ مَا اسْتَطَاعَ فَإِنْ جَاءَ أَحَدٌ يُنَازِعُهُ فَاضْرِبُوا رَقَبَةَ الْآخَرِ فَدَنَوْتُ مِنْهُ فَقُلْتُ سَمِعْتَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ هَذَا قَالَ نَعَمْ وَذَكَرَ الْحَدِيثَ","id":"Telah mengabarkan kepada kami [Hannad bin As Sarri] dari [Abu Mu'awiyah] dari [Al A'masy] dari [Zaid bin wahb] dari [Abdurrahman bin Abdu Rabbil Ka'bah], ia berkata; saya sampai kepada [Abdullah bin 'Amr] dan ia dalam keadaan duduk di bawah naungan Ka'bah dan orang-orang berkumpul mengerumuninya. Abdurrahman berkata; saya mendengar ia berkata; ketika kami bersama Rasulullah shallallahu 'alaihi wasallam dalam suatu safar kemudian kami singgah disuatu tempat, diantara kami ada yang mendirikan tenda, dan diantara kami ada yang berlomba memanah, serta diantara kami ada yang sedang mengeluarkan kuda menuju tempat merumput, tiba- tiba penyeru Rasulullah shallallahu 'alaihi wasallam menyeru; shalat berjama'ah! Maka kami berkumpul lalu Rasulullah shallallahu 'alaihi wasallam berdiri dan berkhutbah kepada kami, beliau bersabda: \"Sesungguhnya sesungguhnya tidak ada seorangpun nabi sebelumku melainkan ia akan menunjukkan umatnya kepada apa yang ia ketahui sebagai kebaikan untuk mereka, dan memperingatkan mereka terhadap apa yang ia ketahui sebagai keburukan bagi mereka dan umat kalian ini dijadikan keselamatannya dari apa yang membahakan agama ada dipermulaan mereka dan orang terakhir diantara mereka akan tertimpa bencana dan perkara-perkara yang mereka ingkari. Akan datang berbagai fitnah kemudian sebagian mereka mendorong sebagian yang lain, kemudian datang sebuah fitnah lalu seorang mukmin akan mengatakan; inilah kebinasaanku, kemudian fitnah tersebut hilang kemudian datang lalu ia berkata; ini adalah kebinasaanku, kemudian fitnah tersebut hilang. Barang siapa diantara kalian yang ingin dijauhkan dari Neraka dan masuk Surga maka hendaknya kematian menjemputnya dalam keadaan beriman kepada Allah dan Hari Akhir, dan hendaknya ia memberikan kepada manusia apa yang ia senang untuk diberikan kepadanya. Barang siapa yang membai'at seorang imam kemudian ia memberikan tangannya serta buah hatinya maka hendaknya ia mentaatinya sesuai dengan kemampuannya, kemudian apabila ada orang yang merebutnya maka penggallahnya.\" Kemudian saya mendekat kepada beliau dan berkata; apakah engkau mendengar Rasulullah shallallahu 'alaihi wasallam mengatakan hal ini? Maka ia berkata; ya. Dan ia menyebutkan hadits tersebut."},"3909":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ يَحْيَى بْنِ حُصَيْنٍ قَالَ سَمِعْتُ جَدَّتِي تَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فِي حَجَّةِ الْوَدَاعِ وَلَوْ اسْتُعْمِلَ عَلَيْكُمْ عَبْدٌ حَبَشِيٌّ يَقُودُكُمْ بِكِتَابِ اللَّهِ فَاسْمَعُوا لَهُ وَأَطِيعُوا","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la] berkata; telah menceritakan kepada kami [Khalid], ia berkata; telah menceritakan kepada kami [Syu'bah] dari [Yahya bin Hushain], ia berkata; saya mendengar [nenekku] berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda pada saat haji wada': \"Apabila seorang budak Habasyah diangkat menjadi pemimpin kalian ia memimpin dengan Kitab Allah maka dengarkan dan taatlah kepadanya.\""},"3910":{"ar":"أَخْبَرَنَا يُوسُفُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا حَجَّاجٌ عَنْ ابْنِ جُرَيْجٍ أَنَّ زِيَادَ بْنَ سَعْدٍ أَخْبَرَهُ أَنَّ ابْنَ شِهَابٍ أَخْبَرَهُ أَنَّ أَبَا سَلَمَةَ أَخْبَرَهُ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَطَاعَنِي فَقَدْ أَطَاعَ اللَّهَ وَمَنْ عَصَانِي فَقَدْ عَصَى اللَّهَ وَمَنْ أَطَاعَ أَمِيرِي فَقَدْ أَطَاعَنِي وَمَنْ عَصَى أَمِيرِي فَقَدْ عَصَانِي","id":"Telah mengabarkan kepada kami [Yusuf bin Sa'id], ia berkata; telah menceritakan kepada kami [Hajjaj] dari [Ibnu Juraij] bahwa [Ziyad bin Sa'd] telah mengabarkan kepadanya bahwa [Ibnu Syihab] telah mengabarkan kepadanya bahwa [Abu Salamah] telah mengabarkan kepadanya bahwa ia mendengar [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Barang siapa yang mentaatiku maka sungguh ia telah mentaati Allah dan barang siapa yang mendurhakai amirku maka sungguh ia telah mendurhakaiku.\""},"3911":{"ar":"أَخْبَرَنَا الْحَسَنُ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا حَجَّاجٌ قَالَ قَالَ ابْنُ جُرَيْجٍ أَخْبَرَنِي يَعْلَى بْنُ مُسْلِمٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ{ يَا أَيُّهَا الَّذِينَ آمَنُوا أَطِيعُوا اللَّهَ وَأَطِيعُوا الرَّسُولَ }قَالَ نَزَلَتْ فِي عَبْدِ اللَّهِ بْنِ حُذَافَةَ بْنِ قَيْسِ بْنِ عَدِيٍّ بَعَثَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَرِيَّةٍ","id":"Telah mengabarkan kepada kami [Al Hasan bin Muhammad], ia berkata; telah menceritakan kepada kami [Hajjaj], ia berkata; [Ibnu Juraij] berkata; telah mengabarkan kepadaku [Ya'la bin Muslim] dari [Sa'id bin Jubair] dari [Ibnu Abbas] ayat hai orang-orang yang beriman taatilah Allah dan taatilah rasulNya ia berkata; ayat ini turun mengenai Abdullah bin Hudzafah bin Qois bin 'Adi, Rasulullah shallallahu 'alaihi wasallam mengirimnya pada suatu ekspedisi."},"3912":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عُثْمَانَ بْنِ سَعِيدٍ قَالَ حَدَّثَنَا بَقِيَّةُ بْنُ الْوَلِيدِ قَالَ حَدَّثَنَا بَحِيرٌ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ أَبِي بَحْرِيَّةَ عَنْ مُعَاذِ بْنِ جَبَلٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْغَزْوُ غَزْوَانِ فَأَمَّا مَنْ ابْتَغَى وَجْهَ اللَّهِ وَأَطَاعَ الْإِمَامَ وَأَنْفَقَ الْكَرِيمَةَ وَاجْتَنَبَ الْفَسَادَ فَإِنَّ نَوْمَهُ وَنُبْهَتَهُ أَجْرٌ كُلُّهُ وَأَمَّا مَنْ غَزَا رِيَاءً وَسُمْعَةً وَعَصَى الْإِمَامَ وَأَفْسَدَ فِي الْأَرْضِ فَإِنَّهُ لَا يَرْجِعُ بِالْكَفَافِ","id":"Telah mengabarkan kepada kami ['Amr bin Utsman bin Sa'id], ia berkata; telah menceritakan kepada kami [Baqiyah bin Al Walid], ia berkata; telah menceritakan kepada kami [Bahir] dari [Khalid bin Ma'dan] dari [Abu Bahriyah] dari [Mu'adz bin Jabal] dari Rasulullah shallallahu 'alaihi wasallam beliau bersabda: \"Perang ada dua, adapun orang yang mengharapkan wajah Allah dan mentaati pemimpin serta menafkahkan hartanya yang berharga serta menjauhi kerusakan maka tidur dan terjaganya seluruhnya adalah pahala, adapun orang yang berperang agar dilihat dan didengar orang serta mendurhakai pemimpin dan membuat kerusakan di muka bumi maka sesungguhnya ia tidak kembali membawa manfaat.\" "},"3913":{"ar":"أَخْبَرَنَا عِمْرَانُ بْنُ بَكَّارٍ قَالَ حَدَّثَنَا عَلِيُّ بْنُ عَيَّاشٍ قَالَ حَدَّثَنَا شُعَيْبٌ قَالَ حَدَّثَنِي أَبُو الزِّنَادِ مِمَّا حَدَّثَهُ عَبْدُ الرَّحْمَنِ الْأَعْرَجُ مِمَّا ذَكَرَ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يُحَدِّثُعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّمَا الْإِمَامُ جُنَّةٌ يُقَاتَلُ مِنْ وَرَائِهِ وَيُتَّقَى بِهِ فَإِنْ أَمَرَ بِتَقْوَى اللَّهِ وَعَدَلَ فَإِنَّ لَهُ بِذَلِكَ أَجْرًا وَإِنْ أَمَرَ بِغَيْرِهِ فَإِنَّ عَلَيْهِ وِزْرًا","id":"Telah mengabarkan kepada kami [Imran bin Bakkar], ia berkata; telah menceritakan kepada kami [Ali bin 'Ayyasy], ia berkata; telah menceritakan kepada kami [Syu'aib], ia berkata; telah menceritakan kepadaku [Abu Az Zinad] dari apa yang telah diceritakan kepadanya oleh [Abdurrahman Al A'raj], diantara apa yang ia sebutkan bahwa ia mendengar [Abu Hurairah] menceritakan dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya seorang imam adalah perisai dilakukan perang dari belakannya dan ia dijadikan sebagai pelindung. Apabila ia memerintahkan untuk bertakwa kepada Allah dan berbuat adil maka dengan hal itu ia mendapatkan pahala sedangkan apabila tidak demikian maka hal itu menjadi dosa baginya.\" "},"3914":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ سَأَلْتُ سُهَيْلَ بْنَ أَبِي صَالِحٍ قُلْتُ حَدَّثَنَا عَمْرٌو عَنْ الْقَعْقَاعِ عَنْ أَبِيكَ قَالَ أَنَا سَمِعْتُهُ مِنَ الَّذِي حَدَّثَ أَبِي حَدَّثَهُ رَجُلٌ مِنْ أَهْلِ الشَّامِ يُقَالُ لَهُ عَطَاءُ بْنُ يَزِيدَ عَنْ تَمِيمٍ الدَّارِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا الدِّينُ النَّصِيحَةُ قَالُوا لِمَنْ يَا رَسُولَ اللَّهِ قَالَ لِلَّهِ وَلِكِتَابِهِ وَلِرَسُولِهِ وَلِأَئِمَّةِ الْمُسْلِمِينَ وَعَامَّتِهِمْ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur], ia berkata; telah menceritakan kepada kami [Sufyan], ia berkata; saya bertanya kepada [Suhail bin Abu Shalih], saya mengatakan; telah menceritakan kepada kami ['Amr] dari [Al Qa'qa'] dari [ayahmu] ia berkata; saya mendengarnya dari orang yang menceritakan kepada ayahku, telah menceritakan kepadanya seorang laki-laki dari penduduk Syam yang dipanggil ['Atho` bin Yazid] dari [Tamim Ad Dari], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya agama adalah nasehat, orang-orang bertanya; untuk siapa wahai Rasulullah? beliau bersabda: \"Untuk Allah, KitabNya, RasulNya dan para pemimpin orang muslim serta mereka secara umum.\""},"3915":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ عَطَاءِ بْنِ يَزِيدَ عَنْ تَمِيمٍ الدَّارِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا الدِّينُ النَّصِيحَةُ قَالُوا لِمَنْ يَا رَسُولَ اللَّهِ قَالَ لِلَّهِ وَلِكِتَابِهِ وَلِرَسُولِهِ وَلِأَئِمَّةِ الْمُسْلِمِينَ وَعَامَّتِهِمْ","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim], ia berkata; telah memberitakan kepada kami [Abdurrahman], ia berkata; telah menceritakan kepada kami [Sufyan] dari [Suhail bin Abu Shalih] dari ['Atho` bin Yazid] dari [Tamim Ad Dari], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Untuk Allah, KitabNya, RasulNya dan para pemimpin orang muslim serta mereka secara umum.\""},"3916":{"ar":"أَخْبَرَنَا الرَّبِيعُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا شُعَيْبُ بْنُ اللَّيْثِ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ عَجْلَانَ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ الْقَعْقَاعِ بْنِ حَكِيمٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الدِّينَ النَّصِيحَةُ إِنَّ الدِّينَ النَّصِيحَةُ إِنَّ الدِّينَ النَّصِيحَةُ قَالُوا لِمَنْ يَا رَسُولَ اللَّهِ قَالَ لِلَّهِ وَلِكِتَابِهِ وَلِرَسُولِهِ وَلِأَئِمَّةِ الْمُسْلِمِينَ وَعَامَّتِهِمْ","id":"Telah mengabarkan kepada kami [Ar Rabi' bin Sulaiman], ia berkata; telah menceritakan kepada kami [Syu'aib bin Al Laits], ia berkata; telah menceritakan kepada kami [Al Laits] dari [Ibnu 'Ajlan] dari [Zaid bin Aslam] dari [Al Qa'qa' bin Hakim] dari [Abu Shaleh] dari [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya agama itu adalah nasehat, sesungguhnya agama itu adalah nasehat, sesungguhnya agama itu adalah nasehat.\" Para sahabat bertanya untuk siapa wahai Rasulullah? Beliau menjawab: \" Untuk Allah, kitabNya, rasulNya, dan para pemimpin kaum muslimin serta mereka secara umum.\""},"3917":{"ar":"أَخْبَرَنَا عَبْدُ الْقُدُّوسِ بْنُ مُحَمَّدِ بْنِ عَبْدِ الْكَبِيرِ بْنِ شُعَيْبِ بْنِ الْحَبْحَابِ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَهْضَمٍ قَالَ حَدَّثَنَا إِسْمَعِيلُ بْنُ جَعْفَرٍ عَنْ ابْنِ عَجْلَانَ عَنْ الْقَعْقَاعِ بْنِ حَكِيمٍ وَعَنْ سُمَيٍّ وَعَنْ عُبَيْدِ اللَّهِ بْنِ مِقْسَمٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الدِّينُ النَّصِيحَةُ قَالُوا لِمَنْ يَا رَسُولَ اللَّهِ قَالَ لِلَّهِ وَلِكِتَابِهِ وَلِرَسُولِهِ وَلِأَئِمَّةِ الْمُسْلِمِينَ وَعَامَّتِهِمْ","id":"Telah mengabarkan kepada kami [Abdul Quddus bin Muhammad bin Abdul Kabir bin Syu'aib bin Al Habhab], ia berkata; telah menceritakan kepada kami [Muhammad Jahdham], ia berkata; telah menceritakan kepada kami [Isma'il bin Ja'far] dari [Ibnu 'Ajlan] dari [Al Qa'qa' bin Hakim] dan dari [Sumai] serta ['Ubaidullah bin Miqsam] dari [Abu Shaleh] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Agama itu adalah nasehat, sesungguhnya agama itu adalah nasehat, sesungguhnya agama itu adalah nasehat.\" "},"3918":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا مُعَمَّرُ بْنُ يَعْمَرَ قَالَ حَدَّثَنِي مُعَاوِيَةُ بْنُ سَلَّامٍ قَالَ حَدَّثَنِي الزُّهْرِيُّ قَالَ حَدَّثَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ وَالٍ إِلَّا وَلَهُ بِطَانَتَانِ بِطَانَةٌ تَأْمُرُهُ بِالْمَعْرُوفِ وَتَنْهَاهُ عَنْ الْمُنْكَرِ وَبِطَانَةٌ لَا تَأْلُوهُ خَبَالًا فَمَنْ وُقِيَ شَرَّهَا فَقَدْ وُقِيَ وَهُوَ مِنْ الَّتِي تَغْلِبُ عَلَيْهِ مِنْهُمَا","id":"Telah mengabarkan kepada kami [Muhammad bin Yahya bin Abdullah], ia berkata; telah menceritakan kepada kami [Mu'ammar bin Ya'mar], ia berkata; telah menceritakan kepadaku [Mu'awiyah bin Sallam], ia berkata; telah menceritakan kepadaku [Az Zuhri], ia berkata; telah menceritakan kepadaku [Abu Salamah bin Abdurrahman] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada seorang pemimpinpun kecuali ia memiliki dua orang teman karib, seorang teman yang menyuruhnya berbuat kebaikan dan melarangnya dari perbuatan mungkar, dan seorang teman yang mengajaknya berbuat kerusakan, maka barangsiapa yang terjaga dari keburukannya maka ia telah terjaga dan ia termasuk diantara yang menang diantara keduanya.\""},"3919":{"ar":"أَخْبَرَنَا يُونُسُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي سَعِيدٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا بَعَثَ اللَّهُ مِنْ نَبِيٍّ وَلَا اسْتَخْلَفَ مِنْ خَلِيفَةٍ إِلَّا كَانَتْ لَهُ بِطَانَتَانِ بِطَانَةٌ تَأْمُرُهُ بِالْخَيْرِ وَبِطَانَةٌ تَأْمُرُهُ بِالشَّرِّ وَتَحُضُّهُ عَلَيْهِ وَالْمَعْصُومُ مَنْ عَصَمَ اللَّهُ عَزَّ وَجَلَّ","id":"Telah mengabarkan kepada kami [Yunus bin Abdul A'la], ia berkata; telah menceritakan kepada kami [Ibnu Wahb], ia berkata; telah memberitakan kepadaku [Yunus] dari [Ibnu Syihab] dari [Abu Salamah bin Abdurrahman] dari [Abu Sa'id] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Tidaklah Allah mengutus seorang nabi dan tidak mengangkat pemimpin setelahnya kecuali ia memiliki dua orang sahabat karib, seorang teman yang menyuruhnya berbuat kebaikan, dan teman yang menyuruhnya melakukan keburukan serta menganjurkannya. Orang yang terlindungi adalah orang yang Allah 'azza wajalla lindungi.\""},"3920":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ عَبْدِ الْحَكَمِ عَنْ شُعَيْبٍ عَنْ اللَّيْثِ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي جَعْفَرٍ عَنْ صَفْوَانَ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي أَيُّوبَ أَنَّهُ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا بُعِثَ مِنْ نَبِيٍّ وَلَا كَانَ بَعْدَهُ مِنْ خَلِيفَةٍ إِلَّا وَلَهُ بِطَانَتَانِ بِطَانَةٌ تَأْمُرُهُ بِالْمَعْرُوفِ وَتَنْهَاهُ عَنْ الْمُنْكَرِ وَبِطَانَةٌ لَا تَأْلُوهُ خَبَالًا فَمَنْ وُقِيَ بِطَانَةَ السُّوءِ فَقَدْ وُقِيَ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin Abdul Hakam] dari [Syu'aib] dari [Al Laits] dari ['Ubaidullah bin Abu Ja'far] dari [Shafwan] dari [Abu Salamah] dari [Abu Ayyub] ia berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada Nabi yang diutus atau seorangpun dari khalifah setelahnya kecuali ia memiliki dua orang teman karib, seorang teman yang menyuruhnya kepada perbuatan baik dan melarangnya dari perbuatan mungkar, dan seorang teman yang mengajaknya kepada kerusakan, maka barangsiapa yang terjaga dari keburukannya berarti ia telah terjaga.\""},"3921":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عُثْمَانَ قَالَ حَدَّثَنَا بَقِيَّةُ قَالَ حَدَّثَنَا ابْنُ الْمُبَارَكِ عَنْ ابْنِ أَبِي حُسَيْنٍ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ قَالَ سَمِعْتُ عَمَّتِي تَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ وَلِيَ مِنْكُمْ عَمَلًا فَأَرَادَ اللَّهُ بِهِ خَيْرًا جَعَلَ لَهُ وَزِيرًا صَالِحًا إِنْ نَسِيَ ذَكَّرَهُ وَإِنْ ذَكَرَ أَعَانَهُ","id":"Telah mengabarkan kepada kami ['Amr bin Utsman], ia berkata; telah menceritakan kepada kami [Baqiyah], ia berkata; telah menceritakan kepada kami [Ibnu Al Mubarak] dari [Ibnu Abu Husain] dari [Al Qosim bin Muhammad] ia berkata; saya mendengar [bibiku] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa diantara kalian yang mengurusi suatu pekerjaan lalu Allah inginkan kebaikan padanya maka Allah akan menjadikan untuknya pembantu yang shaleh, jika ia lupa maka ia mengingatkannya, jika ia ingat maka ia akan membantunya.\""},"3922":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَمُحَمَّدُ بْنُ بَشَّارٍ قَالَا حَدَّثَنَا مُحَمَّدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ زُبَيْدٍ الْإِيَامِيِّ عَنْ سَعْدِ بْنِ عُبَيْدَةَ عَنْ أَبِي عَبْدِ الرَّحْمَنِ عَنْ عَلِيٍّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ جَيْشًا وَأَمَّرَ عَلَيْهِمْ رَجُلًا فَأَوْقَدَ نَارًا فَقَالَ ادْخُلُوهَا فَأَرَادَ نَاسٌ أَنْ يَدْخُلُوهَا وَقَالَ الْآخَرُونَ إِنَّمَا فَرَرْنَا مِنْهَا فَذَكَرُوا ذَلِكَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لِلَّذِينَ أَرَادُوا أَنْ يَدْخُلُوهَا لَوْ دَخَلْتُمُوهَا لَمْ تَزَالُوا فِيهَا إِلَى يَوْمِ الْقِيَامَةِ وَقَالَ لِلْآخَرِينَ خَيْرًا وَقَالَ أَبُو مُوسَى فِي حَدِيثِهِ قَوْلًا حَسَنًا وَقَالَ لَا طَاعَةَ فِي مَعْصِيَةِ اللَّهِ إِنَّمَا الطَّاعَةُ فِي الْمَعْرُوفِ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dan [Muhammad bin Basysyar] mereka berkata; telah menceritakan kepada kami [Muhammad] telah menceritakan kepada kami [Syu'bah] dari [Zubaid Al Iyami] dari [Sa'd bin 'Ubaidah] dari [Abu Abdurrahman] dari [Ali] bahwa Rasulullah shallallahu 'alaihi wasallam telah mengirim pasukan dan menunjuk seseorang menjadi pemimpin bagi mereka. Kemudian orang tersebut membakar api dan mengatakan; masuklah kalian ke dalamnya, kemudian ada beberapa orang yang hendak memasukinya sedang yang lainnya berkata; sesungguhnya kita lari dari api. Kemudian mereka menyebutkan hal tersebut kepada Rasulullah shallallahu 'alaihi wasallam, lalu beliau bersabda kepada orang yang hendak memasukinya: \"Apabila kalian memasukinya maka kalian akan tetap ada padanya hingga hari Kiamat.\" Dan beliau mengatakan kebaikan kepada orang yang lain. Abu Musa dalam haditsnya mengatakan; perkataan yang baik. Beliau bersabda: \"Tidak ada ketaatan dalam bermaksiat kepada Allah, sesungguhnya ketaatan hanya dalam perkara yang baik.\""},"3923":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي جَعْفَرٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْمَرْءِ الْمُسْلِمِ السَّمْعُ وَالطَّاعَةُ فِيمَا أَحَبَّ وَكَرِهَ إِلَّا أَنْ يُؤْمَرَ بِمَعْصِيَةٍ فَإِذَا أُمِرَ بِمَعْصِيَةٍ فَلَا سَمْعَ وَلَا طَاعَةَ","id":"Telah mengabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Al Laits] dari ['Ubaidullah bin Abu Ja'far] dari [Nafi'] dari [Ibnu Umar] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Wajib bagi seorang muslim mendengar dan taat dalam perkara yang ia sukai dan ia benci kecuali jika ia diperintah untuk berbuat maksiat, jika ia diperintah untuk berbuat maksiat maka tidak ada kewajiban mendengar dan taat.\""},"3924":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى عَنْ سُفْيَانَ عَنْ أَبِي حَصِينٍ عَنْ الشَّعْبِيِّ عَنْ عَاصِمٍ الْعَدَوِيِّ عَنْ كَعْبِ بْنِ عُجْرَةَ قَالَخَرَجَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ تِسْعَةٌ فَقَالَ إِنَّهُ سَتَكُونُ بَعْدِي أُمَرَاءُ مَنْ صَدَّقَهُمْ بِكَذِبِهِمْ وَأَعَانَهُمْ عَلَى ظُلْمِهِمْ فَلَيْسَ مِنِّي وَلَسْتُ مِنْهُ وَلَيْسَ بِوَارِدٍ عَلَيَّ الْحَوْضَ وَمَنْ لَمْ يُصَدِّقْهُمْ بِكَذِبِهِمْ وَلَمْ يُعِنْهُمْ عَلَى ظُلْمِهِمْ فَهُوَ مِنِّي وَأَنَا مِنْهُ وَهُوَ وَارِدٌ عَلَيَّ الْحَوْضَ","id":"Telah mengabarkan kepada kami ['Amr bin Ali], ia berkata; telah menceritakan kepada kami [Yahya] dari [Sufyan] dari [Abu Hashin] dari [Asy Sya'bi] dari ['Ashim Al 'Adawi] dari [Ka'ab bin 'Ujrah] ia berkatal Rasulullah shallallahu 'alaihi wasallam keluar menemui kami, ketika itu kami sembilan orang, lalu beliau bersabda: \" Sesungguhnya akan ada setelahku para penguasa, barang siapa yang mempercayai kedustaan mereka dan membantu kezhaliman mereka, maka ia bukan termasuk golonganku dan aku bukan darinya, ia tidak akan menemuiku di telaga, dan barangsiapa yang tidak mempercayai kedustaan mereka dan tidak membantu kezhaliman mereka maka ia adalah termasuk golonganku dan aku bagian darinya, ia akan datang menemuiku di telaga.\""},"3925":{"ar":"أَخْبَرَنَا هَارُونُ بْنُ إِسْحَقَ قَالَ حَدَّثَنَا مُحَمَّدٌ يَعْنِي ابْنَ عَبْدِ الْوَهَّابِ قَالَ حَدَّثَنَا مِسْعَرٌ عَنْ أَبِي حَصِينٍ عَنْ الشَّعْبِيِّ عَنْ عَاصِمٍ الْعَدَوِيِّ عَنْ كَعْبِ بْنِ عُجْرَةَ قَالَخَرَجَ إِلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ تِسْعَةٌ خَمْسَةٌ وَأَرْبَعَةٌ أَحَدُ الْعَدَدَيْنِ مِنْ الْعَرَبِ وَالْآخَرُ مِنْ الْعَجَمِ فَقَالَ اسْمَعُوا هَلْ سَمِعْتُمْ أَنَّهُ سَتَكُونُ بَعْدِي أُمَرَاءُ مَنْ دَخَلَ عَلَيْهِمْ فَصَدَّقَهُمْ بِكَذِبِهِمْ وَأَعَانَهُمْ عَلَى ظُلْمِهِمْ فَلَيْسَ مِنِّي وَلَسْتُ مِنْهُ وَلَيْسَ يَرِدُ عَلَيَّ الْحَوْضَ وَمَنْ لَمْ يَدْخُلْ عَلَيْهِمْ وَلَمْ يُصَدِّقْهُمْ بِكَذِبِهِمْ وَلَمْ يُعِنْهُمْ عَلَى ظُلْمِهِمْ فَهُوَ مِنِّي وَأَنَا مِنْهُ وَسَيَرِدُ عَلَيَّ الْحَوْضَ","id":"Telah mengabarkan kepada kami [Harun bin Ishaq], ia berkata; telah menceritakan kepada kami [Muhammad yaitu Ibnu Abdul Wahhab], ia berkata; telah menceritakan kepada kami [Mis'ar] dari [Abu Hashin] dari [Asy Sya'bi] dari ['Ashim Al 'Adawi] dari [Ka'b bin 'Ujrah], ia berkata; Rasulullah shallallahu 'alaihi wasallam keluar kepada kami dan kami berjumlah sembilan, lima dan empat, salah satu dari dua kelompok dari Arab dan yang lainnya dari orang selain Arab. Kemudian beliau bersabda: \"Apakah kalian pernah mendengar bahwa akan ada setelahku para pemimpin, barang siapa yang menemui mereka dan membenarkan kedustaan mereka serta membantu kezhaliman mereka maka ia bukan termasuk golonganku dan aku bukan darinya. Ia tidak akan menemuiku di telaga, serta tidak menemui mereka dan barang siapa yang tidak mempercayai kedustaan mereka dan tidak membantu kezhaliman mereka maka ia termasuk golonganku dan aku bagian darinya, ia akan menemuiku di telaga.\""},"3926":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ عَنْ طَارِقِ بْنِ شِهَابٍأَنَّ رَجُلًا سَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ وَضَعَ رِجْلَهُ فِي الْغَرْزِ أَيُّ الْجِهَادِ أَفْضَلُ قَالَ كَلِمَةُ حَقٍّ عِنْدَ سُلْطَانٍ جَائِرٍ","id":"Telah mengabarkan kepada kami [Ishaq bin Manshur], ia berkata; telah menceritakan kepada kami [Abdurrahman] dari [Sufyan] dari ['Alqamah bin Martsad] dari [Thariq bin Syihab] bahwa seorang laki bertanya kepada Rasulullah shallallahu 'alaihi wasallam dan ia telah meletakkan kakinya di batang kayu yang ditancapkan di tanah; jihad apakah yang paling utama? Beliau bersabda: \"Perkataan yang benar dihadapan penguasa yang zhalim.\""},"3927":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ أَبِي إِدْرِيسَ الْخَوْلَانِيِّ عَنْ عُبَادَةَ بْنِ الصَّامِتِ قَالَكُنَّا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مَجْلِسٍ فَقَالَ بَايِعُونِي عَلَى أَنْ لَا تُشْرِكُوا بِاللَّهِ شَيْئًا وَلَا تَسْرِقُوا وَلَا تَزْنُوا وَقَرَأَ عَلَيْهِمْ الْآيَةَ فَمَنْ وَفَّى مِنْكُمْ{ فَأَجْرُهُ عَلَى اللَّهِ }وَمَنْ أَصَابَ مِنْ ذَلِكَ شَيْئًا فَسَتَرَ اللَّهُ عَلَيْهِ فَهُوَ إِلَى اللَّهِ عَزَّ وَجَلَّ إِنْ شَاءَ عَذَّبَهُ وَإِنْ شَاءَ غَفَرَ لَهُ","id":"Telah mengabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Abu Idris Al Khaulani] dari ['Ubadah bin Ash Shamit], ia berkata; kami pernah bersama Nabi shallallahu 'alaihi wasallam dalam suatu majelis kemudian beliau bersabda: \"Berbai'atlah kepadaku untuk tidak mensekutukan Allah dengan sesuatu, tidak mencuri, dan tidak berzina.\" Kemudian beliau membacakan sebuah ayat. Barang siapa yang memenuhinya diantara kalian maka pahalanya menjadi tanggungan Allah dan barang siapa yang melakukan sesuatu dari hal tersebut kemudian Allah 'azza wajalla menutupinya maka apabila Allah menghendaki maka Allah akan mengampuninya.\""},"3928":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ آدَمَ بْنِ سُلَيْمَانَ عَنْ ابْنِ الْمُبَارَكِ عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّكُمْ سَتَحْرِصُونَ عَلَى الْإِمَارَةِ وَإِنَّهَا سَتَكُونُ نَدَامَةً وَحَسْرَةً فَنِعْمَتِ الْمُرْضِعَةُ وَبِئْسَتْ الْفَاطِمَةُ","id":"Telah mengabarkan kepada kami [Muhammad bin Adam bin Sulaiman] dari [Ibnu Al Mubarak] dari [Ibnu Abi Dzi'b] dari [Sa'id Al Maqri] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya kalian akan bersaing untuk mendapatkan kekuasaan, dan sesungguhnya ia akan penyesalan dan kerugian, maka sungguh nikmat awal kepemimpinan dan sungguh buruk akhir kepemimpinan tersebut.\""},"3929":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا أَبُو نُعَيْمٍ قَالَ حَدَّثَنَا دَاوُدُ بْنُ قَيْسٍ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْعَقِيقَةِ فَقَالَ لَا يُحِبُّ اللَّهُ عَزَّ وَجَلَّ الْعُقُوقَ وَكَأَنَّهُ كَرِهَ الِاسْمَ قَالَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا نَسْأَلُكَ أَحَدُنَا يُولَدُ لَهُ قَالَ مَنْ أَحَبَّ أَنْ يَنْسُكَ عَنْ وَلَدِهِ فَلْيَنْسُكْ عَنْهُ عَنْ الْغُلَامِ شَاتَانِ مُكَافَأَتَانِ وَعَنْ الْجَارِيَةِ شَاةٌقَالَ دَاوُدُ سَأَلْتُ زَيْدَ بْنَ أَسْلَمَ عَنْ الْمُكَافَأَتَانِ قَالَ الشَّاتَانِ الْمُشَبَّهَتَانِ تُذْبَحَانِ جَمِيعًا","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman], ia berkata; telah menceritakan kepada kami [Abu Nu'aim], ia berkata; telah menceritakan kepada kami [Daud bin Qais] dari ['Amr bin Syu'aib] dari [ayahnya] dari [kakeknya], ia berkata; Rasulullah shallallahu 'alaihi wasallam ditanya mengenai aqiqah, kemudian beliau bersabda: \"Sesungguhnya Allah 'azza wajalla membenci sifat durhaka.\" Sepertinya beliau membenci nama tersebut. Orang yang bertanya mengatakan; sesungguhnya kami bertanya kepadamu mengenai seseorang diantara kami terlahirkan anaknya. beliau bersabda: \"Barang siapa yang ingin menyembelih untuk anaknya maka hendaknya ia menyembelih untuknya, untuk anak laki-laki dua kambing dan untuk anak wanita satu kambing.\" Abu Daud berkata; saya bertanya kepada Zaid bin Aslam mengenai kata mukaafa ataani, ia berkata; dua kambing yang sama dan disembelih bersama."},"3930":{"ar":"أَخْبَرَنَا الْحُسَيْنُ بْنُ حُرَيْثٍ قَالَ حَدَّثَنَا الْفَضْلُ عَنْ الْحُسَيْنِ بْنِ وَاقِدٍ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَقَّ عَنْ الْحَسَنِ وَالْحُسَيْنِ","id":"Telah mengabarkan kepada kami [Al Husain bin Huraits], ia berkata; telah menceritakan kepada kami [Al Fadhl] dari [Al Husain bin Waqid] dari [Abdullah bin Buraidah] dari [ayahnya] bahwa Rasulullah shallallahu 'alaihi wasallam melakukan aqiqah untuk Al Hasan dan Al Husain. "},"3931":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا عَفَّانُ قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ قَالَ حَدَّثَنَا أَيُّوبُ وَحَبِيبٌ وَيُونُسُ وَقَتَادَةُ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ سَلْمَانَ بْنِ عَامِرٍ الضَّبِّيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي الْغُلَامِ عَقِيقَةٌ فَأَهْرِيقُوا عَنْهُ دَمًا وَأَمِيطُوا عَنْهُ الْأَذَى","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna], ia berkata; telah menceritakan kepada kami [Affan], ia berkata; telah menceritakan kepada kami [Hammad bin Salamah], ia berkata; telah menceritakan kepada kami [Ayyub] dan [Habib] dan [Yunus] serta [Qatadah] dari [Muhammad bin Sirin] dari [Salman bin 'Amir Adh Dhabbi] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Untuk anak laki-laki terdapat aqiqah maka alirkanlah darah dan hilangkanlah darinya gangguan.\""},"3932":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا عَفَّانُ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ قَيْسِ بْنِ سَعْدٍ عَنْ عَطَاءٍ وَطَاوُسٍ وَمُجَاهِدٍ عَنْ أُمِّ كُرْزٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي الْغُلَامِ شَاتَانِ مُكَافَأَتَانِ وَفِي الْجَارِيَةِ شَاةٌ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman], ia berkata; telah menceritakan kepada kami ['Affan], ia berkata; telah menceritakan kepada kami [Hammad] dari [Qais bin Sa'd] dari ['Atho`] dan [Thawus] serta [Mujahid] dari [Ummi Kurz] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda mengenai aqiqah seorang anak laki-laki: \"Dua ekor kambing yang sama, sedang untuk seorang anak perempuan adalah seekor kambing.\""},"3933":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ قَالَ عَمْرٌو عَنْ عَطَاءٍ عَنْ حَبِيبَةَ بِنْتِ مَيْسَرَةَ عَنْ أُمِّ كُرْزٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ عَنْ الْغُلَامِ شَاتَانِ مُكَافَأَتَانِ وَعَنْ الْجَارِيَةِ شَاةٌ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'id], ia berkata; telah menceritakan kepada kami [Sufyan], ia berkata; ['Amr] berkata dari ['Atho`] dari [Habibah binti Maisarah] dari [Ummu Kurz] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Untuk anak laki-laki dua ekor kambing yang sama, dan untuk anak wanita satu kambing.\""},"3934":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عُبَيْدِ اللَّهِ وَهُوَ ابْنُ أَبِي يَزِيدَ عَنْ سِبَاعِ بْنِ ثَابِتٍ عَنْ أُمِّ كُرْزٍ قَالَتْأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْحُدَيْبِيَةِ أَسْأَلُهُ عَنْ لُحُومِ الْهَدْيِ فَسَمِعْتُهُ يَقُولُ عَلَى الْغُلَامِ شَاتَانِ وَعَلَى الْجَارِيَةِ شَاةٌ لَا يَضُرُّكُمْ ذُكْرَانًا كُنَّ أَمْ إِنَاثًا","id":"Telah mengabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Sufyan] dari ['Ubaidullah yaitu Ibnu Abu Yazid] dari [Siba' bin Tsabit] dari [Ummu Kurz], ia berkata; saya datang kepada Nabi shallallahu 'alaihi wasallam di Hudaibiyah bertanya kepadanya mengenai daging hewan kurban, saya mendengar beliau bersabda: \"Untuk anak laki-laki dua kambing dan anak wanita satu kambing, tidak masalah atas kalian apakah kambing tersebut jantan atau betina.\""},"3935":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا ابْنُ جُرَيْجٍ قَالَ حَدَّثَنِي عُبَيْدُ اللَّهِ بْنُ أَبِي يَزِيدَ عَنْ سِبَاعِ بْنِ ثَابِتٍ عَنْ أُمِّ كُرْزٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ عَنْ الْغُلَامِ شَاتَانِ وَعَنْ الْجَارِيَةِ شَاةٌ لَا يَضُرُّكُمْ ذُكْرَانًا كُنَّ أَمْ إِنَاثًا","id":"Telah mengabarkan kepada kami ['Amr bin Ali], ia berkata; telah menceritakan kepada kami [Yahya], ia berkata; telah menceritakan kepada kami [Ibnu Juraij], ia berkata; telah menceritakan kepadaku ['Ubaidullah bin Abu Yazid] dari [Siba' bin Tsabit] dari [Ummu Kurz] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Untuk anak laki-laki dua kambing dan untuk anak wanita satu kambing, tidak masalah atas kalian apakah kambing tersebut jantan atau betina.\" "},"3936":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ حَفْصِ بْنِ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي أَبِي قَالَ حَدَّثَنِي إِبْرَاهِيمُ هُوَ ابْنُ طَهْمَانَ عَنْ الْحَجَّاجِ بْنِ الْحَجَّاجِ عَنْ قَتَادَةَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَعَقَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْحَسَنِ وَالْحُسَيْنِ رَضِيَ اللَّهُ عَنْهُمَا بِكَبْشَيْنِ كَبْشَيْنِ","id":"Telah mengabarkan kepada kami [Ahmad bin Hafsh bin Abdullah], ia berkata; telah menceritakan kepadaku [ayahku], ia berkata; telah menceritakan kepadaku [Ibrahim yaitu Ibnu Thahman] dari [Al Hajjaj bin Al Hajjaj] dari [Qatadah] dari [Ikrimah] dari [Ibnu Abbas] ia berkata; Rasulullah shallallahu 'alaihi wasallam melakukan aqiqah untuk Al Hasan dan Al Husain radliallahu 'anhuma dengan dua ekor kambing dua ekor kambing."},"3937":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ وَمُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَا حَدَّثَنَا يَزِيدُ وَهُوَ ابْنُ زُرَيْعٍ عَنْ سَعِيدٍ أَنْبَأَنَا قَتَادَةُ عَنْ الْحَسَنِ عَنْ سَمُرَةَ بْنِ جُنْدُبٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كُلُّ غُلَامٍ رَهِينٌ بِعَقِيقَتِهِ تُذْبَحُ عَنْهُ يَوْمَ سَابِعِهِ وَيُحْلَقُ رَأْسُهُ وَيُسَمَّىأَخْبَرَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا قُرَيْشُ بْنُ أَنَسٍ عَنْ حَبِيبِ بْنِ الشَّهِيدِ قَالَ لِي مُحَمَّدُ بْنُ سِيرِينَ سَلْ الْحَسَنَ مِمَّنْ سَمِعَ حَدِيثَهُ فِي الْعَقِيقَةِ فَسَأَلْتُهُ عَنْ ذَلِكَ فَقَالَ سَمِعْتُهُ مِنْ سَمُرَةَ","id":"Telah mengabarkan kepada kami ['Amr bin Ali] dan [Muhammad bin Abdul A'la], mereka berkata; telah menceritakan kepada kami [Yazid yaitu Ibnu Zurai'] dari [Sa'id], telah memberitakan kepada kami [Qatadah] dari [Al Hasan] dari [Samurah bin Jundub] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Setiap anak laki-laki tergadai dengan aqiqahnya, disembelihkan untuknya pada hari ketujuh dan dicukur kepalanya serta diberi nama.\" Telah mengabarkan kepada kami [Harun bin Abdullah], ia berkata; telah menceritakan kepada kami [Quraisy bin Anas] dari [Habib bin Asy Syahid], telah berkata kepadaku Muhammad bin Sirin; tanyakan kepada [Al Hasan] dari manakah ia mendengar haditsnya mengenai aqiqah. Kemudian saya bertanya kepadanya mengenai hal tersebut, lalu ia berkata; saya mendengarnya dari [Samurah]. "},"3938":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ سَعِيدٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا فَرَعَ وَلَا عَتِيرَةَ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim], ia berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Sa'id] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada fara' (anak hewan pertama yang dipersembahkan untuk berhala) dan tidak ada 'atirah (hewan persembahan pada tanggal sepuluh bulan Rajab).\""},"3939":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ حَدَّثْتُ أَبَا إِسْحَقَ عَنْ مَعْمَرٍ وَسُفْيَانَ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَقَالَ أَحَدُهُمَا نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْفَرَعِ وَالْعَتِيرَةِ وَقَالَ الْآخَرُ لَا فَرَعَ وَلَا عَتِيرَةَ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna], ia berkata; telah menceritakan kepada kami [Abu Daud], ia berkata; telah menceritakan kepada kami [Syu'bah], ia berkata; telah menceritakan kepadaku [Abu Ishaq] dari [Ma'mar] dan [Sufyan] dari [Az Zuhri] dari [Sa'id bin Al Musayyab] dari [Abu Hurairah], salah seorang dari mereka berkata; Rasulullah shallallahu 'alaihi wasallam melarang dari fara' (anak hewan pertama yang dipersembahkan untuk berhala) dan 'atirah (hewan persembahan pada tanggal sepuluh bulan Rajab). Sedang yang lain mengatakan; Tidak ada fara' (anak hewan pertama yang dipersembahkan untuk berhala) dan tidak ada 'atirah (hewan persembahan pada tanggal sepuluh bulan Rajab)."},"3940":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ زُرَارَةَ قَالَ حَدَّثَنَا مُعَاذٌ وَهُوَ ابْنُ مُعَاذٍ قَالَ حَدَّثَنَا ابْنُ عَوْنٍ قَالَ حَدَّثَنَا أَبُو رَمْلَةَ قَالَ أَنْبَأَنَا مِخْنَفُ بْنُ سُلَيْمٍ قَالَبَيْنَا نَحْنُ وُقُوفٌ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِعَرَفَةَ فَقَالَ يَا أَيُّهَا النَّاسُ إِنَّ عَلَى أَهْلِ بَيْتٍ فِي كُلِّ عَامٍ أَضْحَاةً وَعَتِيرَةًقَالَ مُعَاذٌ كَانَ ابْنُ عَوْنٍ يَعْتِرُ أَبْصَرَتْهُ عَيْنِي فِي رَجَبٍ","id":"Telah mengabarkan kepada kami ['Amr bin Zurarah], ia berkata; telah menceritakan kepada kami [Mu'adz yaitu Ibnu Mu'adz], ia berkata; telah menceritakan kepada kami [Ibnu 'Aun], ia berkata; telah menceritakan kepada kami [Abu Ramlah], ia berkata; telah memberitakan kepada kami [Mikhnaf bin Sulaim], ia berkata; ketika kami sedang berdiri bersama Nabi shallallahu 'alaihi wasallam di Arafah, beliau bersabda: \"Wahai manusia, sesungguhnya ahli bait pada setiap tahun menyembelih kurban dan sembelihan pada bulan Rajab.\" Mu'adz berkata; Ibnu 'Aun pernah menyembelih pada bulan Rajab dan saya melihat dengan kedua mataku."},"3941":{"ar":"أَخْبَرَنِي إِبْرَاهِيمُ بْنُ يَعْقُوبَ بْنِ إِسْحَقَ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عَبْدِ الْمَجِيدِ أَبُو عَلِيٍّ الْحَنَفِيُّ قَالَ حَدَّثَنَا دَاوُدُ بْنُ قَيْسٍ قَالَ سَمِعْتُ عَمْرَو بْنَ شُعَيْبِ بْنِ مُحَمَّدِ بْنِ عَبْدِ اللَّهِ بْنِ عَمْرٍو عَنْ أَبِيهِ عَنْ أَبِيهِ وَزَيْدِ بْنِ أَسْلَمَ قَالُوايَا رَسُولَ اللَّهِ الْفَرَعَ قَالَ حَقٌّ فَإِنْ تَرَكْتَهُ حَتَّى يَكُونَ بَكْرًا فَتَحْمِلَ عَلَيْهِ فِي سَبِيلِ اللَّهِ أَوْ تُعْطِيَهُ أَرْمَلَةً خَيْرٌ مِنْ أَنْ تَذْبَحَهُ فَيَلْصَقَ لَحْمُهُ بِوَبَرِهِ فَتُكْفِئَ إِنَاءَكَ وَتُولِهُ نَاقَتَكَ قَالُوا يَا رَسُولَ اللَّهِ فَالْعَتِيرَةُ قَالَ الْعَتِيرَةُ حَقٌّقَالَ أَبُو عَبْد الرَّحْمَنِ أَبُو عَلِيٍّ الْحَنَفِيُّ هُمْ أَرْبَعَةُ إِخْوَةٍ أَحَدُهُمْ أَبُو بَكْرٍ وَبِشْرٌ وَشَرِيكٌ وَآخَرُ","id":"Telah mengabarkan kepada kami [Ibrahim bin Ya'qub bin Ishaq], ia berkata; telah menceritakan kepada kami ['Ubaidullah bin Abdul Majid Abu Ali Al Hanafi], ia berkata; telah menceritakan kepada kami [Dawud bin Qais] berkata; saya mendengar [Amr bin Syu'aib bin Muhammad bin Abdullah bin 'Amr] dari [ayahnya] dan [Zaid bin Aslam] mereka berkata; wahai Rasulullah, bagaimana pendapat anda mengenai fara'? beliau bersabda: \"Itu adalah hak, jika engkau membiarkannya hingga menjadi unta remaja, lalu engkau membawanya di jalan Allah atau engkau memberikan kepada seorang janda adalah lebih baik daripada engkau menyembelihnya, lalu dagingnya menempel dengan bulunya dan engkau penuhi bejanamu, serta engkau mengagetkan untamu dengan kematian anaknya, \" mereka berkata; wahai Rasulullah, bagaimana dengan 'athirah? Beliau bersabda: \" 'Athiroh itu adalah hak.\" Abu Abdurrahman Abu Ali Al Hanafi berkata; mereka adalah empat bersaudara salah satunya adalah Abu Bakar, Bisyr, Syarik dan yang lainnya."},"3942":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ يَعْنِي ابْنَ الْمُبَارَكِ عَنْ يَحْيَى وَهُوَ ابْنُ زُرَارَةَ بْنِ كُرَيْمِ بْنِ الْحَارِثِ بْنِ عَمْرٍو الْبَاهِلِيُّ قَالَ سَمِعْتُ أَبِي يَذْكُرُ أَنَّهُ سَمِعَ جَدَّهُ الْحَارِثَ بْنَ عَمْرٍو يُحَدِّثُأَنَّهُ لَقِيَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَجَّةِ الْوَدَاعِ وَهُوَ عَلَى نَاقَتِهِ الْعَضْبَاءِ فَأَتَيْتُهُ مِنْ أَحَدِ شِقَّيْهِ فَقُلْتُ يَا رَسُولَ اللَّهِ بِأَبِي أَنْتَ وَأُمِّي اسْتَغْفِرْ لِي فَقَالَ غَفَرَ اللَّهُ لَكُمْ ثُمَّ أَتَيْتُهُ مِنْ الشِّقِّ الْآخَرِ أَرْجُو أَنْ يَخُصَّنِي دُونَهُمْ فَقُلْتُ يَا رَسُولَ اللَّهِ اسْتَغْفِرْ لِي فَقَالَ بِيَدِهِ غَفَرَ اللَّهُ لَكُمْ فَقَالَ رَجُلٌ مِنْ النَّاسِ يَا رَسُولَ اللَّهِ الْعَتَائِرُ وَالْفَرَائِعُ قَالَ مَنْ شَاءَ عَتَرَ وَمَنْ شَاءَ لَمْ يَعْتِرْ وَمَنْ شَاءَ فَرَّعَ وَمَنْ شَاءَ لَمْ يُفَرِّعْ فِي الْغَنَمِ أُضْحِيَّتُهَا وَقَبَضَ أَصَابِعَهُ إِلَّا وَاحِدَةًأَخْبَرَنِي هَارُونُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا عَفَّانُ قَالَ حَدَّثَنَا يَحْيَى بْنُ زُرَارَةَ السَّهْمِيُّ قَالَ حَدَّثَنِي أَبِي عَنْ جَدِّهِ الْحَارِثِ بْنِ عَمْرٍو ح وَأَنْبَأَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا هِشَامُ بْنُ عَبْدِ الْمَلِكِ قَالَ حَدَّثَنِي يَحْيَى بْنُ زُرَارَةَ السَّهْمِيُّ قَالَ حَدَّثَنِي أَبِي عَنْ جَدِّهِ الْحَارِثِ بْنِ عَمْرٍو أَنَّهُ لَقِيَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَجَّةِ الْوَدَاعِ فَقُلْتُ بِأَبِي أَنْتَ يَا رَسُولَ اللَّهِ وَأُمِّي اسْتَغْفِرْ لِي فَقَالَ غَفَرَ اللَّهُ لَكُمْ وَهُوَ عَلَى نَاقَتِهِ الْعَضْبَاءِ ثُمَّ اسْتَدَرْتُ مِنْ الشِّقِّ الْآخَرِ وَسَاقَ الْحَدِيثَ","id":"Telah mengabarkan kepada kami [Suwaid bin Nahs], ia berkata; telah memberitakan kepada kami [Abdullah yaitu Ibnu Al Mubarak] dari [Yahya yaitu Ibnu Zurarah bin Kuraim bin Al Harits bin 'Amr Al Bahili], ia berkata; saya mendengar [ayahku] menyebutkan bahwa ia mendengar [kakeknya yaitu Al Harits bin 'Amr] menceritakan bahwa ia berjumpa dengan Rasulullah shallallahu 'alaihi wasallam pada saat haji wada' dan beliau berada di atas ontanya yang berwarna Abu- Abu, kemudian saya mendatangi beliau dari salah satu sisi dan berkata; wahai Rasulullah, engkau ditebus dengan ayah dan ibuku, mintakan ampunan untukku. Kemudian beliau bersabda: \" Semoga Allah mengampuni kalian.\" Kemudian saya mendatanginya dari sisi yang lain, berharap beliau mengkhuskan saya tanpa mereka. Saya katakan; wahai Rasulullah, mintakan ampunan untukku. Kemudian beliau bersabda menggunakan tangannya: \" Semoga Allah mengampuni kalian.\" Kemudian seorang laki-laki berkata; wahai Rasulullah, bagaimana dengan 'atirah dan fara'? beliau bersabda: \"Barang siapa yang menginginkan maka ia menyembelih 'atirah dan barang siapa yang menginginkan maka ia tidak menyembelih 'atirah. Dan barang siapa yang menginginkan maka ia menyembelih fara' dan barang siapa yang menginginkan maka ia tidak menyembelih fara'. Dalam kambing terdapat kurbannya.\" Dan beliau mengenggam jari-jarinya kecuali satu. Telah mengabarkan kepadaku [Harun bin Abdullah], ia berkata; telah menceritakan kepadaku [Affan], ia berkata; telah menceritakan kepada kami [Yahya bin Zurarah As Sahmi], ia berkata; telah menceritakan kepadaku [ayahku] dari [kakekku yaitu Al Harits bin 'Amr]. telah menceritakan dan memberitakan kepadaku [Harun bin Abdullah], ia berkata; telah menceritakan kepada kami [Hisyam bin Abdul Malik], ia berkata; telah menceritakan kepadaku [Yahya bin Zurarah As Sahmi], ia berkata; telah menceritakan kepadaku [ayahku] dari [kakekku yaitu Al Harits bin 'Amr] bahwa ia bertemu dengan Rasulullah shallallahu 'alaihi wasallam pada saat haji wada' kemudian berkata; wahai Rasulullah, engkau ditebus dengan ayah dan ibuku, mintakan ampunan untukku. Kemudian beliau bersabda: \" Semoga Allah mengampuni kalian.\" Kemudian saya memutar dari sisi yang lain... kemudian ia menyebutkan hadits tersebut. "},"3943":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ ابْنِ عَوْنٍ قَالَ حَدَّثَنَا جَمِيلٌ عَنْ أَبِي الْمَلِيحِ عَنْ نُبَيْشَةَ قَالَذُكِرَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كُنَّا نَعْتِرُ فِي الْجَاهِلِيَّةِ قَالَ اذْبَحُوا لِلَّهِ عَزَّ وَجَلَّ فِي أَيِّ شَهْرٍ مَا كَانَ وَبَرُّوا اللَّهَ عَزَّ وَجَلَّ وَأَطْعِمُوا","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna], ia berkata; telah menceritakan kepada kami [Ibnu Abu Adi] dari [Ibnu 'Aun], ia berkata; telah menceritakan kepada kami [Jamil] dari [Abu Al Malih] dari [Nubaisyah], ia berkata; disebutkan kepada Nabi shallallahu 'alaihi wasallam... ia berkata; kami menyembelih 'atirah pada masa jahiliyah. Beliau bersabda: \"Sembelihlah untuk Allah 'azza wajalla pada bulan apa saja, berbuat baiklah kepada Allah dan berilah makan kepada orang lain.\" "},"3944":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا بِشْرٌ وَهُوَ ابْنُ الْمُفَضَّلِ عَنْ خَالِدٍ وَرُبَّمَا قَالَ عَنْ أَبِي الْمَلِيحِ وَرُبَّمَا ذَكَرَ أَبَا قِلَابَةَ عَنْ نُبَيْشَةَ قَالَنَادَى رَجُلٌ وَهُوَ بِمِنًى فَقَالَ يَا رَسُولَ اللَّهِ إِنَّا كُنَّا نَعْتِرُ عَتِيرَةً فِي الْجَاهِلِيَّةِ فِي رَجَبٍ فَمَا تَأْمُرُنَا يَا رَسُولَ اللَّهِ قَالَ اذْبَحُوا فِي أَيِّ شَهْرٍ مَا كَانَ وَبَرُّوا اللَّهَ عَزَّ وَجَلَّ وَأَطْعِمُوا قَالَ إِنَّا كُنَّا نُفْرِعُ فَرَعًا فَمَا تَأْمُرُنَا قَالَ فِي كُلِّ سَائِمَةٍ فَرَعٌ تَغْذُوهُ مَاشِيَتُكَ حَتَّى إِذَا اسْتَحْمَلَ ذَبَحْتَهُ وَتَصَدَّقْتَ بِلَحْمِهِ","id":"Telah mengabarkan kepada kami ['Amr bin Ali], ia berkata; telah menceritakan kepada kami [Bisyr yaitu Ibnu Al Mufadhdhal] dari [Khalid], terkadang ia berkata; dari [Abu Al Malih] dan terkadang ia menyebutkan [Abu Qilabah] dari [Nubaisyah], ia berkata; seseorang menyeru di Mina dan berkata; wahai Rasulullah, sesungguhnya dahulu kami menyembelih 'atirah pada masa jahiliyah pada Bulan Rajab. Maka apakah yang anda perintahkan wahai Rasulullah? beliau bersabda: \"Sembelihlah pada bulan apa saja, dan berbuat baiklah kepada Allah 'azza wajalla, dan berilah makan.\" beliau bersabda: \"Dalam setiap saimah (kambing yang berumur lehih dari setahun) terdapat fara', hewan ternakmu memberinya makan hingga apabila telah kuat untuk hamil maka engaku sembelih kambing tersebut dan bersedekah dengan dagingnya.\""},"3945":{"ar":"أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ قَالَ حَدَّثَنَا غُنْدَرٌ عَنْ شُعْبَةَ عَنْ خَالِدٍ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي الْمَلِيحِ وَأَحْسَبُنِي قَدْ سَمِعْتُهُ مِنْ أَبِي الْمَلِيحِ عَنْ نُبَيْشَةَ رَجُلٍ مِنْ هُذَيْلٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنِّي كُنْتُ نَهَيْتُكُمْ عَنْ لُحُومِ الْأَضَاحِيِّ فَوْقَ ثَلَاثٍ كَيْمَا تَسَعَكُمْ فَقَدْ جَاءَ اللَّهُ عَزَّ وَجَلَّ بِالْخَيْرِ فَكُلُوا وَتَصَدَّقُوا وَادَّخِرُوا وَإِنَّ هَذِهِ الْأَيَّامَ أَيَّامُ أَكْلٍ وَشُرْبٍ وَذِكْرِ اللَّهِ عَزَّ وَجَلَّ فَقَالَ رَجُلٌ إِنَّا كُنَّا نَعْتِرُ عَتِيرَةً فِي الْجَاهِلِيَّةِ فِي رَجَبٍ فَمَا تَأْمُرُنَا قَالَ اذْبَحُوا لِلَّهِ عَزَّ وَجَلَّ فِي أَيِّ شَهْرٍ مَا كَانَ وَبَرُّوا اللَّهَ عَزَّ وَجَلَّ وَأَطْعِمُوا فَقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ إِنَّا كُنَّا نُفْرِعُ فَرَعًا فِي الْجَاهِلِيَّةِ فَمَا تَأْمُرُنَا قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي كُلِّ سَائِمَةٍ مِنْ الْغَنَمِ فَرَعٌ تَغْذُوهُ غَنَمُكَ حَتَّى إِذَا اسْتَحْمَلَ ذَبَحْتَهُ وَتَصَدَّقْتَ بِلَحْمِهِ عَلَى ابْنِ السَّبِيلِ فَإِنَّ ذَلِكَ هُوَ خَيْرٌ","id":"Telah mengabarkan kepada kami [Abdullah bin Muhammad Abdurrahman], ia berkata; telah menceritakan kepada kami [Ghundar] dari [Syu'bah] dari [Khalid] dari [Abu Qilabah] dari [Abu Al Malih] dan yakin telah mendengarnya dari Abu Al Malih dari [Nubaisyah] yaitu seorang laki-laki dari Hudzail dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Sesungguhnya saya pernah melarang dari menyimpan daging kurban lebih dari tiga hari, agar boleh bagi kalian maka Allah 'azza wajalla telah datang dengan kebaikan, makan dan bersedekahlah serta simpanlah. Dan sesungguhnya hari-hari ini adalah hari-hari makan dan minum serta berdzikir kepada Allah 'azza wajalla pada bulan apa saja. Berbuatlah baik kepada Allah 'azza wajalla dan berilah makan.\" Kemudian seorang laki-laki berkata; wahai Rasulullah, dahulu kami menyembelih anak hewan yang pertama pada masa jahiliyah, maka apakah yang anda perintahkan kepada kami? Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dalam setiap kambing yang berumur lebih dari satu tahun terdapat anak pertama yang disembelih yang diberi makan oleh kambingmu hingga apabila telah siap untuk hamil maka engkau menyembelihnya dan mensedekahkan dagingnya untuk orang yang diperjalanan, maka hal tersebut adalah lebih baik."},"3946":{"ar":"أَخْبَرَنَا أَبُو الْأَشْعَثِ أَحْمَدُ بْنُ الْمِقْدَامِ قَالَ حَدَّثَنَا يَزِيدُ وَهُوَ ابْنُ زُرَيْعٍ قَالَ أَنْبَأَنَا خَالِدٌ عَنْ أَبِي الْمَلِيحِ عَنْ نُبَيْشَةَ قَالَنَادَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلٌ فَقَالَ إِنَّا كُنَّا نَعْتِرُ عَتِيرَةً يَعْنِي فِي الْجَاهِلِيَّةِ فِي رَجَبٍ فَمَا تَأْمُرُنَا قَالَ اذْبَحُوهَا فِي أَيِّ شَهْرٍ كَانَ وَبَرُّوا اللَّهَ عَزَّ وَجَلَّ وَأَطْعِمُوا قَالَ إِنَّا كُنَّا نُفْرِعُ فَرَعًا فِي الْجَاهِلِيَّةِ قَالَ فِي كُلِّ سَائِمَةٍ فَرَعٌ حَتَّى إِذَا اسْتَحْمَلَ ذَبَحْتَهُ وَتَصَدَّقْتَ بِلَحْمِهِ فَإِنَّ ذَلِكَ هُوَ خَيْرٌ","id":"Telah mengabarkan kepada kami [Abu Al Asy'ats Ahmad bin Al Miqdad], ia berkata; telah menceritakan kepada kami [Yazid yaitu Ibnu Zurai'], ia berkata; telah memberitakan kepada kami [Khalid] dari [Abu Al Malih] dari [Nubaisyah], ia berkata; seorang laki-laki menyeru kepada Nabi shallallahu 'alaihi wasallam kemudian ia berkata; wahai Rasulullah, kami dahulu menyembelih pada sepuluh pertama bulan Rajab pada masa jahiliyah, maka apakah yang anda perintahkan kepada kami? Beliau bersabda: \"Sembelihlah pada bulan apa saja, dan berbuat baiklah kepada Allah 'azza wajalla, serta berilah makan.\" Orang tersebut berkata; sesungguhnya dahulu pada masa jahiliyah kami menyembelih anak hewan yang pertama. Beliau bersabda: \"Pada setiap kambing yang berumur lebih dari satu tahun terdapat anak pertama yang disembelih hingga apabila telah siap untuk hamil engkau menyembelihnya dan bersedekah dengan dagingnya, sesungguhnya hal tersebut adalah lebih baik. "},"3947":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ عَنْ ابْنِ عُلَيَّةَ عَنْ خَالِدٍ قَالَ حَدَّثَنِي أَبُو قِلَابَةَ عَنْ أَبِي الْمَلِيحِ فَلَقِيتُ أَبَا الْمَلِيحِ فَسَأَلْتُهُ فَحَدَّثَنِي عَنْ نُبَيْشَةَ الْهُذَلِيِّ قَالَقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ إِنَّا كُنَّا نَعْتِرُ عَتِيرَةً فِي الْجَاهِلِيَّةِ فَمَا تَأْمُرُنَا قَالَ اذْبَحُوا لِلَّهِ عَزَّ وَجَلَّ فِي أَيِّ شَهْرٍ مَا كَانَ وَبَرُّوا اللَّهَ عَزَّ وَجَلَّ وَأَطْعِمُوا","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim] dari [Ibnu 'Ulayyah] dari [Khalid], ia berkata; telah menceritakan kepadaku [Abu Qilabah] dari [Abu Al Malih] kemudian Saya bertemu dengan Abu Al Malih dan bertanya kepadanya. Kemudian ia menceritakan kepadaku dari [Nusyaibah Al Hudzali], ia berkata; berkata seorang laki-laki; wahai Rasulullah, sesungguhnya kami dahulu menyembelih hewan di awal bulan Rajab pada masa jahiliyah, maka apakah yang anda perintahkan kepada kami? Beliau bersabda: \"Sembelihlah untuk 'azza wajalla pada bulan apa saja dan berbuatlah baik kepada Allah 'azza wajalla, dan berilah makanan. "},"3948":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ يَعْلَى بْنِ عَطَاءٍ عَنْ وَكِيعِ بْنِ عُدُسٍ عَنْ عَمِّهِ أَبِي رَزِينٍ لَقِيطِ بْنِ عَامِرٍ الْعُقَيْلِيِّ قَالَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّا كُنَّا نَذْبَحُ ذَبَائِحَ فِي الْجَاهِلِيَّةِ فِي رَجَبٍ فَنَأْكُلُ وَنُطْعِمُ مَنْ جَاءَنَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا بَأْسَ بِهِقَالَ وَكِيعُ بْنُ عُدُسٍ فَلَا أَدَعُهُ","id":"Telah mengabarkan kepada kami ['Amr bin Ali], ia berkata; telah menceritakan kepada kami [Abdurrahman], ia berkata; telah menceritakan kepada kami [Abu 'Awanah] dari [Ya'la bin 'Atho`] dari [Waki' bin 'Adas] dari pamannya yaitu [Abu Razin Laqith bin 'Amir Al 'Uqali], ia berkata; saya berkata; wahai Rasulullah, sesungguhnya dahulu kami menyembelih sembelihan-sembelihan pada masa jahiliyah di Bulan Rajab, kemudian kami makan dan memberi makan orang yang datang kepada kami. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hal tersebut tidak mengapa.\" Waki' bin 'Adas berkata; saya tidak meninggalkannya. "},"3949":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ عَنْ مَيْمُونَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ عَلَى شَاةٍ مَيِّتَةٍ مُلْقَاةٍ فَقَالَ لِمَنْ هَذِهِ فَقَالُوا لِمَيْمُونَةَ فَقَالَ مَا عَلَيْهَا لَوْ انْتَفَعَتْ بِإِهَابِهَا قَالُوا إِنَّهَا مَيْتَةٌ فَقَالَ إِنَّمَا حَرَّمَ اللَّهُ عَزَّ وَجَلَّ أَكْلَهَا","id":"Telah mengabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari ['Ubaidullah bin Abdullah] dari [Ibnu Abbas] dari [Maimun] bahwa Nabi shallallahu 'alaihi wasallam pernah melewati seekor kambing yang mati yang terbuang, kemudian beliau bersabda: \"Milik siapakah ini?\" mereka berkata; milik Maimunah. Lalu beliau bersabda: \"Tidak ada dosa baginya apabila ia memanfaatkan kulitnya.\" Mereka berkata; sesungguh itu adalah bangkai. Kemudian beliau bersabda: \"Sesungguhnya Allah 'azza wajalla hanya mengharamkan untuk memakannya.\""},"3950":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ وَاللَّفْظُ لَهُ عَنْ ابْنِ الْقَاسِمِ قَالَ حَدَّثَنِي مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ قَالَمَرَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِشَاةٍ مَيِّتَةٍ كَانَ أَعْطَاهَا مَوْلَاةً لِمَيْمُونَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ هَلَّا انْتَفَعْتُمْ بِجِلْدِهَا قَالُوا يَا رَسُولَ اللَّهِ إِنَّهَا مَيْتَةٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا حُرِّمَ أَكْلُهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dan [Al Harits bin Miskin] dengan membacakan riwayat dan saya mendengar, lafazhnya adalah lafazh Al Harits, dari [Ibnu Al Qasim], ia berkata; telah menceritakan kepadaku [Malik] dari [Ibnu Syihab] dari ['Ubaidullah bin Abdullah] dari [Ibnu Abbas], ia berkata; Rasulullah shallallahu 'alaihi wasallam melewati seekor kambing yang telah mati, yang dahulunya beliau berikan kepada maula Maimunah isteri Nabi shallallahu 'alaihi wasallam. Kemudian beliau bersabda: \"Tidakkah kalian memanfaatkan kulitnya? Mereka berkata; wahai Rasulullah, itu adalah bangkai. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya yang diharamkan hanya memakannya.\""},"3951":{"ar":"أَخْبَرَنِي عَبْدُ الرَّحْمَنِ بْنُ خَالِدٍ الْقَطَّانُ الرَّقِّيُّ قَالَ حَدَّثَنَا حَجَّاجٌ قَالَ قَالَ ابْنُ جُرَيْجٍ أَخْبَرَنِي عَمْرُو بْنُ دِينَارٍ قَالَ أَخْبَرَنِي عَطَاءٌ مُنْذُ حِينٍ عَنْ ابْنِ عَبَّاسٍ أَخْبَرَتْنِي مَيْمُونَةُأَنَّ شَاةً مَاتَتْ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَّا دَفَعْتُمْ إِهَابَهَا فَاسْتَمْتَعْتُمْ بِهِ","id":"Telah mengabarkan kepada kami [Abdurrahman bin Khalid Al Qaththan Ar Raqqi], ia berkata; telah menceritakan kepada kami [Hajjaj], ia berkata; telah berkata; [Ibnu Juraij] telah mengabarkan kepadaku ['Amr bin Dinar], ia berkata; telah memberitakan kepadaku ['Atho`] sejak beberapa saat dari [Ibnu Abbas] telah mengabarkan kepadaku [Maimunah] bahwa terdapat sesekor kambing mati, kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Tidaklah kalian berikan kulitnya kemudian kalian menikmatinya? "},"3952":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ عَنْ سُفْيَانَ عَنْ عَمْرٍو عَنْ عَطَاءٍ قَالَ سَمِعْتُ ابْنَ عَبَّاسٍ قَالَمَرَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِشَاةٍ لِمَيْمُونَةَ مَيِّتَةٍ فَقَالَ أَلَّا أَخَذْتُمْ إِهَابَهَا فَدَبَغْتُمْ فَانْتَفَعْتُمْ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur] dari [Sufyan] dari ['Amr] dari ['Atho`], ia berkata; saya mendengar [Ibnu Abbas] berkata; Nabi shallallahu 'alaihi wasallam melewati seekor kambing milik Maimunah yang telah mati, kemudian beliau bersabda: \"Tidakkah kalian ambil kulitnya, kemudian kalian samak dan kalian manfaatkan?\""},"3953":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْعَزِيزِ بْنِ أَبِي رِزْمَةَ قَالَ أَنْبَأَنَا الْفَضْلُ بْنُ مُوسَى عَنْ إِسْمَعِيلَ بْنِ أَبِي خَالِدٍ عَنْ الشَّعْبِيِّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ عَنْ سَوْدَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْمَاتَتْ شَاةٌ لَنَا فَدَبَغْنَا مَسْكَهَا فَمَا زِلْنَا نَنْبِذُ فِيهَا حَتَّى صَارَتْ شَنًّا","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul Aziz bin Abu Rizmah], ia berkata; telah memberitakan kepada kami [Al Fadhl bin Musa] dari [Isma'il bin Abu Khalid] dari [Asy Sya'bi] dari [Ikrimah] dari [Ibnu Abbas] dari [Saudah] isteri Nabi shallallahu 'alaihi wasallam, ia berkata; kambing kami telah mati kemudian kami menyamak kulitnya dan kami masih terus membuat rendaman anggur padanya hingga menjadi geriba yang basah."},"3954":{"ar":"أَخْبَرَنَا قُتَيْبَةُ وَعَلِيُّ بْنُ حُجْرٍ عَنْ سُفْيَانَ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ ابْنِ وَعْلَةَ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّمَا إِهَابٍ دُبِغَ فَقَدْ طَهُرَ","id":"Telah mengabarkan kepada kami [Qutaibah] dan [Ali bin Hujr] dari [Sufyan] dari [Zaid bin Aslam] dari [Ibnu Wa'lah] dari [Ibnu Abbas], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kulit apapun apabila telah disamak maka telah menjadi suci.\""},"3955":{"ar":"أَخْبَرَنِي الرَّبِيعُ بْنُ سُلَيْمَانَ بْنِ دَاوُدَ قَالَ حَدَّثَنَا إِسْحَقُ بْنُ بَكْرٍ وَهُوَ ابْنُ مُضَرَ قَالَ حَدَّثَنِي أَبِي عَنْ جَعْفَرِ بْنِ رَبِيعَةَ أَنَّهُ سَمِعَ أَبَا الْخَيْرِ عَنْ ابْنِ وَعْلَةَ أَنَّهُ سَأَلَ ابْنَ عَبَّاسٍ فَقَالَإِنَّا نَغْزُو هَذَا الْمَغْرِبَ وَإِنَّهُمْ أَهْلُ وَثَنٍ وَلَهُمْ قِرَبٌ يَكُونُ فِيهَا اللَّبَنُ وَالْمَاءُ فَقَالَ ابْنُ عَبَّاسٍ الدِّبَاغُ طَهُورٌ قَالَ ابْنُ وَعْلَةَ عَنْ رَأْيِكَ أَوْ شَيْءٌ سَمِعْتَهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بَلْ عَنْ رَسُولِ اللَّهِ","id":"Telah mengabarkan kepada kami [Ar Rabi' bin Sulaiman bin Daud], ia berkata; telah menceritakan kepada kami [Ishaq bin Bakr yaitu Ibnu Mudhar], ia berkata; telah menceritakan kepadaku [ayahku] dari [Ja'far bin Rabi'ah] bahwa ia mendengar [Abu Al Khair] dari [Ibnu Wa'lah] bahwa ia bertanya kepada [Ibnu Abbas], ia berkata; Sesungguhnya kami memerangi Negeri Maghrib ini dan mereka adalah para penyembah berhala, dan mereka memiliki beberapa geriba yang berisi susu dan air. Kemudian Ibnu Abbas berkata; samak mensucikan. Ibnu Wa'lah berkata; apakah itu berasal dari pendapatmu atau sesuatu yang engkau dengar dari Rasulullah shallallahu 'alaihi wasallam? Ibnu Abbas berkata; melainkan dari Rasulullah shallallahu 'alaihi wasallam. "},"3956":{"ar":"أَخْبَرَنَا الْحُسَيْنُ بْنُ مَنْصُورِ بْنِ جَعْفَرٍ النَّيْسَابُورِيُّ قَالَ حَدَّثَنَا الْحُسَيْنُ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا شَرِيكٌ عَنْ الْأَعْمَشِ عَنْ عُمَارَةَ بْنِ عُمَيْرٍ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْسُئِلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ جُلُودِ الْمَيْتَةِ فَقَالَ دِبَاغُهَا طَهُورُهَا","id":"Telah mengabarkan kepada kami [Al Husain bin Manshur bin Ja'far An Naisaburi], ia berkata; telah menceritakan kepada kami [Al Husain bin Muhammad], ia berkata; telah menceritakan kepada kami [Syarik] dari [Al A'masy] dari ['Umarah bin 'Umair] dari [Al Aswad] dari [Aisyah], ia berkata; Nabi shallallahu 'alaihi wasallam ditanya mengenai kulit binatang yang telah mati. Kemudian beliau bersabda: \"Penyamakannya adalah pensuciannya.\""},"3957":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعْدِ بْنِ إِبْرَاهِيمَ بْنِ سَعْدٍ قَالَ حَدَّثَنَا عَمِّي قَالَ حَدَّثَنَا شَرِيكٌ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ جُلُودِ الْمَيْتَةِ فَقَالَ دِبَاغُهَا ذَكَاتُهَا","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'd bin Ibrahim bin Sa'd], ia berkata; telah menceritakan kepada kami [pamanku], ia berkata; telah menceritakan kepada kami [Syarik] dari [Al A'masy] dari [Ibrahim] dari [Al Aswad] dari [Aisyah], ia berkata; Rasulullah shallallahu 'alaihi wasallam ditanya mengenai kult bangkai. Kemudian beliau bersabda: \"Penyamakannya adalah pensuciannya.\""},"3958":{"ar":"أَخْبَرَنِي إِبْرَاهِيمُ بْنُ يَعْقُوبَ قَالَ حَدَّثَنَا مَالِكُ بْنُ إِسْمَعِيلَ قَالَ حَدَّثَنَا إِسْرَائِيلُ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَكَاةُ الْمَيْتَةِ دِبَاغُهَا","id":"Telah mengabarkan kepadaku [Ibrahim bin Ya'qub], ia berkata; telah menceritakan kepada kami [Malik bin Isma'il], ia berkata; telah menceritakan kepada kami [Israil] dari [Al A'masy] dari [Ibrahim] dari [Al Aswad] dari [Aisyah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Penyembelihan bangkai adalah penyemakannya.\" "},"3959":{"ar":"أَخْبَرَنَا سُلَيْمَانُ بْنُ دَاوُدَ عَنْ ابْنِ وَهْبٍ قَالَ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ وَاللَّيْثُ بْنُ سَعْدٍ عَنْ كَثِيرِ بْنِ فَرْقَدٍ أَنَّ عَبْدَ اللَّهِ بْنَ مَالِكِ بْنِ حُذَافَةَ حَدَّثَهُ عَنْ الْعَالِيَةِ بِنْتِ سُبَيْعٍ أَنَّ مَيْمُونَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدَّثَتْهَاأَنَّهُ مَرَّ بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رِجَالٌ مِنْ قُرَيْشٍ يَجُرُّونَ شَاةً لَهُمْ مِثْلَ الْحِصَانِ فَقَالَ لَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ أَخَذْتُمْ إِهَابَهَا قَالُوا إِنَّهَا مَيْتَةٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُطَهِّرُهَا الْمَاءُ وَالْقَرَظُ","id":"Telah mengabarkan kepada kami [Sulaiman bin Daud] dari [Ibnu Wahb], ia berkata; telah mengabarkan kepadaku ['Amr bin Al Harits] dan [Al Laits bin Sa'd] dari [Katsir bin Farqad] bahwa [Abdullah bin Malik bin Hudzafah] telah menceritakan kepadanya dari [Al 'Aliyah binti Subai'] bahwa [Maimunah] istri Nabi shallallahu 'alaihi wasallam telah menceritakan kepadanya bahwa orang-orang Quraisy lewat didepan Rasulullah shallallahu 'alaihi wasallam dengan menyeret kambing mereka yang seperti kuda, lalu Rasulullah shallallahu 'alaihi wasallam bersabda kepada mereka: \"Andai saja kalian mengambil kulitnya.\" Mereka berkata; wahai Rasulullah, sungguh itu adalah bangkai, lalu Rasulullah shallallahu alaihi wa sallam bersabda: \"Air dan daun akasia akan mensucikannya.\" "},"3960":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا بِشْرٌ يَعْنِي ابْنَ الْمُفَضَّلِ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ عَنْ ابْنِ أَبِي لَيْلَى عَنْ عَبْدِ اللَّهِ بْنِ عُكَيْمٍ قَالَقُرِئَ عَلَيْنَا كِتَابُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا غُلَامٌ شَابٌّ أَنْ لَا تَنْتَفِعُوا مِنْ الْمَيْتَةِ بِإِهَابٍ وَلَا عَصَبٍ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud], ia berkata; telah menceritakan kepada kami [Bisyr yaitu Ibnu Al Mufadhdhal], ia berkata; telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] dari [Ibnu Abu Laila] dari [Abdullah bin 'Ukaim], ia berkata; telah dibacakan kepada kami surat Rasulullah shallallahu 'alaihi wasallam sedang saya adalah seorang pemuda: \"Janganlah kalian memanfaatkan dari bangkai baik kulit yang belum disamak ataupun uratnya.\""},"3961":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ قُدَامَةَ قَالَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ الْحَكَمِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ عَبْدِ اللَّهِ بْنِ عُكَيْمٍ قَالَكَتَبَ إِلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ لَا تَسْتَمْتِعُوا مِنْ الْمَيْتَةِ بِإِهَابٍ وَلَا عَصَبٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Qudamah], ia berkata; telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Al Hakam] dari [Abdurrahman bin Abu Laila] dari [Abdullah bin 'Ukaim], ia berkata; Rasulullah shallallahu 'alaihi wasallam menulis surat kepada kami: \"\"Janganlah kalian menikmati dari bangkai baik kulit yang belum disamak ataupun uratnya.\""},"3962":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ حَدَّثَنَا شَرِيكٌ عَنْ هِلَالٍ الْوَزَّانِ عَنْ عَبْدِ اللَّهِ بْنِ عُكَيْمٍ قَالَكَتَبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى جُهَيْنَةَ أَنْ لَا تَنْتَفِعُوا مِنْ الْمَيْتَةِ بِإِهَابٍ وَلَا عَصَبٍقَالَ أَبُو عَبْد الرَّحْمَنِ أَصَحُّ مَا فِي هَذَا الْبَابِ فِي جُلُودِ الْمَيْتَةِ إِذَا دُبِغَتْ حَدِيثُ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ عَنْ مَيْمُونَةَ وَاللَّهُ تَعَالَى أَعْلَمُ","id":"Telah mengabarkan kepada kami [Ali bin Hujr], ia berkata; telah menceritakan kepada kami [Syarik] dari [Hilal Al Wazzan] dari [Abdullah bin 'Ukaim], ia berkata; Rasulullah shallallahu 'alaihi wasallam menulis surat kepada penduduk Juhainah: \"Janganlah kalian memanfaatkan dari bangkai baik kulit baik kulit yang belum disamak ataupun uratnya.\" Abdurrahman berkata; yang paling shahih dalam bab ini mengenai kulit bangkai yang telah disamak adalah hadits Az Zuhri dari 'Ubaidullah bin Abdullah dari Ibnu Abbas dari Maimunah. Wallahu a'lam. "},"3963":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا بِشْرُ بْنُ عُمَرَ قَالَ حَدَّثَنَا مَالِكٌ ح وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ ابْنِ الْقَ��سِمِ قَالَ حَدَّثَنِي مَالِكٌ عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ بْنِ قُسَيْطٍ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ ثَوْبَانَ عَنْ أُمِّهِ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ أَنْ يُسْتَمْتَعَ بِجُلُودِ الْمَيْتَةِ إِذَا دُبِغَتْ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim], ia berkata; telah memberitakan kepada kami [Bisyr bin Umar], ia berkata; telah menceritakan kepada kami [Malik] dan [Harits bin Miskin] dengan membacakan riwayat dan saya mendengar dari [Ibnu Al Qasim], ia berkata; telah menceritakan kepadaku [Malik] dari [Yazid bin Abdullah bin Qusaith] dari [Muhammad bin Abdurrahman bin Tsauban] dari [ibunya] dari [Aisyah] bahwa Rasulullah shallallahu 'alaihi wasallam memerintahkan agar kulit bangkai dinikmati apabila telah disamak."},"3964":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ عَنْ يَحْيَى عَنْ ابْنِ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ أَبِي الْمَلِيحِ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ جُلُودِ السِّبَاعِ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'id] dari [Yahya] dari [Ibnu Abu 'Arubah] dari [Qatadah] dari [Abu Al Malih] dari [ayahnya] bahwa Nabi shallallahu 'alaihi wasallam melarang dari kulit binatang buas."},"3965":{"ar":"أَخْبَرَنِي عَمْرُو بْنُ عُثْمَانَ قَالَ حَدَّثَنَا بَقِيَّةُ عَنْ بَحِيرٍ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ الْمِقْدَامِ بْنِ مَعْدِيكَرِبَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْحَرِيرِ وَالذَّهَبِ وَمَيَاثِرِ النُّمُورِ","id":"Telah mengabarkan kepada kami ['Amr bin Utsman], ia berkata; telah menceritakan kepada kami [Baqiyah] dari [Bahir] dari [Khalid bin Ma'dan] dari [Al Miqdam bin Ma'dikarib], ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang dari sutra, emas, dan menghamparkan kulit harimau untuk duduk."},"3966":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عُثْمَانَ قَالَ حَدَّثَنَا بَقِيَّةُ عَنْ بَحِيرٍ عَنْ خَالِدٍ قَالَ وَفَدَ الْمِقْدَامُ بْنُ مَعْدِيكَرِبَ عَلَى مُعَاوِيَةَ فَقَالَ لَهُأَنْشُدُكَ بِاللَّهِ هَلْ تَعْلَمُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ لُبُوسِ جُلُودِ السِّبَاعِ وَالرُّكُوبِ عَلَيْهَا قَالَ نَعَمْ","id":"Telah mengabarkan kepada kami ['Amr bin Utsman], ia berkata; telah menceritakan kepada kami [Baqiyah] dari [Bahir] dari [Khalid], ia berkata; [Al Miqdam bin Ma'dikarib] datang kepada [Mu'awiyah] sebagai utusan kemudian berkata; saya bersumpah kepada Allah dan bertanya kepadamu, apakah engkau mengetahui bahwa Rasulullah shallallahu 'alaihi wasallam melarang memakai kulit binatang buas dan menaikinya? Ia berkata; ya."},"3967":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ عَطَاءِ بْنِ أَبِي رَبَاحٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَامَ الْفَتْحِ وَهُوَ بِمَكَّةَ يَقُولُ إِنَّ اللَّهَ عَزَّ وَجَلَّ وَرَسُولَهُ حَرَّمَ بَيْعَ الْخَمْرِ وَالْمَيْتَةِ وَالْخِنْزِيرِ وَالْأَصْنَامِ فَقِيلَ يَا رَسُولَ اللَّهِ أَرَأَيْتَ شُحُومَ الْمَيْتَةِ فَإِنَّهُ يُطْلَى بِهَا السُّفُنُ وَيُدَّهَنُ بِهَا الْجُلُودُ وَيَسْتَصْبِحُ بِهَا النَّاسُ فَقَالَ لَا هُوَ حَرَامٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَ ذَلِكَ قَاتَلَ اللَّهُ الْيَهُودَ إِنَّ اللَّهَ عَزَّ وَجَلَّ لَمَّا حَرَّمَ عَلَيْهِمْ الشُّحُومَ جَمَّلُوهُ ثُمَّ بَاعُوهُ فَأَكَلُوا ثَمَنَهُ","id":"Telah mengabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Al Laits] dari [Yazid bin Abu Habib] dari ['Atho` bin Abu Rabah] dari [Jabir bin Abdullah] bahwa ia mendengar Rasulullah shallallahu 'alaihi wasallam pada tahun penaklukan Mekkah dan ia berada di Mekkah, beliau bersabda: \"Sesungguhnya Allah 'azza wajalla dan rasulNya telah mengharamkan menjual minuman keras, bangkai, babi, serta berhala.\" Kemudian beliau ditanya; wahai Rasulullah, bagaimana pendapatmu mengenai lemak bangkai, sesungguhnya lemak tersebut dapat digunakan untuk mengecat kapal, dan maminyaki kulit serta digunakan orang untuk penerangan. Maka beliau bersabda: \"Tidak, itu adalah haram.\" Pada saat itu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Semoga Allah memerangi orang-orang Yahudi, sesungguhnya Allah 'azza wajalla tatkala mengharamkan lemak atas mereka maka mereka mencairkannya kemudian menjualnya dan memakan harganya.\""},"3968":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا سُفْيَانُ عَنْ عَمْرٍو عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ قَالَأُبْلِغَ عُمَرُ أَنَّ سَمُرَةَ بَاعَ خَمْرًا قَالَ قَاتَلَ اللَّهُ سَمُرَةَ أَلَمْ يَعْلَمْ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قَاتَلَ اللَّهُ الْيَهُودَ حُرِّمَتْ عَلَيْهِمْ الشُّحُومُ فَجَمَّلُوهَاقَالَ سُفْيَانُ يَعْنِي أَذَابُوهَا","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim], ia berkata; telah memberitakan kepada kami [Sufyan] dari ['Amr] dari [Thawus] dari [Ibnu Abbas], ia berkata; telah disampaikan kepada [Umar] bahwa Samurah telah menjual minuman keras, maka ia berkata; semoga Allah memerangi Samurah. Tidakkah ia mengetahui bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Semoga Allah memerangi orang-orang yahudi, telah diharamkan lemak atas mereka kemudian mereka mencairkannya.\" Sufyan berkata; yaitu mencairkannya."},"3969":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ عَنْ مَيْمُونَةَأَنَّ فَأْرَةً وَقَعَتْ فِي سَمْنٍ فَمَاتَتْ فَسُئِلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَلْقُوهَا وَمَا حَوْلَهَا وَكُلُوهُ","id":"Telah mengabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari ['Ubaidullah bin Abdullah] dari [Ibnu Abbas] dari [Maimunah] bahwa seekor tikus terjatuh di dalam mentega kemudian mati. Kemudian Nabi shallallahu 'alaihi wasallam ditanya mengenai hal tersebut, lalu beliau bersabda: \"Buanglah tikus tersebut dan yang ada di sekitarnya dan makanlah mentega tersebut.\""},"3970":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ الدَّوْرَقِيُّ وَمُحَمَّدُ بْنُ يَحْيَى بْنِ عَبْدِ اللَّهِ النَّيْسَابُورِيُّ عَنْ عَبْدِ الرَّحْمَنِ عَنْ مَالِكٍ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ عَنْ مَيْمُونَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُئِلَ عَنْ فَأْرَةٍ وَقَعَتْ فِي سَمْنٍ جَامِدٍ فَقَالَ خُذُوهَا وَمَا حَوْلَهَا فَأَلْقُوهُ","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim Ad Duraqi] dan [Muhammad bin Yahya bin Abdullah An Naisaburi] dari [Abdurrahman] dari [Malik] dari [Az Zuhri] dari ['Ubaidullah bin Abdullah] dari [Ibnu Abbas] dari [Maimunah] bahwa Nabi shallallahu 'alaihi wasallam ditanya mengenai tikus yang jatuh di dalam mentega, maka beliau bersabda: \"Ambillah tikus tersebut dan yang ada di sekitarnya kemudian buanglah.\" "},"3971":{"ar":"أَخْبَرَنَا خُشَيْشُ بْنُ أَصْرَمَ قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَخْبَرَنِي عَبْدُ الرَّحْمَنِ بْنُ بُوذُوَيْهِ أَنَّ مَعْمَرًا ذَكَرَهُ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ عَنْ مَيْمُونَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ سُئِلَ عَنْ الْفَأْرَةِ تَقَعُ فِي السَّمْنِ فَقَالَ إِنْ كَانَ جَامِدًا فَأَلْقُوهَا وَمَا حَوْلَهَا وَإِنْ كَانَ مَائِعًا فَلَا تَقْرَبُوهُ","id":"Telah mengabarkan kepada kami [Khusyaisy bin Ashram], ia berkata; telah menceritakan kepada kami [Abdur Razzaq], ia berkata; telah memberitakan kepadaku [Abdurrahman bin Budzuwaih] bahwa [Ma'mar] menyebutkannya dari [Az Zuhri] dari ['Ubaidullah bin Abdullah] dari [Ibnu Abbas] dari [Maimunah] dari Nabi shallallahu 'alaihi wasallam bahwa beliau ditanya mengenai tikus yang jatuh di dalam mentega, maka beliau bersabda: 'Apabila mentega itu beku maka buanglah tikus tersebut dan yang ada disekitarnya dan apabila mentega itu cair maka janganlah kalian mendekatinya.\""},"3972":{"ar":"أَخْبَرَنَا سَلَمَةُ بْنُ أَحْمَدَ بْنِ سُلَيْمِ بْنِ عُثْمَانَ الْفَوْزِيُّ قَالَ حَدَّثَنَا جَدِّي الْخَطَّابُ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ حِمْيَرَ قَالَ حَدَّثَنَا ثَابِثُ بْنُ عَجْلَانَ قَالَ سَمِعْتُ سَعِيدَ بْنَ جُبَيْرٍ يَقُولُ سَمِعْتُ ابْنَ عَبَّاسٍ يَقُولُإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ بِعَنْزٍ مَيِّتَةٍ فَقَالَ مَا كَانَ عَلَى أَهْلِ هَذِهِ الشَّاةِ لَوْ انْتَفَعُوا بِإِهَابِهَا","id":"Telah mengabarkan kepada kami [Salamah bin Ahmad bin Sulaim bin Utsman Al Fauzi], ia berkata; telah menceritakan kepada kami [kakekku yaitu Al Khathab], ia berkata; telah menceritakan kepada kami [Muhammad bin Humair], ia berkata; telah menceritakan kepada kami [Tsabit bin 'Ajlan], ia berkata; saya mendengar [Sa'id bin Jubair] berkata; saya mendengar [Ibnu Abbas] berkata; sesungguhnya Rasulullah shallallahu 'alaihi wasallam pernah melewati kambing betina yang telah mati, kemudian beliau bersabda: \"Tidak berdosa atas pemilik kambing ini seandainya mereka memanfaatkan kulitnya.\""},"3973":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ قَالَ حَدَّثَنِي سَعِيدُ بْنُ خَالِدٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا وَقَعَ الذُّبَابُ فِي إِنَاءِ أَحَدِكُمْ فَلْيَمْقُلْهُ","id":"Telah mengabarkan kepada kami ['Amr bin Ali], ia berkata; telah menceritakan kepada kami [Yahya], ia berkata; telah menceritakan kepada kami [Ibnu Abu Dzi`b], ia berkata; telah menceritakan kepadaku [Sa'id bin Khalid] dari [Abu Salamah] dari [Abu Sa'id Al Khudri] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Apabila seekor lalat jatuh dalam bejana salah seorang diantara kalian maka hendaknya ia membenamkannya ke dalam air.\" "},"3974":{"ar":"أَخْبَرَنَا الْإِمَامُ أَبُو عَبْدِ الرَّحْمَنِ النَّسَائِيُّ بِمِصْرَ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ سُوَيْدِ بْنِ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ عَاصِمٍ عَنْ الشَّعْبِيِّ عَنْ عَدِيِّ بْنِ حَاتِمٍأَنَّهُ سَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الصَّيْدِ فَقَالَ إِذَا أَرْسَلْتَ كَلْبَكَ فَاذْكُرْ اسْمَ اللَّهِ عَلَيْهِ فَإِنْ أَدْرَكْتَهُ لَمْ يَقْتُلْ فَاذْبَحْ وَاذْكُرْ اسْمَ اللَّهِ عَلَيْهِ وَإِنْ أَدْرَكْتَهُ قَدْ قَتَلَ وَلَمْ يَأْكُلْ فَكُلْ فَقَدْ أَمْسَكَهُ عَلَيْكَ فَإِنْ وَجَدْتَهُ قَدْ أَكَلَ مِنْهُ فَلَا تَطْعَمْ مِنْهُ شَيْئًا فَإِنَّمَا أَمْسَكَ عَلَى نَفْسِهِ وَإِنْ خَالَطَ كَلْبُكَ كِلَابًا فَقَتَلْنَ فَلَمْ يَأْكُلْنَ فَلَا تَأْكُلْ مِنْهُ شَيْئًا فَإِنَّكَ لَا تَدْرِي أَيُّهَا قَتَلَ","id":"Telah mengabarkan kepada kami Imam Abu Abdurrahman An Nasai di Mesir dengan membacakan riwayat dan saya mendengar, dari [Suwaid bin Nashr], ia berkata; telah memberitakan kepada kami [Abdullah bin Al Mubarak] dari ['Ashim] dari [Asy Sya'bi] dari ['Adi bin Hatim] bahwa ia bertanya kepada Rasulullah shallallahu 'alaihi wasallam mengenai hewan buruan maka beliau bersabda: 'Apabila engkau melepaskan anjingmu maka sebutlah nama Allah padanya, kemudian apabila engkau mendapatinya belum membunuh maka sembelihlah dan sebutlah nama Allah padanya. Namun apabila ia telah membunuh dan belum memakan buruan maka makanlah sungguh ia telah menangkap untukmu. Apabila engkau mendapatinya telah memakan sebagiannya maka janganlah engkau memakan sedikitpun dari buruan tersebut, karena sesungguhnya anjing tersebut menangkap untuk dirinya sendiri. Dan apabila anjingmu bercampur dengan anjing- anjing yang lain kemudian membunuh buruan dan anjing- anjing tersebut tidak makan sesuatupun darinya maka sesungguhnya engkau tidak mengetahui anjing yang manakah yang membunuh.\""},"3975":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ عَنْ زَكَرِيَّا عَنْ الشَّعْبِيِّ عَنْ عَدِيِّ بْنِ حَاتِمٍ قَالَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ صَيْدِ الْمِعْرَاضِ فَقَالَ مَا أَصَبْتَ بِحَدِّهِ فَكُلْ وَمَا أَصَبْتَ ��ِعَرْضِهِ فَهُوَ وَقِيذٌ وَسَأَلْتُهُ عَنْ الْكَلْبِ فَقَالَ إِذَا أَرْسَلْتَ كَلْبَكَ فَأَخَذَ وَلَمْ يَأْكُلْ فَكُلْ فَإِنَّ أَخْذَهُ ذَكَاتُهُ وَإِنْ كَانَ مَعَ كَلْبِكَ كَلْبٌ آخَرُ فَخَشِيتَ أَنْ يَكُونَ أَخَذَ مَعَهُ فَقَتَلَ فَلَا تَأْكُلْ فَإِنَّكَ إِنَّمَا سَمَّيْتَ عَلَى كَلْبِكَ وَلَمْ تُسَمِّ عَلَى غَيْرِهِ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr], ia berkata; telah menceritakan kepada kami [Abdullah] dari [Zakariya] dari [Asy Sya'bi] dari [Adi bin Hatim], ia berkata; saya bertanya kepada Rasulullah shallallahu 'alaihi wasallam mengenai hewan buruan dengan anak panah tanpa mata panah, maka beliau bersabda: \"Apa yang engkau kenai dengan bagian yang tajam maka makanlah dan apa yang engkau kenai dengan bagian yang tumpul maka itu adalah hewan yang mati karena terkena benda tumpul.\" Dan saya bertanya kepada beliau mengenai anjing, maka beliau bersabda: \"Apabila engkau melepaskan anjingmu kemudian ia menangkap dan tidak memakannya maka makanlah karena sesungguhnya tangkapannya adalah penyembelihannya, apabila terdapat anjing lain bersama dengan anjingmu kemudian kamu khawatir anjing tersebut menangkap bersamanya dan membunuh buruan tersebut maka janganlah engkau memakannya karena sesunggunya engkau hanya menyebutkan nama Allah pada anjingmu dan tidak menyebutkan nama Allah pada anjing yang lain.\""},"3976":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا أَبُو عَبْدِ الصَّمَدِ عَبْدُ الْعَزِيزِ بْنُ عَبْدِ الصَّمَدِ قَالَ حَدَّثَنَا مَنْصُورٌ عَنْ إِبْرَاهِيمَ عَنْ هَمَّامِ بْنِ الْحَارِثِ عَنْ عَدِيِّ بْنِ حَاتِمٍأَنَّهُ سَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أُرْسِلُ الْكَلْبَ الْمُعَلَّمَ فَيَأْخُذُ فَقَالَ إِذَا أَرْسَلْتَ الْكَلْبَ الْمُعَلَّمَ وَذَكَرْتَ اسْمَ اللَّهِ عَلَيْهِ فَأَخَذَ فَكُلْ قُلْتُ وَإِنْ قَتَلَ قَالَ وَإِنْ قَتَلَ قُلْتُ أَرْمِي بِالْمِعْرَاضِ قَالَ إِذَا أَصَابَ بِحَدِّهِ فَكُلْ وَإِذَا أَصَابَ بِعَرْضِهِ فَلَا تَأْكُلْ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud], ia berkata; telah menceritakan kepada kami [Abu Abdush Shamad Abdul 'Aziz bin Abdush Shamad], ia berkata; telah menceritakan kepada kami [Manshur] dari [Ibrahim] dari [Hammam bin Al Harits] dari [Adi bin Hatim] bahwa ia bertanya kepada Rasulullah shallallahu 'alaihi wasallam, ia berkata; saya mengirimkan anjing yang telah dilatih kemudian ia menangkap buruan. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila engkau mengirim anjing yang telah dilatih dan telah engkau sebutkan nama Allah padanya kemudian ia menangkap buruan maka makanlah.\" Saya katakan; walaupun ia telah membunuh buruan? Beliau bersabda: \"walaupun ia telah membunuhnya.\" Saya katakan; Apakah saya boleh memanah dengan anak panah yang tumpul? Beliau bersabda: \"Apabila ia mengenai dengannya bagian tajamnya maka makanlah dan apabila ia mengenai dengan bagian yang tumpul maka jangan engkau makan.\" "},"3977":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ عُبَيْدِ بْنِ مُحَمَّدٍ الْكُوفِيُّ الْمُحَارِبِيُّ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ حَيْوَةَ بْنِ شُرَيْحٍ قَالَ سَمِعْتُ رَبِيعَةَ بْنَ يَزِيدَ يَقُولُ أَنْبَأَنَا أَبُو إِدْرِيسَ عَائِذُ اللَّهِ قَالَ سَمِعْتُ أَبَا ثَعْلَبَةَ الْخُشَنِيَّ يَقُولُقُلْتُ يَا رَسُولَ اللَّهِ إِنَّا بِأَرْضِ صَيْدٍ أَصِيدُ بِقَوْسِي وَأَصِيدُ بِكَلْبِي الْمُعَلَّمِ وَبِكَلْبِي الَّذِي لَيْسَ بِمُعَلَّمٍ فَقَالَ مَا أَصَبْتَ بِقَوْسِكَ فَاذْكُرْ اسْمَ اللَّهِ عَلَيْهِ وَكُلْ وَمَا أَصَبْتَ بِكَلْبِكَ الْمُعَلَّمِ فَاذْكُرْ اسْمَ اللَّهِ وَكُلْ وَمَا أَصَبْتَ بِكَلْبِكَ الَّذِي لَيْسَ بِمُعَلَّمٍ فَأَدْرَكْتَ ذَكَاتَهُ فَكُلْ","id":"Telah mengabarkan kepadaku [Muhammad bin 'Ubaid bin Muhammad Al Kufi Al Muharibi], ia berkata; telah menceritakan kepada kami [Abdullah bin Al Mubarak] dari [Haiwah bin Syuraih], ia berkata; saya mendengar [Rabi'ah bin Yazid] berkata; telah memberitakan kepada kami [Abu Idris 'Aidzullah], ia berkata; saya mendengar [Abu Tsa'labah Al Khusyani] berkata; saya berkata; wahai Rasulullah, sesungguhnya kami berada di lahan perburuan, saya berburu menggunakan busurku dan berburu dengan anjingku yang telah terlatih dan anjingku yang belum terlatih. Maka beliau bersabda: \"Apa yang engkau kenai dengan busurmu maka sebutlah nama Allah padanya dan makanlah, dan apa yang engkau kenai dengan anjingmu yang terlatih maka sebutlah nama Allah dan makanlah, dan apa yang engkau kenai dengan anjingmu yang belum terlatih kemudian engkau sempat menyembelihnya maka makanlah.\""},"3978":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ زُنْبُورٍ أَبُو صَالِحٍ الْمَكِّيُّ قَالَ حَدَّثَنَا فُضَيْلُ بْنُ عِيَاضٍ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ هَمَّامِ بْنِ الْحَارِثِ عَنْ عَدِيِّ بْنِ حَاتِمٍ قَالَقُلْتُ يَا رَسُولَ اللَّهِ أُرْسِلُ كِلَابِي الْمُعَلَّمَةَ فَيُمْسِكْنَ عَلَيَّ فَآكُلُ قَالَ إِذَا أَرْسَلْتَ كِلَابَكَ الْمُعَلَّمَةَ فَأَمْسَكْنَ عَلَيْكَ فَكُلْ قُلْتُ وَإِنْ قَتَلْنَ قَالَ وَإِنْ قَتَلْنَ قَالَ مَا لَمْ يَشْرَكْهُنَّ كَلْبٌ مِنْ سِوَاهُنَّ قُلْتُ أَرْمِي بِالْمِعْرَاضِ فَيَخْزِقُ قَالَ إِنْ خَزَقَ فَكُلْ وَإِنْ أَصَابَ بِعَرْضِهِ فَلَا تَأْكُلْ","id":"Telah mengabarkan kepada kami [Muhammad bin Zunbur Abu Shaleh Al Makki], ia berkata; telah menceritakan kepada kami [Fudhail bin 'Iyadh] dari [Manshur] dari [Ibrahim] dari [Hammam bin Al Harits] dari ['Adi bin Hatim], ia berkata; saya berkata; wahai Rasulullah, saya mengirim anjing- anjingku yang telah terlatih, kemudian mereka menangkap untukku, apakah saya boleh memakannya? Beliau bersabda: \"Apabila engkau mengirim anjing- anjing yang telah terlatih kemudian mereka menangkap untukmu maka makanlah.\" Saya katakan; walaupun anjing - anjing tersebut membunuh? Beliau bersabda: \"Walaupun anjing- anjing tersebut membunuh.\" Beliau bersabda: \"Selama tidak ada anjing lain yang ikut bersama mereka.\" Saya katakan; bolehkah saya memanah menggunakan anak panah yang tidka bermata kemudian menancap padanya? Beliau bersabda: \"Apabila menancap maka makanlah, dan apabila mengenai dengan bagian yang tumpul maka janganlah engkau makan.\""},"3979":{"ar":"أَخْبَرَنِي عَمْرُو بْنُ يَحْيَى بْنِ الْحَارِثِ قَالَ حَدَّثَنَا أَحْمَدُ بْنُ أَبِي شُعَيْبٍ قَالَ حَدَّثَنَا مُوسَى بْنُ أَعْيَنَ عَنْ مَعْمَرٍ عَنْ عَاصِمِ بْنِ سُلَيْمَانَ عَنْ عَامِرٍ الشَّعْبِيِّ عَنْ عَدِيِّ بْنِ حَاتِمٍأَنَّهُ سَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الصَّيْدِ فَقَالَ إِذَا أَرْسَلْتَ كَلْبَكَ فَخَالَطَتْهُ أَكْلُبٌ لَمْ تُسَمِّ عَلَيْهَا فَلَا تَأْكُلْ فَإِنَّكَ لَا تَدْرِي أَيَّهَا قَتَلَهُ","id":"Telah mengabarkan kepada kami ['Amr bin Yahya bin Al Harits], ia berkata; telah menceritakan kepada kami [Ahmad bin Abu Syu'aib], ia berkata; telah menceritakan kepada kami [Musa bin A'yan] dari [Ma'mar] dari ['Ashim bin Sulaiman] dari ['Amir Asy Sya'bi] dari ['Adi bin Hatim] bahwa Ia bertanya kepada Rasulullah shallallahu 'alaihi wasallam mengenai hewan buruan, maka beliau bersabda: \"Apabila engkau mengirim anjingmu kemudian ada anjing- anjing lain yang bercampur dengannya dan engkau belum menyebut nama Allah padanya maka janganlah engkau makan, karena sesungguhnya engkau tidak tahu aniing manakah yang membunuhnya.\""},"3980":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا زَكَرِيَّا وَهُوَ ابْنُ أَبِي زَائِدَةَ قَالَ حَدَّثَنَا عَامِرٌ عَنْ عَدِيِّ بْنِ حَاتِمٍ قَالَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْكَلْبِ فَقَالَ إِذَا أَرْسَلْتَ كَلْبَكَ فَسَمَّيْتَ فَكُلْ وَإِنْ وَجَدْتَ كَلْبًا آخَرَ مَعَ كَلْبِكَ فَلَا تَأْكُلْ فَإِنَّمَا سَمَّيْتَ عَلَى كَلْبِكَ وَلَمْ تُسَمِّ عَلَى غَيْرِهِ","id":"Telah mengabarkan kepada kami ['Amr bin Ali], ia berkata; telah menceritakan kepada kami [Yahya], ia berkata; telah menceritakan kepada kami [Zakariya yaitu Ibnu Abu Zaidah], ia berkata; telah menceritakan kepada kami ['Amir] dari ['Adi bin Hatim], ia berkata; saya bertanya kepada Rasulullah shallallahu 'alaihi wasallam mengenai anjing. Kemudian beliau bersabda: \"Apabila engkau mengirimkan anjingmu maka sebutkan nama Allah dan makanlah, dan apabila engkau dapati anjing yang lain bersama dengan anjingmu maka janganlah engkau makan, karena sesungguhnya engkau hanya menyebut nama Allah pada anjingmu saja, dan tidak menyebutnya pada anjing yang lain.\""},"3981":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ بْنِ الْحَكَمِ قَالَ حَدَّثَنَا مُحَمَّدٌ وَهُوَ ابْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ سَعِيدِ بْنِ مَسْرُوقٍ قَالَ حَدَّثَنَا الشَّعْبِيُّ عَنْ عَدِيِّ بْنِ حَاتِمٍ وَكَانَ لَنَا جَارًا وَدَخِيلًا وَرَبِيطًا بِالنَّهْرَيْنِأَنَّهُ سَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أُرْسِلُ كَلْبِي فَأَجِدُ مَعَ كَلْبِي كَلْبًا قَدْ أَخَذَ لَا أَدْرِي أَيَّهُمَا أَخَذَ قَالَ لَا تَأْكُلْ فَإِنَّمَا سَمَّيْتَ عَلَى كَلْبِكَ وَلَمْ تُسَمِّ عَلَى غَيْرِهِأَخْبَرَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ بْنِ الْحَكَمِ قَالَ حَدَّثَنَا مُحَمَّدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ قَالَ حَدَّثَنَا عَنْ الشَّعْبِيِّ عَنْ عَدِيٍّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِ ذَلِكَ","id":"Telah mengabarkan kepada kami [Ahmad bin Abdullah bin Al Hakam], ia berkata; telah menceritakan kepada kami [Muhammad yaitu Ibnu Ja'far], ia berkata; telah menceritakan kepada kami [Syu'bah] dari [Sa'id bin Masruq], ia berkata; telah menceritakan kepada kami [Asy Sya'bi] dari ['Adi bin Hatim] dan ia adalah tetangga kami, orang yang bercampur dengan kami dan senantiasa tinggal di Nahrain, bahwa ia bertanya kepada Nabi shallallahu 'alaihi wasallam, ia berkata; saya mengirim ajingku dan saya dapati anjing lain bersamanya yang telah menangkap buruan, saya tidak tahu manakah diantara keduanya yang menangkap. Beliau bersabda: \"Janganlah engkau memakannya karena engkau hanya menyebutkan nama Allah pada anjingmu saja dan tidak menyebutkannya pada anjing yang lain.\" telah mengabarkan kepada kami [Ahmad bin Abdullah bin Al Hakam], ia berkata; telah menceritakan kepada kami [Muhammad], ia berkata; telah menceritakan kepada kami [Syu'bah] dari [Al Hakam], ia berkata; ia telah menceritakan kepada kami [Asy Sya'bi] dari ['Adi] dari Nabi shallallahu 'alaihi wasallam dengan hadits yang sama Seperti itu."},"3982":{"ar":"أَخْبَرَنَا سُلَيْمَانُ بْنُ عُبَيْدِ اللَّهِ بْنِ عَمْرٍو الْغَيْلَانِيُّ الْبَصْرِيُّ قَالَ حَدَّثَنَا بَهْزٌ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ أَبِي السَّفَرِ عَنْ عَامِرٍ الشَّعْبِيِّ عَنْ عَدِيِّ بْنِ حَاتِمٍ قَالَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْتُ أُرْسِلُ كَلْبِي قَالَ إِذَا أَرْسَلْتَ كَلْبَكَ فَسَمَّيْتَ فَكُلْ وَإِنْ أَكَلَ مِنْهُ فَلَا تَأْكُلْ فَإِنَّمَا أَمْسَكَ عَلَى نَفْسِهِ وَإِذَا أَرْسَلْتَ كَلْبَكَ فَوَجَدْتَ مَعَهُ غَيْرَهُ فَلَا تَأْكُلْ فَإِنَّكَ إِنَّمَا سَمَّيْتَ عَلَى كَلْبِكَ وَلَمْ تُسَمِّ عَلَى غَيْرِهِ","id":"Telah mengabarkan kepada kami [Sulaiman bin 'Ubaidullah bin 'Amr Al Ghailani Al Bashri], ia berkata; telah menceritakan kepada kami [Bahz], ia berkata; telah menceritakan kepada kami [Syu'bah], ia berkata; telah menceritakan kepada kami [Abdullah bin Abu As Safar] dari ['Amir Asy Sya'bi] dari ['Adi bin Hatim], ia berkata; saya bertanya kepada Rasulullah shallallahu 'alaihi wasallam, saya katakan; saya mengirimkan anjingku. Beliau bersabda: \"Apabila engkau mengirim anjingmu dan engkau sebutkan nama Allah maka makanlah dan apabila ia memakan sebagian darinya maka jangan engakau makan, karena ia menangkap untuk dirinya dan apabila engkau mengirim anjingmu kemudian engkau dapati anjing lain bersamanya maka janganlah engkau makan, karena sesungguhnya engkau hanya menyebutkan nama Allah pada anjingmu saja dan tidak menyebutkannya pada selainnya."},"3983":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا أَبُو دَاوُدَ عَنْ شُعْبَةَ عَنْ ابْنِ أَبِي السَّفَرِ عَنْ الشَّعْبِيِّ وَعَنْ الْحَكَمِ عَنْ الشَّعْبِيِّ وَعَنْ سَعِيدِ بْنِ مَسْرُوقٍ عَنْ الشَّعْبِيِّ عَنْ عَدِيِّ بْنِ حَاتِمٍ قَالَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْتُ أُرْسِلُ كَلْبِي فَأَجِدُ مَعَ كَلْبِي كَلْبًا آخَرَ لَا أَدْرِي أَيَّهُمَا أَخَذَ قَالَ لَا تَأْكُلْ فَإِنَّمَا سَمَّيْتَ عَلَى كَلْبِكَ وَلَمْ تُسَمِّ عَلَى غَيْرِهِ","id":"Telah mengabarkan kepada kami ['Amr bin Ali], ia berkata; telah menceritakan kepada kami [Abu Daud] dari [Syu'bah] dari [Ibnu Abu As Safar] dari [Asy Sya'bi]. Dan dari [Al Hakam] dari [Asy Sya'bi]. Juga dari [Sa'id bin Masruq] dari [Asy Sya'bi] dari ['Adi bin Hatim], ia berkata; saya bertanya kepada Rasulullah shallallahu 'alaihi wasallam, saya katakan; saya mengirimkan anjingku kemuidian saya dapati anjing yang lain bersama anjingku, saya tidak tahu anjing yang manakah yang menangkap buruan tersebut. Beliau bersabda: \"Janganlah engkau makan, karena sesungguhnya engkau menyebutkan nama Allah pada anjingmu dan tidak menyebutkan pada selainnya."},"3984":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا يَزِيدُ وَهُوَ ابْنُ هَارُونَ أَنْبَأَنَا زَكَرِيَّا وَعَاصِمٌ عَنْ الشَّعْبِيِّ عَنْ عَدِيِّ بْنِ حَاتِمٍ قَالَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ صَيْدِ الْمِعْرَاضِ فَقَالَ مَا أَصَابَ بِحَدِّهِ فَكُلْ وَمَا أَصَابَ بِعَرْضِهِ فَهُوَ وَقِيذٌ قَالَ وَسَأَلْتُهُ عَنْ كَلْبِ الصَّيْدِ فَقَالَ إِذَا أَرْسَلْتَ كَلْبَكَ وَذَكَرْتَ اسْمَ اللَّهِ عَلَيْهِ فَكُلْ قُلْتُ وَإِنْ قَتَلَ قَالَ وَإِنْ قَتَلَ فَإِنْ أَكَلَ مِنْهُ فَلَا تَأْكُلْ وَإِنْ وَجَدْتَ مَعَهُ كَلْبًا غَيْرَ كَلْبِكَ وَقَدْ قَتَلَهُ فَلَا تَأْكُلْ فَإِنَّكَ إِنَّمَا ذَكَرْتَ اسْمَ اللَّهِ عَزَّ وَجَلَّ عَلَى كَلْبِكَ وَلَمْ تَذْكُرْ عَلَى غَيْرِهِ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman], ia berkata; telah menceritakan kepada kami [Yazid yaitu Ibnu Harun], telah memberitakan kepada kami [Zakariya] dan ['Ashim] dari [Asy Sya'bi] dari ['Adi bin Hatim], ia berkata; saya bertanya kepada Rasulullah shallallahu 'alaihi wasallam mengenai hewan buruan dengan anak panah tanpa mata panah, maka beliau bersabda: \"Apa yang engkau kenai dengan bagian yang tajam maka makanlah dan apa yang engkau kenai dengan bagian yang tumpul maka itu adalah hewan yang mati karena terkena benda tumpul.\" Dan saya bertanya kepada beliau mengenai anjing pemburu, maka beliau bersabda: \"Apabila engkau mengirimkan anjingmu dan menyebut nama Allah padanya maka makanlah.\" Saya katakan; walaupun ia membunuhnya? Beliau bersabda: \"Walaupun ia membunuhnya, apabila ia makan sebagian darinya maka janganlah engkau makan, dan jika engkau dapati bersamanya terdapat anjing lain selain anjingmu dan ia telah membunuhnya maka jangan engkau makan karena sesungguhnya engkau hanya menyebutkan nama Allah 'azza wajalla pada anjingmu dan tidak engkau sebutkan pada anjing yang lain.\""},"3985":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ يَحْيَى بْنِ الْحَارِثِ قَالَ حَدَّثَنَا أَحْمَدُ بْنُ أَبِي شُعَيْبٍ قَالَ حَدَّثَنَا مُوسَى بْنُ أَعْيَنَ عَنْ مَعْمَرٍ عَنْ عَاصِمِ بْنِ سُلَيْمَانَ عَنْ الشَّعْبِيِّ عَنْ عَدِيِّ بْنِ حَاتِمٍ الطَّائِيِّأَنَّهُ سَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الصَّيْدِ قَالَ إِذَا أَرْسَلْتَ كَلْبَكَ فَذَكَرْتَ اسْمَ اللَّهِ عَلَيْهِ فَقَتَلَ وَلَمْ يَأْكُلْ فَكُلْ وَإِنْ أَكَلَ مِنْهُ فَلَا تَأْكُلْ فَإِنَّمَا أَمْسَكَهُ عَلَيْهِ وَلَمْ يُمْسِكْ عَلَيْكَ","id":"Telah mengabarkan kepada kami ['Amr bin Yahya bin Al Harits], ia berkata; telah menceritakan kepada kami [Ahmad bin Abu Syu'aib], ia berkata; telah menceritakan kepada kami [Musa bin A'yan] dari [Ma'mar] dari ['Ashim bin Sulaiman] dari [Asy Sya'bi] dari ['Adi bin Hatim Ath Tha'i] bahwa Ia bertanya kepada Rasulullah shallallahu 'alaihi wasallam mengenai hewan buruan, beliau bersabda: \"Apabila engkau mengirim anjingmu dan engkau sebutkan nama Allah padanya kemudian ia membunuh dan tidak makan maka makanlah, dan apabila ia makan sebagian darinya maka jangan engkau makan, karena sesungguhnya ia menangkap untuk dirinya dan tidak menangkap untukmu.\""},"3986":{"ar":"أَخْبَرَنَا كَثِيرُ بْنُ عُبَيْدٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ حَرْبٍ عَنْ الزُّبَيْدِيِّ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي ابْنُ السَّبَّاقِ قَالَ أَخْبَرَتْنِي مَيْمُونَةُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَهُ جِبْرِيلُ عَلَيْهِ السَّلَام لَكِنَّا لَا نَدْخُلُ بَيْتًا فِيهِ كَلْبٌ وَلَا صُورَةٌ فَأَصْبَحَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَئِذٍ فَأَمَرَ بِقَتْلِ الْكِلَابِ حَتَّى إِنَّهُ لَيَأْمُرُ بِقَتْلِ الْكَلْبِ الصَّغِيرِ","id":"Telah mengabarkan kepada kami [Katsir bin 'Ubaid], ia berkata; telah menceritakan kepada kami [Muhammad bin Harb] dari [Az Zubaidi] dari [Az Zuhri], ia berkata; telah mengabarkan kepadaku [Ibnu As Sabbaq], ia berkata; telah mengabarkan kepadaku [Maimunah] bahwa Jibril berkata kepada Rasulullah shallallahu 'alaihi wasallam; kami tidak memasuki rumah yang padanya terdapat anjing dan gambar. Kemudian pada pagi hari tersebut Rasulullah shallallahu 'alaihi wasallam memerintahkan untuk membunuh anjing hingga beliau memerintahkan untuk membunuh anjing kecil. "},"3987":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ بِقَتْلِ الْكِلَابِ غَيْرَ مَا اسْتَثْنَى مِنْهَا","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] dari [Malik] dari [Nafi'] dari [Ibnu Umar] bahwa Rasulullah shallallahu 'alaihi wasallam memerintahkan untuk membunuh anjing tanpa terkecuali. "},"3988":{"ar":"أَخْبَرَنَا وَهْبُ بْنُ بَيَانٍ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ قَالَ قَالَ ابْنُ شِهَابٍ حَدَّثَنِي سَالِمُ بْنُ عَبْدِ اللَّهِ عَنْ أَبِيهِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَافِعًا صَوْتَهُ يَأْمُرُ بِقَتْلِ الْكِلَابِ فَكَانَتْ الْكِلَابُ تُقْتَلُ إِلَّا كَلْبَ صَيْدٍ أَوْ مَاشِيَةٍ","id":"Telah mengabarkan kepada kami [Wahb bin Bayan], ia berkata; telah menceritakan kepada kami [Ibnu Wahb], ia berkata; telah mengabarkan kepadaku [Yunus], ia berkata; [Ibnu Syihab] berkata; telah menceritakan kepadaku [Salim bin Abdullah] dari [ayahnya], ia berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam meninggikan suaranya memerintahkan untuk membunuh anjing, maka semua anjing dibunuh kecuali anjing pemburu dan anjing penjaga hewan ternak. "},"3989":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ عَمْرٍو عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ بِقَتْلِ الْكِلَابِ إِلَّا كَلْبَ صَيْدٍ أَوْ كَلْبَ مَاشِيَةٍ","id":"Telah mengabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Hammad] dari ['Amr] dari [Ibnu Umar] bahwa Rasulullah shallallahu 'alaihi wasallam memerintahkan untuk membunuh seluruh anjing kecuali anjing pemburu dan anjing penjaga hewan ternak."},"3990":{"ar":"أَخْبَرَنَا عِمْرَانُ بْنُ مُوسَى قَالَ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ قَالَ حَدَّثَنَا يُونُسُ عَنْ الْحَسَنِ عَنْ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْلَا أَنَّ الْكِلَابَ أُمَّةٌ مِنْ الْأُمَمِ لَأَمَرْتُ بِقَتْلِهَا فَاقْتُلُوا مِنْهَا الْأَسْوَدَ الْبَهِيمَ وَأَيُّمَا قَوْمٍ اتَّخَذُوا كَلْبًا لَيْسَ بِكَلْبِ حَرْثٍ أَوْ صَيْدٍ أَوْ مَاشِيَةٍ فَإِنَّهُ يَنْقُصُ مِنْ أَجْرِهِ كُلَّ يَوْمٍ قِيرَاطٌ","id":"Telah mengabarkan kepada kami [Imran bin Musa], ia berkata; telah menceritakan kepada kami [Yazid bin Zurai'], ia berkata; telah menceritakan kepada kami [Yunus] dari [Al Hasan] dari [Abdullah bin Mughaffal], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jikalau anjing itu bukan umat diantara umat niscaya saya akan memerintahkan untuk membunuhnya, bunuhlah anjing yang hitam pekat, siapapun orang yang mengambil anjing yang bukan anjing penjaga kebun atau anjing pemburu atau penjaga hewan ternak maka sesungguhnya akan berkurang dari pahalanya setiap hari sebanyak satu qirath. "},"3991":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا مُحَمَّدٌ وَيَحْيَى بْنُ سَعِيدٍ قَالَا حَدَّثَنَا شُعْبَةُ عَنْ عَليِّ بْنِ مُدْرِكٍ عَنْ أَبِي زُرْعَةَ عَنْ عَبْدِ اللَّهِ بْنِ نُجَيٍّ عَنْ أَبِيهِ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْمَلَائِكَةُ لَا تَدْخُلُ بَيْتًا فِيهِ صُورَةٌ وَلَا كَلْبٌ وَلَا جُنُبٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar], ia berkata; telah menceritakan kepada kami [Muhammad] dan [Yahya bin Sa'id] mereka berkata; telah menceritakan kepada kami [Syu'bah] dari [Ali bin Mudrik] dari [Abu Zur'ah] dari [Abdullah bin Nuji] dari [Ayahnya] dari [Ali bin Abu Thalib] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Malaikat tidak masuk rumah yang padanya terdapat gambar dan anjing serta orang yang junub.\""},"3992":{"ar":"أَخْبَرَنَا قُتَيْبَةُ وَإِسْحَقُ بْنُ مَنْصُورٍ عَنْ سُفْيَانَ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ عَنْ أَبِي طَلْحَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَدْخُلُ الْمَلَائِكَةُ بَيْتًا فِيهِ كَلْبٌ وَلَا صُورَةٌ","id":"Telah mengabarkan kepada kami [Qutaibah] dan [Ishaq bin Manshur] dari [Sufyan] dari [Az Zuhri] dari ['Ubaidullah bin Abdullah] dari [Ibnu Abbas] dari [Abu Thalhah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Malaikat tidak masuk rumah yang padanya terdapat anjing dan gambar.\""},"3993":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ خَالِدِ بْنِ خَلِيٍّ قَالَ حَدَّثَنَا بِشْرُ بْنُ شُعَيْبٍ عَنْ أَبِيهِ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي ابْنُ السَّبَّاقِ عَنْ ابْنِ عَبَّاسٍ قَالَ أَخْبَرَتْنِي مَيْمُونَةُ زَوْجُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَصْبَحَ يَوْمًا وَاجِمًا فَقَالَتْ لَهُ مَيْمُونَةُ أَيْ رَسُولَ اللَّهِ لَقَدْ اسْتَنْكَرْتُ هَيْئَتَكَ مُنْذُ الْيَوْمَ فَقَالَ إِنَّ جِبْرِيلَ عَلَيْهِ السَّلَام كَانَ وَعَدَنِي أَنْ يَلْقَانِي اللَّيْلَةَ فَلَمْ يَلْقَنِي أَمَا وَاللَّهِ مَا أَخْلَفَنِي قَالَ فَظَلَّ يَوْمَهُ كَذَلِكَ ثُمَّ وَقَعَ فِي نَفْسِهِ جَرْوُ كَلْبٍ تَحْتَ نَضَدٍ لَنَا فَأَمَرَ بِهِ فَأُخْرِجَ ثُمَّ أَخَذَ بِيَدِهِ مَاءً فَنَضَحَ بِهِ مَكَانَهُ فَلَمَّا أَمْسَى لَقِيَهُ جِبْرِيلُ عَلَيْهِ السَّلَام فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ كُنْتَ وَعَدْتَنِي أَنْ تَلْقَانِي الْبَارِحَةَ قَالَ أَجَلْ وَلَكِنَّا لَا نَدْخُلُ بَيْتًا فِيهِ كَلْبٌ وَلَا صُورَةٌ قَالَ فَأَصْبَحَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ ذَلِكَ الْيَوْمِ فَأَمَرَ بِقَتْلِ الْكِلَابِ","id":"Telah mengabarkan kepada kami [Muhammad bin Khalid bin Khali], ia berkata; telah menceritakan kepada kami [Bisyr bin Syu'aib] dari [ayahnya] dari [Az Zuhri], ia berkata; telah mengabarkan kepadaku [Ibnu As Sibaq] dari [Ibnu Abbas], ia berkata; telah mengabarkan kepadaku [Maimunah] isteri Nabi shallallahu 'alaihi wasallam bahwa Rasulullah shallallahu 'alaihi wasallam sangat bersedih di pagi hari, kemudian Maimunah berkata kepadanya; wahai Rasulullah, sungguh saya tidak mengetahui keadaan anda sejak hari ini. Beliau bersabda: \"Sesungguhnya Jibril 'alaihis salam telah berjanji untuk menemuiku pada malam ini, kemudian Ia tidak menemuiku. Demi Allah ia tidak pernah mengingkari janjinya kepadaku.\" Ibnu Abbas berkata; Beliau selama seharian dalam keadaan demikian, kemudian beliau teringat anjing kecil di bawah ranjang kami. Kemudian beliau memerintahkan agar anjing tersebut dikeluarkan, maka anjing tersebut dikeluarkan. Kemudian beliau mengambil air dengan tangannya dan mempercici tempat anjing tersebut. Kemudian pada sore harinya beliau berjumpa dengan Jibril 'alaihis salam. Lalu Rasulullah shallallahu 'alaihi wasallam bersabda kepadanya: \"Sungguh engkau telah berjanji kepadaku untuk menemuiku tadi malam.\" Jibril berkata; benar. Akan tetapi kami tidak memasuki rumah padanya terdapat anjing dan gambar. Ibnu Abbas berkata; kemudian pada pagi harinya Rasulullah shallallahu 'alaihi wasallam memerintahkan untuk membunuh Anjing. "},"3994":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرِ بْنِ سُوَيْدٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ وَهُوَ ابْنُ الْمُبَارَكِ عَنْ حَنْظَلَةَ قَالَ سَمِعْتُ سَالِمًا يُحَدِّثُ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ اقْتَنَى كَلْبًا نَقَصَ مِنْ أَجْرِهِ كُلَّ يَوْمٍ قِيرَاطَانِ إِلَّا ضَارِيًا أَوْ صَاحِبَ مَاشِيَةٍ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr bin Suwaid], ia berkata; telah memberitakan kepada kami [Abdullah yaitu Ibnu Al Mubarak] dari [Hanzhalah], ia berkata; saya mendengar [Salim] menceritakan dari [Ibnu Umar], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang memelihara anjing maka telah berkurang dari pahalanya setiap hari dua sebanyak dua qirath kecuali anjing pemburu atau anjing penjaga hewan ternak.\""},"3995":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرِ بْنِ إِيَاسِ بْنِ مُقَاتِلِ بْنِ مُشَمْرِجِ بْنِ خَالِدٍ السَّعْدِيُّ عَنْ إِسْمَعِيلَ وَهُوَ ابْنُ جَعْفَرٍ عَنْ يَزِيدَ وَهُوَ ابْنُ خُصَيْفَةَ قَالَ أَخْبَرَنِي السَّائِبُ بْنُ يَزِيدَأَنَّهُ وَفَدَ عَلَيْهِمْ سُفْيَانُ بْنُ أَبِي زُهَيْرٍ الشَّنَائِيُّ وَقَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ اقْتَنَى كَلْبًا لَا يُغْنِي عَنْهُ زَرْعًا وَلَا ضَرْعًا نَقَصَ مِنْ عَمَلِهِ كُلَّ يَوْمٍ قِيرَاطٌ قُلْتُ يَا سُفْيَانُ أَنْتَ سَمِعْتَ هَذَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَعَمْ وَرَبِّ هَذَا الْمَسْجِدِ","id":"Telah mengabarkan kepada kami [Ali bin Hujr bin Iyas bin Muqatil bin Musyamrij bin Khalid As Sa'di] dari [Isma'il yaitu Ibnu Ja'far] dari [Yazid yaitu Ibnu Khushaifah], ia berkata; telah mengabarkan kepadaku [As Saib bin Yazid] bahwa telah datang sebagai utusan kepada mereka Sufyan bin Abu Zuhair Asy Syanai dan ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang memelihara anjing tidak ia manfaatkan untuk menjaga tanaman dan hewan ternak maka telah berkurang dari pahala amalannya Setiap hari sebanyak dua qirath. Saya bertanya; wahai Sufyan, apakah engkau mendengar hal ini dari Rasulullah shallallahu 'alaihi wasallam? Ia berkata; ya, demi Tuhan masjid ini. "},"3996":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ أَنَّهُ سَمِعَهُ يَقُولُإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَمْسَكَ كَلْبًا إِلَّا كَلْبًا ضَارِيًا أَوْ كَلْبَ مَاشِيَةٍ نَقَصَ مِنْ أَجْرِهِ كُلَّ يَوْمٍ قِيرَاطَانِ","id":"Telah mengabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Al Laits] dari [Nafi'] dari [Ibnu Umar] bahwa ia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang menahan anjing kecuali anjing pemburu dan anjing penjaga hewan ternak maka telh berkurng dari pahalanya setiap hari sebanyak dua qirath. "},"3997":{"ar":"أَخْبَرَنَا عَبْدُ الْجَبَّارِ بْنُ الْعَلَاءِ عَنْ سُفْيَانَ قَالَ حَدَّثَنَا الزُّهْرِيُّ عَنْ سَالِمٍ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ اقْتَنَى كَلْبًا إِلَّا كَلْبَ صَيْدٍ أَوْ مَاشِيَةٍ نَقَصَ مِنْ أَجْرِهِ كُلَّ يَوْمٍ قِيرَاطَانِ","id":"Telah mengabarkan kepada kami [Abdul Jabbar bin Al 'Ala`] dari [Sufyan], ia berkata; telah menceritakan kepada kami [Az Zuhri] dari [Salim] dari [ayahnya] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: 'Barang siapa yang memelihara anjing selain anjing pemburu dan penjaga hewan ternak maka telah berkurang dari pahalanya setiap hari sebanyak dua qirath.\""},"3998":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا يَحْيَى وَابْنُ أَبِي عَدِيٍّ وَمُحَمَّدُ بْنُ جَعْفَرٍ عَنْ عَوْفٍ عَنْ الْحَسَنِ عَنْ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ اتَّخَذَ كَلْبًا إِلَّا كَلْبَ صَيْدٍ أَوْ مَاشِيَةٍ أَوْ زَرْعٍ نَقَصَ مِنْ أَجْرِهِ كُلَّ يَوْمٍ قِيرَاطٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar], ia berkata; telah menceritakan kepada kami [Yahya] dan [Ibnu Abu 'Adi] dan [Muhammad bin Ja'far] dari ['Auf] dari [Al Hasan] dari [Abdullah bin Mughaffal] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Barang siapa yang mengambil anjing selain anjing pemburu dan anjing penjaga hewan ternak dan tanaman maka telah berkurang dari pahalanya setiap hari sebanyak satu qirath.\" "},"3999":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عَبْدُ الرَّزَّاقِ قَالَ حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ اتَّخَذَ كَلْبًا إِلَّا كَلْبَ صَيْدٍ أَوْ زَرْعٍ أَوْ مَاشِيَةٍ نَقَصَ مِنْ عَمَلِهِ كُلَّ يَوْمٍ قِيرَاطٌ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim], ia berkata; telah memberitakan kepada kami [Abdur Razzaq], ia berkata; telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Abu Salamah] dari [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam beliau bersabda: \"\"Barang siapa yang mengambil anjing selain anjing pemburu dan anjing penjaga hewan tanaman dan ternak maka telah berkurang dari amalannya setiap hari sebanyak satu qirath.\" "},"4000":{"ar":"أَخْبَرَنَا وَهْبُ بْنُ بَيَانٍ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ قَالَ أَنْبَأَنَا ابْنُ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ اقْتَنَى كَلْبًا لَيْسَ بِكَلْبِ صَيْدٍ وَلَا مَاشِيَةٍ وَلَا أَرْضٍ فَإِنَّهُ يَنْقُصُ مِنْ أَجْرِهِ قِيرَاطَانِ كُلَّ يَوْمٍ","id":"Telah mengabarkan kepada kami [Wahb bin Bayan], ia berkata; telah menceritakan kepada kami [Ibnu Wahb], ia berkata; telah menceritakan kepadaku [Yunus], ia berkata; telah memberitakan kepada kami [Ibnu Syihab] dari [Sa'id bin Al Musayyab] dari [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam beliau bersabda: \"Barang siapa yang memelihara anjing yang bukan anjing pemburu dan anjing penjaga hewan ternak dan kebun maka akan berkurang dari pahalanya setiap hari sebanyak dua qirath.\" "}};
